INSERT INTO questions (id, domain, type, question, options, answer, difficulty, explanation, tags, vector, source)
VALUES
  ($$agr_001$$, $$农业与农学常识$$, $$single$$, $$被誉为‘杂交水稻之父’的中国著名农学家是？$$, $$["袁隆平", "屠呦呦", "钱学森", "竺可桢"]$$, $$[0]$$, $$easy$$, $$袁隆平院士在杂交水稻研究领域做出了开创性贡献。$$, ARRAY[$$农业研究$$,$$农学家$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_002$$, $$农业与农学常识$$, $$single$$, $$玉米的原产地是哪里？$$, $$["亚洲", "欧洲", "美洲", "非洲"]$$, $$[2]$$, $$easy$$, $$玉米原产于美洲（中美洲），由哥伦布发现新大陆后传播到世界各地。$$, ARRAY[$$主粮作物史$$,$$农作物源起$$]::text[], $${"农学": 1.0, "理学": 0.8, "工学": 0.05}$$, 'batch'),
  ($$agr_003$$, $$农业与农学常识$$, $$single$$, $$植物生长所需的‘三大营养元素’（大量元素）是？$$, $$["碳、氢、氧", "氮、磷、钾", "钙、镁、硫", "铁、锰、锌"]$$, $$[1]$$, $$easy$$, $$氮、磷、钾是植物干物中需求量最大的三种常见矿质元素，俗称肥料三要素。$$, ARRAY[$$农业科技$$,$$植物营养$$]::text[], $${"农学": 1.0, "理学": 0.8, "日子人": 1.0, "医学": 0.2, "工学": 0.05}$$, 'batch'),
  ($$agr_004$$, $$农业与农学常识$$, $$single$$, $$氮肥对农作物的最主要作用是？$$, $$["促进根系发育", "促进茎叶繁茂、叶色浓绿", "提高抗寒、抗旱能力", "促进开花结果"]$$, $$[1]$$, $$medium$$, $$氮是蛋白质和叶绿素的重要成分，氮肥主要促进植物茎叶的生长。$$, ARRAY[$$农业科技$$,$$植物营养$$]::text[], $${"农学": 1.0, "理学": 0.8, "日子人": 1.0, "医学": 0.2, "工学": 0.05}$$, 'batch'),
  ($$agr_005$$, $$农业与农学常识$$, $$single$$, $$俗话说的‘无土栽培’，主要是利用什么来为植物提供营养？$$, $$["空气", "纯净水", "营养液", "有机沙子"]$$, $$[2]$$, $$easy$$, $$无土栽培是通过营养液来替代土壤，为植物提供水分和矿质元素。$$, ARRAY[$$农业科技$$,$$栽培技术$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_006$$, $$农业与农学常识$$, $$single$$, $$长期在同一块土地上连续种植同一种作物，容易导致产量下降或病害严重。为了解决这个问题，农业上常采用的措施是？$$, $$["大量施用化肥", "温室栽培", "轮作", "密植"]$$, $$[2]$$, $$medium$$, $$轮作(Crop Rotation)能均衡利用土壤养分、减轻病虫害，是保护地力的重要措施。$$, ARRAY[$$农业科技$$,$$耕作制度$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_007$$, $$农业与农学常识$$, $$single$$, $$起源于以色列，现广泛应用于干旱地区，能够极大地节约水资源的灌溉技术是？$$, $$["漫灌", "喷灌", "滴灌", "渠道灌溉"]$$, $$[2]$$, $$medium$$, $$滴灌技术源于以色列，通过管道将水分一滴滴送达根部，是最省水的灌溉方式之一。$$, ARRAY[$$农业科技$$,$$灌溉技术$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_008$$, $$农业与农学常识$$, $$single$$, $$转基因抗虫棉之所以能抗虫，是因为向棉花中转入了能够表达什么的基因？$$, $$["除草剂抗性蛋白", "Bt杀虫蛋白", "抗寒防冻蛋白", "抗病原菌抗体"]$$, $$[1]$$, $$hard$$, $$转基因抗虫棉转入了苏云金芽孢杆菌(Bt)基因，这种基因表达的蛋白能杀死特定的鳞翅目害虫。$$, ARRAY[$$农业科技$$,$$转基因作物$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.6, "工学": 0.05}$$, 'batch'),
  ($$agr_009$$, $$农业与农学常识$$, $$single$$, $$波尔多液是农业上常用的一种优良的保护性杀菌剂，它的主要配制原料是？$$, $$["硫酸铜和生石灰", "硫酸锌和纯碱", "氯化钠和熟石灰", "硝酸银和氨水"]$$, $$[0]$$, $$hard$$, $$波尔多液是由硫酸铜、生石灰和水混合制成的天蓝色胶状悬浮液，能有效防治多种植物真菌病害。$$, ARRAY[$$农业科技$$,$$农药基础$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3, "农学": 0.5, "工学": 0.05}$$, 'batch'),
  ($$agr_010$$, $$农业与农学常识$$, $$single$$, $$在作物的种植季节上，我国俗称为‘冬小麦’的小麦，其播种和收获的季节分别是？$$, $$["春季播种，秋季收获", "秋季或初冬播种，次年春末夏初收获", "冬季播种，次年冬季收获", "夏季播种，秋季收获"]$$, $$[1]$$, $$medium$$, $$冬小麦需要经历冬天的低温春化阶段，一般在秋末冬初播种，次年夏季收割。$$, ARRAY[$$主粮作物$$,$$栽培常识$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_011$$, $$农业与农学常识$$, $$single$$, $$在同一块田地上，有顺序地在季节间或年间轮换种植不同作物的制度被称为？$$, $$["连作", "间作", "套作", "轮作"]$$, $$[3]$$, $$medium$$, $$间作和套作是在同一生长期内混合种植，轮作是在时间先后上的轮换。$$, ARRAY[$$农学基础$$,$$耕作制度$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_012$$, $$农业与农学常识$$, $$single$$, $$人类最早驯化的小麦品种起源于哪个地区？$$, $$["东亚的黄河流域", "西亚的新月沃地", "中美洲", "南美洲的安第斯山脉"]$$, $$[1]$$, $$hard$$, $$小麦最早驯化于西亚的新月沃地。黄河流域是粟(小米)的起源地，美洲是玉米和土豆的起源地。$$, ARRAY[$$主粮作物史$$,$$农业起源$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_013$$, $$农业与农学常识$$, $$single$$, $$以下不属于禾本科作物的是？$$, $$["水稻", "玉米", "大豆", "小麦"]$$, $$[2]$$, $$easy$$, $$大豆属于豆科植物。水稻、玉米、小麦均为禾本科。$$, ARRAY[$$农学分类$$,$$作物常识$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_014$$, $$农业与农学常识$$, $$single$$, $$钾肥对农作物的主要作用包括？$$, $$["只长茎叶不结实", "促进根系深度发育", "增强作物抗病、抗倒伏能力", "促进叶绿素迅速合成"]$$, $$[2]$$, $$medium$$, $$钾被称为‘品质元素’和‘抗逆元素’，能增强作物的抗病虫害、抗旱抗寒及抗倒伏能力。$$, ARRAY[$$农学基础$$,$$植物营养$$]::text[], $${"农学": 1.0, "理学": 0.8, "日子人": 1.0, "医学": 0.2, "工学": 0.05}$$, 'batch'),
  ($$agr_015$$, $$农业与农学常识$$, $$single$$, $$温室大棚能显著提高棚内温度，这种现象被称为‘温室效应’。大气中引发类似现象的最主要的温室气体是？$$, $$["氧气", "二氧化碳", "氮气", "由于氧气过多"]$$, $$[1]$$, $$easy$$, $$CO2吸收和放出红外辐射，是大气中最重要的温室气体。$$, ARRAY[$$农业设施$$,$$生态常识$$]::text[], $${"农学": 1.0, "理学": 0.8, "工学": 0.05}$$, 'batch'),
  ($$agr_016$$, $$农业与农学常识$$, $$single$$, $$农业生产上所说的‘嫁接’，是指把一种植物的枝或芽，接到另一种植物的茎或根上。这种繁殖方式属于？$$, $$["有性生殖", "无性生殖", "转基因繁殖", "自交繁殖"]$$, $$[1]$$, $$medium$$, $$嫁接保留了母本的遗传特性，没有经过精卵细胞的结合，因此属于营养生殖（无性生殖）。$$, ARRAY[$$农业科技$$,$$繁殖技术$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_017$$, $$农业与农学常识$$, $$single$$, $$马铃薯（土豆）的可食用部分，在植物学上属于它的什么器官？$$, $$["根", "花", "果实", "茎"]$$, $$[3]$$, $$medium$$, $$马铃薯是地下块茎。虽然长在地下，但它有芽眼（节），属于变态茎。$$, ARRAY[$$作物常识$$,$$植物器官$$]::text[], $${"医学": 1.0, "理学": 0.8, "日子人": 0.3, "农学": 1.0, "工学": 0.05}$$, 'batch'),
  ($$agr_018$$, $$农业与农学常识$$, $$single$$, $$‘杂种优势’在农业生产中广泛应用，它的主要表现是？$$, $$["杂交后代一定比纯种容易感染病害", "杂交一代在生长势、生活力、繁殖力等方面优于双亲", "杂种不用施肥也能高产", "杂交种子可以无限留种继续种植且表现依然优异"]$$, $$[1]$$, $$medium$$, $$杂种优势指异型杂交产生的F1代在多个性状上超越双亲。但如果继续留种F2代，会发生性状分离。$$, ARRAY[$$农学基础$$,$$遗传育种$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.6, "工学": 0.05}$$, 'batch'),
  ($$agr_019$$, $$农业与农学常识$$, $$single$$, $$通常被称为‘白色农业’的农业类型是指？$$, $$["在雪地里进行的冻土农业", "种植棉花等白色经济作物的农业", "大量使用白色塑料薄膜的温室大棚农业", "以微生物工业化应用为特征的工厂化农业"]$$, $$[3]$$, $$hard$$, $$传统的绿色农业以植物为核心，蓝色农业指海洋水产，白色农业则是指以微生物发酵工程为核心的工厂化农业（因研究人员穿白大褂而得名）。$$, ARRAY[$$农业科技$$,$$现代农业概念$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_020$$, $$农业与农学常识$$, $$single$$, $$世界三大主要粮食作物(主粮)是哪些？$$, $$["水稻、小麦、大豆", "水稻、小麦、玉米", "水稻、高粱、薯类", "小麦、玉米、黑麦"]$$, $$[1]$$, $$easy$$, $$水稻、小麦、玉米被称为世界三大主粮。$$, ARRAY[$$主粮作物史$$,$$农作物$$]::text[], $${"农学": 1.0, "理学": 0.8, "工学": 0.05}$$, 'batch'),
  ($$agr_021$$, $$农业与农学常识$$, $$single$$, $$被誉为‘杂交水稻之父’的中国科学家是？$$, $$["钟南山", "屠呦呦", "袁隆平", "钱学森"]$$, $$[2]$$, $$easy$$, $$袁隆平培育出了高产的杂交水稻。$$, ARRAY[$$农业科技$$,$$现代科技$$]::text[], $${"农学": 1.0, "理学": 0.5, "工学": 0.1}$$, 'batch'),
  ($$agr_022$$, $$农业与农学常识$$, $$single$$, $$波尔多液是一种传统的农业杀菌剂，它主要是由硫酸铜和哪种物质配制而成的？$$, $$["生石灰", "小苏打", "氯化钠", "漂白粉"]$$, $$[0]$$, $$medium$$, $$波尔多液是由硫酸铜、生石灰和水配制成的无机杀菌农药。$$, ARRAY[$$农药与肥料基础$$,$$农业化学$$]::text[], $${"医学": 1.0, "理学": 1.0, "日子人": 0.3, "工学": 0.6, "农学": 0.5}$$, 'batch'),
  ($$ai_001$$, $$人工智能基础$$, $$single$$, $$1956年奠定人工智能这一学科术语的历史性会议被称为？$$, $$["日内瓦会议", "达特矛斯会议", "布雷顿森林会议", "图灵学术研讨会"]$$, $$[1]$$, $$easy$$, $$1956年的美国达特矛斯会议（Dartmouth Conference）被公认为是人工智能（AI）学科诞生的标志。$$, ARRAY[$$AI史$$,$$达特矛斯$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_002$$, $$人工智能基础$$, $$single$$, $$阿兰·图灵提出的“图灵测试”主要目的是为了判断机器是否具有？$$, $$["逻辑纠错能力", "超越人类的计算速度", "表现出与人类同等的智能", "自我修复能力"]$$, $$[2]$$, $$easy$$, $$图灵测试旨在判断一台机器能否表现出让测试者无法分辨其为机器的人类智能水平。$$, ARRAY[$$人工智能$$,$$图灵测试$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_003$$, $$人工智能基础$$, $$single$$, $$机器学习（Machine Learning）与人工智能（AI）的关系是？$$, $$["两者是不同的完全独立学科", "AI是机器学习的一个子领域", "机器学习是实现AI的一种途径和子领域", "两者等价且可随时互换"]$$, $$[2]$$, $$easy$$, $$人工智能是大概念，机器学习是实现人工智能的一个极其重要的子集/子领域。$$, ARRAY[$$基础概念$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_004$$, $$人工智能基础$$, $$single$$, $$击败人类围棋世界冠军的AI系统AlphaGo，其核心技术主要依赖于深度学习和？$$, $$["专家系统", "强化学习", "KNN分类算法", "线性回归"]$$, $$[1]$$, $$medium$$, $$AlphaGo主要结合了深度卷积神经网络与蒙特卡洛树搜索，并使用了强化学习进行自我对弈进化。$$, ARRAY[$$AlphaGo$$,$$强化学习$$]::text[], $${"理学": 1.0, "工学": 0.6, "日子人": 0.15}$$, 'batch'),
  ($$ai_005$$, $$人工智能基础$$, $$single$$, $$如果在训练分类模型时，给予的数据集带有明确的正确标签（Label），这种学习方式称为？$$, $$["监督学习", "无监督学习", "半监督学习", "强化学习"]$$, $$[0]$$, $$easy$$, $$使用带有标签的数据进行模型训练被称为监督学习（Supervised Learning）。$$, ARRAY[$$机器学习$$,$$监督学习$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_006$$, $$人工智能基础$$, $$single$$, $$无监督学习中最典型的一种任务是？$$, $$["图像分类", "机器翻译", "聚类", "回归预测"]$$, $$[2]$$, $$medium$$, $$聚类（如K-Means算法）是在没有标签的数据中寻找内部结构和相似性，是典型的无监督学习。$$, ARRAY[$$无监督学习$$,$$聚类$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_007$$, $$人工智能基础$$, $$single$$, $$在人工神经网络（ANN）中，引入非线性特征，使得网络能够拟合复杂函数的关键组件是？$$, $$["权重", "偏置", "激活函数", "池化层"]$$, $$[2]$$, $$medium$$, $$激活函数（如ReLU、Sigmoid）引入了非线性，否则多层神经网络的叠加效果等同于一层线性模型。$$, ARRAY[$$神经网络$$,$$激活函数$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$ai_008$$, $$人工智能基础$$, $$single$$, $$专门针对于图像识别、对象分类等视觉任务设计，并在近十年取得巨大成功的深度学习网络架构是？$$, $$["CNN", "RNN", "GAN", "SVM"]$$, $$[0]$$, $$easy$$, $$卷积神经网络（CNN）通过卷积核提取局部特征，是计算机视觉领域的核心模型结构。$$, ARRAY[$$深度学习$$,$$CNN$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_009$$, $$人工智能基础$$, $$single$$, $$在自然语言处理(NLP)中，目前占据统治地位，且为GPT模型基础的架构是？$$, $$["RNN", "LSTM", "Transformer", "决策树"]$$, $$[2]$$, $$easy$$, $$Transformer是Google于2017年提出的基于自注意力机制的架构，彻底改变了NLP领域。$$, ARRAY[$$NLP$$,$$Transformer$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_010$$, $$人工智能基础$$, $$single$$, $$在机器学习中，“过拟合”（Overfitting）意味着模型？$$, $$["在训练集和测试集上表现都极差", "在训练集上表现极好，但在未见过的测试集上表现差", "训练速度极慢", "模型过于简单，无法学习数据的特征"]$$, $$[1]$$, $$medium$$, $$过拟合是指模型过于复杂，把训练数据的噪音也学去了，导致泛化能力差。$$, ARRAY[$$模型评估$$,$$过拟合$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_011$$, $$人工智能基础$$, $$single$$, $$在优化神经网络的过程中，用于不断调整参数以最小化损失函数的核心算法通常是？$$, $$["二分查找", "梯度下降", "贪心算法", "动态规划"]$$, $$[1]$$, $$medium$$, $$梯度下降算法是深度学习最基础的优化算法，通过计算损失函数关于参数的梯度来更新权重。$$, ARRAY[$$优化算法$$,$$梯度下降$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.15}$$, 'batch'),
  ($$ai_012$$, $$人工智能基础$$, $$single$$, $$能够通过两个网络（生成器和判别器）相互博弈来生成逼真图像或数据的模型是？$$, $$["CNN", "GAN", "GNN", "Autoencoder"]$$, $$[1]$$, $$medium$$, $$GAN（Generative Adversarial Network）由Ian Goodfellow发明，包含生成器和判别器的零和博弈。$$, ARRAY[$$生成模型$$,$$GAN$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_013$$, $$人工智能基础$$, $$single$$, $$ChatGPT等大模型属于AIGC，AIGC的核心含义是指？$$, $$["AI芯片制造", "人工智能生成内容", "人工智能通用计算", "AI全球控制"]$$, $$[1]$$, $$easy$$, $$AIGC全称 AI-Generated Content，即利用人工智能技术来自动生成文本、图像、音频等内容。$$, ARRAY[$$前沿概念$$,$$AIGC$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_014$$, $$人工智能基础$$, $$single$$, $$大语言模型（LLM）常会出现“幻觉”（Hallucination），在此语境下幻觉指的是？$$, $$["电脑屏幕闪烁", "模型产生自我意识并做梦", "模型一本正经地生成虚假或不符合事实的信息", "模型拒绝回答任何问题"]$$, $$[2]$$, $$easy$$, $$幻觉指AI生成的看似合理连贯但实际上是不正确或与现实不符的虚假陈述。$$, ARRAY[$$大模型$$,$$AI幻觉$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_015$$, $$人工智能基础$$, $$single$$, $$GPT全称为 Generative Pre-trained Transformer，其中“Pre-trained”指的是？$$, $$["前向传播", "预训练", "预测准确", "精确调整"]$$, $$[1]$$, $$medium$$, $$Pre-trained指模型在使用特定数据微调（Fine-tuning）之前，已在海量无标注文本上完成了预训练。$$, ARRAY[$$NLP$$,$$GPT$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_016$$, $$人工智能基础$$, $$single$$, $$深度学习广泛采用GPU而非仅仅用CPU进行训练的原因主要是？$$, $$["GPU功耗更低", "GPU适合海量数据的并行矩阵运算", "GPU显存通常比主机内存大", "算法要求只能在显卡上运行"]$$, $$[1]$$, $$medium$$, $$GPU具备成千上万个计算核心，非常适合深度学习中必须的大规模并行矩阵相乘操作。$$, ARRAY[$$硬件$$,$$GPU$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.15}$$, 'batch'),
  ($$ai_017$$, $$人工智能基础$$, $$single$$, $$通用人工智能 (AGI) 与 弱人工智能 (ANI) 的主要区别在于？$$, $$["前者的运算速度更快", "前者需要量子计算机", "前者能够像人类一样跨领域理解、学习并执行各种智能任务", "前者是目前的行业主流"]$$, $$[2]$$, $$easy$$, $$目前的AI都是弱/专用人工智能(ANI)。AGI指的是具备等同甚至超越人类的广泛认知能力的智能体。$$, ARRAY[$$AI分类$$,$$AGI$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_018$$, $$人工智能基础$$, $$single$$, $$为了评估多分类模型的综合性能，常常用来表示所有分类情况的正误统计矩阵被称为？$$, $$["协方差矩阵", "混淆矩阵", "海森矩阵", "单位矩阵"]$$, $$[1]$$, $$hard$$, $$混淆矩阵能直观地反应出模型正确分类与误分类分布（包含TP, TN, FP, FN）。$$, ARRAY[$$模型评估$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_019$$, $$人工智能基础$$, $$single$$, $$将输入的自然语言句子切分成模型可以处理的基础单元的过程叫做？$$, $$["切片运算", "Tokenization", "正则化", "归一化"]$$, $$[1]$$, $$hard$$, $$Tokenization是将长文本分解为可以被向量化表示的片段（Tokens，如字、词或子词单元）的关键语言预处理步骤。$$, ARRAY[$$NLP$$,$$数据预处理$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_020$$, $$人工智能基础$$, $$single$$, $$在强化学习中，智能体（Agent）根据什么信号来不断调整自己的动作策略以实现最终目标？$$, $$["异常报错", "重置信号", "奖励 或惩罚", "标签标注"]$$, $$[2]$$, $$medium$$, $$Agent通过与环境互动，接收奖励(Reward)信号来最大化长期期望收益。$$, ARRAY[$$强化学习$$]::text[], $${"理学": 1.0, "工学": 0.6, "日子人": 0.15}$$, 'batch'),
  ($$ai_021$$, $$人工智能基础$$, $$single$$, $$在经典算法中，常用于寻找图或迷宫中最短路径的启发式搜索算法是？$$, $$["冒泡排序", "K-Means", "A* 算法", "Apriori算法"]$$, $$[2]$$, $$hard$$, $$A* 算法是一种利用启发函数评估优先级的经典寻路算法，在自动驾驶、游戏AI中常用。$$, ARRAY[$$经典AI学$$,$$寻路算法$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_022$$, $$人工智能基础$$, $$single$$, $$解决深度神经网络层数增加带来的“梯度消失/爆炸”问题的一个重要网络结构创新是（常用于ResNet）？$$, $$["增加全连接层", "引入残差连接", "删除隐藏层", "使用Sigmoid全替代ReLU"]$$, $$[1]$$, $$hard$$, $$残差网络(ResNet)通过跳跃连接使得梯度能直接向回传递，成功解决了超深网络的训练难题。$$, ARRAY[$$深度学习$$,$$ResNet$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_023$$, $$人工智能基础$$, $$multiple$$, $$按照学习范式，经典的机器学习主要包括哪几种类型？$$, $$["监督学习", "无监督学习", "强化学习", "睡眠学习"]$$, $$[0, 1, 2]$$, $$easy$$, $$经典的机器学习三大范式即：监督学习、无监督学习和强化学习。$$, ARRAY[$$机器学习$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_024$$, $$人工智能基础$$, $$multiple$$, $$以下哪些是目前工业界及学术界主流的深度学习开源框架？$$, $$["TensorFlow", "PyTorch", "Microsoft Word", "Keras"]$$, $$[0, 1, 3]$$, $$medium$$, $$PyTorch、TensorFlow和构建在其之上的Keras是主流DL框架。Word是文字处理器。$$, ARRAY[$$开发工具$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.15}$$, 'batch'),
  ($$ai_025$$, $$人工智能基础$$, $$multiple$$, $$自然语言处理（NLP）在生活中的典型应用场景有？$$, $$["机器自动翻译", "语音助手对话", "文本情感分析", "人脸识别门禁"]$$, $$[0, 1, 2]$$, $$easy$$, $$前三者均处理文本或语音，属于NLP。人脸识别属于计算机视觉（CV）。$$, ARRAY[$$应用场景$$,$$NLP$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_026$$, $$人工智能基础$$, $$multiple$$, $$减轻或防止大模型/神经网络训练中“过拟合”的常见方法有？$$, $$["增加训练数据的多样性和数量", "使用正则化技术", "引入Dropout层", "提前停止训练"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$数据增强、正则化约束权重、Dropout随机失活神经元与通过验证集监控Early Stopping均是抗过拟合的重要手段。$$, ARRAY[$$模型训练$$,$$优化$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_027$$, $$人工智能基础$$, $$multiple$$, $$在评价一个二分类模型的准确情况时，常涉及哪些评估指标？$$, $$["准确率", "精确率", "召回率", "F1分数"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$这四大指标全面衡量了分类器对正负样本拦截、检出及平衡性能。$$, ARRAY[$$评估指标$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_028$$, $$人工智能基础$$, $$multiple$$, $$历史上的“AI寒冬”（AI Winter）主要是由哪些原因导致的？$$, $$["当时计算能力严重不足", "可用以训练的数据极度匮乏", "专家过度承诺未兑现导致资金撤走", "早期模型如单纯感知机无法解决非线性问题"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$硬件落后、无大数据、感知机缺陷导致的理论瓶颈加上资本的失望共同导致了冷冬。$$, ARRAY[$$AI史$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_029$$, $$人工智能基础$$, $$multiple$$, $$获得2018年图灵奖，被称为“深度学习三剑客”的科学家有哪些？$$, $$["Geoffrey Hinton", "Yann LeCun", "Yoshua Bengio", "Andrew Ng"]$$, $$[0, 1, 2]$$, $$hard$$, $$Hinton、LeCun 和 Bengio 因在深度学习领域的开创性贡献共获此殊荣。吴恩达也是大牛，但非这三人之列。$$, ARRAY[$$主要贡献者$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$ai_030$$, $$人工智能基础$$, $$multiple$$, $$近年来大火的大型语言模型（LLM）包括以下哪些产品或模型族？$$, $$["GPT-4", "Claude", "Llama", "Photoshop"]$$, $$[0, 1, 2]$$, $$easy$$, $$GPT、Claude和Llama是近年来最具代表性的大语言模型。Photoshop是图像处理软件。$$, ARRAY[$$通用大模型$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3}$$, 'batch'),
  ($$arc_001$$, $$建筑与设计$$, $$single$$, $$古代世界七大奇迹中唯一现存的建筑是？$$, $$["巴比伦空中花园", "亚历山大灯塔", "吉萨金字塔", "罗德岛巨像"]$$, $$[2]$$, $$easy$$, $$位于埃及吉萨的胡夫金字塔是古代世界七大奇迹中最古老且唯一保存至今的建筑。$$, ARRAY[$$古建筑$$,$$奇迹$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_002$$, $$建筑与设计$$, $$single$$, $$以飞扶壁、尖肋拱顶和彩色玻璃窗为显著特征的欧洲中世纪建筑风格是？$$, $$["罗马式建筑", "哥特式建筑", "巴洛克建筑", "拜占庭式建筑"]$$, $$[1]$$, $$easy$$, $$哥特式建筑起源于12世纪的法国，强调垂直向上的线条和光线的运用，代表作如巴黎圣母院、科隆大教堂。$$, ARRAY[$$建筑史$$,$$哥特式$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_003$$, $$建筑与设计$$, $$single$$, $$古希腊建筑中的三大柱式不包括下列哪一种？$$, $$["多立克柱式", "爱奥尼柱式", "科林斯柱式", "塔斯干柱式"]$$, $$[3]$$, $$medium$$, $$塔斯干柱式是后来古罗马人发展出的柱式。古希腊三大古典柱式是多立克、爱奥尼和科林斯。$$, ARRAY[$$古希腊$$,$$建筑柱式$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_004$$, $$建筑与设计$$, $$single$$, $$被称为“现代建筑的最后大师”，设计了朗香教堂和萨伏伊别墅的瑞士裔法国建筑师是？$$, $$["弗兰克·劳埃德·赖特", "勒·柯布西耶", "密斯·凡·德罗", "瓦尔特·格罗皮乌斯"]$$, $$[1]$$, $$medium$$, $$勒·柯布西耶是现代主义建筑的主要倡导者之一，提出了“新建筑五点”。$$, ARRAY[$$现代建筑$$,$$勒·柯布西耶$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_005$$, $$建筑与设计$$, $$single$$, $$设计了悉尼歌剧院的丹麦建筑师是？$$, $$["约翰·乌松", "阿尔瓦·阿尔托", "诺曼·福斯特", "雷姆·库哈斯"]$$, $$[0]$$, $$medium$$, $$约翰·乌松因设计悉尼歌剧院而闻名于世，该建筑是20世纪最具特色的建筑之一。$$, ARRAY[$$标志性建筑$$,$$悉尼歌剧院$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_006$$, $$建筑与设计$$, $$single$$, $$提出“少即是多”(Less is more) 这一名言，对极简主义和现代玻璃幕墙建筑产生深远影响的建筑师是？$$, $$["弗兰克·盖里", "勒·柯布西耶", "密斯·凡·德罗", "安藤忠雄"]$$, $$[2]$$, $$easy$$, $$密斯·凡·德罗（Mies van der Rohe）是现代主义建筑大师，这句名言确立了他的极简设计哲学。$$, ARRAY[$$现代建筑$$,$$极简主义$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.5, "哲学": 1.0, "法学": 0.3, "理学": 0.1}$$, 'batch'),
  ($$arc_007$$, $$建筑与设计$$, $$single$$, $$以“流水别墅”（Fallingwater）闻名，提倡“有机建筑”理念的美国建筑巨匠是？$$, $$["路易斯·康", "理查德·迈耶", "菲利普·约翰逊", "弗兰克·劳埃德·赖特"]$$, $$[3]$$, $$medium$$, $$赖特（Frank Lloyd Wright）是美国最伟大的建筑师之一，流水别墅是他有机建筑理念的巅峰之作。$$, ARRAY[$$有机建筑$$,$$赖特$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_008$$, $$建筑与设计$$, $$single$$, $$包豪斯（Bauhaus）是20世纪初在哪个国家成立的世界上第一所完全为发展现代设计教育而建立的学院？$$, $$["法国", "美国", "德国", "英国"]$$, $$[2]$$, $$easy$$, $$包豪斯学校于1919年在德国魏玛由瓦尔特·格罗皮乌斯创立，彻底改变了现代设计和建筑教育。$$, ARRAY[$$包豪斯$$,$$设计史$$]::text[], $${"艺术学": 1.0, "工学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_009$$, $$建筑与设计$$, $$single$$, $$巴黎卢浮宫广场上的玻璃金字塔入口是由哪位著名华裔建筑师设计的？$$, $$["林徽因", "贝聿铭", "梁思成", "马岩松"]$$, $$[1]$$, $$easy$$, $$贝聿铭（I. M. Pei）设计了卢浮宫扩建工程的关键部分——玻璃金字塔。$$, ARRAY[$$现代设计$$,$$贝聿铭$$]::text[], $${"艺术学": 1.0, "工学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_010$$, $$建筑与设计$$, $$single$$, $$被称为建筑界“诺贝尔奖”的最高荣誉奖项是？$$, $$["斯特林奖", "阿卡汗建筑奖", "普利兹克建筑奖", "AIA金奖"]$$, $$[2]$$, $$easy$$, $$普利兹克奖每年颁发一次，以表彰在世的杰出建筑师，被公认为全球建筑领域的最高荣誉。$$, ARRAY[$$建筑奖项$$,$$普利兹克$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_011$$, $$建筑与设计$$, $$single$$, $$西班牙巴塞罗那的著名地标建筑“圣家族大教堂”（Sagrada Família），其设计师是？$$, $$["安东尼·高迪", "圣地亚哥·卡拉特拉瓦", "理查德·罗杰斯", "伦佐·皮亚诺"]$$, $$[0]$$, $$easy$$, $$高迪（Antoni Gaudí）是加泰罗尼亚现代主义的代表，圣家族大教堂是他倾注毕生心血的未完杰作。$$, ARRAY[$$高迪$$,$$圣家族大教堂$$]::text[], $${"工学": 0.7, "艺术学": 0.8, "理学": 0.2}$$, 'batch'),
  ($$arc_012$$, $$建筑与设计$$, $$single$$, $$中国现存规模最大、保存最完整的皇家木构建筑群是？$$, $$["承德避暑山庄", "沈阳外八庙", "北京故宫", "曲阜孔庙"]$$, $$[2]$$, $$easy$$, $$北京故宫是明清两代的皇家宫殿，是世界上现存规模最大、保存最为完整的木质结构古建筑之一。$$, ARRAY[$$中国建筑$$,$$故宫$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_013$$, $$建筑与设计$$, $$single$$, $$罗马帝国时期的一项伟大工程杰作，拥有巨大半球形穹顶及中央采光圆洞（Oculus）的古建筑是？$$, $$["罗马斗兽场", "万神庙", "君士坦丁凯旋门", "卡拉卡拉浴场"]$$, $$[1]$$, $$medium$$, $$万神庙建于公元2世纪，其巨大的无钢筋混凝土穹顶至今仍是建筑史上的奇迹。$$, ARRAY[$$古罗马建筑$$,$$万神庙$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_014$$, $$建筑与设计$$, $$single$$, $$在工业设计领域，Dieter Rams (迪特·拉姆斯) 为哪个德国品牌做出了卓越贡献，提出了“好设计的十项原则”？$$, $$["博世", "保时捷", "博朗", "阿迪达斯"]$$, $$[2]$$, $$hard$$, $$拉姆斯在博朗公司担任首席设计师几十年，其极简、功能至上的设计深刻影响了后来的苹果公司等众多品牌。$$, ARRAY[$$工业设计$$,$$Dieter Rams$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "艺术学": 1.0, "理学": 0.1}$$, 'batch'),
  ($$arc_015$$, $$建筑与设计$$, $$single$$, $$以清水混凝土和对光线的极致运用（如“光之教堂”）而著称的当代日本建筑大师是？$$, $$["隈研吾", "安藤忠雄", "伊东丰雄", "丹下健三"]$$, $$[1]$$, $$medium$$, $$安藤忠雄自学成才，通过清水混凝土呈现极具禅意与自然交互的建筑空间，荣获普利兹克奖。$$, ARRAY[$$安藤忠雄$$,$$现代建筑$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_016$$, $$建筑与设计$$, $$single$$, $$中国古代建筑中，由于缺乏长木材，为了增加屋檐的挑出深度而发明的一种由斗与栱层层交叠出来的独特木构件称为？$$, $$["榫卯", "梁架", "斗栱", "雀替"]$$, $$[2]$$, $$medium$$, $$斗栱是中国传统木结构建筑中的关键承重和装饰构件，具有将屋顶荷载传递到柱子的作用，兼具出挑屋檐的功能。$$, ARRAY[$$中国古建筑$$,$$木结构$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_017$$, $$建筑与设计$$, $$single$$, $$巴黎蓬皮杜艺术中心（内脏外露式建筑）是哪一种建筑流派/风格的代表作？$$, $$["高技派", "粗野主义", "解构主义", "新古典主义"]$$, $$[0]$$, $$hard$$, $$蓬皮杜中心由理查德·罗杰斯和伦佐·皮亚诺设计，管线和结构暴露在外，是高技派的典型代表。$$, ARRAY[$$高技派$$,$$蓬皮杜中心$$]::text[], $${"工学": 0.7, "艺术学": 0.8, "理学": 0.2}$$, 'batch'),
  ($$arc_018$$, $$建筑与设计$$, $$single$$, $$拜占庭建筑的巅峰之作，位于今土耳其伊斯坦布尔，拥有巨大穹顶的建筑是？$$, $$["蓝色清真寺", "圣索菲亚大教堂", "托普卡帕宫", "科尔多瓦大清真寺"]$$, $$[1]$$, $$easy$$, $$建于公元6世纪的圣索菲亚大教堂以其巨大的穹顶和华丽的马赛克装饰成为拜占庭艺术的最高成就。$$, ARRAY[$$拜占庭建筑$$,$$圣索菲亚大教堂$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_019$$, $$建筑与设计$$, $$single$$, $$在UX/UI设计中，“UI”全称是User Interface（用户界面），那么“UX”的全称是？$$, $$["User Experience", "User Exchange", "User Execution", "Unity Exchange"]$$, $$[0]$$, $$easy$$, $$UX设计侧重于用户在使用产品时的心理感受、逻辑流程和整体体验。$$, ARRAY[$$数字设计$$,$$UX$$]::text[], $${"艺术学": 1.0, "工学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_020$$, $$建筑与设计$$, $$multiple$$, $$以下哪些属于勒·柯布西耶提出的“新建筑五点”？$$, $$["底层架空", "屋顶花园", "自由平面与自由立面", "横向长窗"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$这四项加上自由平面、自由立面共同组成了勒·柯布西耶1926年发表的现代建筑设计的五大原则（其中自由平面和立面通常算作两点，选项为了精简整合合并，四项均为其理念的核心部分）。$$, ARRAY[$$现代建筑理论$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "工学": 0.8, "艺术学": 0.8, "理学": 0.1}$$, 'batch'),
  ($$arc_021$$, $$建筑与设计$$, $$multiple$$, $$解构主义（Deconstructivism）建筑以破碎、非线性、反常规的形态著称。以下哪些建筑师是解构主义的代表人物？$$, $$["弗兰克·盖里", "扎哈·哈迪德", "雷姆·库哈斯", "安德烈·帕拉第奥"]$$, $$[0, 1, 2]$$, $$hard$$, $$帕拉第奥是文艺复兴时期古典主义的大师。前三位均是当代解构主义和前卫实验建筑的重要人物。$$, ARRAY[$$解构主义$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "工学": 0.35, "艺术学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_022$$, $$建筑与设计$$, $$multiple$$, $$关于中国四大名园，以下哪些属于此列？$$, $$["北京颐和园", "苏州拙政园", "承德避暑山庄", "苏州留园"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$中国四大名园为：颐和园、避暑山庄、拙政园、留园，分别代表了皇家园林和私家园林的最高水平。$$, ARRAY[$$中国古典园林$$]::text[], $${"工学": 0.7, "艺术学": 0.8, "理学": 0.2}$$, 'batch'),
  ($$arc_023$$, $$建筑与设计$$, $$multiple$$, $$人体工程学（Ergonomics）在工业设计中至关重要，其主要目的是？$$, $$["使产品的外形最具艺术美感", "确保人、机器与环境之间的协调", "提高使用的安全性、舒适性和效率", "最大限度地减少生产材料"]$$, $$[1, 2]$$, $$medium$$, $$人体工程学旨在优化人机交互系统，让人在使用工具时更健康、舒适和高效，而非单纯追求艺术美或省料。$$, ARRAY[$$工业设计$$,$$人体工程学$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "艺术学": 1.0, "医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$arc_024$$, $$建筑与设计$$, $$multiple$$, $$古典拱券结构系统在西方建筑史占有重要地位，以下哪些属于常见的拱券类型？$$, $$["半圆拱", "尖肋拱", "马蹄拱", "榫卯"]$$, $$[0, 1, 2]$$, $$medium$$, $$榫卯是中国木结构建筑的连接方式，不是西方砌筑承重结构中的拱券。$$, ARRAY[$$建筑结构$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$arc_025$$, $$建筑与设计$$, $$multiple$$, $$在字体排印学（Typography）中，关于无衬线体（Sans-serif），下列说法正确的有？$$, $$["字母笔画的首尾没有多余的装饰性线脚", "通常被认为具有现代、简洁的视觉感受", "常见的无衬线体如 Helvetica 和 Arial", "在任何时候都比衬线体更适合长篇印刷阅读"]$$, $$[0, 1, 2]$$, $$medium$$, $$衬线体（如Times New Roman或宋体）通常被认为在长篇实体纸质印刷中更利于眼睛追踪和阅读，而不是无衬线体一定更好。$$, ARRAY[$$平面设计$$,$$字体设计$$]::text[], $${"艺术学": 1.0, "工学": 0.4, "理学": 0.1}$$, 'batch'),
  ($$art_001$$, $$艺术史$$, $$single$$, $$文艺复兴时期的一位全才，不仅创作了《蒙娜丽莎》和《最后的晚餐》，还在解剖学、工程学上有极深造诣的是？$$, $$["米开朗基罗", "拉斐尔", "达·芬奇", "提香"]$$, $$[2]$$, $$easy$$, $$列奥纳多·达·芬奇是意大利文艺复兴时期的博学者，代表作包括《蒙娜丽莎》。$$, ARRAY[$$文艺复兴$$,$$达芬奇$$]::text[], $${"艺术学": 1.0, "历史学": 0.6, "文学": 0.3}$$, 'batch'),
  ($$art_002$$, $$艺术史$$, $$single$$, $$印象派（Impressionism）这一名称得自于哪位画家的一幅名为《日出·印象》的画作？$$, $$["文森特·梵高", "克劳德·莫奈", "保罗·塞尚", "爱德华·马奈"]$$, $$[1]$$, $$easy$$, $$克劳德·莫奈的《日出·印象》在1874年展出时被评论家嘲讽为“印象”，该流派由此得名。$$, ARRAY[$$印象派$$,$$莫奈$$]::text[], $${"艺术学": 1.0, "历史学": 0.6, "文学": 0.3}$$, 'batch'),
  ($$art_003$$, $$艺术史$$, $$single$$, $$创作了《星月夜》（The Starry Night）等传世名作，最终因精神疾病而割下自己耳朵乃至自杀的后印象派画家是？$$, $$["梵高", "高更", "塞尚", "雷诺阿"]$$, $$[0]$$, $$easy$$, $$文森特·梵高是荷兰后印象派著名画家，生前穷困潦倒，死后声名大噪。$$, ARRAY[$$后印象派$$,$$梵高$$]::text[], $${"艺术学": 1.0, "历史学": 0.6, "文学": 0.3}$$, 'batch'),
  ($$art_004$$, $$艺术史$$, $$single$$, $$立体派（Cubism）的创始人之一，以《格尔尼卡》、《亚威农的少女》闻名的西班牙艺术巨匠是？$$, $$["达利", "米罗", "毕加索", "戈雅"]$$, $$[2]$$, $$easy$$, $$巴勃罗·毕加索是立体主义的主要创始人之一，对20世纪现代艺术影响深远。$$, ARRAY[$$立体主义$$,$$毕加索$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 0.5, "文学": 0.15}$$, 'batch'),
  ($$art_005$$, $$艺术史$$, $$single$$, $$中国北宋时期张择端创作的传世名画，详实记录了北宋都城汴京繁华景象的是？$$, $$["《千里江山图》", "《清明上河图》", "《富春山居图》", "《步辇图》"]$$, $$[1]$$, $$easy$$, $$《清明上河图》生动记录了北宋都城汴京（今河南开封）的城市面貌和各阶层人民的生活状况。$$, ARRAY[$$中国画$$,$$宋代$$]::text[], $${"艺术学": 1.0, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_006$$, $$艺术史$$, $$single$$, $$“文艺复兴三杰”通常指的是达·芬奇、拉斐尔和？$$, $$["乔托", "米开朗基罗", "提香", "波提切利"]$$, $$[1]$$, $$medium$$, $$米开朗基罗（雕塑《大卫》，西斯廷教堂天顶画）与达·芬奇、拉斐尔并称为文艺复兴后期的三大巨匠。$$, ARRAY[$$文艺复兴$$,$$三杰$$]::text[], $${"艺术学": 1.0, "历史学": 0.6, "文学": 0.3}$$, 'batch'),
  ($$art_007$$, $$艺术史$$, $$single$$, $$《掷铁饼者》（Discobolus）是古希腊鼎盛时期哪位雕塑家的代表作？$$, $$["米隆", "菲迪亚斯", "波利克里托斯", "普拉克西特列斯"]$$, $$[0]$$, $$medium$$, $$《掷铁饼者》是古希腊雕塑家米隆的青铜雕塑作品，原品已失传，现多为罗马时期的大理石复制品。$$, ARRAY[$$古希腊艺术$$,$$雕塑$$]::text[], $${"艺术学": 1.0, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_008$$, $$艺术史$$, $$single$$, $$超现实主义（Surrealism）的代表人物，其作品《记忆的永恒》中包含著名的“融化的钟”的画家是？$$, $$["马格利特", "马克斯·恩斯特", "萨尔瓦多·达利", "夏加尔"]$$, $$[2]$$, $$medium$$, $$达利的《记忆的永恒》(The Persistence of Memory) 中的软表是超现实主义最著名的意象之一。$$, ARRAY[$$超现实主义$$,$$达利$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 0.5, "文学": 0.15}$$, 'batch'),
  ($$art_009$$, $$艺术史$$, $$single$$, $$在西方艺术史中，以华丽、繁复、强调曲线和金碧辉煌为特征，盛行于18世纪法国宫廷的艺术风格是？$$, $$["巴洛克", "洛可可", "新古典主义", "浪漫主义"]$$, $$[1]$$, $$medium$$, $$洛可可艺术起源于法国，以其轻盈、精巧、繁冗的装饰和甜美的色彩著称。$$, ARRAY[$$艺术风格$$,$$洛可可$$]::text[], $${"艺术学": 1.0, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_010$$, $$艺术史$$, $$single$$, $$波普艺术（Pop Art）的核心代表人物，经常使用玛丽莲·梦露肖像和金宝汤罐头作为创作素材的艺术家是？$$, $$["安迪·沃霍尔", "罗伊·利希滕斯坦", "贾斯珀·琼斯", "让-米歇尔·巴斯斯奎特"]$$, $$[0]$$, $$medium$$, $$安迪·沃霍尔（Andy Warhol）是视觉艺术运动“波普艺术”的主导人物。$$, ARRAY[$$波普艺术$$,$$安迪沃霍尔$$]::text[], $${"艺术学": 1.0, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_011$$, $$艺术史$$, $$single$$, $$西方古典艺术中的颜料在干结前可以不断进行修改调整被称为什么画？通常使用亚麻仁油作为调和剂。$$, $$["水彩画", "水粉画", "油画", "版画"]$$, $$[2]$$, $$easy$$, $$油画(Oil painting)由于使用快干油（如亚麻仁油）调和，干燥时间较长，允许画家从容修改和叠加。$$, ARRAY[$$油画$$,$$绘画材质$$]::text[], $${"艺术学": 1.0, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_012$$, $$艺术史$$, $$single$$, $$以强烈的明暗对比（Chiaroscuro）和神秘感著称的17世纪巴洛克时期荷兰画坛巨匠，代表作有《夜巡》的是？$$, $$["伦勃朗", "维米尔", "鲁本斯", "卡拉瓦乔"]$$, $$[0]$$, $$medium$$, $$伦勃朗 (Rembrandt) 被誉为绘画史上的明暗大师，《夜巡》是其最著名的群像画。$$, ARRAY[$$巴洛克$$,$$伦勃朗$$]::text[], $${"艺术学": 1.0, "历史学": 0.6, "文学": 0.3}$$, 'batch'),
  ($$art_013$$, $$艺术史$$, $$single$$, $$中国书法史上的“书圣”王羲之，其代表作被誉为“天下第一行书”的是？$$, $$["《多宝塔碑》", "《九成宫醴泉铭》", "《兰亭集序》", "《祭侄文稿》"]$$, $$[2]$$, $$medium$$, $$东晋王羲之的《兰亭集序》在行书艺术上登峰造极，被称为天下第一行书。$$, ARRAY[$$中国书法$$]::text[], $${"艺术学": 1.0, "历史学": 0.6, "文学": 0.3}$$, 'batch'),
  ($$art_014$$, $$艺术史$$, $$single$$, $$创立了绝对透视法、以一系列彩色小圆点来作画的点彩画派（Pointillism）创始人是？$$, $$["修拉", "塞尚", "德加", "马奈"]$$, $$[0]$$, $$hard$$, $$乔治·修拉（Georges Seurat）是新印象画派（点彩派）的代表人物，名作有《大碗岛的星期天下午》。$$, ARRAY[$$新印象派$$,$$点彩$$]::text[], $${"艺术学": 1.0, "历史学": 0.6, "文学": 0.3}$$, 'batch'),
  ($$art_015$$, $$艺术史$$, $$single$$, $$现代艺术流派“野兽派”（Fauvism）以其大胆、狂野的色彩使用而闻名，其领军人物是？$$, $$["亨利·马蒂斯", "安德烈·德兰", "乔治·布拉克", "马塞尔·杜尚"]$$, $$[0]$$, $$hard$$, $$马蒂斯（Henri Matisse）是野兽派的创始人和主要代表人物。$$, ARRAY[$$野兽派$$,$$马蒂斯$$]::text[], $${"理学": 0.8, "农学": 0.5, "艺术学": 0.5, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_016$$, $$艺术史$$, $$multiple$$, $$欧洲艺术史上，巴洛克（Baroque）艺术风格的主要特征包括？$$, $$["充满动感与戏剧性的紧张气氛", "强调光影的强烈对比", "追求严谨理性的几何平衡", "金碧辉煌的宏大装饰感"]$$, $$[0, 1, 3]$$, $$medium$$, $$巴洛克艺术打破了文艺复兴时期的宁静和平衡，追求动势、激情、光影和宏伟感。$$, ARRAY[$$艺术流派$$,$$巴洛克$$]::text[], $${"艺术学": 1.0, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_017$$, $$艺术史$$, $$multiple$$, $$意大利文艺复兴早期的两位先驱，分别在文学和绘画上开启了人文主义新时代的是？$$, $$["但丁", "达芬奇", "乔托", "米开朗基罗"]$$, $$[0, 2]$$, $$hard$$, $$但丁（《神曲》）是文学上的先驱，而乔托则在绘画上率先打破中世纪的刻板，被誉为欧洲绘画之父。$$, ARRAY[$$文艺复兴早期$$]::text[], $${"艺术学": 1.0, "历史学": 0.6, "文学": 0.3}$$, 'batch'),
  ($$art_018$$, $$艺术史$$, $$multiple$$, $$关于中国古代画作，以下哪些属于“中国十大传世名画”的内容？$$, $$["《步辇图》", "《韩熙载夜宴图》", "《洛神赋图》", "《伏尔加河上的纤夫》"]$$, $$[0, 1, 2]$$, $$easy$$, $$前三幅均为中国十大传世名画之一；《伏尔加河上的纤夫》是俄国列宾的油画。$$, ARRAY[$$中国名画$$]::text[], $${"艺术学": 1.0, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_019$$, $$艺术史$$, $$multiple$$, $$印象派艺术由于其强调捕捉瞬间的光影变化，常涉及哪些创作手法？$$, $$["在户外进行写生作画", "使用未经大量调和的纯色色彩并置", "极度执着于宗教题材的细致描绘", "刻意淡化传统的清晰轮廓线"]$$, $$[0, 1, 3]$$, $$medium$$, $$印象派抛弃了古典派的宗教神话题材和严谨轮廓，转而走向大自然捕捉光色。$$, ARRAY[$$印象派$$,$$创作手法$$]::text[], $${"艺术学": 1.0, "历史学": 0.6, "文学": 0.3}$$, 'batch'),
  ($$art_020$$, $$艺术史$$, $$multiple$$, $$20世纪初期涌现的现代主义前卫艺术流派包括？$$, $$["未来主义", "达达主义", "表现主义", "新古典主义"]$$, $$[0, 1, 2]$$, $$hard$$, $$新古典主义兴起于18世纪中叶到19世纪初；其余三个均是20世纪涌现的先锋现代艺术流派。$$, ARRAY[$$现代艺术$$]::text[], $${"艺术学": 1.0, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_021$$, $$艺术史$$, $$single$$, $$文艺复兴时期的‘美术三杰’不包括以下哪位？$$, $$["达·芬奇", "米开朗基罗", "拉斐尔", "梵高"]$$, $$[3]$$, $$easy$$, $$美术三杰是指达·芬奇、米开朗基罗和拉斐尔。梵高是后印象派画家。$$, ARRAY[$$文艺复兴$$,$$西方美术$$]::text[], $${"艺术学": 1.0, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_022$$, $$艺术史$$, $$single$$, $$《向日葵》和《星月夜》是哪位现代艺术先驱的代表作？$$, $$["莫奈", "梵高", "毕加索", "塞尚"]$$, $$[1]$$, $$easy$$, $$文森特·梵高创作了《向日葵》和《星月夜》。他影响了后来的现代流派。$$, ARRAY[$$现代艺术流派$$,$$表现主义$$]::text[], $${"艺术学": 1.0, "历史学": 0.5, "哲学": 1.0, "法学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$art_023$$, $$艺术史$$, $$single$$, $$世界著名艺术馆卢浮宫位于哪座城市？$$, $$["伦敦", "巴黎", "罗马", "纽约"]$$, $$[1]$$, $$easy$$, $$卢浮宫位于法国巴黎。$$, ARRAY[$$著名艺术馆藏$$,$$艺术馆博物馆$$]::text[], $${"艺术学": 1.0, "历史学": 0.3, "文学": 0.15}$$, 'batch'),
  ($$astro_001$$, $$天文学$$, $$single$$, $$太阳系中体积最大的行星是？$$, $$["火星", "地球", "木星", "土星"]$$, $$[2]$$, $$easy$$, $$木星是太阳系中质量和体积最大的行星。$$, ARRAY[$$太阳系$$,$$行星$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_002$$, $$天文学$$, $$single$$, $$距离地球最近的恒星是？$$, $$["比邻星", "天狼星", "太阳", "北极星"]$$, $$[2]$$, $$easy$$, $$太阳是距离地球最近的恒星，比邻星是距离太阳系最近的恒星。$$, ARRAY[$$恒星$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_003$$, $$天文学$$, $$single$$, $$光年是什么的单位？$$, $$["时间", "距离", "速度", "亮度"]$$, $$[1]$$, $$easy$$, $$光年是长度单位，指光在真空中行走一年的距离。$$, ARRAY[$$天文单位$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_004$$, $$天文学$$, $$single$$, $$人类首次登月乘坐的阿波罗登月舱属于哪个国家？$$, $$["苏联", "中国", "美国", "英国"]$$, $$[2]$$, $$easy$$, $$1969年，美国阿波罗11号实现了人类首次登月。$$, ARRAY[$$天文史$$,$$登月$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_005$$, $$天文学$$, $$single$$, $$银河系属于哪种星系类型？$$, $$["椭圆星系", "漩涡星系", "不规则星系", "透镜星系"]$$, $$[1]$$, $$medium$$, $$银河系是一个棒旋星系，属于漩涡星系的一种。$$, ARRAY[$$星系$$,$$银河系$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_006$$, $$天文学$$, $$single$$, $$太阳系八大行星中，唯一自转方向是从东向西的行星是？$$, $$["火星", "木星", "金星", "海王星"]$$, $$[2]$$, $$medium$$, $$金星的自转方向不仅与太阳系大部分行星相反（自东向西），并且自转周期比公转周期还长。$$, ARRAY[$$太阳系$$,$$金星$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_007$$, $$天文学$$, $$single$$, $$由于光速有限，当我们仰望夜空看到星星时，实际上看到的是它们的？$$, $$["现在", "过去", "未来", "幻影"]$$, $$[1]$$, $$easy$$, $$星光传到地球需要时间，所以看到的是星星过去的状态。$$, ARRAY[$$光速$$,$$常识$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_008$$, $$天文学$$, $$single$$, $$著名的哈雷彗星绕太阳公转的周期大约是？$$, $$["24年", "50年", "76年", "100年"]$$, $$[2]$$, $$medium$$, $$哈雷彗星的公转周期约为76年，最近一次过近日点是1986年。$$, ARRAY[$$彗星$$,$$哈雷$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_009$$, $$天文学$$, $$single$$, $$第一位提出“日心说”的近代天文学家是？$$, $$["托勒密", "伽利略", "哥白尼", "开普勒"]$$, $$[2]$$, $$easy$$, $$尼古拉·哥白尼在《天体运行论》中提出了日心说。$$, ARRAY[$$天文史$$,$$日心说$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_010$$, $$天文学$$, $$single$$, $$脉冲星实际上是快速自转的哪种天体？$$, $$["白矮星", "中子星", "黑洞", "恒星"]$$, $$[1]$$, $$medium$$, $$脉冲星是快速自转并发出电磁脉冲的中子星。$$, ARRAY[$$恒星演化$$,$$脉冲星$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_011$$, $$天文学$$, $$single$$, $$太阳的主要成分是？$$, $$["氢和氦", "氧和碳", "氮和氢", "硅和铁"]$$, $$[0]$$, $$medium$$, $$太阳主要由氢（约四分之三总量）和氦构成。$$, ARRAY[$$太阳恒星$$,$$化学组成$$]::text[], $${"理学": 1.0, "工学": 0.6, "哲学": 0.1}$$, 'batch'),
  ($$astro_012$$, $$天文学$$, $$single$$, $$根据大爆炸宇宙学模型，宇宙的年龄大约是多少？$$, $$["约46亿年", "约138亿年", "约1000亿年", "永恒无限"]$$, $$[1]$$, $$medium$$, $$普朗克卫星测量等多种观测支持宇宙年龄约为138亿年。$$, ARRAY[$$宇宙学$$,$$大爆炸$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_013$$, $$天文学$$, $$single$$, $$大质量恒星生命演化的最终归宿是？$$, $$["白矮星", "红巨星", "黑洞", "褐矮星"]$$, $$[2]$$, $$hard$$, $$极高质量的恒星核心坍缩，突破奥本海默-沃尔科夫极限，最终形成黑洞。较小质量核心形成中子星。$$, ARRAY[$$恒星演化$$,$$黑洞$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_014$$, $$天文学$$, $$single$$, $$在天文距离测量中，1个秒差距(pc)大约等于多少光年？$$, $$["1光年", "3.26光年", "8光年", "10光年"]$$, $$[1]$$, $$hard$$, $$秒差距是由视差定义的距离单位，1 pc ≈ 3.26 光年。$$, ARRAY[$$天文单位$$,$$测距$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_015$$, $$天文学$$, $$single$$, $$类星体（Quasar）通常被认为是极度明亮的活动星系核，它的能量来源主要依赖于？$$, $$["暗物质湮灭", "中心超大质量黑洞的吸积", "极化磁场", "数千亿颗恒星的核聚变"]$$, $$[1]$$, $$hard$$, $$类星本由宿主星系中心的超大质量黑洞吸积周围气体和物质释放巨大能量形成。$$, ARRAY[$$深空天体$$,$$类星体$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_016$$, $$天文学$$, $$multiple$$, $$太阳系八大行星中，属于“类地行星”（岩石行星）的有？$$, $$["水星", "金星", "地球", "木星"]$$, $$[0, 1, 2]$$, $$medium$$, $$水星、金星、地球、火星为岩石星球，属于类地行星。木星是气态巨行星。$$, ARRAY[$$太阳系$$,$$行星分类$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_017$$, $$天文学$$, $$multiple$$, $$现代天文学中，发现系外行星的主要方法有哪些？$$, $$["凌星法", "径向速度法", "直接成像法", "微引力透镜法"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$这四种均是主要的天文学中发现系外行星的探测方法，其中凌星法和视向速度法发现数量最多。$$, ARRAY[$$系外行星$$,$$探测方法$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_018$$, $$天文学$$, $$multiple$$, $$以下哪些天体属于太阳系的矮行星？$$, $$["冥王星", "谷神星", "阋神星", "海卫一"]$$, $$[0, 1, 2]$$, $$medium$$, $$冥王星、谷神星、阋神星都是公认的矮行星。海卫一是海王星的卫星。$$, ARRAY[$$太阳系$$,$$矮行星$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$astro_019$$, $$天文学$$, $$multiple$$, $$关于黑洞的描述，正确的有？$$, $$["引力极强，光也无法逃脱", "中间存在奇点", "只能通过吸积盘和辐射间接观测", "是由气态行星演化而来"]$$, $$[0, 1, 2]$$, $$medium$$, $$恒星级黑洞由大质量恒星演化而来，并非气态行星。其他描述正确。$$, ARRAY[$$黑洞$$,$$引力$$]::text[], $${"理学": 1.0, "工学": 1.0, "哲学": 0.1}$$, 'batch'),
  ($$astro_020$$, $$天文学$$, $$multiple$$, $$宇宙微波背景辐射的特征包括？$$, $$["各向同性", "温度约为2.7K", "起源于大爆炸后约38万年", "肉眼可见"]$$, $$[0, 1, 2]$$, $$hard$$, $$宇宙微波背景辐射位于微波波段，肉眼不可见，其他均为正确特征。$$, ARRAY[$$宇宙学$$,$$微波背景$$]::text[], $${"理学": 1.0, "工学": 0.2, "哲学": 0.2}$$, 'batch'),
  ($$bio_001$$, $$生物常识$$, $$single$$, $$控制生物遗传性状的主要遗传物质是？$$, $$["蛋白质", "RNA", "DNA", "糖类"]$$, $$[2]$$, $$easy$$, $$绝大多数生物(除部分病毒外)的遗传物质是DNA。$$, ARRAY[$$分子生物学$$,$$遗传物质$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.8, "农学": 0.6}$$, 'batch'),
  ($$bio_002$$, $$生物常识$$, $$single$$, $$在细胞结构中，被称为“动力工厂”，主要进行有氧呼吸的细胞器是？$$, $$["高尔基体", "核糖体", "线粒体", "内质网"]$$, $$[2]$$, $$easy$$, $$线粒体是细胞内氧化磷酸化和产生ATP的主要场所，被称作动力工厂。$$, ARRAY[$$细胞生物学$$,$$细胞器$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.5, "工学": 0.3}$$, 'batch'),
  ($$bio_003$$, $$生物常识$$, $$single$$, $$植物光合作用产生的氧气，其氧原子全部来自于哪种物质的分解？$$, $$["二氧化碳", "水", "葡萄糖", "叶绿素"]$$, $$[1]$$, $$medium$$, $$同位素标记实验证明，光合作用释放的O2全部来源于H2O的光解。$$, ARRAY[$$植物生理学$$,$$光合作用$$]::text[], $${"医学": 1.0, "理学": 0.8, "日子人": 0.3, "农学": 1.0, "工学": 0.3}$$, 'batch'),
  ($$bio_004$$, $$生物常识$$, $$single$$, $$人类的体细胞拥有多少条染色体？$$, $$["23条", "46条", "48条", "22条"]$$, $$[1]$$, $$easy$$, $$正常人体细胞有23对染色体，共46条（包含两性染色体XX或XY）。生殖细胞包含23条。$$, ARRAY[$$人体遗传学$$,$$染色体$$]::text[], $${"理学": 1.0, "医学": 1.0, "农学": 0.6, "日子人": 0.3, "工学": 0.3}$$, 'batch'),
  ($$bio_005$$, $$生物常识$$, $$single$$, $$由DNA转录生成信使RNA(mRNA)，再由mRNA指导合成蛋白质的过程在分子生物学上被称为？$$, $$["克隆定律", "基因工程", "中心法则", "PCR扩增"]$$, $$[2]$$, $$medium$$, $$克里克提出的中心法则描述了遗传信息从DNA到RNA再到蛋白质的流向。$$, ARRAY[$$分子生物学$$,$$中心法则$$]::text[], $${"理学": 1.0, "工学": 0.6, "农学": 0.4, "医学": 0.4}$$, 'batch'),
  ($$bio_006$$, $$生物常识$$, $$single$$, $$世界上第一个成功克隆的哺乳动物“多莉”是一只？$$, $$["狗", "猴", "羊", "鼠"]$$, $$[2]$$, $$easy$$, $$多莉(Dolly)是体细胞克隆技术培育出的一只绵羊。$$, ARRAY[$$生物技术$$,$$克隆$$]::text[], $${"理学": 1.0, "工学": 0.6, "农学": 0.8, "医学": 0.8}$$, 'batch'),
  ($$bio_007$$, $$生物常识$$, $$single$$, $$提出生物进化论，认为“物竞天择，适者生存”的科学家是？$$, $$["孟德尔", "拉马克", "达尔文", "巴斯德"]$$, $$[2]$$, $$easy$$, $$查尔斯·达尔文在《物种起源》中提出了基于自然选择的进化论。$$, ARRAY[$$进化生物学$$,$$达尔文$$]::text[], $${"理学": 1.0, "工学": 0.6, "农学": 0.8, "医学": 0.8}$$, 'batch'),
  ($$bio_008$$, $$生物常识$$, $$single$$, $$血型系统的ABO血型是由红细胞表面的什么物质决定的？$$, $$["抗体", "抗原", "脂质", "无机盐"]$$, $$[1]$$, $$medium$$, $$血型主要由红细胞膜表面特异性糖蛋白（抗原）的种类决定。$$, ARRAY[$$人体生理$$,$$血液$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3, "工学": 0.3, "农学": 0.4}$$, 'batch'),
  ($$bio_009$$, $$生物常识$$, $$single$$, $$青霉素是由哪类微生物产生的？$$, $$["细菌", "真菌", "病毒", "原虫"]$$, $$[1]$$, $$easy$$, $$青霉素(Penicillin)是由青霉菌（一种真菌）分泌的抗生素。$$, ARRAY[$$微生物学$$,$$抗生素$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.5, "工学": 0.3}$$, 'batch'),
  ($$bio_010$$, $$生物常识$$, $$single$$, $$负责合成蛋白质的游离或附着型细胞器是？$$, $$["溶酶体", "核糖体", "中心体", "液泡"]$$, $$[1]$$, $$medium$$, $$核糖体是细胞中翻译mRNA生成蛋白质亚基的分子机器。$$, ARRAY[$$细胞成分$$,$$核糖体$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.5, "工学": 0.9, "军事学": 0.4}$$, 'batch'),
  ($$bio_011$$, $$生物常识$$, $$single$$, $$构成人体蛋白质的氨基酸种类主要有？$$, $$["8种", "20种", "64种", "过百万种"]$$, $$[1]$$, $$medium$$, $$构成蛋白质的标准氨基酸约有20种（加上硒半胱氨酸等罕见种类约为22种，通用讲法为20）。$$, ARRAY[$$生物化学$$,$$氨基酸$$]::text[], $${"理学": 1.0, "工学": 0.6, "农学": 0.4, "医学": 0.4}$$, 'batch'),
  ($$bio_012$$, $$生物常识$$, $$single$$, $$免疫系统中，能够产生抗体的细胞是？$$, $$["红细胞", "巨噬细胞", "B淋巴细胞", "T淋巴细胞"]$$, $$[2]$$, $$hard$$, $$体液免疫中，B淋巴细胞分化为浆细胞，负责分泌特异性抗体。$$, ARRAY[$$免疫学$$,$$淋巴细胞$$]::text[], $${"医学": 1.0, "理学": 1.0, "日子人": 0.3, "农学": 0.5, "工学": 0.3}$$, 'batch'),
  ($$bio_013$$, $$生物常识$$, $$single$$, $$生态系统中的“分解者”主要是？$$, $$["绿色植物", "食草动物", "细菌和真菌", "食肉动物"]$$, $$[2]$$, $$easy$$, $$细菌和真菌等微生物可以分解动植物遗体，将有机物转化为无机物，归还环境。$$, ARRAY[$$生态学$$,$$生物圈$$]::text[], $${"农学": 1.0, "理学": 0.8, "工学": 0.3, "医学": 0.4}$$, 'batch'),
  ($$bio_014$$, $$生物常识$$, $$single$$, $$鸟类不仅肺能进行气体交换，还具有辅助呼吸的器官是？$$, $$["气管", "气囊", "鳃", "皮肤"]$$, $$[1]$$, $$medium$$, $$鸟类具有特殊的气囊辅助呼吸，进行高效的双重呼吸。$$, ARRAY[$$动物学$$,$$鸟类特征$$]::text[], $${"理学": 0.8, "农学": 0.5, "工学": 0.3, "医学": 0.4}$$, 'batch'),
  ($$bio_015$$, $$生物常识$$, $$single$$, $$大多数植物体内水分散失到大气中的主要途径作用叫做？$$, $$["蒸发作用", "呼吸作用", "光合作用", "蒸腾作用"]$$, $$[3]$$, $$easy$$, $$植物体内的水分主要通过气孔以水蒸气形式散失，这叫做蒸腾作用。$$, ARRAY[$$植物学$$,$$生理循环$$]::text[], $${"农学": 1.0, "理学": 0.8, "医学": 1.0, "日子人": 0.3, "工学": 0.3}$$, 'batch'),
  ($$bio_016$$, $$生物常识$$, $$single$$, $$DNA双螺旋结构的主要发现者（获得诺贝尔奖）是？$$, $$["沃森和克里克", "孟德尔", "摩尔根", "艾弗里"]$$, $$[0]$$, $$easy$$, $$1953年，沃森和克里克基于富兰克林的X射线衍射数据提出了DNA双螺旋模型。$$, ARRAY[$$生物史$$,$$DNA$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.6, "工学": 0.3}$$, 'batch'),
  ($$bio_017$$, $$生物常识$$, $$single$$, $$狂犬病病毒(Rabies virus)的遗传物质是？$$, $$["单链DNA", "双链DNA", "单链RNA", "双链RNA"]$$, $$[2]$$, $$hard$$, $$狂犬病病毒是典型的单股负链RNA病毒。$$, ARRAY[$$微生物学$$,$$病毒学$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.5, "工学": 0.3}$$, 'batch'),
  ($$bio_018$$, $$生物常识$$, $$single$$, $$“食物链”常由什么生物作为能量转化的第一营养级（起点）？$$, $$["食肉动物", "初级消费者", "分解者", "生产者"]$$, $$[3]$$, $$easy$$, $$生产者体内的叶绿体通过光合作用固定太阳能，是食物链的基础。$$, ARRAY[$$生态学$$,$$食物链$$]::text[], $${"农学": 1.0, "理学": 0.8, "工学": 0.3, "医学": 0.4}$$, 'batch'),
  ($$bio_019$$, $$生物常识$$, $$single$$, $$能够降低血糖浓度的主要激素是？$$, $$["肾上腺素", "甲状腺激素", "胰高血糖素", "胰岛素"]$$, $$[3]$$, $$easy$$, $$胰岛B细胞分泌的胰岛素是体内唯一能降低血糖水平的激素。$$, ARRAY[$$人体生理$$,$$内分泌$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3, "工学": 0.3, "农学": 0.4}$$, 'batch'),
  ($$bio_020$$, $$生物常识$$, $$single$$, $$神经系统中，细胞之间的信息传递主要通过释放什么化学物质完成跨突触传递？$$, $$["神经递质", "血红蛋白", "激素", "消化酶"]$$, $$[0]$$, $$medium$$, $$突触前膜释放神经递质作用于突触后膜，实现神经元间的化学信号传导。$$, ARRAY[$$神经生物学$$,$$突触$$]::text[], $${"理学": 1.0, "工学": 0.6, "农学": 0.8, "医学": 0.8}$$, 'batch'),
  ($$bio_021$$, $$生物常识$$, $$single$$, $$果蝇因其什么特点而长期作为遗传学的重要模式生物？$$, $$["寿命超长", "繁殖快、染色体少且易观察", "基因组与人类完全一致", "几乎不发生突变"]$$, $$[1]$$, $$medium$$, $$果蝇培养容易、繁殖快、世代短且巨型染色体便于观察，摩尔根用其证明了基因在染色体上。$$, ARRAY[$$遗传学$$,$$模式生物$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.6, "工学": 0.3}$$, 'batch'),
  ($$bio_022$$, $$生物常识$$, $$single$$, $$艾滋病病毒（HIV）破坏的人体关键免疫细胞主要是？$$, $$["红细胞", "血小板", "辅助性T细胞", "骨髓干细胞"]$$, $$[2]$$, $$hard$$, $$HIV特异性攻击人体的CD4+ T淋巴细胞，导致细胞免疫及体液免疫崩溃。$$, ARRAY[$$免疫学$$,$$病毒感染$$]::text[], $${"医学": 1.0, "理学": 1.0, "日子人": 0.3, "农学": 0.5, "工学": 0.3}$$, 'batch'),
  ($$bio_023$$, $$生物常识$$, $$multiple$$, $$以下哪些选项属于高等植物体特有的细胞结构？$$, $$["细胞壁", "叶绿体", "线粒体", "中心体"]$$, $$[0, 1]$$, $$medium$$, $$动植物都有线粒体；中心体见于动物和低等植物；植物特有细胞壁（含纤维素）、叶绿体和大液泡。$$, ARRAY[$$细胞学$$,$$动植物细胞比较$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 1.0, "工学": 0.3}$$, 'batch'),
  ($$bio_024$$, $$生物常识$$, $$multiple$$, $$现代分类系统中，生物被分为多个界，下列属于“真核生物域”的有？$$, $$["动物界", "植物界", "真菌界", "原核生物"]$$, $$[0, 1, 2]$$, $$easy$$, $$除了原核生物无成形的细胞核结构外，动植物及真菌都拥有包裹在核膜内的真核结构。$$, ARRAY[$$生物分类$$]::text[], $${"理学": 1.0, "工学": 0.6, "农学": 0.8, "医学": 0.8}$$, 'batch'),
  ($$bio_025$$, $$生物常识$$, $$multiple$$, $$关于DNA复制过程，下列说法正确的有？$$, $$["半保留复制", "需要DNA聚合酶", "需要解旋酶", "以单股RNA为模板"]$$, $$[0, 1, 2]$$, $$medium$$, $$DNA是通过解旋酶解链后，在DNA聚合酶作用下利用游离核苷酸按照半保留方式进行复制的。逆转录才用RNA作模板。$$, ARRAY[$$分子生物学$$,$$复制$$]::text[], $${"理学": 1.0, "工学": 0.6, "农学": 0.4, "医学": 0.4}$$, 'batch'),
  ($$bio_026$$, $$生物常识$$, $$multiple$$, $$维生素在人体中起着重要的调节作用成分，下列缺乏症匹配正确的有？$$, $$["缺乏维A易得夜盲症", "缺乏维C易得坏血病", "缺乏维D易得佝偻病", "缺乏维K引起贫血"]$$, $$[0, 1, 2]$$, $$medium$$, $$缺乏维K会导致凝血障碍出血。维B12缺乏也可导致巨幼红细胞贫血等。$$, ARRAY[$$人体健康$$,$$营养学$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 1.0, "农学": 0.4, "工学": 0.3}$$, 'batch'),
  ($$bio_027$$, $$生物常识$$, $$multiple$$, $$减数分裂(Meiosis)区别于有丝分裂的重要特征包括？$$, $$["染色体复制两次", "细胞连续分裂两次", "产生四个单倍体子细胞", "发生同源染色体联会及交叉互换"]$$, $$[1, 2, 3]$$, $$hard$$, $$减数分裂复制一次分裂两次；包含联会；最终染色体减半，产生四个生殖细胞。$$, ARRAY[$$细胞分裂$$,$$减数分裂$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.5, "工学": 0.3}$$, 'batch'),
  ($$bio_028$$, $$生物常识$$, $$multiple$$, $$植物体内主要用于运输水分、无机盐和有机营养物质的组织包括？$$, $$["木质部", "韧皮部", "分生组织", "机械组织"]$$, $$[0, 1]$$, $$easy$$, $$导管(木质部)主要自下而上运输水和无机盐，筛管(韧皮部)运输光合作用产生的营养有机物。$$, ARRAY[$$植物学$$,$$组织$$]::text[], $${"农学": 1.0, "理学": 0.8, "工学": 0.3, "医学": 0.4}$$, 'batch'),
  ($$bio_029$$, $$生物常识$$, $$multiple$$, $$下列属于哺乳动物典型共同特征的有？$$, $$["胎生", "哺乳", "体表长毛或被毛", "有成形的下颌骨和外耳壳"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$胎生(绝大多数)、哺乳、恒温、长毛、具外耳是哺乳动物基本特征。$$, ARRAY[$$动物分类学$$,$$哺乳动物$$]::text[], $${"理学": 0.8, "农学": 0.5, "工学": 0.3, "医学": 0.4}$$, 'batch'),
  ($$bio_030$$, $$生物常识$$, $$multiple$$, $$现代基因工程技术中必不可少的“工具酶”主要包括？$$, $$["限制性核酸内切酶", "DNA连接酶", "载体", "胃蛋白酶"]$$, $$[0, 1]$$, $$hard$$, $$限制酶和连接酶是工具酶。质粒虽然是必需的基因运载体，但它不是酶而是DNA分子。胃蛋白酶属于消化酶。$$, ARRAY[$$生物工程$$,$$基因工程$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.6, "工学": 0.3}$$, 'batch'),
  ($$chem_001$$, $$化学常识$$, $$single$$, $$化学元素周期表是由哪位俄国科学家首创的？$$, $$["居里夫人", "拉瓦锡", "门捷列夫", "玻尔"]$$, $$[2]$$, $$easy$$, $$德米特里·门捷列夫于1869年发表了第一版化学元素周期表。$$, ARRAY[$$化学史$$,$$元素周期表$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_002$$, $$化学常识$$, $$single$$, $$地壳中含量最丰富的元素是？$$, $$["硅", "氧", "铝", "铁"]$$, $$[1]$$, $$easy$$, $$地壳中含量前四的元素依次是氧、硅、铝、铁。$$, ARRAY[$$地球化学$$,$$元素丰度$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_003$$, $$化学常识$$, $$single$$, $$在常温常压下，唯一呈液态的金属元素是？$$, $$["汞", "溴", "镓", "铯"]$$, $$[0]$$, $$easy$$, $$汞(Hg)在室温下为液态金属；溴(Br)虽为液态但是非金属。$$, ARRAY[$$无机化学$$,$$金属元素$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_004$$, $$化学常识$$, $$single$$, $$水的化学式是H2O，其中氢和氧的质量比是？$$, $$["2:1", "1:8", "1:16", "8:1"]$$, $$[1]$$, $$medium$$, $$氢的相对原子质量约1，氧约16。H2O中有2个H和1个O，质量比 = 2:16 = 1:8。$$, ARRAY[$$基础化学$$,$$质量比$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_005$$, $$化学常识$$, $$single$$, $$酸雨的主要成因是大气中哪一类气体的超标排放？$$, $$["二氧化碳", "二氧化硫和氮氧化物", "甲烷", "氟利昂"]$$, $$[1]$$, $$easy$$, $$工业排放的SO2和NOx溶于水形成硫酸和硝酸，导致酸雨。$$, ARRAY[$$环境化学$$,$$酸雨$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_006$$, $$化学常识$$, $$single$$, $$区分有机物和无机物的最主要标志是该化合物中是否含有哪种元素？$$, $$["氧", "氢", "碳", "氮"]$$, $$[2]$$, $$easy$$, $$有机物主要指含碳化合物（除去一氧化碳、二氧化碳、碳酸盐等特殊无机含碳物）。$$, ARRAY[$$有机化学$$,$$碳$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_007$$, $$化学常识$$, $$single$$, $$pH值等于7的溶液呈现？$$, $$["酸性", "中性", "弱碱性", "强碱性"]$$, $$[1]$$, $$easy$$, $$在常温下，pH=7为中性，<7为酸性，>7为碱性。$$, ARRAY[$$溶液化学$$,$$酸碱度$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_008$$, $$化学常识$$, $$single$$, $$铁生锈主要发生的是什么化学反应？$$, $$["氧化反应", "还原反应", "置换反应", "中和反应"]$$, $$[0]$$, $$medium$$, $$铁生锈是铁与空气中的氧气、水分发生缓慢氧化反应生成氧化铁水合物的过程。$$, ARRAY[$$氧化还原$$,$$日常生活化学$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_009$$, $$化学常识$$, $$single$$, $$干冰是哪种物质的固态形式？$$, $$["水", "二氧化碳", "一氧化碳", "氮气"]$$, $$[1]$$, $$easy$$, $$干冰即固态二氧化碳，常用于制冷或制造舞台烟雾效果。$$, ARRAY[$$无机化学$$,$$状态$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_010$$, $$化学常识$$, $$single$$, $$“王水”是由哪两种浓酸按体积比大约3:1混合而成的？$$, $$["浓硝酸和浓硫酸", "浓盐酸和浓硝酸", "浓硫酸和浓盐酸", "浓盐酸和氢氟酸"]$$, $$[1]$$, $$medium$$, $$王水由浓盐酸(HCl)和浓硝酸(HNO3)以3:1体积比混合，能溶解黄金。$$, ARRAY[$$无机化学$$,$$酸性物质$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_011$$, $$化学常识$$, $$single$$, $$在原子和分子水平上对物质进行合成和改造的化学体系，被称为？$$, $$["绿色化学", "量子化学", "分析化学", "超分子化学"]$$, $$[3]$$, $$hard$$, $$超分子化学(也被称为纳米化学的一部分)研究非共价键作用的复杂分子组装体。$$, ARRAY[$$现代化学$$,$$超分子$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_012$$, $$化学常识$$, $$single$$, $$哪一类碳水化合物是人类膳食中淀粉分解和血糖的主要来源？$$, $$["果糖", "葡萄糖", "蔗糖", "纤维素"]$$, $$[1]$$, $$medium$$, $$淀粉在人体内最终水解为葡萄糖，是血糖的直接来源。$$, ARRAY[$$生物化学$$,$$糖类$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_013$$, $$化学常识$$, $$single$$, $$臭氧(O3)相对于氧气(O2)属于？$$, $$["同分异构体", "同位素", "同素异形体", "高聚物"]$$, $$[2]$$, $$medium$$, $$由同一种元素组成的不同单质互称为同素异形体。$$, ARRAY[$$分子结构$$,$$氧元素$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_014$$, $$化学常识$$, $$single$$, $$催化剂在化学反应中的主要作用是？$$, $$["增加反应物浓度", "改变反应的焓变", "降低反应活化能以改变反应速率", "改变反应的方向"]$$, $$[2]$$, $$medium$$, $$催化剂能改变反应途径，降低(或升高)活化能，从而改变反应速率，但不改变总和反应热。$$, ARRAY[$$物理化学$$,$$动力学$$]::text[], $${"理学": 1.0, "工学": 1.0, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_015$$, $$化学常识$$, $$single$$, $$石油经过分馏过程后，沸点最高且残留在底部的产物是？$$, $$["汽油", "柴油", "航空煤油", "沥青"]$$, $$[3]$$, $$easy$$, $$分馏塔底部出来的是重油、沥青等高沸点大分子碳氢化合物。$$, ARRAY[$$有机化工$$,$$石油$$]::text[], $${"理学": 1.0, "工学": 0.7, "医学": 0.5, "农学": 0.5}$$, 'batch'),
  ($$chem_016$$, $$化学常识$$, $$single$$, $$在元素周期表中，第一主族（IA族，氢除外）的元素统称为？$$, $$["碱金属", "碱土金属", "卤素", "稀有气体"]$$, $$[0]$$, $$medium$$, $$第一主族包括Li、Na、K等，统称为碱金属。$$, ARRAY[$$元素周期表$$,$$无机化学$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_017$$, $$化学常识$$, $$single$$, $$化学电池（原电池）工作时发生能量转化的本质是？$$, $$["热能转化为化学能", "化学能转化为电能", "电能转化为化学能", "机械能转化为电能"]$$, $$[1]$$, $$easy$$, $$原电池是通过自发氧化还原反应，将化学能转化为电能的装置。$$, ARRAY[$$电化学$$,$$能量$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_018$$, $$化学常识$$, $$single$$, $$工业上合成氨的主要方法“哈伯法”（Haber process）需要的反应物是？$$, $$["氢气和氧气", "氮气和氧气", "氮气和氢气", "甲烷和水"]$$, $$[2]$$, $$medium$$, $$哈伯法是在高温高压及催化剂下，N2和H2反应生成NH3(氨)。$$, ARRAY[$$工业化学$$,$$合成氨$$]::text[], $${"理学": 1.0, "工学": 1.0, "军事学": 0.4, "管理学": 0.2, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_019$$, $$化学常识$$, $$single$$, $$含有孤对电子并常显碱性的经典配体是下面哪种物质？$$, $$["甲烷", "氨", "乙烷", "四氯化碳"]$$, $$[1]$$, $$hard$$, $$氨分子中的氮原子有一对孤对电子，可充当路易斯碱或配体形成络合物。$$, ARRAY[$$配位化学$$,$$分子结构$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_020$$, $$化学常识$$, $$single$$, $$不粘锅涂层特氟龙(Teflon)的主要化学成分是哪种聚合物？$$, $$["聚氯乙烯", "聚四氟乙烯", "聚丙烯", "聚苯乙烯"]$$, $$[1]$$, $$medium$$, $$特氟龙即聚四氟乙烯(PTFE)，具备极佳的不粘性、耐热性和抗腐蚀性。$$, ARRAY[$$高分子材料$$,$$有机化学$$]::text[], $${"工学": 1.0, "理学": 1.0, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_021$$, $$化学常识$$, $$single$$, $$哪一类反应通常指酯类与碱溶液发生反应生成皂类？$$, $$["酯化反应", "水解反应", "皂化反应", "加成反应"]$$, $$[2]$$, $$easy$$, $$脂肪(一种酯)和强碱反应生成高级脂肪酸盐和甘油，该过程即皂化反应，是制皂的基础。$$, ARRAY[$$有机化学$$,$$皂化$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_022$$, $$化学常识$$, $$single$$, $$焰色反应中，含有钠元素的物质在火焰中呈现的颜色是？$$, $$["紫色", "砖红色", "黄色", "绿色"]$$, $$[2]$$, $$medium$$, $$钠元素的特征焰色为黄色；钾为紫色(透过蓝色钴玻璃)，铜为绿色。$$, ARRAY[$$分析化学$$,$$金属鉴定$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_023$$, $$化学常识$$, $$multiple$$, $$下面哪些物质属于高分子化合物？$$, $$["蛋白质", "纤维素", "脂肪", "聚乙烯"]$$, $$[0, 1, 3]$$, $$medium$$, $$蛋白质和纤维素是天然高分子，聚乙烯是合成高分子。脂肪(甘油三酯)分子量一般在千以下，不属于高分子。$$, ARRAY[$$有机化学$$,$$高分子$$]::text[], $${"理学": 1.0, "工学": 1.0, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_024$$, $$化学常识$$, $$multiple$$, $$以下哪些属于化学变化？$$, $$["冰雪融化", "铁钉生锈", "食物腐败", "汽油挥发"]$$, $$[1, 2]$$, $$easy$$, $$铁生锈(氧化)和食物腐败(变质反应)有新物质生成为化学变化。融化和挥发是物理变化。$$, ARRAY[$$基础概念$$,$$化学反应$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_025$$, $$化学常识$$, $$multiple$$, $$温室气体除了二氧化碳(CO2)，还主要包括哪些？$$, $$["甲烷", "水蒸气", "一氧化二氮", "氮气"]$$, $$[0, 1, 2]$$, $$medium$$, $$氮气和氧气不能吸收红外辐射不属温室气体。甲烷、水汽和一氧化二氮均为重要温室气体。$$, ARRAY[$$环境化学$$,$$温室效应$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_026$$, $$化学常识$$, $$multiple$$, $$元素周期表中常见的四大卤素元素是？$$, $$["氟", "氯", "溴", "碘"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$第七主族元素氟、氯、溴、碘是典型的卤素。砹具有放射性很少见。$$, ARRAY[$$无机化学$$,$$卤素$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_027$$, $$化学常识$$, $$multiple$$, $$关于同位素，下列哪些说法是正确的？$$, $$["质子数相同", "中子数不同", "原子序数不同", "属于同种元素"]$$, $$[0, 1, 3]$$, $$medium$$, $$同位素是质子数相同(属于同种元素、原子序数相同)但中子数不同的原子互称。$$, ARRAY[$$原子结构$$,$$同位素$$]::text[], $${"理学": 1.0, "工学": 0.4, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_028$$, $$化学常识$$, $$multiple$$, $$在有机化学中，碳碳三键(C≡C)常见的反应类型包含？$$, $$["取代反应", "加成反应", "加聚反应", "消去反应"]$$, $$[1, 2]$$, $$hard$$, $$炔烃中的三键极易发生加成反应，也能进行加聚反应(如生成导电聚乙炔等)。取代和消去不是三键本身的主要特征反应。$$, ARRAY[$$有机反应$$,$$炔烃$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_029$$, $$化学常识$$, $$multiple$$, $$电化学中，电解池的阳极发生的现象有？$$, $$["发生氧化反应", "发生还原反应", "与电源正极相连", "与电源负极相连"]$$, $$[0, 2]$$, $$hard$$, $$在电解池中，阳极与直流电源的正极相连，失去电子，发生氧化反应。$$, ARRAY[$$电化学$$,$$电解池$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$chem_030$$, $$化学常识$$, $$multiple$$, $$硬水是指含有较多可溶性钙、镁化合物的水。将暂时硬水软化的常见简单方法有哪些？$$, $$["过滤", "煮沸", "加酸", "离子交换法"]$$, $$[1, 3]$$, $$medium$$, $$加热煮沸可以使碳酸氢钙分解沉淀软化暂时硬水。离子交换树脂能软化永久和暂时硬水。过滤只能去悬浮物，加酸不能去除金属离子。$$, ARRAY[$$生活化学$$,$$硬水$$]::text[], $${"理学": 1.0, "工学": 0.6, "医学": 0.25, "农学": 0.25}$$, 'batch'),
  ($$cs_001$$, $$计算机基础$$, $$single$$, $$世界上第一台通用电子数字计算机是？$$, $$["EDVAC", "ENIAC", "UNIVAC", "Turing Machine"]$$, $$[1]$$, $$easy$$, $$ENIAC（电子数值积分计算机）于1946年诞生，是世界上第一台通用电子数字计算机。$$, ARRAY[$$计算机史$$,$$ENIAC$$]::text[], $${"工学": 1.0, "理学": 0.8}$$, 'batch'),
