  ($$cs_029$$, $$计算机基础$$, $$single$$, $$多线程或多进程并发访问共享资源而不加锁，可能导致？$$, $$["竞态条件", "内存泄露", "栈溢出", "空指针异常"]$$, $$[0]$$, $$hard$$, $$没有经过互斥同步的并发访问可能引起数据不一致，即所谓竞态条件。$$, ARRAY[$$并发编程$$]::text[], $${"工学": 1.0, "理学": 0.8}$$, 'batch'),
  ($$cs_030$$, $$计算机基础$$, $$single$$, $$摩尔定律预测，集成电路上可容纳的晶体管数目大约每隔多长时间增加一倍？$$, $$["1个月", "6个月", "18-24个月", "10年"]$$, $$[2]$$, $$medium$$, $$由戈登·摩尔提出，集成电路晶体管数约每18至24个月翻一倍。$$, ARRAY[$$半导体$$,$$摩尔定律$$]::text[], $${"工学": 1.0, "理学": 0.8}$$, 'batch'),
  ($$cs_031$$, $$计算机基础$$, $$multiple$$, $$高级语言程序的执行方式通常包括？$$, $$["编译执行", "解释执行", "人工口算执行", "混合执行"]$$, $$[0, 1, 3]$$, $$medium$$, $$代码可编译成机器码，或者逐行解释执行，或者如Java/C#等先编译字节码再JIT解释编译混合执行。$$, ARRAY[$$编程基础$$]::text[], $${"工学": 1.0, "理学": 0.8}$$, 'batch'),
  ($$cs_032$$, $$计算机基础$$, $$multiple$$, $$下面哪些属于常见的数据结构？$$, $$["队列", "图", "B+树", "HTML"]$$, $$[0, 1, 2]$$, $$easy$$, $$HTML是超文本标记语言，不是表示内存中数据的结构。队列、图和树(B+树)是经典数据结构。$$, ARRAY[$$数据结构$$]::text[], $${"工学": 1.0, "理学": 0.6}$$, 'batch'),
  ($$cs_033$$, $$计算机基础$$, $$multiple$$, $$常见的进程调度算法有？$$, $$["先来先服务", "时间片轮转", "最短作业优先", "RSA加密算法"]$$, $$[0, 1, 2]$$, $$hard$$, $$RSA是非对称加密算法，其余均为操作系统的进程调度算法。$$, ARRAY[$$操作系统$$,$$调度算法$$]::text[], $${"工学": 1.0, "理学": 0.8}$$, 'batch'),
  ($$cs_034$$, $$计算机基础$$, $$multiple$$, $$关系型数据库中，事务（Transaction）具备的ACID特性包括？$$, $$["原子性", "一致性", "隔离性", "持久性"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$ACID即这四大特性，是关系型数据库保证事务安全的核心依据。$$, ARRAY[$$数据库$$,$$ACID$$]::text[], $${"工学": 1.0, "理学": 0.6}$$, 'batch'),
  ($$cs_035$$, $$计算机基础$$, $$multiple$$, $$以下哪些选项属于面向对象编程的核心概念？$$, $$["封装", "继承", "多态", "闭包"]$$, $$[0, 1, 2]$$, $$medium$$, $$多态、继承和封装是OOP的三大护法。闭包更多强调于函数式编程或作用域特性。$$, ARRAY[$$编程模式$$,$$OOP$$]::text[], $${"工学": 1.0, "理学": 0.8}$$, 'batch'),
  ($$cs_036$$, $$计算机基础$$, $$multiple$$, $$常用的无损数据压缩算法或工具有？$$, $$["ZIP", "JPEG", "MP3", "GZIP"]$$, $$[0, 3]$$, $$medium$$, $$ZIP和GZIP是无损压缩，解压后和原文件完全一致。JPEG和MP3分别是图像和音频的有损压缩。$$, ARRAY[$$算法$$,$$压缩$$]::text[], $${"工学": 1.0, "理学": 0.8}$$, 'batch'),
  ($$cs_037$$, $$计算机基础$$, $$multiple$$, $$下列属于非易失性存储器的有？$$, $$["硬盘", "U盘", "只读存储器", "静态随机存取存储器"]$$, $$[0, 1, 2]$$, $$medium$$, $$硬盘、U盘和ROM断电均不丢失数据。而SRAM属于RAM的一种，掉电丢失数据。$$, ARRAY[$$硬件$$,$$存储$$]::text[], $${"工学": 1.0, "理学": 0.8}$$, 'batch'),
  ($$cs_038$$, $$计算机基础$$, $$multiple$$, $$为了提高硬盘读写性能和数据容错冗余能力，常使用的技术类型是？$$, $$["RAID 0", "RAID 1", "RAID 5", "VGA"]$$, $$[0, 1, 2]$$, $$medium$$, $$RAID（独立磁盘冗余阵列）技术用于硬盘扩容、提速或备份。VGA是显示接口。$$, ARRAY[$$硬件$$,$$磁盘阵列$$]::text[], $${"工学": 1.0, "理学": 0.8}$$, 'batch'),
  ($$cs_039$$, $$计算机基础$$, $$multiple$$, $$常见的操作系统有？$$, $$["Windows", "macOS", "Linux", "Microsoft Office"]$$, $$[0, 1, 2]$$, $$easy$$, $$Office是应用软件，其余三个是广为人知的操作系统。$$, ARRAY[$$操作系统$$]::text[], $${"工学": 1.0, "理学": 0.6}$$, 'batch'),
  ($$cs_040$$, $$计算机基础$$, $$multiple$$, $$在衡量算法好坏时，主要考虑哪两个方面的复杂度？$$, $$["时间复杂度", "空间复杂度", "网络复杂度", "编译复杂度"]$$, $$[0, 1]$$, $$easy$$, $$评价算法通常关注其耗费的执行时间（时间复杂度）及占用内存资源（空间复杂度）。$$, ARRAY[$$算法$$,$$复杂度$$]::text[], $${"工学": 1.0, "理学": 0.8}$$, 'batch'),
  ($$dip_001$$, $$国际组织与外交$$, $$single$$, $$联合国（United Nations）是在哪一次世界大战结束后成立以取代国际联盟的？$$, $$["第一次世界大战", "第二次世界大战", "冷战结束时", "拿破仑战争时期"]$$, $$[1]$$, $$easy$$, $$联合国成立于1945年10月24日，二战结束后以维护世界和平为初衷宣告成立。$$, ARRAY[$$联合国$$,$$二战$$]::text[], $${"法学": 0.8, "历史学": 0.6, "政治学": 0.5, "经济学": 0.15}$$, 'batch'),
  ($$dip_002$$, $$国际组织与外交$$, $$single$$, $$联合国的总部主要设在哪个城市？$$, $$["日内瓦", "巴黎", "纽约", "维也纳"]$$, $$[2]$$, $$easy$$, $$联合国大会、安理会等核心机构所在地为美国纽约曼哈顿。$$, ARRAY[$$联合国总部$$]::text[], $${"法学": 0.8, "历史学": 0.6, "政治学": 0.5, "经济学": 0.15}$$, 'batch'),
  ($$dip_003$$, $$国际组织与外交$$, $$single$$, $$欧洲联盟（EU）是在哪个条约签署后正式成立为现代的泛欧经济政治共同体的？$$, $$["凡尔赛条约", "马斯特里赫特条约", "华沙条约", "申根协定"]$$, $$[1]$$, $$medium$$, $$1992年签署、1993年生效的《马斯特里赫特条约》标志着欧共体发展为欧盟。$$, ARRAY[$$欧盟$$,$$条约$$]::text[], $${"法学": 0.8, "历史学": 0.6, "政治学": 0.5, "经济学": 0.15}$$, 'batch'),
  ($$dip_004$$, $$国际组织与外交$$, $$single$$, $$北大西洋公约组织（NATO）最初成立的性质是？$$, $$["全球气候保护组织", "跨国贸易经济联盟", "军事防御同盟", "文化交流平台"]$$, $$[2]$$, $$easy$$, $$北约是1949年由美国牵头西方国家建立的针对苏联和华约的军事防卫组织。$$, ARRAY[$$国际组织$$,$$北约$$]::text[], $${"法学": 0.8, "历史学": 0.5, "经济学": 0.3}$$, 'batch'),
  ($$dip_005$$, $$国际组织与外交$$, $$single$$, $$WTO的中文全称是？$$, $$["世界卫生组织", "世界旅游组织", "世界贸易组织", "国际反恐组织"]$$, $$[2]$$, $$easy$$, $$WTO (World Trade Organization) 是规范全球贸易原则裁决争端的世界贸易组织。$$, ARRAY[$$WTO$$]::text[], $${"法学": 0.8, "历史学": 0.5, "经济学": 0.3}$$, 'batch'),
  ($$dip_006$$, $$国际组织与外交$$, $$single$$, $$如果某陷入经济倒退或货币崩溃危机的国家需要申请主权紧急救助贷款，通常会求助于？$$, $$["国际货币基金组织", "世界卫生组织", "国际刑警组织", "万国邮政联盟"]$$, $$[0]$$, $$medium$$, $$IMF主要负责监察国际货币汇率体系和在成员国遭遇外汇流动性危机时提供短期借款进行救助。$$, ARRAY[$$IMF$$,$$全球金融$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "法学": 0.4, "历史学": 0.25}$$, 'batch'),
  ($$dip_007$$, $$国际组织与外交$$, $$single$$, $$世界卫生组织（WHO）的总部位于？$$, $$["美国纽约", "瑞士日内瓦", "英国伦敦", "比利时苏黎世"]$$, $$[1]$$, $$medium$$, $$WHO是联合国负责公共卫生事务的专门机构，总部设在瑞士日内瓦。$$, ARRAY[$$WHO$$,$$日内瓦$$]::text[], $${"法学": 0.8, "历史学": 0.5, "经济学": 0.3}$$, 'batch'),
  ($$dip_008$$, $$国际组织与外交$$, $$single$$, $$在联合国核心机构中，拥有所谓“一票否决权”权力的机构是？$$, $$["联合国大会所有成员", "经济及社会理事会", "安全理事会的五大常任理事国", "国际法院的法官"]$$, $$[2]$$, $$easy$$, $$联合国安理会五大常任理事国（中、俄、法、英、美）在实质性决议上拥有一票否决的主权优势。$$, ARRAY[$$联合国$$,$$安理会$$]::text[], $${"法学": 0.8, "历史学": 0.6, "政治学": 0.5, "经济学": 0.15}$$, 'batch'),
  ($$dip_009$$, $$国际组织与外交$$, $$single$$, $$由中国参与发起，专注于欧亚大陆反恐、安全及经济合作的重要区域性国际组织是？$$, $$["不结盟运动", "上海合作组织", "东盟", "美洲国家组织"]$$, $$[1]$$, $$medium$$, $$上合组织是由中国、俄罗斯、中亚等国组成的维护区域稳定与多边合作的重要联盟。$$, ARRAY[$$上合组织$$]::text[], $${"法学": 0.8, "历史学": 0.5, "经济学": 0.3}$$, 'batch'),
  ($$dip_010$$, $$国际组织与外交$$, $$single$$, $$东南亚国家联盟简称东盟（ASEAN），目前以下哪个国家不属于东盟正式成员国？$$, $$["印度尼西亚", "泰国", "日本", "越南"]$$, $$[2]$$, $$easy$$, $$日本位于东亚，不是东南亚十国联盟（共含印尼、马来、菲、新、泰、文、越、老、缅、柬）。$$, ARRAY[$$东盟$$]::text[], $${"法学": 0.8, "历史学": 0.5, "经济学": 0.3}$$, 'batch'),
  ($$dip_011$$, $$国际组织与外交$$, $$single$$, $$冷战时期兴起的“不结盟运动”旨在？$$, $$["脱离任何经济交易", "坚决不加入大国两大阵营的军事结盟之中", "不结婚不成立家庭", "抵制全球化进程"]$$, $$[1]$$, $$medium$$, $$不结盟运动是由一大批发展中国家组成，奉行奉行独立自主，不结盟（不参与美苏两大超级大国军备联盟）政策的运动。$$, ARRAY[$$外交史$$,$$不结盟$$]::text[], $${"法学": 0.8, "历史学": 0.6, "政治学": 0.5, "经济学": 0.15}$$, 'batch'),
  ($$dip_012$$, $$国际组织与外交$$, $$single$$, $$国际法院 (ICJ) 作为联合国的司法裁判机关，其所在地被称为“国际法都”，这个城市是？$$, $$["荷兰海牙", "法国斯特拉斯堡", "美国华盛顿", "奥地利维也纳"]$$, $$[0]$$, $$hard$$, $$国际法院位于荷兰历史名城海牙的和平宫内，负责处理国家间的争讼。$$, ARRAY[$$国际法院$$,$$海牙$$]::text[], $${"法学": 1.0, "管理学": 0.2, "历史学": 0.25, "经济学": 0.15}$$, 'batch'),
  ($$dip_013$$, $$国际组织与外交$$, $$single$$, $$在外交用语中，“引渡”（Extradition）是指？$$, $$["护送外交官安全归国", "一国应另一国请求，将逃入其境内的涉嫌犯罪嫌疑人转移交还以受审判", "引进其他国家的先进技术度出难关", "互相驱逐彼此的大使"]$$, $$[1]$$, $$medium$$, $$引渡是国际司法协助中的惩治罪犯合作程序。$$, ARRAY[$$国际法$$,$$引渡$$]::text[], $${"法学": 0.8, "历史学": 0.5, "经济学": 0.3}$$, 'batch'),
  ($$dip_014$$, $$国际组织与外交$$, $$single$$, $$外交人员派驻他国后依法享有一种极高的保护特权：其人身、住所、档案等不受驻在国司法管辖和强制措施。这被称为？$$, $$["领事裁判权", "治外法权", "外交豁免权", "免签入境权"]$$, $$[2]$$, $$easy$$, $$外交豁免(Diplomatic immunity)保证了使节能够免受驻留国刑事起诉等，以确立无障碍履职（除非派遣国主动放弃）。$$, ARRAY[$$外交特权$$]::text[], $${"法学": 0.8, "历史学": 0.6, "政治学": 0.5, "经济学": 0.15}$$, 'batch'),
  ($$dip_015$$, $$国际组织与外交$$, $$single$$, $$致力于全球气候治理和控制碳排放，并在2015年通过了一项代替京都议定书的一项全球性协定，该协定名为？$$, $$["《日内瓦气候协定》", "《巴黎协定》", "《哥本哈根宣言》", "《里约地球宪章》"]$$, $$[1]$$, $$medium$$, $$2015年的《巴黎协定》是联合国气候变化框架公约下具有里程碑意义的控制全球平均升温的国际协定。$$, ARRAY[$$环保外交$$,$$巴黎协定$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.5, "经济学": 0.3, "法学": 0.8, "历史学": 0.6, "政治学": 0.5}$$, 'batch'),
  ($$dip_016$$, $$国际组织与外交$$, $$multiple$$, $$联合国安全理事会拥有五大常任理事国地位（P5），它们是？$$, $$["中国与俄罗斯", "美国", "英国与法国", "德国、日本与印度"]$$, $$[0, 1, 2]$$, $$easy$$, $$五常席位由二战主要战胜国：中俄（苏）美英法组成。德日印不是五常。$$, ARRAY[$$安理会常任理事国$$]::text[], $${"法学": 0.8, "历史学": 0.5, "经济学": 0.3}$$, 'batch'),
  ($$dip_017$$, $$国际组织与外交$$, $$multiple$$, $$欧盟（EU）作为高度一体化的超国家组织，拥有其独特的运转机构体系。主要包括？$$, $$["欧洲议会", "欧洲理事会与欧盟理事会", "欧盟委员会", "欧洲央行与欧洲法院"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$欧盟有一套相当于一国三权分立与央行结合的非常庞大的机构框架。$$, ARRAY[$$欧盟机构$$]::text[], $${"法学": 0.8, "历史学": 0.5, "经济学": 0.3}$$, 'batch'),
  ($$dip_018$$, $$国际组织与外交$$, $$multiple$$, $$世界银行集团（World Bank Group）包含多个机构，其主要任务重心是？$$, $$["向发展中国家提供低息或无息贷款减贫", "进行大型民生基建、能源及教育项目融资", "进行全人类武装维和任务", "提供全球统一法定货币兑换网"]$$, $$[0, 1]$$, $$medium$$, $$世行重在长期长效的扶贫建设融资。武力维和属联合国；法币并无统一兑换机构而是外汇市场化决定。$$, ARRAY[$$世界银行$$,$$全球经济组织$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "法学": 0.4, "历史学": 0.25}$$, 'batch'),
  ($$dip_019$$, $$国际组织与外交$$, $$multiple$$, $$“金砖国家”（BRICS）是一个具有极高影响力的新兴经济体合作机制，其早期创始核心成员包括？$$, $$["巴西 与 俄罗斯", "印度 与 中国", "南非", "加拿大"]$$, $$[0, 1, 2]$$, $$easy$$, $$BRICS的拼写就代表巴、俄、印、中、南非。近两年该组织已开启扩员，但早期创始即这五国。$$, ARRAY[$$金砖国家$$,$$新兴经济体$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "法学": 0.4, "历史学": 0.25}$$, 'batch'),
  ($$dip_020$$, $$国际组织与外交$$, $$multiple$$, $$《日内瓦公约》系列法案奠定了现代国际人道法的基础。其核心保护对象在战争冲突中一般包括？$$, $$["战场上的伤病武装人员", "放下武器放弃抵抗的战俘", "战争波及地区的平民", "核武器发射密码"]$$, $$[0, 1, 2]$$, $$medium$$, $$日内瓦公约是约束交战双方人道原则的文件，不涉及武器密码归属此类秘密军事资料。$$, ARRAY[$$国际公约法$$,$$人道主义$$]::text[], $${"法学": 0.8, "历史学": 0.6, "政治学": 0.5, "哲学": 1.0, "经济学": 0.15}$$, 'batch'),
  ($$eco_001$$, $$经济学常识$$, $$single$$, $$被称为“经济学之父”，提出“看不见的手”理论的是？$$, $$["大卫·李嘉图", "卡尔·马克思", "约翰·梅纳德·凯恩斯", "亚当·斯密"]$$, $$[3]$$, $$easy$$, $$亚当·斯密在其代表作《国富论》中描述了市场自动调节资源配置的“看不见的手”。$$, ARRAY[$$经济学史$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_002$$, $$经济学常识$$, $$single$$, $$在经济学中，“机会成本”（Opportunity Cost）是指？$$, $$["购买物品直接支付的货币", "为了得到某种东西而放弃的最高价值的替代选择", "机器折旧耗费的成本", "交易过程中的手续费"]$$, $$[1]$$, $$medium$$, $$机会成本是指做出某个选择时所放弃的其他所有可能选择中价值最高的那一个。$$, ARRAY[$$基本概念$$,$$成本$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_003$$, $$经济学常识$$, $$single$$, $$宏观经济学中，用于衡量一个国家或地区在一定时期内生产的所有最终产品和劳务总价值的指标是？$$, $$["GDP", "CPI", "PPI", "GNP"]$$, $$[0]$$, $$easy$$, $$GDP（国内生产总值）是衡量国民经济发展情况最重要的经济指标。$$, ARRAY[$$宏观经济$$,$$GDP$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_004$$, $$经济学常识$$, $$single$$, $$消费者物价指数（CPI）持续显著上涨通常反映了经济体出现了？$$, $$["通货紧缩", "通货膨胀", "经济停滞", "货币升值"]$$, $$[1]$$, $$easy$$, $$CPI是反映通货膨胀（物价普遍持续上涨）的关键指标。$$, ARRAY[$$宏观经济$$,$$CPI$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_005$$, $$经济学常识$$, $$single$$, $$在完全竞争市场中，商品的价格主要是由什么决定的？$$, $$["政府统一定价", "生产商协会规定", "市场的供给和需求力量", "个别消费者的意愿"]$$, $$[2]$$, $$easy$$, $$在完全自由的市场中，供求关系交汇点决定了商品的市场均衡价格。$$, ARRAY[$$供求关系$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_006$$, $$经济学常识$$, $$single$$, $$随着消费者持续消费同一种商品，其从中获得的额外满足感会逐渐减少。这种现象称为？$$, $$["需求递增律", "边际效用递减规律", "规模报酬递减", "劣等品效应"]$$, $$[1]$$, $$medium$$, $$这是微观经济学中非常有名的边际效用递减规律，如吃第1个包子很爽，第5个就不想吃了。$$, ARRAY[$$消费者行为$$,$$微观经济$$]::text[], $${"理学": 1.0, "工学": 0.4, "经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_007$$, $$经济学常识$$, $$single$$, $$用于衡量国家收入分配不平等程度的指标是？$$, $$["恩格尔系数", "基尼系数", "道琼斯指数", "采购经理指数"]$$, $$[1]$$, $$medium$$, $$基尼系数介于0到1之间，数值越高表示收入分配越不均。$$, ARRAY[$$经济指标$$,$$分配$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_008$$, $$经济学常识$$, $$single$$, $$在经济衰退时期，主张政府应通过增加公共开支、减税等手段来刺激总需求，以实现充分就业的经济学派是？$$, $$["古典学派", "奥地利学派", "凯恩斯学派", "货币学派"]$$, $$[2]$$, $$medium$$, $$凯恩斯在其《就业、利息和货币通论》中强调国家干预经济以克服危机，创立了宏观经济学基石。$$, ARRAY[$$经济学派$$,$$凯恩斯$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_009$$, $$经济学常识$$, $$single$$, $$沉没成本（Sunk Cost）在理性人的经济决策中应当？$$, $$["占决定性因素", "被完全忽略不计", "按比例折算后考虑", "必须赚回来"]$$, $$[1]$$, $$hard$$, $$沉没成本是指已经发生且不可收回的成本。理性经济人决策应看未来边际收益成本，不应受沉没成本影响。$$, ARRAY[$$微观经济$$,$$沉没成本$$]::text[], $${"理学": 1.0, "工学": 0.4, "经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_010$$, $$经济学常识$$, $$single$$, $$当商品价格上升，消费者对它的需求量不减反增（违背了平常的需求规律），这通常属于哪种特殊商品？$$, $$["奢侈品", "吉芬商品", "替代品", "互补品"]$$, $$[1]$$, $$hard$$, $$吉芬物品是劣等品中的极端情况，由于收入效应大于替代效应，价格上涨反而促使消费者买得更多（如灾荒年的主要口粮）。$$, ARRAY[$$特殊商品$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_011$$, $$经济学常识$$, $$single$$, $$恩格尔定律指出，随着家庭收入增加，用于食品支出的比重（恩格尔系数）会？$$, $$["增加", "保持不变", "下降", "随机波动"]$$, $$[2]$$, $$easy$$, $$恩格尔系数下降反映了居民生活水平和宽裕程度的提升。$$, ARRAY[$$生活指数$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_012$$, $$经济学常识$$, $$single$$, $$国际贸易理论中，大卫·李嘉图提出了什么著名理论，证明即便一国在哪方面都不如别国，大家仍能通过贸易互惠？$$, $$["绝对优势理论", "比较优势理论", "要素禀赋理论", "重商主义"]$$, $$[1]$$, $$medium$$, $$比较优势理论强调：国与国之间应分工生产各自机会成本相对较低的产品以进行贸易。$$, ARRAY[$$国际贸易$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_013$$, $$经济学常识$$, $$single$$, $$一件商品因为难以找到替代品（如治疗重病的特效药），其需求对价格的变化极其不敏感，这被称为？$$, $$["需求富有弹性", "需求缺乏弹性", "供给富有弹性", "完全弹性"]$$, $$[1]$$, $$medium$$, $$需求价格弹性小（缺乏弹性）表示价格大幅波动，需求量也很少改变；通常为生活必需品或无替代品引发。$$, ARRAY[$$价格弹性$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_014$$, $$经济学常识$$, $$single$$, $$垄断市场（Monopoly）最核心的区别特征是？$$, $$["有许多卖家", "买卖双方信息完全对称", "行业中只有一个商品的唯一供应商，且无相近替代品", "商家不能决定任何价格"]$$, $$[2]$$, $$easy$$, $$完全垄断市场指的是有一家企业控制整个市场的特殊结构。$$, ARRAY[$$市场结构$$,$$垄断$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_015$$, $$经济学常识$$, $$single$$, $$经济学里的“规模经济”（Economies of scale）通常是指？$$, $$["企业规模越大，赚的利润越多", "随着产量增加，长期平均单位成本下降", "国家经济体量大", "投资股市的资金规模大风险低"]$$, $$[1]$$, $$medium$$, $$随着生产规模扩大，固定成本摊薄，单位产品的平均低成本会下降即规模经济。$$, ARRAY[$$生产理论$$,$$规模经济$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_016$$, $$经济学常识$$, $$multiple$$, $$现代经济学的四大生产要素（Factors of Production）通常被归纳为？$$, $$["土地", "劳动", "资本", "企业家才能"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$古典经济学主张土地、劳动、资本，现代拓展后加入了企业家才能或数据/技术等要素。$$, ARRAY[$$生产要素$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_017$$, $$经济学常识$$, $$multiple$$, $$一般而言，中央银行运用常规宏观调控抑制通货膨胀（给经济降温）的手段包括？$$, $$["提高基准利率", "提高商业银行的法定存款准备金率", "在公开市场上卖出政府债券", "大规模印发超额纸币"]$$, $$[0, 1, 2]$$, $$hard$$, $$大量印发货币会导致通胀进一步恶化。前三项均为紧缩性货币政策的正规手段。$$, ARRAY[$$货币政策$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_018$$, $$经济学常识$$, $$multiple$$, $$微观经济学中，分析两种彼此关联商品的“交叉弹性”以界定其关系时，常将其分为哪些？$$, $$["替代品", "互补品", "完全无关商品", "无限需求商品"]$$, $$[0, 1]$$, $$medium$$, $$商品间关系常见的是替代与互补。两者交叉价格弹性的符号不同，借此分辨消费者偏好转化。$$, ARRAY[$$消费者理论$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "经济学": 0.5, "管理学": 0.25}$$, 'batch'),
  ($$eco_019$$, $$经济学常识$$, $$multiple$$, $$关于GDP（国内生产总值），下列哪些计入本年度的一国GDP中？$$, $$["国内本年度新建并销售的住宅", "国外公民在我国境内本年的合法劳务产出", "二手闲鱼市场上转卖的上年旧手机交易额", "黑市及走私交易的收入"]$$, $$[0, 1]$$, $$hard$$, $$GDP计算一定时期内国内生产的最终产品。旧货交易并非当年生产，黑市交易因无法统计也通常排除。$$, ARRAY[$$GDP核算$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.4, "经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_020$$, $$经济学常识$$, $$multiple$$, $$“外部性”（Externality）是导致市场失灵的原因之一。外部性可以分为哪两种？$$, $$["正外部性", "负外部性", "边际外部性", "混合外部性"]$$, $$[0, 1]$$, $$medium$$, $$外部性典型分支为正外部性（溢出收益给社会）和负外部性（代价推卸给社会）。$$, ARRAY[$$市场失灵$$,$$外部性$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_021$$, $$经济学常识$$, $$single$$, $$在宏观经济学中，CPI通常用来衡量什么？$$, $$["通货膨胀率", "失业率", "经济增长率", "国际贸易差额"]$$, $$[0]$$, $$easy$$, $$CPI指居民消费价格指数，是反映通货膨胀水平的重要指标。$$, ARRAY[$$宏观指标$$,$$经济学原理$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_022$$, $$经济学常识$$, $$single$$, $$GDP(国内生产总值)不包括以下哪项内容？$$, $$["外企在国内的生产价值", "国内企业在国外的生产价值", "政府购买的公共服务", "居民购买的消费品"]$$, $$[1]$$, $$medium$$, $$GDP按地域原则计算，国内企业在国外的产值属于GNP而不属于GDP。$$, ARRAY[$$宏观指标$$,$$国民经济$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_023$$, $$经济学常识$$, $$single$$, $$在行为经济学中，人们常常在失去同样价值的物品时产生的痛苦，大于获得带来的快乐，这一现象称为？$$, $$["沉没成本", "禀赋效应", "损失厌恶", "羊群效应"]$$, $$[2]$$, $$medium$$, $$损失厌恶是行为经济学中的重要概念，人们对损失比对获得更敏感。$$, ARRAY[$$行为经济学$$,$$认知偏差$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$eco_024$$, $$经济学常识$$, $$single$$, $$在证券交易市场中，‘A股’的正式名称是？$$, $$["外资股", "人民币普通股票", "国家股", "红筹股"]$$, $$[1]$$, $$easy$$, $$A股指人民币普通股票。$$, ARRAY[$$交易市场常识$$,$$股市$$]::text[], $${"经济学": 1.0, "管理学": 0.5}$$, 'batch'),
  ($$env_001$$, $$环境与可持续发展$$, $$single$$, $$引起温室效应的主要气体是$$, $$["氧气", "二氧化碳", "氮气", "氩气"]$$, $$[1]$$, $$easy$$, $$CO2是主要温室气体$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_002$$, $$环境与可持续发展$$, $$single$$, $$哪种能源属于不可再生能源$$, $$["太阳能", "风能", "地热能", "煤炭"]$$, $$[3]$$, $$easy$$, $$煤炭是化石燃料$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_003$$, $$环境与可持续发展$$, $$single$$, $$破坏臭氧层的主要物质是$$, $$["二氧化碳", "氟利昂", "二氧化硫", "甲烷"]$$, $$[1]$$, $$medium$$, $$氟利昂破坏大氧层$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_004$$, $$环境与可持续发展$$, $$single$$, $$酸雨的主要成因气体$$, $$["CO2", "SO2", "O3", "N2"]$$, $$[1]$$, $$medium$$, $$二氧化硫形成酸雨$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_005$$, $$环境与可持续发展$$, $$single$$, $$世界地球日是哪一天$$, $$["3.12", "4.22", "6.5", "12.1"]$$, $$[1]$$, $$easy$$, $$4月22日是地球日$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_006$$, $$环境与可持续发展$$, $$single$$, $$水俣病是由哪种重金属引起的$$, $$["铅", "汞", "镉", "铬"]$$, $$[1]$$, $$hard$$, $$汞污染引起水俣病$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_007$$, $$环境与可持续发展$$, $$single$$, $$痛痛病是由哪种元素引起的$$, $$["铅", "汞", "镉", "铬"]$$, $$[2]$$, $$hard$$, $$镉中毒$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_008$$, $$环境与可持续发展$$, $$single$$, $$不属于可降解塑料的是$$, $$["PLA", "PBAT", "PVC", "PHA"]$$, $$[2]$$, $$medium$$, $$PVC难降解$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_009$$, $$环境与可持续发展$$, $$single$$, $$雾霾的主要成分指标是$$, $$["PM2.5", "CO", "O3", "VOCs"]$$, $$[0]$$, $$easy$$, $$主要看PM2.5$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_010$$, $$环境与可持续发展$$, $$single$$, $$京都议定书主要针对什么$$, $$["保护濒危动物", "控制温室气体", "防止核扩散", "跨国界垃圾"]$$, $$[1]$$, $$medium$$, $$温室气体减排$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_011$$, $$环境与可持续发展$$, $$single$$, $$巴黎协定目标将全球升温限制在多少度内$$, $$["1.5", "2.0", "2.5", "3.0"]$$, $$[1]$$, $$hard$$, $$相比工业化前最好1.5，限制在2.0$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_012$$, $$环境与可持续发展$$, $$single$$, $$白色污染主要指什么$$, $$["废玻璃", "废塑料", "废纸", "废铁"]$$, $$[1]$$, $$easy$$, $$难降解的塑料废弃物$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_013$$, $$环境与可持续发展$$, $$single$$, $$碳中和是指$$, $$["不排放碳", "把碳变中性", "碳排放与吸收平衡", "多吸收碳"]$$, $$[2]$$, $$medium$$, $$净零排放$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_014$$, $$环境与可持续发展$$, $$single$$, $$回收标志中的三个箭头代表$$, $$["减少、再利用、循环", "燃烧、填埋、堆肥", "分类、清洗、打包", "生产、消费、回收"]$$, $$[0]$$, $$easy$$, $$3R原则$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_015$$, $$环境与可持续发展$$, $$single$$, $$森林被称为地球的$$, $$["心脏", "肝脏", "肺", "肾脏"]$$, $$[2]$$, $$easy$$, $$光合作用产生氧气$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_016$$, $$环境与可持续发展$$, $$multiple$$, $$哪些属于新能源$$, $$["太阳能", "风能", "核能", "煤炭"]$$, $$[0, 1, 2]$$, $$medium$$, $$煤不是新能源$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_017$$, $$环境与可持续发展$$, $$multiple$$, $$常见的温室气体有$$, $$["二氧化碳", "甲烷", "氧化亚氮", "氧气"]$$, $$[0, 1, 2]$$, $$medium$$, $$氧气不是温室气体$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_018$$, $$环境与可持续发展$$, $$multiple$$, $$有助于节能减排的行为包括$$, $$["随手关灯", "多坐公交", "空调调低", "使用一次性餐具"]$$, $$[0, 1]$$, $$easy$$, $$日常环保行为$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_019$$, $$环境与可持续发展$$, $$multiple$$, $$生物多样性包括$$, $$["遗传多样性", "物种多样性", "生态系统多样性", "文化多样性"]$$, $$[0, 1, 2]$$, $$medium$$, $$三大层次$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$env_020$$, $$环境与可持续发展$$, $$multiple$$, $$可持续发展的原则包括$$, $$["公平性原则", "持续性原则", "共同性原则", "逐利性原则"]$$, $$[0, 1, 2]$$, $$hard$$, $$不是逐利$$, ARRAY[$$综合$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.6, "经济学": 0.3}$$, 'batch'),
  ($$fas_001$$, $$时尚与服装史$$, $$single$$, $$被称为“时尚界的凯撒大帝”，曾长期执掌香奈儿（Chanel）并创立同名品牌的著名设计师是？$$, $$["克里斯汀·迪奥", "伊夫·圣·罗兰", "卡尔·拉格斐", "乔治·阿玛尼"]$$, $$[2]$$, $$easy$$, $$卡尔·拉格斐（Karl Lagerfeld）被尊称为“老佛爷”，职业生涯跨越半个多世纪。$$, ARRAY[$$设计师$$,$$时尚史$$]::text[], $${"艺术学": 1.0, "工学": 0.4, "日子人": 0.8, "历史学": 0.3, "经济学": 0.15}$$, 'batch'),
  ($$fas_002$$, $$时尚与服装史$$, $$single$$, $$在1947年推出以“蜂腰长裙”为特征的“新风貌”（New Look），彻底改变了战后女性时尚的设计师是？$$, $$["可可·香奈儿", "克里斯汀·迪奥", "艾尔莎·夏帕瑞丽", "休伯特·德·纪梵希"]$$, $$[1]$$, $$medium$$, $$Dior的New Look通过收腰和宽大的裙褶重塑了女性轮廓。$$, ARRAY[$$时尚史$$,$$New Look$$]::text[], $${"艺术学": 1.0, "日子人": 0.8, "历史学": 0.3, "经济学": 0.15}$$, 'batch'),
  ($$fas_003$$, $$时尚与服装史$$, $$single$$, $$以下哪项是Coco Chanel设计的标志性单品，旨在将女性从束身衣中解放出来？$$, $$["吸烟装", "小黑裙", "比基尼", "松糕鞋"]$$, $$[1]$$, $$easy$$, $$小黑裙（Little Black Dress）和香奈儿套装是Chanel定义的经典独立风格。$$, ARRAY[$$经典设计$$,$$Chanel$$]::text[], $${"艺术学": 1.0, "工学": 0.4, "日子人": 0.4, "经济学": 0.15}$$, 'batch'),
  ($$fas_004$$, $$时尚与服装史$$, $$single$$, $$1960年代由设计师玛丽·奎恩特（Mary Quant）推广开来，成为当时青年文化象征的服饰是？$$, $$["喇叭裤", "阔腿裤", "迷你裙", "紧身胸衣"]$$, $$[2]$$, $$medium$$, $$迷你裙（Miniskirt）是60年代摇摆伦敦和女性解放运动的重要视觉标签。$$, ARRAY[$$时尚史$$,$$亚文化$$]::text[], $${"艺术学": 1.0, "日子人": 0.8, "历史学": 0.3, "经济学": 0.15}$$, 'batch'),
  ($$fas_005$$, $$时尚与服装史$$, $$single$$, $$时尚品牌“爱马仕”（Hermès）最著名的丝巾系列常以什么作为设计母本和技艺展示的核心？$$, $$["花卉图案", "赛马与马具文化", "现代几何图形", "世界地图"]$$, $$[1]$$, $$medium$$, $$爱马仕最早以制造高级马具起家，马具文化深深植根于其丝巾及皮具设计中。$$, ARRAY[$$奢侈品牌$$,$$文化渊源$$]::text[], $${"管理学": 1.0, "经济学": 0.6, "艺术学": 1.0, "日子人": 0.8, "历史学": 0.3}$$, 'batch'),
  ($$fas_006$$, $$时尚与服装史$$, $$single$$, $$“安特卫普六君子”代表了哪个国家在20世纪80年代末在时装设计界的崛起？$$, $$["法国", "意大利", "比利时", "日本"]$$, $$[2]$$, $$hard$$, $$这六位来自比利时安特卫普皇家艺术学院的设计师为现代主义设计注入了先锋力量。$$, ARRAY[$$设计师集群$$,$$先锋设计$$]::text[], $${"艺术学": 1.0, "工学": 0.4, "日子人": 0.8, "历史学": 0.3, "经济学": 0.15}$$, 'batch'),
  ($$fas_007$$, $$时尚与服装史$$, $$single$$, $$日本设计师川久保玲创建的追求解构主义和打破常规审美的品牌是？$$, $$["Yohji Yamamoto", "Comme des Garçons", "Issey Miyake", "Kenzo"]$$, $$[1]$$, $$hard$$, $$Comme des Garçons（像小男孩一样）是川久保玲建立的反传统美学巅峰品牌。$$, ARRAY[$$日本设计$$,$$解构主义$$]::text[], $${"艺术学": 1.0, "工学": 0.4, "哲学": 1.0, "历史学": 0.5, "法学": 0.3, "日子人": 0.4, "经济学": 0.15}$$, 'batch'),
  ($$fas_008$$, $$时尚与服装史$$, $$single$$, $$所谓的“高定时装”（Haute Couture）起源于哪个城市，并受法律保护其标准？$$, $$["伦敦", "纽约", "巴黎", "米兰"]$$, $$[2]$$, $$easy$$, $$高级定制起源于巴黎，受法国时装公会的法律严格规定其准入门槛。$$, ARRAY[$$时装词霸$$,$$时尚制度$$]::text[], $${"文学": 1.0, "历史学": 0.4, "艺术学": 1.0, "日子人": 0.8, "经济学": 0.15}$$, 'batch'),
  ($$fas_009$$, $$时尚与服装史$$, $$single$$, $$被誉为“剪裁大师”，曾为电影《龙凤配》设计奥黛丽·赫本绝大多数造型的设计师是？$$, $$["圣罗兰", "纪梵希", "华伦天奴", "维维安·韦斯特伍德"]$$, $$[1]$$, $$medium$$, $$纪梵希与奥黛丽·赫本的长期友谊造就了时尚史上无数经典时刻。$$, ARRAY[$$电影时尚$$,$$经典偶像$$]::text[], $${"艺术学": 1.0, "日子人": 0.8, "历史学": 0.3, "经济学": 0.15}$$, 'batch'),
  ($$fas_010$$, $$时尚与服装史$$, $$multiple$$, $$以下哪些品牌属于当今时尚界的传统“蓝血”奢侈品牌（依据业界非正式分类）？$$, $$["Louis Vuitton", "Chanel", "Supreme", "Dior"]$$, $$[0, 1, 3]$$, $$medium$$, $$“蓝血”通常指LV, Chanel, Dior, Gucci, Prada, Calvin Klein六个品牌（早期划分方法）。Supreme属于街头品牌。$$, ARRAY[$$品牌知识$$,$$奢侈品$$]::text[], $${"管理学": 1.0, "经济学": 0.6, "艺术学": 1.0, "日子人": 0.8, "历史学": 0.3}$$, 'batch'),
  ($$fin_001$$, $$金融常识$$, $$single$$, $$股票和债券的本质区别在于投资者对企业持有的是什么权利？$$, $$["股票对应债权，债券对应所有权", "股票对应所有权，债券对应债权", "股票风险通常低于债券", "没有任何区别"]$$, $$[1]$$, $$easy$$, $$买股票是入股做了部分主（所有权），买债券是借钱给发债人拿利息（债权）。$$, ARRAY[$$证券基础$$,$$股票债券$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "理学": 0.2}$$, 'batch'),
  ($$fin_002$$, $$金融常识$$, $$single$$, $$IPO通常是指企业在资本市场的什么行为？$$, $$["宣告破产", "首次公开募股", "增发债券", "从交易所退市"]$$, $$[1]$$, $$easy$$, $$IPO (Initial Public Offering) 即公司第一次向公众投资者发售股份并准备上市。$$, ARRAY[$$企业融资$$,$$IPO$$]::text[], $${"管理学": 1.0, "经济学": 0.6, "理学": 0.2}$$, 'batch'),
  ($$fin_003$$, $$金融常识$$, $$single$$, $$在金融市场术语中，“牛市”(Bull Market) 是指？$$, $$["市场行情持续下跌", "市场交投惨淡", "市场整体价格持续上涨，投资者看好", "仅仅指农产品期货大涨"]$$, $$[2]$$, $$easy$$, $$牛市象征着价格上涨，多头活跃；熊市则代表大跌。$$, ARRAY[$$市场术语$$,$$牛市$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "理学": 0.4}$$, 'batch'),
  ($$fin_004$$, $$金融常识$$, $$single$$, $$投资者预期某股票价格即将下跌，先向券商借入股票卖出，等价格跌落后再在市场低价买回还给券商。这种操作叫？$$, $$["做多", "杠杆申购", "做空", "期货交割"]$$, $$[2]$$, $$medium$$, $$做空（买跌）是期望利用资产降价来吃差价的交易行为。$$, ARRAY[$$交易策略$$,$$做空$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "理学": 0.4}$$, 'batch'),
  ($$fin_005$$, $$金融常识$$, $$single$$, $$市盈率 (P/E Ratio) 是评估公司股价估值的重要指标，它的计算公式是？$$, $$["总资产除以总负债", "每股市价除以每股盈利", "市值除以年营业额", "净利润除以员工人数"]$$, $$[1]$$, $$medium$$, $$市盈率指市场价格与股票的每股收益之比，用以衡量回本周期或估值高低。$$, ARRAY[$$股票估值$$,$$市盈率$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "理学": 0.2}$$, 'batch'),
  ($$fin_006$$, $$金融常识$$, $$single$$, $$各国现代法定货币（Fiat Money）的价值基础主要来源于什么？$$, $$["该国黄金储备量等额背书", "国家政府信用和法定强制力", "美元汇率", "特定加密算法"]$$, $$[1]$$, $$medium$$, $$自布雷顿森林体系金本位瓦解后，法币均为信用货币，不再挂钩对应定额实体黄金，靠国家信用维持。$$, ARRAY[$$货币制度基础$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "理学": 0.2}$$, 'batch'),
  ($$fin_007$$, $$金融常识$$, $$single$$, $$我们常听到的 ETF 全称是 Exchange-Traded Fund，其中文确切含义是？$$, $$["货币市场基金", "对冲基金", "交易型开放式指数基金", "私募股权基金"]$$, $$[2]$$, $$medium$$, $$ETF是一种在股票交易所买卖的开放式投资基金，常用于跟踪股票市场某个指数。$$, ARRAY[$$投资基金$$,$$ETF$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "理学": 0.2}$$, 'batch'),
  ($$fin_008$$, $$金融常识$$, $$single$$, $$如果投资的年化收益率为10%，依据“72法则”，大约多少年资金会翻一番？$$, $$["5年", "7.2年", "10年", "15年"]$$, $$[1]$$, $$easy$$, $$72法则是一个方便估算复利翻倍时间的公式。72/10 = 7.2年。$$, ARRAY[$$复利$$,$$72法则$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "理学": 0.4}$$, 'batch'),
  ($$fin_009$$, $$金融常识$$, $$single$$, $$以下哪种资产类型的“流动性”（Liquidity）通常被认为是最强的？$$, $$["房地产", "未上市企业股权", "活期银行存款或现金", "古董与艺术品"]$$, $$[2]$$, $$easy$$, $$流动性指资产变现无大损的快捷程度，现金和活期存款变现能力最强。$$, ARRAY[$$资产属性$$,$$流动性$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "法学": 0.8, "文学": 0.3, "理学": 0.2}$$, 'batch'),
  ($$fin_010$$, $$金融常识$$, $$single$$, $$世界上首个基于区块链技术并实现去中心化的加密数字货币是？$$, $$["以太坊", "比特币", "瑞波币", "泰达币"]$$, $$[1]$$, $$easy$$, $$中本聪于2008年提出，2009年诞生的比特币是第一个大规模去中心化加密货币。$$, ARRAY[$$数字加密$$,$$比特币$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "理学": 0.4}$$, 'batch'),
  ($$fin_011$$, $$金融常识$$, $$single$$, $$股份公司按一定的比例将利润分配给股东的收益形式被称为？$$, $$["利息", "贴现", "股息/分红", "资本利得"]$$, $$[2]$$, $$easy$$, $$股息（分红）是公司从盈余中向持有者派发的核心利润回报。资本利得则是股价低买高卖赚的差价。$$, ARRAY[$$公司金融$$]::text[], $${"经济学": 1.0, "管理学": 1.0, "理学": 0.2}$$, 'batch'),
  ($$fin_012$$, $$金融常识$$, $$single$$, $$“对冲基金” (Hedge Fund) 相对于普通公募基金的最典型特征是？$$, $$["保证客户绝不亏本", "主要面向大众零散投资者", "使用高杠杆、做空和衍生品等复杂策略，且只面向少数高净值合格投资者", "只投资于政府债券"]$$, $$[2]$$, $$medium$$, $$对冲基金监管限制较少，常使用激进或跨市场套利策略，门槛极高而非大众可买。$$, ARRAY[$$基金机构$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "理学": 0.2}$$, 'batch'),
  ($$fin_013$$, $$金融常识$$, $$single$$, $$由国家授权，作为一国的“银行的银行”、负责发行法币并制定货币政策的顶层金融机构是？$$, $$["商业银行", "中央银行", "投资银行", "世界银行"]$$, $$[1]$$, $$easy$$, $$中央银行（如中国人民银行，美联储，欧洲央行）负责一国货币顶层发配。$$, ARRAY[$$央行体制$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "理学": 0.4}$$, 'batch'),
  ($$fin_014$$, $$金融常识$$, $$single$$, $$贷款方将原本不流通的信贷资产（如住房抵押贷款），打包重组成以其现金流为支持的有价证券在市场出售。这一金融创新过程叫做？$$, $$["破产重组", "资产证券化", "洗钱", "债券赎回"]$$, $$[1]$$, $$hard$$, $$MBS、CDO等均是典型的资产证券化产物，在2008次贷危机中扮演了关键角色。$$, ARRAY[$$金融衍生工具$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "理学": 0.2}$$, 'batch'),
  ($$fin_015$$, $$金融常识$$, $$single$$, $$如果一个国家存在严重的通货膨胀，其货币在国际汇率市场上的购买力通常会表现为？$$, $$["升值", "不变", "贬值", "不受影响"]$$, $$[2]$$, $$medium$$, $$通货膨胀代表对内购买力下降，往往也会伴随这部分货币在对外汇率市场上的贬值。$$, ARRAY[$$汇率$$,$$通货系统$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "理学": 0.2}$$, 'batch'),
  ($$fin_016$$, $$金融常识$$, $$multiple$$, $$被公认为企业或个人进行财务分析基础的“三大财务报表”有？$$, $$["资产负债表", "利润表", "现金流量表", "股东日记表"]$$, $$[0, 1, 2]$$, $$medium$$, $$这三张主表是反映企业资产健康情况、盈利能力、以及现金存活能力的正统公认度量核心。$$, ARRAY[$$财务报表$$,$$会计$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "理学": 0.4}$$, 'batch'),
  ($$fin_017$$, $$金融常识$$, $$multiple$$, $$金融衍生品（Derivatives）的价值依赖于基础资产的表现。常见的经典衍生品合约包括？$$, $$["远期合约", "期货", "期权", "互换"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$这四大类是最主流、使用最广泛的标准化及非标金融衍生工具，用以套期保值或投机。$$, ARRAY[$$衍生品市场$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "理学": 0.4}$$, 'batch'),
  ($$fin_018$$, $$金融常识$$, $$multiple$$, $$在传统的低风险投资及资产配置框架内，哪些常被称作“避险资产”？$$, $$["实物黄金或金条", "新兴市场未盈利科创股", "主要发达经济体的国债", "高杠杆加密货币"]$$, $$[0, 2]$$, $$medium$$, $$避险情绪高涨时，资金往往回流黄金、美元或主要发达国债保本避劫；未盈利股票和加密资产属于高风险资产。$$, ARRAY[$$配置$$,$$避险$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "理学": 0.4}$$, 'batch'),
  ($$fin_019$$, $$金融常识$$, $$multiple$$, $$我国的“五险一金”常常是求职者关心的社会保障福利。其中的“五险”通常包括？$$, $$["养老保险", "医疗保险", "工伤保险、失业保险与生育保险", "车船税与商业重疾险"]$$, $$[0, 1, 2]$$, $$easy$$, $$国家法定五险即养老、医疗、失业、工伤和生育。一金是指住房公积金。$$, ARRAY[$$社保$$,$$基础福利$$]::text[], $${"经济学": 1.0, "管理学": 0.8, "理学": 0.4}$$, 'batch'),
  ($$fin_020$$, $$金融常识$$, $$multiple$$, $$关于复利（Compound Interest）与单利（Simple Interest），下列说法正确的有？$$, $$["单利仅以本金计算利息", "复利不仅本金产生利息，前期的利息也会在后续周期生息", "长期来看，复利的累计收益远远大于相同利率下的单利", "短期借款绝没有复利现象"]$$, $$[0, 1, 2]$$, $$medium$$, $$信用卡逾期等实际金融贷款场景中不仅有复利，甚至会复利计算违约金等极高成本。$$, ARRAY[$$金融数学$$,$$利息$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "理学": 0.2}$$, 'batch'),
  ($$foo_001$$, $$美食与营养$$, $$single$$, $$人体提供直接生命能量最三大宏量营养素是蛋白质、脂肪和？$$, $$["维生素", "矿物质", "碳水化合物", "膳食纤维"]$$, $$[2]$$, $$easy$$, $$碳水化合物、蛋白质和脂肪是人体三大供能营养素。微量元素和纤维不提供或极少提供热量卡路里。$$, ARRAY[$$宏量营养素$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.2, "理学": 0.1}$$, 'batch'),
  ($$foo_002$$, $$美食与营养$$, $$single$$, $$由于缺少哪一种维生素会导致坏血病（大航海时代水手常见的疾病）？$$, $$["维生素A", "维生素B群", "维生素C", "维生素D"]$$, $$[2]$$, $$easy$$, $$缺乏维生素C会影响胶原合成产生坏血病，常由于未吃新鲜果蔬造成。$$, ARRAY[$$维生素C$$,$$坏血病$$]::text[], $${"日子人": 1.0, "医学": 0.4, "农学": 0.4, "理学": 0.2}$$, 'batch'),
  ($$foo_003$$, $$美食与营养$$, $$single$$, $$中国八大菜系中，以麻辣鲜香为特色，使用大量花椒和辣椒的菜系是？$$, $$["粤菜", "鲁菜", "川菜", "闽菜"]$$, $$[2]$$, $$easy$$, $$川菜是中国八大菜系之一，以成都和重庆两地的菜肴为代表，特点是麻辣。$$, ARRAY[$$中国美食$$,$$八大菜系$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.2, "理学": 0.1}$$, 'batch'),
  ($$foo_004$$, $$美食与营养$$, $$single$$, $$著名的法国料理常会使用的高级菌类，具有浓郁的奇异香气，被称为“餐桌上的黑钻石”的是？$$, $$["牛肝菌", "松露", "冬虫夏草", "猴头菇"]$$, $$[1]$$, $$easy$$, $$松露极其珍贵稀有，带有一种复杂的麝香、蒜香气味，是西餐最高级调味品之一。$$, ARRAY[$$西餐文化$$,$$高级食材$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.2, "理学": 0.1}$$, 'batch'),
  ($$foo_005$$, $$美食与营养$$, $$single$$, $$在发酵面点时常用的膨松剂主要是利用哪种气体让面团变得蓬松松软？$$, $$["氧气", "氮气", "二氧化碳", "硫化氢"]$$, $$[2]$$, $$medium$$, $$酵母或泡打粉在面团里发酵或发生化学反应释放出二氧化碳气泡，使受热膨胀。$$, ARRAY[$$食品科学$$]::text[], $${"日子人": 1.0, "医学": 0.4, "农学": 0.4, "理学": 0.2}$$, 'batch'),
  ($$foo_006$$, $$美食与营养$$, $$single$$, $$被称为高品质脂肪代表，地中海饮食中被大量使用的一种植物油是？$$, $$["大豆油", "棕榈油", "橄榄油", "牛油"]$$, $$[2]$$, $$easy$$, $$橄榄油富含单不饱和脂肪酸，是地中海长寿饮食结构的核心组成部分。$$, ARRAY[$$健康饮食$$,$$油脂$$]::text[], $${"日子人": 1.0, "医学": 0.4, "农学": 0.4, "理学": 0.2}$$, 'batch'),
  ($$foo_007$$, $$美食与营养$$, $$single$$, $$人体的骨骼和牙齿最主要需要吸收哪一种矿物质才能维持坚固？$$, $$["铁", "钙", "锌", "碘"]$$, $$[1]$$, $$easy$$, $$钙是人体含量最多的矿物元素，大部分储存在骨骼和牙齿内。$$, ARRAY[$$微量元素$$,$$钙$$]::text[], $${"理学": 1.0, "工学": 0.6, "日子人": 0.5, "医学": 0.2, "农学": 0.2}$$, 'batch'),
  ($$foo_008$$, $$美食与营养$$, $$single$$, $$大蒜切碎或捣碎后散发出强烈的辛辣刺激性气味是因为生成了什么物质？$$, $$["辣椒素", "花青素", "大蒜素", "苹果酸"]$$, $$[2]$$, $$medium$$, $$大蒜中的蒜氨酸在蒜氨酸酶作用下分解形成大蒜素，产生杀菌的强烈味道。$$, ARRAY[$$香辛料$$]::text[], $${"日子人": 1.0, "医学": 0.4, "农学": 0.4, "理学": 0.2}$$, 'batch'),
  ($$foo_009$$, $$美食与营养$$, $$single$$, $$“米其林指南” (Michelin Guide) 中，给予餐厅最高赞誉的星级评分最高是几颗星？$$, $$["三颗星", "四颗星", "五颗星", "七颗星"]$$, $$[0]$$, $$easy$$, $$米其林餐厅评价最高级别为三星，代表“卓越的烹调，值得专程造访”。$$, ARRAY[$$顶级餐饮$$]::text[], $${"日子人": 1.0, "医学": 0.4, "农学": 0.4, "理学": 0.2}$$, 'batch'),
  ($$foo_010$$, $$美食与营养$$, $$single$$, $$咖啡中的什么生物碱成分能够阻断大脑中的腺苷受体，从而让人感到精神焕发不困倦？$$, $$["可卡因", "茶碱", "咖啡因", "尼古丁"]$$, $$[2]$$, $$easy$$, $$咖啡因通过竞争性地占据疲劳信号分子腺苷在大脑的受体，从而阻绝疲劳感。$$, ARRAY[$$饮品科学$$]::text[], $${"日子人": 1.0, "医学": 0.4, "农学": 0.4, "理学": 0.2}$$, 'batch'),
  ($$foo_011$$, $$美食与营养$$, $$single$$, $$日本传统的“刺身”（Sashimi）常指？$$, $$["油炸天妇罗海鲜", "将新鲜生鱼片或生海鲜切片蘸酱进食", "一种甜腻的红豆糕点", "拉面的一种底汤"]$$, $$[1]$$, $$easy$$, $$刺身是对切成薄片的高级生肉（通常为海鲜）料理的称呼。$$, ARRAY[$$日本料理$$]::text[], $${"日子人": 1.0, "医学": 0.4, "农学": 0.4, "理学": 0.2}$$, 'batch'),
  ($$foo_012$$, $$美食与营养$$, $$single$$, $$烘焙面包和烤肉时表面变为了极为诱人的焦褐色，并散发出复杂香气，这是因为发生了什么化学反应？$$, $$["光合作用", "水解反应", "美拉德反应", "酸碱中和"]$$, $$[2]$$, $$hard$$, $$美拉德反应是含氨基的化合物和还原糖在特定温度下相互作用出棕黑色且产香的褐变反应。$$, ARRAY[$$烹饪化学$$,$$美拉德$$]::text[], $${"理学": 1.0, "工学": 0.6, "日子人": 1.0, "农学": 0.4, "医学": 0.2}$$, 'batch'),
  ($$foo_013$$, $$美食与营养$$, $$single$$, $$缺铁会导致人体易发生哪种常见的健康问题？$$, $$["夜盲症", "骨质疏松", "缺铁性贫血", "甲状腺肿大"]$$, $$[2]$$, $$medium$$, $$铁是合成红细胞内血红蛋白的核心元素，缺铁会导致难以携氧运输引发贫血。$$, ARRAY[$$营养素缺陷$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.2, "理学": 0.1}$$, 'batch'),
  ($$foo_014$$, $$美食与营养$$, $$single$$, $$经常用来发酵制作葡萄酒的酒类核心真菌是？$$, $$["青霉", "酵母菌", "放线菌", "乳酸菌"]$$, $$[1]$$, $$medium$$, $$酿酒酵母在微氧或无氧下能将葡萄的果糖代谢出乙醇与二氧化碳。$$, ARRAY[$$酿酒$$]::text[], $${"日子人": 1.0, "医学": 0.4, "农学": 0.4, "理学": 0.2}$$, 'batch'),
  ($$foo_015$$, $$美食与营养$$, $$single$$, $$关于食品保质，巴氏杀菌法（Pasteurization）通常采用什么手段？$$, $$["用高温高压彻底杀灭所有孢子，改变食品风味", "用极低温冷冻杀死细菌", "在低于水沸点的一定温度下加热一段时间，杀灭病原菌但保留风味", "加入大量的化学防腐剂如苯甲酸钠"]$$, $$[2]$$, $$hard$$, $$由巴斯德发明的巴氏灭菌采用相对温和的加热方法杀死大部分有害细菌而尽可能保全营养（常用于牛奶）。$$, ARRAY[$$食品工艺$$]::text[], $${"日子人": 1.0, "医学": 0.4, "农学": 0.4, "理学": 0.2}$$, 'batch'),
  ($$foo_016$$, $$美食与营养$$, $$multiple$$, $$以下哪些食物提供了丰富的优质蛋白质？$$, $$["鸡胸肉", "鱼肉和鸡蛋", "大豆及其制品", "白糖与黄油"]$$, $$[0, 1, 2]$$, $$easy$$, $$白糖是纯碳水，黄油几乎是纯脂肪，都不能提供丰富蛋白。$$, ARRAY[$$优质营养蛋白$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.2, "理学": 0.1}$$, 'batch'),
  ($$foo_017$$, $$美食与营养$$, $$multiple$$, $$中国传统的四大地方名酒（1952年评选）包括哪些典范？$$, $$["茅台酒", "汾酒", "泸州老窖", "西凤酒"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$首届全国评酒会共评出四大国家级名酒即：茅台酒、汾酒、泸州大曲酒（老窖）和西凤酒。（选项特意留全）$$, ARRAY[$$中国酒水名牌$$]::text[], $${"艺术学": 1.0, "日子人": 0.8, "历史学": 0.3, "医学": 0.2, "农学": 0.2, "理学": 0.1}$$, 'batch'),
  ($$foo_018$$, $$美食与营养$$, $$multiple$$, $$吃辣时感觉嘴部燃烧的“辣味”实际上是一种什么感觉？$$, $$["一种由味蕾捕获的基础酸味", "一种痛觉，不是纯味觉", "由辣椒素刺激了三叉神经等痛觉神经引发的热痛感", "真正的第五种基础味觉体系"]$$, $$[1, 2]$$, $$hard$$, $$辣味在科学上不属于酸甜苦咸鲜五大基本味蕾感受，而是由化学受体被激活引发类似高温灼烧的灼痛感。$$, ARRAY[$$美食感官科学$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.2, "理学": 0.1}$$, 'batch'),
  ($$foo_019$$, $$美食与营养$$, $$multiple$$, $$膳食纤维在现代饮食中极其重要，它的主要健康益处包括？$$, $$["虽不能被消化，但能促进肠道蠕动，防止便秘", "帮助延缓血糖上升曲线，稳定血糖", "产生大量的高热能让人强壮", "作为肠道益生菌的发酵粮食，维持肠道微生态"]$$, $$[0, 1, 3]$$, $$medium$$, $$膳食纤维是不产生或产生极低热量的，不能让人迅速获得热能变强壮。$$, ARRAY[$$肠道健康$$]::text[], $${"日子人": 1.0, "医学": 0.4, "农学": 0.4, "理学": 0.2}$$, 'batch'),
  ($$foo_020$$, $$美食与营养$$, $$multiple$$, $$被称为世界三大非酒精咖啡因饮料的有？$$, $$["茶", "咖啡", "可可", "可口可乐"]$$, $$[0, 1, 2]$$, $$medium$$, $$茶、咖啡、可可是全球三大传统植物类无酒精提神饮品。$$, ARRAY[$$植物饮品$$]::text[], $${"农学": 1.0, "理学": 0.8, "日子人": 0.5, "医学": 0.2}$$, 'batch'),
  ($$foo_021$$, $$美食与营养$$, $$single$$, $$中国八大菜系中，以麻辣鲜香著称，代表菜有麻婆豆腐的是？$$, $$["鲁菜", "粤菜", "徽菜", "川菜"]$$, $$[3]$$, $$easy$$, $$川菜以麻辣醇浓并重著称，麻婆豆腐是经典名菜。$$, ARRAY[$$菜系$$,$$中国饮食$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.2, "理学": 0.1}$$, 'batch'),
  ($$foo_022$$, $$美食与营养$$, $$single$$, $$制作咖啡时，被称为‘Espresso’的是指什么咖啡？$$, $$["拿铁咖啡", "浓缩咖啡", "美式咖啡", "卡布奇诺"]$$, $$[1]$$, $$easy$$, $$Espresso是意式浓缩咖啡，通过高温高压水快速穿过咖啡粉提取。$$, ARRAY[$$咖啡饮料$$,$$西方饮食$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.2, "理学": 0.1}$$, 'batch'),
  ($$game_001$$, $$游戏知识$$, $$single$$, $$在经典的《超级马里奥兄弟》中，马里奥为了救谁而踏上冒险？$$, $$["碧琪公主", "塞尔达公主", "林克", "路易吉"]$$, $$[0]$$, $$easy$$, $$马里奥的宿命是救被库巴抓走的蘑菇王国碧琪公主。$$, ARRAY[$$游戏史$$,$$任天堂$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_002$$, $$游戏知识$$, $$single$$, $$被誉为“电子竞技常青树”、由Valve公司开发的知名第一人称射击游戏系列是？$$, $$["《守望先锋》", "《使命召唤》", "《反恐精英》", "《穿越火线》"]$$, $$[2]$$, $$easy$$, $$CS系列二十多年来一直是全球最热门和核心的硬核竞技FPS游戏。$$, ARRAY[$$FPS$$,$$电子竞技$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_003$$, $$游戏知识$$, $$multiple$$, $$MOBA类（多人在线战术竞技）游戏的代表作有哪些？$$, $$["《英雄联盟》", "《DOTA 2》", "《王者荣耀》", "《我的世界》"]$$, $$[0, 1, 2]$$, $$easy$$, $$Minecraft属于沙盒建造生存，其余三者为经典的PC移动端MOBA巨头。$$, ARRAY[$$游戏类型$$,$$MOBA$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_004$$, $$游戏知识$$, $$single$$, $$《塞尔达传说：旷野之息》是任天堂哪台主机首发时的护航神作？$$, $$["Wii U", "Nintendo Switch", "Nintendo 3DS", "GameCube"]$$, $$[1]$$, $$easy$$, $$随Switch同捆首发（也发售了WiiU版），重新定义了开放世界游戏。$$, ARRAY[$$任天堂$$,$$主机游戏$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_005$$, $$游戏知识$$, $$single$$, $$著名游戏制作人“宫崎英高”主导开发，以极高难度和碎片化叙事闻名并在2022年斩获年度游戏的魂系代表作是？$$, $$["《血源诅咒》", "《黑神话：悟空》", "《艾尔登法环》", "《只狼：影逝二度》"]$$, $$[2]$$, $$easy$$, $$《艾尔登法环》结合了乔治·R·R·马丁的神话构建和魂系极高挑战性，横扫2022年各项大奖。$$, ARRAY[$$魂类游戏$$,$$ARPG$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_006$$, $$游戏知识$$, $$multiple$$, $$《我的世界》(Minecraft)中的核心玩法通常包括哪些？$$, $$["破坏和放置方块进行建造", "合成工具和武器", "探索无限程序生成的地图", "控制一架波音客机飞行"]$$, $$[0, 1, 2]$$, $$easy$$, $$这是一个利用方块构建、生存和探索的沙盒游戏。$$, ARRAY[$$沙盒游戏$$,$$Minecraft$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_007$$, $$游戏知识$$, $$single$$, $$《巫师3：狂猎》的主角名叫？$$, $$["叶奈法", "杰洛特", "特莉丝", "希里"]$$, $$[1]$$, $$easy$$, $$玩家扮演狩魔猎人“白狼”杰洛特，寻找他的养女希里。$$, ARRAY[$$RPG$$,$$巫师系列$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_008$$, $$游戏知识$$, $$single$$, $$被称为“吃鸡”玩法的游戏类型，其正式名称是？$$, $$["塔防游戏", "大逃杀", "角色扮演", "回合制策略"]$$, $$[1]$$, $$easy$$, $$Battle Royale类型指数十至上百人在不断缩小的安全区内厮杀至最后一人（队伍）。$$, ARRAY[$$大逃杀$$,$$射击游戏$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_009$$, $$游戏知识$$, $$multiple$$, $$下列哪些是由暴雪娱乐（Valve主要竞争对手之一）开发的游戏？$$, $$["《魔兽世界》", "《星际争霸》", "《暗黑破坏神》", "《半条命》"]$$, $$[0, 1, 2]$$, $$medium$$, $$《半条命》是Valve开发的，其余三款是暴雪的经典IP。$$, ARRAY[$$暴雪$$,$$PC游戏$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_010$$, $$游戏知识$$, $$single$$, $$在《生化危机》(Resident Evil)系列中，制造丧尸病毒的邪恶垄断企业名叫什么？$$, $$["保护伞公司 / 安布雷拉", "阿布斯泰戈", "黑山基地", "三岛财阀"]$$, $$[0]$$, $$easy$$, $$经典的反派跨国药企，暗中进行生化武器研发导致了浣熊市惨剧。$$, ARRAY[$$恐怖游戏$$,$$生化危机$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_011$$, $$游戏知识$$, $$single$$, $$在著名的沙盒射击游戏《侠盗猎车手5》(GTA V)中，游戏的主要舞台洛圣都（Los Santos）是基于现实中的哪座城市设计的？$$, $$["纽约", "洛杉矶", "迈阿密", "拉斯维加斯"]$$, $$[1]$$, $$easy$$, $$Los Santos复刻了南加州及洛杉矶的风貌，包括好莱坞标志（Vinewood）等。$$, ARRAY[$$开放世界$$,$$GTA$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_012$$, $$游戏知识$$, $$multiple$$, $$以下哪些是著名的主机游戏开发商第一方(独占)阵营？$$, $$["索尼互动娱乐", "任天堂", "微软 Xbox Game Studios", "育碧"]$$, $$[0, 1, 2]$$, $$easy$$, $$索尼、微软、任天堂是当今三大主机硬件厂商及最强的第一方阵容，育碧为第三方厂商。$$, ARRAY[$$游戏主机$$,$$第一方$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_013$$, $$游戏知识$$, $$single$$, $$《荒野大镖客：救赎2》的故事背景设定在美国哪个历史时期？$$, $$["美国独立战争", "美国西部拓荒时代末期", "第一次世界大战", "二战后"]$$, $$[1]$$, $$easy$$, $$讲述了1899年西部时代即将终结时，范德林德帮的故事。$$, ARRAY[$$剧情游戏$$,$$西部题材$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_014$$, $$游戏知识$$, $$single$$, $$《最终幻想》 (Final Fantasy)系列是由哪家日本公司开发的？$$, $$["卡普空", "科乐美", "史克威尔艾尼克斯", "万代南梦宫"]$$, $$[2]$$, $$easy$$, $$该系列由SE负责，是JRPG的巅峰代表系列之一。$$, ARRAY[$$JRPG$$,$$最终幻想$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_015$$, $$游戏知识$$, $$multiple$$, $$传统桌游/实体桌面角色扮演游戏中，TRPG（如《龙与地下城》）进行判定和判决成败最常用的核心道具往往是？$$, $$["二十面骰子", "角色卡/人物卡", "各种多面体骰子", "电脑主机"]$$, $$[0, 1, 2]$$, $$medium$$, $$TRPG基于纸笔和骰子运算进行判定，而不需要电脑主机辅助介入。$$, ARRAY[$$桌游$$,$$TRPG$$,$$龙与地下城$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_016$$, $$游戏知识$$, $$single$$, $$电子游戏中常说的“NPC”是指什么？$$, $$["网络连接错误", "非玩家角色", "游戏测试服", "无尽模式"]$$, $$[1]$$, $$easy$$, $$指游戏中不由玩家控制，由计算机AI控制的路人、村民或发放任务的人。$$, ARRAY[$$游戏术语$$,$$名词$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3, "文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$game_017$$, $$游戏知识$$, $$single$$, $$被中国玩家称为“猛男捡树枝”的任天堂现象级社交模拟游戏是？$$, $$["《牧场物语》", "《星露谷物语》", "《集合啦！动物森友会》", "《星光创造营》"]$$, $$[2]$$, $$easy$$, $$动森因为在岛上除草、钓鱼、捡树枝等玩法极其轻松休闲而得名。$$, ARRAY[$$休闲游戏$$,$$动森$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_018$$, $$游戏知识$$, $$multiple$$, $$《文明》 (Civilization)系列游戏的主要特色玩法标签是“4X”，4X代表哪四个英文单词的缩写？$$, $$["eXplore", "eXpand", "eXploit", "eXterminate"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$玩家在战略地图上从远古发展到未来，这四个X是所有此类回合制4X策略游戏的核心。$$, ARRAY[$$策略游戏$$,$$文明$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_019$$, $$游戏知识$$, $$single$$, $$游戏类型中的“Rogue-like/Rogue-lite”主要特征之一是？$$, $$["可以随时读档存档", "每次游戏地图程序随机生成，死亡后通常会失去全部或大部分进度重头再来", "只能联机游玩", "剧情完全一样且是线性打怪"]$$, $$[1]$$, $$medium$$, $$肉鸽游戏最大的魅力在于永久死亡机制和每次都不一样的随机关卡体验。$$, ARRAY[$$Rogue类$$,$$游戏机制$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_020$$, $$游戏知识$$, $$single$$, $$《半条命2》之所以被视为神作，其当时划时代的革命性进步主要体现在？$$, $$["采用了真正的3D画面", "首次引入了极其拟真、解谜与战斗紧密结合的物理引擎", "游戏完全免费", "支持百人同屏"]$$, $$[1]$$, $$medium$$, $$物理引擎不仅用于表现尸体，更核心的是重力枪系统和基于物理学的关卡解谜。$$, ARRAY[$$FPS$$,$$游戏史$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_021$$, $$游戏知识$$, $$multiple$$, $$以下哪些是著名的格斗类(FTG)电子游戏系列？$$, $$["《街头霸王》", "《铁拳》", "《拳皇》", "《极限竞速》"]$$, $$[0, 1, 2]$$, $$easy$$, $$极限竞速(Forza)是赛车游戏，前三个都是享誉全球的硬派格斗游戏。$$, ARRAY[$$格斗游戏$$,$$FTG$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_022$$, $$游戏知识$$, $$single$$, $$在电竞比赛中，“APM”是衡量选手操作水平的一个重要指标，它代表？$$, $$["每次点击的伤害", "每分钟操作次数", "游戏内的魔法值", "鼠标移动速度"]$$, $$[1]$$, $$easy$$, $$如星际和魔兽中，职业选手的APM通常达到300以上，代表手速极快。$$, ARRAY[$$电竞$$,$$术语$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_023$$, $$游戏知识$$, $$single$$, $$被称为“赛博朋克”风格的游戏《赛博朋克2077》，开发商是因《巫师3》备受赞誉的哪家波兰公司？$$, $$["CD Projekt RED", "Techland", "Naughty Dog", "Remedy"]$$, $$[0]$$, $$easy$$, $$CDPR开发了巫师和2077两部顶级制作并以厚道无加密闻名玩家圈。$$, ARRAY[$$赛博朋克$$,$$开发商$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.5, "艺术学": 0.1}$$, 'batch'),
  ($$game_024$$, $$游戏知识$$, $$multiple$$, $$游戏圈中，玩家如果被称为“云玩家”，通常意味着他？$$, $$["使用云电脑玩游戏", "自己很少或完全没玩过该游戏，仅通过看视频或直播了解", "却喜欢在论坛和评论区指点江山或批评他人", "是最顶级的职业选手"]$$, $$[1, 2]$$, $$easy$$, $$云玩家指不亲自去体验实机操作，却喜欢基于表面云体验发表断言的人。$$, ARRAY[$$网络语$$,$$玩家社群$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.2, "艺术学": 0.1}$$, 'batch'),
  ($$game_025$$, $$游戏知识$$, $$single$$, $$魂类游戏中，当遇到强力Boss过不去时，玩家间戏称最根本的解决办法是“Git Gud”，这也是什么意思？$$, $$["作弊修改器", "变强吧/提升自己的操作技术水平", "换个电脑", "充钱买装备"]$$, $$[1]$$, $$medium$$, $$源指“get good”，嘲讽或鼓励玩家放弃投机取巧，靠反复受苦练出真本领。$$, ARRAY[$$魂系梗$$,$$外网术语$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.2, "艺术学": 0.1}$$, 'batch'),
  ($$game_026$$, $$游戏知识$$, $$single$$, $$知名沙盒游戏《泰拉瑞亚》（Terraria）由于也具有挖矿和建造系统，常被称为2D版的？$$, $$["塞尔达", "我的世界", "星露谷", "魂斗罗"]$$, $$[1]$$, $$easy$$, $$虽然侧重点更偏向战斗和探索冒险，但因2D像素建造特色常被与MC相比。$$, ARRAY[$$独立游戏$$,$$沙盒$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_027$$, $$游戏知识$$, $$multiple$$, $$下列哪些电子游戏具有强烈的“银河恶魔城”（Metroidvania）标签特征？$$, $$["《空洞骑士》", "《奥日与黑暗森林》", "《血污：夜之仪式》", "《俄罗斯方块》"]$$, $$[0, 1, 2]$$, $$medium$$, $$此类游戏特色是一体化的巨大地图，随着获得新能力不断解锁回溯旧区域。这三款都是此类别名作。$$, ARRAY[$$银河恶魔城$$,$$游戏分类$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_028$$, $$游戏知识$$, $$single$$, $$恐怖生存游戏的鼻祖之一《寂静岭》 (Silent Hill) 系列中，极具标志性压迫感的怪物是？$$, $$["暴君", "三角头", "循声者", "异形"]$$, $$[1]$$, $$medium$$, $$三角头头戴巨大金字塔铁盔，手拖巨剑，代表了主角内心的罪恶与惩罚。$$, ARRAY[$$恐怖游戏$$,$$怪物设定$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_029$$, $$游戏知识$$, $$single$$, $$经常有玩家将“DLC”称作“扩展包”，DLC的全称是什么？$$, $$["Downloadable Character", "Downloadable Content", "Direct Link Connection", "Digital Level Code"]$$, $$[1]$$, $$easy$$, $$DLC一般指游戏发售后发布的额外新地图、新剧情、新服装等附加购买内容。$$, ARRAY[$$游戏名词$$,$$商业模式$$]::text[], $${"文学": 1.0, "历史学": 0.4, "日子人": 1.0, "工学": 0.3, "艺术学": 0.3, "管理学": 1.0, "经济学": 0.6}$$, 'batch'),
  ($$game_030$$, $$游戏知识$$, $$multiple$$, $$在多人游戏中，哪几种定位分配（铁三角）是MMORPG（如魔兽世界）打副本的经典标配？$$, $$["坦克", "治疗 / 奶妈", "输出", "裁判"]$$, $$[0, 1, 2]$$, $$easy$$, $$“战法牧”铁三角是几乎所有团队PvE下本的核心职业构架。$$, ARRAY[$$MMORPG$$,$$组队机制$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_031$$, $$游戏知识$$, $$single$$, $$任天堂著名的角色“卡比” (Kirby) 是一团粉色的圆球，他最主要的能力是？$$, $$["飞行射箭", "潜水", "将敌人吸入肚子中并吞下，复制复制敌人的能力", "变透明"]$$, $$[2]$$, $$easy$$, $$卡比有着巨胃，能通过把敌人吸进去而获得火、剑、雷等数十种不同的能力。$$, ARRAY[$$游戏角色$$,$$任天堂$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_032$$, $$游戏知识$$, $$single$$, $$在《底特律：变人》等互动电影冒险游戏中，玩家常面临“QTE”，QTE代表什么？$$, $$["快速反应事件", "问题测试评估", "质量测试执行", "量子计算"]$$, $$[0]$$, $$easy$$, $$玩家必须在屏幕提示出现的极短时间内按下特定按键或按键组合的机制。$$, ARRAY[$$游戏机制$$,$$交互设计$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 1.0}$$, 'batch'),
  ($$game_033$$, $$游戏知识$$, $$multiple$$, $$电竞赛事“Ti” (The International的缩写)和“S赛”分别对应哪两款著名的MOBA游戏总决赛？$$, $$["DOTA 2", "英雄联盟", "守望先锋", "CSGO"]$$, $$[0, 1]$$, $$easy$$, $$Ti是Dota2的国际邀请赛；而S系列赛（S1、S10等）是英雄联盟全球总决赛的称呼。$$, ARRAY[$$电竞赛事$$,$$MOBA$$]::text[], $${"教育学": 1.0, "日子人": 1.0, "历史学": 0.3, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_034$$, $$游戏知识$$, $$single$$, $$被许多玩家视为神作的解谜游戏《传送门》(Portal)，其中贯穿始终、陪伴并刁难玩家的人工智能反派名叫？$$, $$["Cortana", "GLaDOS", "Siri", "HAL 9000"]$$, $$[1]$$, $$medium$$, $$GLaDOS以其独特的刻薄幽默和病娇性格成为了游戏史上最经典的AI反派之一。$$, ARRAY[$$解谜游戏$$,$$角色设定$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_035$$, $$游戏知识$$, $$single$$, $$在《上古卷轴5》中，玩家因为在游戏中拥有吸收龙魂的力量，被称为？$$, $$["灰卫", "龙裔", "狩魔猎人", "大不净者"]$$, $$[1]$$, $$easy$$, $$玩家在天际省的角色是龙裔，能够使用龙之吐息龙吼（如著名的Fus Ro Dah）。$$, ARRAY[$$RPG$$,$$上古卷轴$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_036$$, $$游戏知识$$, $$multiple$$, $$近期在国内非常火的“国产独立游戏/派对游戏”如《猛兽派对》（Party Animals）或者《糖豆人》，其核心乐趣在于？$$, $$["极其硬核硬派的操作比拼", "软切或布娃娃物理引擎带来的滑稽搞笑动作", "和朋友联机之间互相坑害或合作破冰", "沉重深沉的悲剧剧情"]$$, $$[1, 2]$$, $$easy$$, $$派对游戏主打简单易上手、节目效果拉满的欢乐互坑氛围。$$, ARRAY[$$派对游戏$$,$$联机娱乐$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_037$$, $$游戏知识$$, $$single$$, $$老玩家常说的“FC”也就是“红白机”，是指任天堂的哪台游戏主机？$$, $$["Family Computer", "Fantasy Console", "First Controller", "Final Control"]$$, $$[0]$$, $$easy$$, $$FC全称为Family Computer，因其机身红白相间而在中国被广泛称为“红白机”（小霸王的原型）。$$, ARRAY[$$复古游戏$$,$$任天堂$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_038$$, $$游戏知识$$, $$single$$, $$主机游戏常常分为第一方、第二方和第三方，这里所说的“第三方”指的是？$$, $$["生产游戏光盘盒子的工厂", "拥有主机的平台商自己", "既不拥有硬件平台，也不被平台商控股的独立游戏开发商/发行商", "买游戏的玩家"]$$, $$[2]$$, $$medium$$, $$平台方是第一方，参股是第二方，完全独立能在任何机器上发布的就是第三方。$$, ARRAY[$$游戏产业$$,$$市场常识$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_039$$, $$游戏知识$$, $$multiple$$, $$下列哪些元素通常是被称为“生存建造类（Survival Crafting）”游戏（如《方舟》《Rust》《七日杀》）的机制？$$, $$["玩家初始通常一无所有，需要砍树砸石头收集资源", "合成装备和建造庇护所", "管理饥饿、口渴、体温等生理数值", "通过充值几万元直接购买一把杀死全服玩家的神剑"]$$, $$[0, 1, 2]$$, $$easy$$, $$纯正的沙盒生存主打白手起家克服环境困难，Pay to win机制大多在这种主流单机联机生存中遭抵制。$$, ARRAY[$$生存游戏$$,$$游戏系统$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_040$$, $$游戏知识$$, $$single$$, $$“G胖”是很多Steam玩家爱恨交加的男人，他是这家公司的联合创始人，其真名叫？$$, $$["比尔·盖茨", "加布·纽维尔", "岩田聪", "宫本茂"]$$, $$[1]$$, $$easy$$, $$G胖是Valve公司的老总，由于常推出Steam大促“抢钱”，但迟迟不出半条命3而被玩家调侃。$$, ARRAY[$$游戏人物$$,$$Steam$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_041$$, $$游戏知识$$, $$single$$, $$著名科幻史诗RPG《质量效应》(Mass Effect) 是哪家曾经擅长刻画深邃剧情的公司制作的代表作？$$, $$["Bethesda", "BioWare", "Obsidian", "Blizzard"]$$, $$[1]$$, $$medium$$, $$生动展现了外星种族恩怨结合的太空歌剧，是BioWare的巅峰之作。$$, ARRAY[$$RPG$$,$$科幻游戏$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_042$$, $$游戏知识$$, $$multiple$$, $$索尼的“白金奖杯”、微软Xbox的“成就解锁”，这些系统的初衷是为了什么？$$, $$["鼓励玩家挑战游戏的各种困难条件或隐藏要素", "延长游戏的重复游玩寿命", "直接转化为现金", "给玩家一种成就虚荣感展示在个人主页"]$$, $$[0, 1, 3]$$, $$easy$$, $$成就/奖杯系统不提供真金白银，主要提供玩家精神满足和游戏附加挑战动力。$$, ARRAY[$$游戏系统$$,$$主机体系$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_043$$, $$游戏知识$$, $$single$$, $$很多速通(Speedrun)玩家在玩游戏时会故意利用地图穿模漏洞等跳过大段剧情，这种利用游戏漏洞速通的分类被称为？$$, $$["Glitchless", "Any% / Any Percentage", "100% 全收集", "休闲模式"]$$, $$[1]$$, $$medium$$, $$Any%只看最终通关画面用时最短，不管完成度或使用了什么邪门的游戏出图Bug。$$, ARRAY[$$竞速通关$$,$$速通文化$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_044$$, $$游戏知识$$, $$single$$, $$2016年现象级的移动AR游戏，让无数宅男宅女走上街头去捕捉虚拟怪物的是什么游戏？$$, $$["《阴阳师》", "《Pokémon GO》", "《愤怒的小鸟》", "《哈利波特：巫师联盟》"]$$, $$[1]$$, $$easy$$, $$Niantic结合了谷歌地图功能，将宝可梦IP投射到真实地理坐标中引起全球狂飙去公园抓精灵。$$, ARRAY[$$AR游戏$$,$$手游$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_045$$, $$游戏知识$$, $$multiple$$, $$目前游戏领域热议的“云游戏”（Cloud Gaming）其特点包括哪些？$$, $$["游戏画面在远程高性能服务器上渲染，传回手机或旧电脑", "不需要下载安装几百G的庞大游戏客户端", "极度依赖稳定且低延迟的高速宽带网络", "即使断网也能离线游玩"]$$, $$[0, 1, 2]$$, $$medium$$, $$本质是看交互视频，断网直接凉凉。$$, ARRAY[$$云游戏$$,$$前沿技术$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_046$$, $$游戏知识$$, $$single$$, $$《暗黑破坏神》等装备驱动类刷子游戏(Looter)的终局体验（Endgame）往往是？$$, $$["看完长达3小时的结局大电影", "为了刷出属性极品的词条装备，不断重复地刷最高难度秘境/副本", "卸载游戏", "开始建造房子"]$$, $$[1]$$, $$medium$$, $$俗称“刷刷刷”游戏，打完主线剧情才意味着装备毕业赛跑的开始。$$, ARRAY[$$装备驱动$$,$$游戏模式$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_047$$, $$游戏知识$$, $$single$$, $$“Rougelike”分类里的命名祖师爷《Rogue》游戏发售于什么时期？$$, $$["2010年代的Steam时代", "1980年的早期计算机命令行字符界面时代", "1995年红白机时代", "2000年初的网吧时代"]$$, $$[1]$$, $$hard$$, $$《Rogue》采用ASCII字符作为图形显示，创造了随机地牢和永久死亡的深远模式。$$, ARRAY[$$游戏极简史$$,$$Rogue历史$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3, "历史学": 1.0, "文学": 0.4, "军事学": 0.3}$$, 'batch'),
  ($$game_048$$, $$游戏知识$$, $$single$$, $$对于《英雄联盟》（LOL）这款游戏而言，“大龙”通常指代游戏地图上的哪一种史诗级野怪？$$, $$["远古巨龙", "纳什男爵", "峡谷先锋", "红Buff"]$$, $$[1]$$, $$easy$$, $$玩家俗称为大龙的是男爵Baron，能提供关键团队Buff。$$, ARRAY[$$MOBA游戏$$,$$LOL$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_049$$, $$游戏知识$$, $$multiple$$, $$下列哪些是电子游戏常见的收费商业模式（Monetization）？$$, $$["买断制 发售获得完整游戏", "免费游玩，内购物充值", "基于时间的月卡/点卡订阅制", "必须每天给开发商写感谢信"]$$, $$[0, 1, 2]$$, $$easy$$, $$这是游戏史上主要的三种商业模式。$$, ARRAY[$$游戏行业$$,$$商业模式$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3, "管理学": 1.0, "经济学": 0.6}$$, 'batch'),
  ($$game_050$$, $$游戏知识$$, $$single$$, $$《双人成行》(It Takes Two) 是哪位知名制作人（常在TGA大奖上飙脏话“Fuck the Oscars”）监制的需要强制两人合作的神作神作？$$, $$["小岛秀夫", "约瑟夫·法尔斯", "三上真司", "蒂姆·斯维尼"]$$, $$[1]$$, $$medium$$, $$法尔斯因其暴脾气和对合作类游戏的极高造诣（前作逃出生天）而闻名。$$, ARRAY[$$双人游戏$$,$$TGA大奖$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_051$$, $$游戏知识$$, $$single$$, $$对于游戏设计而言，“Hitbox” (受击判定框) 的作用是？$$, $$["装游戏光盘的盒子", "音乐游戏里的节拍点", "在代码模型中不可见的多边形框，用来计算子弹或攻击是否碰到了这个角色", "游戏内弹出的聊天框"]$$, $$[2]$$, $$medium$$, $$命中判定框是射击和格斗游戏最核心的系统判定边界。$$, ARRAY[$$游戏术语$$,$$设计$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 1.0}$$, 'batch'),
  ($$game_052$$, $$游戏知识$$, $$multiple$$, $$下列哪些中国本土开发的游戏作品属于著名的国产单机“三剑”？$$, $$["《仙剑奇侠传》", "《轩辕剑》", "《剑侠情缘》", "《古剑奇谭》"]$$, $$[0, 1, 2]$$, $$easy$$, $$国产老三剑是仙剑、轩辕剑、剑侠情缘（古剑被称为新三剑之一）。$$, ARRAY[$$国产游戏$$,$$仙侠RPG$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_053$$, $$游戏知识$$, $$single$$, $$在经典的战略沙盘游戏《星际争霸》（StarCraft）中，三大种族是人族、神族以及？$$, $$["兽族", "虫族", "不死族", "暗夜精灵"]$$, $$[1]$$, $$easy$$, $$Zerg虫族依靠庞大的数量和生物异化战术淹没对手网络。$$, ARRAY[$$RTS$$,$$星际争霸$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_054$$, $$游戏知识$$, $$single$$, $$对于《反恐精英》 (CS:GO) 而言，“ECO局”通常是什么意思？$$, $$["环保局，游戏地图中种树", "经济局 ，全队不买或极少买装备攒钱以备下一局购买全甲长枪", "疯狂花钱购买投掷物", "退出游戏的局"]$$, $$[1]$$, $$medium$$, $$ECO局是CS竞技战术核心，用最廉价手枪度过资金薄弱的回合。$$, ARRAY[$$战术射击$$,$$CS赛事$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "工学": 0.2, "艺术学": 0.1}$$, 'batch'),
  ($$game_055$$, $$游戏知识$$, $$single$$, $$《大航海时代》和《三国志》系列是日本哪家著名游戏公司开发的经典历史策略游戏老字号IP？$$, $$["光荣特库摩", "万代南梦宫", "SEGA", "Konami"]$$, $$[0]$$, $$easy$$, $$光荣(Koei)以历史题材的模拟策略游戏和无双割草系列见长。$$, ARRAY[$$历史策略$$,$$光荣$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "日子人": 0.5, "工学": 0.2, "艺术学": 0.1}$$, 'batch'),
  ($$game_056$$, $$游戏知识$$, $$multiple$$, $$下列哪些平台属于PC（个人电脑）平台的数字游戏发行商城/商店？$$, $$["Steam", "Epic Games Store", "GOG", "PlayStation Network"]$$, $$[0, 1, 2]$$, $$easy$$, $$PSN是索尼主机的专用网路商店，不是主要负责PC发行的商店。$$, ARRAY[$$PC游戏$$,$$Steam$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_057$$, $$游戏知识$$, $$single$$, $$被称为魂系游戏祖师爷、“赞美太阳”文化来源的作品是？$$, $$["《恶魔之魂》", "《黑暗之魂》", "《国王密令》", "《怪物猎人》"]$$, $$[1]$$, $$easy$$, $$黑魂中索拉尔等太阳骑士传播的“赞美太阳”成为了圈内绝对的膜拜梗。$$, ARRAY[$$ARPG$$,$$黑暗之魂$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_058$$, $$游戏知识$$, $$single$$, $$赛车游戏中通常有两类分支，一类像《极限竞速：地平线》《极品飞车》追求爽快，而另一类极其追求物理拟真硬核手感（如《神力科莎》《iRacing》《GT赛车》）的被称为？$$, $$["街机休闲赛车", "卡丁车", "模拟竞速/拟真赛车", "太空飞船赛"]$$, $$[2]$$, $$medium$$, $$Sim Racing通过精准的轮胎级物理摩擦演算逼近真实赛道体验。$$, ARRAY[$$RAC$$,$$赛车游戏$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$game_059$$, $$游戏知识$$, $$multiple$$, $$《动物森友会》（动森）里那只总是找你要房贷、掌控着海岛经济命脉的著名狸猫商人叫什么？$$, $$["西施惠", "Tom Nook", "KK", "九尾"]$$, $$[1]$$, $$easy$$, $$狸克（Tom Nook）提供房贷但可以无限期慢慢还清，是玩家的“债主”。$$, ARRAY[$$动森$$,$$NPC角色$$]::text[], $${"日子人": 1.0, "工学": 0.4, "艺术学": 0.2}$$, 'batch'),
  ($$game_060$$, $$游戏知识$$, $$single$$, $$电子游戏中，让角色能够连续在空中进行两次向上动作的操作通常被简称为？$$, $$["冲刺", "二段跳", "翻滚", "闪避"]$$, $$[1]$$, $$easy$$, $$这是一种极度违背现实物理学，但能极大增强平台跳跃流畅度的经典机制。$$, ARRAY[$$动作游戏$$,$$操作机制$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3}$$, 'batch'),
  ($$geo_001$$, $$地理$$, $$single$$, $$世界上面积最大的国家是？$$, $$["加拿大", "俄罗斯", "中国", "美国"]$$, $$[1]$$, $$easy$$, $$按国土面积，俄罗斯位列世界第一。$$, ARRAY[$$国家$$,$$地理之最$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_002$$, $$地理$$, $$single$$, $$世界上最长的河流是？$$, $$["亚马逊河", "长江", "尼罗河", "密西西比河"]$$, $$[2]$$, $$easy$$, $$公认世界上最长的河流是尼罗河，不过也有学者认为亚马逊河最长。$$, ARRAY[$$河流$$,$$地理之最$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_003$$, $$地理$$, $$single$$, $$世界最高峰珠穆朗玛峰位于哪两个国家边境？$$, $$["中国和印度", "中国和尼泊尔", "中国和不丹", "中国和巴基斯坦"]$$, $$[1]$$, $$easy$$, $$珠峰位于中国西藏自治区与尼泊尔交界处。$$, ARRAY[$$山脉$$,$$亚洲地理$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_004$$, $$地理$$, $$single$$, $$世界上最大的沙漠是？$$, $$["阿拉伯沙漠", "戈壁沙漠", "南极荒漠", "撒哈拉沙漠"]$$, $$[2]$$, $$medium$$, $$严格按降水量定义，南极荒漠是世界最大的沙漠（极地荒漠）。撒哈拉是最大的沙质荒漠。$$, ARRAY[$$沙漠$$,$$自然地理$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_005$$, $$地理$$, $$single$$, $$澳大利亚的首都是？$$, $$["悉尼", "墨尔本", "堪培拉", "布里斯班"]$$, $$[2]$$, $$easy$$, $$澳大利亚首都是堪培拉，悉尼和墨尔本是其最大城市。$$, ARRAY[$$首都$$,$$大洋洲$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_006$$, $$地理$$, $$single$$, $$欧洲流经国家最多的河流是？$$, $$["莱茵河", "伏尔加河", "多瑙河", "塞纳河"]$$, $$[2]$$, $$medium$$, $$多瑙河是欧洲第二长河，流经10个国家，是流经国家最多的河流。$$, ARRAY[$$欧洲地理$$,$$河流$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_007$$, $$地理$$, $$single$$, $$南美洲完全内陆的国家是哪两个？$$, $$["玻利维亚和巴拉圭", "秘鲁和智利", "哥伦比亚和委内瑞拉", "乌拉圭和阿根廷"]$$, $$[0]$$, $$hard$$, $$南美洲只有两个内陆国：玻利维亚和巴拉圭。$$, ARRAY[$$南美洲$$,$$国家$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_008$$, $$地理$$, $$single$$, $$非洲面积最大的国家是？$$, $$["苏丹", "刚果民主共和国", "阿尔及利亚", "利比亚"]$$, $$[2]$$, $$hard$$, $$南苏丹独立后，阿尔及利亚成为非洲面积最大的国家。$$, ARRAY[$$非洲地理$$,$$国家$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_009$$, $$地理$$, $$single$$, $$被称为“千湖之国”的是？$$, $$["挪威", "瑞典", "芬兰", "冰岛"]$$, $$[2]$$, $$easy$$, $$芬兰境内湖泊众多，被称为“千湖之国”。$$, ARRAY[$$欧洲地理$$,$$国家别称$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_010$$, $$地理$$, $$single$$, $$世界上最大的热带雨林是？$$, $$["刚果雨林", "亚马逊雨林", "东南亚雨林", "大熊雨林"]$$, $$[1]$$, $$easy$$, $$亚马逊热带雨林是世界最大热带雨林。$$, ARRAY[$$雨林$$,$$自然生态$$]::text[], $${"农学": 1.0, "理学": 0.8, "历史学": 0.25}$$, 'batch'),
  ($$geo_011$$, $$地理$$, $$multiple$$, $$以下属于联合国的常任理事国的是？$$, $$["中国", "德国", "法国", "印度"]$$, $$[0, 2]$$, $$easy$$, $$联合国五常是中、美、俄、英、法。$$, ARRAY[$$人文地理$$,$$国际组织$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_012$$, $$地理$$, $$multiple$$, $$北极圈穿过以下哪些国家？$$, $$["加拿大", "俄罗斯", "瑞典", "英国"]$$, $$[0, 1, 2]$$, $$medium$$, $$北极圈穿过俄罗斯、加拿大、美国、丹麦(格陵兰)、挪威、瑞典、芬兰、冰岛。英国在北极圈以南。$$, ARRAY[$$纬线$$,$$极点地理$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_013$$, $$地理$$, $$multiple$$, $$以下哪些选项是地球的大洋？$$, $$["大西洋", "印度洋", "南冰洋", "地中海"]$$, $$[0, 1, 2]$$, $$easy$$, $$传统四大洋加南冰洋（南大洋）共五大洋，地中海是陆间海，不是大洋。$$, ARRAY[$$海洋地理$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
