  ($$geo_015$$, $$地理$$, $$single$$, $$世界陆地的最低点是？$$, $$["死海", "马里亚纳海沟", "里海", "艾尔湖"]$$, $$[0]$$, $$medium$$, $$死海湖面海拔在海平面以下400多米，是地球表面的陆地最低点。$$, ARRAY[$$地形$$,$$地理之最$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_016$$, $$地理$$, $$single$$, $$黄石国家公园主要位于哪个国家？$$, $$["加拿大", "美国", "澳大利亚", "南非"]$$, $$[1]$$, $$easy$$, $$黄石国家公园是美国也是世界上第一个国家公园。$$, ARRAY[$$公园$$,$$北美地理$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_017$$, $$地理$$, $$single$$, $$世界上最大的半岛是？$$, $$["阿拉伯半岛", "印度半岛", "中南半岛", "斯堪的纳维亚半岛"]$$, $$[0]$$, $$medium$$, $$阿拉伯半岛是世界上最大的半岛。$$, ARRAY[$$半岛$$,$$亚洲地理$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_018$$, $$地理$$, $$multiple$$, $$以下国家中位于南半球的是？$$, $$["新西兰", "厄瓜多尔", "巴西", "埃及"]$$, $$[0, 2]$$, $$medium$$, $$新西兰在南半球，巴西大部分在南半球，厄瓜多尔横跨赤道，埃及完全在北半球。$$, ARRAY[$$南北半球$$,$$国家分布$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_019$$, $$地理$$, $$single$$, $$赤道不穿过以下哪个洲？$$, $$["亚洲", "非洲", "南美洲", "欧洲"]$$, $$[3]$$, $$easy$$, $$赤道穿过亚洲、非洲、大洋洲、南美洲。$$, ARRAY[$$赤道$$,$$大洲分布$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_020$$, $$地理$$, $$single$$, $$企鹅主要分布在自然地理上的哪里？$$, $$["北冰洋", "南极圈及其周边", "格陵兰岛", "撒哈拉沙漠"]$$, $$[1]$$, $$easy$$, $$企鹅主要生活在南极地区及南半球的高纬度地区。$$, ARRAY[$$动物分布$$,$$独特生态$$]::text[], $${"理学": 0.8, "农学": 1.0, "历史学": 0.25}$$, 'batch'),
  ($$geo_021$$, $$地理$$, $$single$$, $$湄公河发源于哪个国家？$$, $$["越南", "老挝", "泰国", "中国"]$$, $$[3]$$, $$medium$$, $$湄公河发源于中国青海省，在中国境内称为澜沧江。$$, ARRAY[$$河流$$,$$亚洲水系$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_022$$, $$地理$$, $$multiple$$, $$组成英国的实体包括？$$, $$["英格兰", "苏格兰", "威尔士", "北爱尔兰"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$英国全称大不列颠及北爱尔兰联合王国，由英格兰、苏格兰、威尔士和北爱尔兰组成。$$, ARRAY[$$国家构成$$,$$欧洲地理$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_023$$, $$地理$$, $$single$$, $$世界上面积最小的国家是？$$, $$["摩纳哥", "瑙鲁", "梵蒂冈", "圣马力诺"]$$, $$[2]$$, $$easy$$, $$梵蒂冈是世界面积最小的国家，被称为城中国。$$, ARRAY[$$微型国家$$,$$地理之最$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_024$$, $$地理$$, $$single$$, $$大堡礁位于哪个国家东北沿海？$$, $$["印度尼西亚", "菲律宾", "澳大利亚", "马达加斯加"]$$, $$[2]$$, $$easy$$, $$大堡礁位于澳大利亚东北海岸，是世界最大最长的珊瑚礁群。$$, ARRAY[$$珊瑚礁$$,$$海洋保护$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_025$$, $$地理$$, $$multiple$$, $$下列属于死火山或休眠火山的是？$$, $$["威苏威火山", "富士山", "乞力马扎罗山", "黄石超级火山"]$$, $$[1, 2, 3]$$, $$hard$$, $$富士山是休眠火山，乞力马扎罗是休眠火山；黄石也是休眠的超级火山。威苏威是活火山。$$, ARRAY[$$火山$$,$$地质活动$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_026$$, $$地理$$, $$single$$, $$按面积，地球上最大的洲是？$$, $$["非洲", "南美洲", "亚洲", "南极洲"]$$, $$[2]$$, $$easy$$, $$亚洲是面积最大、人口最多的大洲。$$, ARRAY[$$大洲$$,$$面积排名$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_027$$, $$地理$$, $$single$$, $$加拿大的首都是？$$, $$["多伦多", "温哥华", "渥太华", "蒙特利尔"]$$, $$[2]$$, $$medium$$, $$渥太华是加拿大首都，尽管多伦多和温哥华更有知名度。$$, ARRAY[$$首府$$,$$北美洲$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_028$$, $$地理$$, $$single$$, $$跨三个半球且赤道横贯的洲是？$$, $$["非洲", "亚洲", "大洋洲", "南美洲"]$$, $$[0]$$, $$hard$$, $$非洲位于东半球，跨南北半球，不仅赤道横穿，本初子午线也穿过，因此跨四个半球(东西南北)。$$, ARRAY[$$半球地理$$,$$综合题$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_029$$, $$地理$$, $$multiple$$, $$中国的三大平原是？$$, $$["东北平原", "华北平原", "长江中下游平原", "成都平原"]$$, $$[0, 1, 2]$$, $$medium$$, $$中国的三大平原是东北、华北、长江中下游平原。成都平原属于四川盆地一部分。$$, ARRAY[$$中国地理$$,$$地形地貌$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_030$$, $$地理$$, $$single$$, $$里海是什么性质的水体？$$, $$["淡水湖", "咸水湖", "边缘海", "内陆海"]$$, $$[1]$$, $$medium$$, $$里海是世界上最大的湖泊，属于咸水湖。$$, ARRAY[$$湖泊$$,$$水文地理$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_031$$, $$地理$$, $$single$$, $$连续多年位居中国省级经济总值（GDP）榜首的省份是？$$, $$["江苏省", "浙江省", "广东省", "山东省"]$$, $$[2]$$, $$easy$$, $$广东省自1989年起连续多年GDP居全国首位。$$, ARRAY[$$人文地理$$,$$省份经济$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "理学": 0.4, "历史学": 0.25, "农学": 0.1}$$, 'batch'),
  ($$geo_032$$, $$地理$$, $$multiple$$, $$吴语主要分布在我国的哪些地区？$$, $$["上海市", "浙江省大部", "江苏省大部", "江苏省南部"]$$, $$[0, 1, 3]$$, $$medium$$, $$吴语主要通行于上海、浙江大部以及江苏南部的苏南地区。$$, ARRAY[$$人文地理$$,$$方言$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_033$$, $$地理$$, $$single$$, $$中国传统的“八大菜系”中，以麻辣著称且发源于巴蜀地区的是？$$, $$["湘菜", "川菜", "鲁菜", "徽菜"]$$, $$[1]$$, $$easy$$, $$川菜发源于四川和重庆（巴蜀地区），以麻、辣、鲜、香著称。$$, ARRAY[$$人文地理$$,$$饮食文化$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_034$$, $$地理$$, $$single$$, $$目前世界GDP总量排名第三的国家（按2023-2024年数据）是？$$, $$["日本", "英国", "印度", "德国"]$$, $$[3]$$, $$hard$$, $$受汇率等因素影响，近年来德国GDP超越日本，成为世界第三大经济体（前两名为美、中）。$$, ARRAY[$$人文地理$$,$$世界经济$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "理学": 0.4, "历史学": 0.25, "农学": 0.1}$$, 'batch'),
  ($$geo_035$$, $$地理$$, $$single$$, $$“客家话”主要通行于我国的哪些省份交界地带？$$, $$["陕甘宁", "粤闽赣", "黑吉辽", "湘鄂渝"]$$, $$[1]$$, $$medium$$, $$客家人主要聚居在广东、福建、江西三省交界处（即粤闽赣）。$$, ARRAY[$$人文地理$$,$$方言$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_036$$, $$地理$$, $$multiple$$, $$以下属于中国三大都市圈（城市群）的有哪些？$$, $$["京津冀", "长三角", "珠三角", "滇中城市群"]$$, $$[0, 1, 2]$$, $$easy$$, $$京津冀、长三角、珠三角是中国最具活力和规模的三大城市群。$$, ARRAY[$$人文地理$$,$$城市化$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_037$$, $$地理$$, $$single$$, $$美国的“硅谷”（Silicon Valley）位于哪个州？$$, $$["纽约州", "得克萨斯州", "加利福尼亚州", "华盛顿州"]$$, $$[2]$$, $$easy$$, $$硅谷位于美国加利福尼亚州北部的大部分旧金山湾区。$$, ARRAY[$$人文地理$$,$$国际产业$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_038$$, $$地理$$, $$single$$, $$世界上人口密度最高的主权国家是？$$, $$["新加坡", "摩纳哥", "马尔代夫", "孟加拉国"]$$, $$[1]$$, $$medium$$, $$摩纳哥是世界上人口密度最高的主权国家。$$, ARRAY[$$人文地理$$,$$人口状况$$]::text[], $${"法学": 0.8, "管理学": 0.6, "文学": 0.3, "理学": 0.4, "历史学": 0.25, "农学": 0.1}$$, 'batch'),
  ($$geo_039$$, $$地理$$, $$single$$, $$泼水节是我国哪个少数民族最盛大的传统节日？$$, $$["苗族", "壮族", "傣族", "彝族"]$$, $$[2]$$, $$easy$$, $$泼水节是傣族以及泰语民族和东南亚地区的传统节日。$$, ARRAY[$$人文地理$$,$$民俗文化$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_040$$, $$地理$$, $$multiple$$, $$我国八大菜系中，位于华东地区（东南沿海）的有？$$, $$["鲁菜", "苏菜", "闽菜", "浙菜"]$$, $$[1, 2, 3]$$, $$medium$$, $$鲁菜属于北方菜系，苏菜（江苏）、闽菜（福建）、浙菜（浙江）位于华东、东南沿海。$$, ARRAY[$$人文地理$$,$$饮食文化$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_041$$, $$地理$$, $$single$$, $$简称“豫”的中国省份是？$$, $$["河北省", "河南省", "安徽省", "湖北省"]$$, $$[1]$$, $$easy$$, $$河南省简称“豫”，因古为豫州之地而得名。$$, ARRAY[$$人文地理$$,$$中国省份$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_042$$, $$地理$$, $$single$$, $$在全球语言体系中，巴西的官方语言是？$$, $$["西班牙语", "英语", "葡萄牙语", "印第安语"]$$, $$[2]$$, $$easy$$, $$巴西曾是葡萄牙的殖民地，所以其官方语言是葡萄牙语，南美大多数其他国家则是西班牙语。$$, ARRAY[$$人文地理$$,$$世界语言$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_043$$, $$地理$$, $$single$$, $$我国的“经济特区”中，位于福建省的是？$$, $$["深圳", "珠海", "汕头", "厦门"]$$, $$[3]$$, $$medium$$, $$深圳、珠海、汕头均位于广东省，厦门位于福建省。$$, ARRAY[$$人文地理$$,$$城市经济$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "理学": 0.4, "历史学": 0.25, "农学": 0.1}$$, 'batch'),
  ($$geo_044$$, $$地理$$, $$single$$, $$被誉为“世界工厂”，以强大制造业闻名的中国南方城市，最典型的是？$$, $$["东莞", "温州", "义乌", "宁波"]$$, $$[0]$$, $$medium$$, $$东莞因其高度发达的制造业和完善的产业链，常被称为“世界工厂”。$$, ARRAY[$$人文地理$$,$$工业分布$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "理学": 0.4, "历史学": 0.25, "农学": 0.1}$$, 'batch'),
  ($$geo_045$$, $$地理$$, $$multiple$$, $$藏族主要分布在我国的哪些省级行政区？$$, $$["西藏自治区", "青海省", "四川省西部", "新疆维吾尔自治区"]$$, $$[0, 1, 2]$$, $$hard$$, $$除西藏外，青海、四川（西部如甘孜、阿坝）、甘肃、云南也有大量藏族聚居，新疆少数民族以维吾尔族等为主。$$, ARRAY[$$人文地理$$,$$民族分布$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_046$$, $$地理$$, $$single$$, $$素有“天府之国”美誉的是我国哪个平原？$$, $$["关中平原", "成都平原", "江汉平原", "太湖平原"]$$, $$[1]$$, $$easy$$, $$成都平原土地肥沃、水利发达（如都江堰），自古便有“天府之国”之称。$$, ARRAY[$$人文地理$$,$$地区别称$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_047$$, $$地理$$, $$multiple$$, $$联合国的六种正式工作语言包括？$$, $$["汉语", "英语", "德语", "阿拉伯语"]$$, $$[0, 1, 3]$$, $$hard$$, $$联合国六种工作语言是：阿拉伯语、汉语、英语、法语、俄语、西班牙语。德语不在其列。$$, ARRAY[$$人文地理$$,$$国际组织$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_048$$, $$地理$$, $$single$$, $$中国面积最大的直辖市是？$$, $$["北京市", "上海市", "重庆市", "天津市"]$$, $$[2]$$, $$easy$$, $$重庆市总面积达8.24万平方公里，是中国面积最大的直辖市。$$, ARRAY[$$人文地理$$,$$中国城市$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_049$$, $$地理$$, $$single$$, $$我国拥有最多陆上邻国的省（区）是？$$, $$["西藏自治区", "内蒙古自治区", "新疆维吾尔自治区", "云南省"]$$, $$[2]$$, $$hard$$, $$新疆维吾尔自治区与8个国家接壤（俄罗斯、哈萨克斯坦、吉尔吉斯斯坦、塔吉克斯坦、巴基斯坦、蒙古、印度、阿富汗），是我国陆上邻国最多的省级行政区。$$, ARRAY[$$人文地理$$,$$国界接壤$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_050$$, $$地理$$, $$single$$, $$印度的主体信仰宗教是？$$, $$["伊斯兰教", "佛教", "印度教", "锡克教"]$$, $$[2]$$, $$medium$$, $$印度大约有80%左右的人口信仰印度教，伊斯兰教为第二大宗教，佛教目前在印度的信徒比例较小。$$, ARRAY[$$人文地理$$,$$世界宗教$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_051$$, $$地理$$, $$single$$, $$秘鲁寒流减弱会导致以下哪种气候异常现象？$$, $$["拉尼娜现象", "厄尔尼诺现象", "温室效应", "极光现象"]$$, $$[1]$$, $$medium$$, $$秘鲁寒流异常减弱、水温升高会导致厄尔尼诺现象，引发全球气候异常。$$, ARRAY[$$自然地理$$,$$洋流$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_052$$, $$地理$$, $$single$$, $$喀斯特地貌主要是由哪种岩石受到水的溶蚀作用形成的？$$, $$["花岗岩", "大理岩", "玄武岩", "石灰岩"]$$, $$[3]$$, $$easy$$, $$喀斯特地貌是地下水与地表水对可溶性岩石（主要是石灰岩）溶蚀与沉淀形成的。$$, ARRAY[$$自然地理$$,$$地貌$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_053$$, $$地理$$, $$single$$, $$我国著名的丹霞地貌，其岩石呈现出的主要颜色是？$$, $$["青灰色", "黑赤色", "紫红色", "灰白色"]$$, $$[2]$$, $$easy$$, $$丹霞地貌主要由红色砂砾岩构成，因此呈现出红、紫红等颜色。$$, ARRAY[$$自然地理$$,$$地貌$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_054$$, $$地理$$, $$single$$, $$伊斯兰教的发源地是哪里？$$, $$["中亚", "阿拉伯半岛", "南亚次大陆", "北非"]$$, $$[1]$$, $$medium$$, $$伊斯兰教发源于公元7世纪的阿拉伯半岛。$$, ARRAY[$$人文地理$$,$$宗教信仰$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_055$$, $$地理$$, $$single$$, $$直布罗陀海峡连通了哪两个海域？$$, $$["地中海与黑海", "太平洋与大西洋", "地中海与大西洋", "红海与印度洋"]$$, $$[2]$$, $$easy$$, $$直布罗陀海峡连接地中海和大西洋，是重要的海上通道。$$, ARRAY[$$政区边界$$,$$海峡运河$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_056$$, $$地理$$, $$single$$, $$本国境内有一块完全被其他国家领土包围的土地，这块土地被称为该国的什么？$$, $$["飞地", "外岛", "租界", "自治区"]$$, $$[0]$$, $$medium$$, $$飞地指隶属于某一行政区管辖但不与本区毗连的土地。$$, ARRAY[$$政区边界$$,$$领土概念$$]::text[], $${"理学": 0.8, "历史学": 0.5, "农学": 0.2}$$, 'batch'),
  ($$geo_sci_001$$, $$地球科学$$, $$single$$, $$地球上最大的淡水水库是？$$, $$["河流", "地下水", "冰川和冰盖", "湖泊"]$$, $$[2]$$, $$easy$$, $$地球上大部分淡水储存在南北极和高山的冰川和冰盖中。$$, ARRAY[$$水圈$$,$$淡水资源$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_002$$, $$地球科学$$, $$single$$, $$引起地球上潮汐现象的最主要拉力来源于？$$, $$["月球", "太阳", "木星", "地转偏向力"]$$, $$[0]$$, $$easy$$, $$主要是由于月球引力（其次是太阳引力）引起的潮汐作用。$$, ARRAY[$$潮汐$$,$$自然现象$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_003$$, $$地球科学$$, $$single$$, $$大气层中绝大部分的紫外线被哪一层吸收？$$, $$["对流层", "平流层", "中间层", "热层"]$$, $$[1]$$, $$easy$$, $$平流层内含有臭氧层，能够吸收大量太阳紫外线，保护地球生物。$$, ARRAY[$$大气圈$$,$$臭氧层$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_004$$, $$地球科学$$, $$single$$, $$地球板块构造学说认为，岩石圈浮在什么之上？$$, $$["莫霍面", "内核", "软流层", "海洋"]$$, $$[2]$$, $$medium$$, $$岩石圈被分为多个板块，漂浮在具有一定塑性的地幔软流层之上滑动。$$, ARRAY[$$板块构造$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_005$$, $$地球科学$$, $$single$$, $$测量地震强弱通常使用的震级标度是？$$, $$["摩氏硬度", "里氏震级", "热力学温度", "蒲福风级"]$$, $$[1]$$, $$easy$$, $$地震普遍使用里氏震级和矩震级标度。蒲福是风级，摩氏是硬度。$$, ARRAY[$$地质基础$$,$$地震$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_006$$, $$地球科学$$, $$single$$, $$导致洋流形成和流动的主要驱动力包括风力和？$$, $$["热盐差异", "降雨量", "地下水流动", "地磁场"]$$, $$[0]$$, $$medium$$, $$洋流分为风海流和密度流（热盐环流，由温度和盐度差异引起）。$$, ARRAY[$$海洋学$$,$$洋流$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_007$$, $$地球科学$$, $$single$$, $$在莫氏硬度等级中，硬度最高（级别为10）的天然矿物是？$$, $$["滑石", "石英", "金刚石", "刚玉"]$$, $$[2]$$, $$easy$$, $$莫氏硬度等级10是金刚石（钻石），滑石是最软的1，石英是7，刚玉是9。$$, ARRAY[$$矿物学$$,$$硬度$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_008$$, $$地球科学$$, $$single$$, $$地球内部圈层由外向里可以分为？$$, $$["地壳-地核-地幔", "地壳-地幔-地核", "地幔-地壳-地核", "大气层-水圈-生物圈"]$$, $$[1]$$, $$easy$$, $$地球内部结构从表面往下分为地壳、地幔和地核。$$, ARRAY[$$内部结构$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_009$$, $$地球科学$$, $$single$$, $$气象学中，北半球在强烈的气旋区（如台风）中，风的旋转方向为？$$, $$["顺时针", "逆时针", "由中心向外直线吹", "随机旋转"]$$, $$[1]$$, $$medium$$, $$受科里奥利力（地转偏向力）影响，北半球气旋（低压中心）的气流呈逆时针旋转。$$, ARRAY[$$气象学$$,$$气旋$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_010$$, $$地球科学$$, $$single$$, $$世界上最深的海沟是太平洋的哪条海沟？$$, $$["日本海沟", "秘鲁-智利海沟", "马里亚纳海沟", "汤加海沟"]$$, $$[2]$$, $$medium$$, $$马里亚纳海沟是已知地球海洋中最深的地方，最深处达一万一千多米。$$, ARRAY[$$海洋洋底地形$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_011$$, $$地球科学$$, $$single$$, $$由于碳酸盐岩石的可溶性，在水流溶蚀作用下形成的特殊地貌称为什么地貌？$$, $$["冰川地貌", "风蚀地貌", "丹霞地貌", "喀斯特地貌"]$$, $$[3]$$, $$medium$$, $$岩溶地貌即喀斯特地貌，是可溶性岩石（主要为碳酸盐岩）受水的溶蚀作用形成的。$$, ARRAY[$$地貌学$$,$$喀斯特$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_012$$, $$地球科学$$, $$single$$, $$通常认为生命起源于大约多少亿年前的地球？$$, $$["46亿年", "38亿年", "15亿年", "6亿年"]$$, $$[1]$$, $$medium$$, $$地球形成于约46亿年前，最早的生命记录（单细胞生物化石）可追溯到约35-38亿年前。$$, ARRAY[$$地球历史$$,$$生命起源$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "理学": 0.5, "工学": 0.2, "农学": 0.15}$$, 'batch'),
  ($$geo_sci_013$$, $$地球科学$$, $$single$$, $$大理岩（大理石）属于岩石三大分类中的哪一类？$$, $$["岩浆岩", "沉积岩", "变质岩", "陨石"]$$, $$[2]$$, $$medium$$, $$大理岩是由石灰岩或白云岩等沉积岩在高温高压下发生变质作用形成的变质岩。$$, ARRAY[$$地质学$$,$$岩石分类$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_014$$, $$地球科学$$, $$single$$, $$科里奥利力主要是由于什么原因引起的？$$, $$["地球自转", "地球公转", "地核高温", "月球引力"]$$, $$[0]$$, $$medium$$, $$科里奥利力（地转偏向力）是由于地球自转而对运动中的物体产生的惯性偏转力。$$, ARRAY[$$地球物理$$,$$自转$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_015$$, $$地球科学$$, $$single$$, $$寒武纪生命大爆发爆发于什么地质时代？$$, $$["太古代", "中生代", "古生代", "新生代"]$$, $$[2]$$, $$hard$$, $$寒武纪属于古生代的第一个纪，大约5.4亿年前发生了多细胞生物门类迅速增多的大爆发。$$, ARRAY[$$地质年代$$,$$寒武纪$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_016$$, $$地球科学$$, $$multiple$$, $$三大岩石类型指的是？$$, $$["岩浆岩", "沉积岩", "变质岩", "玄武岩"]$$, $$[0, 1, 2]$$, $$medium$$, $$沉积、变质、岩浆是岩石体系的三大分类，玄武岩属于岩浆岩的一种。$$, ARRAY[$$地学常识$$,$$岩石$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_017$$, $$地球科学$$, $$multiple$$, $$下列哪些气体是地球大气层非常关键的“温室气体”？$$, $$["水蒸气", "二氧化碳", "甲烷", "氧气"]$$, $$[0, 1, 2]$$, $$medium$$, $$氧气不吸收地表长波辐射，不是温室气体。其他三种是自然界和人类产生的主要温室气体。$$, ARRAY[$$大气科学$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_018$$, $$地球科学$$, $$multiple$$, $$厄尔尼诺现象通常会导致哪些气候异常表现？$$, $$["太平洋赤道东部海温异常升高", "秘鲁沿岸降水增多，发生洪涝", "印尼和澳大利亚东部干旱", "全球性气温下降"]$$, $$[0, 1, 2]$$, $$hard$$, $$厄尔尼诺通常导致全球平均气温偏高，并引发太平洋区域水文气象格局改变，东部（秘鲁）多雨、西部（印尼、澳洲）干旱。$$, ARRAY[$$气候学$$,$$厄尔尼诺$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.5, "经济学": 0.3}$$, 'batch'),
  ($$geo_sci_019$$, $$地球科学$$, $$multiple$$, $$根据大陆漂移假说和板块构造学说，喜马拉雅山脉是哪两个板块碰撞隆起的结果？$$, $$["欧亚板块", "印度洋板块", "太平洋板块", "非洲板块"]$$, $$[0, 1]$$, $$medium$$, $$喜马拉雅山造山运动是由印度洋板块与欧亚板块碰撞挤压形成的。$$, ARRAY[$$板块构造$$]::text[], $${"理学": 1.0, "工学": 0.4, "农学": 0.3}$$, 'batch'),
  ($$geo_sci_020$$, $$地球科学$$, $$multiple$$, $$自然界水循环的主要环节包括？$$, $$["蒸发和蒸腾", "水汽输送", "降水", "地表和地下径流"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$水循环涵盖海陆间水的运动，涉及蒸发、凝结降水、水汽输送和径流等全过程。$$, ARRAY[$$水文学$$,$$水循环$$]::text[], $${"文学": 1.0, "历史学": 0.3, "理学": 0.5, "工学": 0.2, "农学": 0.15}$$, 'batch'),
  ($$his_001$$, $$历史$$, $$single$$, $$中国历史上第一个大一统的封建王朝是？$$, $$["夏朝", "商朝", "周朝", "秦朝"]$$, $$[3]$$, $$easy$$, $$公元前221年，秦始皇嬴政统一六国，建立了中国历史上第一个大一统的封建王朝秦朝。$$, ARRAY[$$古代史$$,$$中国朝代$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_002$$, $$历史$$, $$single$$, $$传统上的“世界四大文明古国”不包括以下哪一个？$$, $$["古巴比伦", "古埃及", "古罗马", "古印度"]$$, $$[2]$$, $$easy$$, $$四大文明古国通常指古巴比伦、古埃及、古印度和古代中国，不包括古罗马。$$, ARRAY[$$世界古代史$$,$$文明古国$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_003$$, $$历史$$, $$single$$, $$宣告美国独立的纲领性文件《独立宣言》发表于哪一年？$$, $$["1776年", "1783年", "1787年", "1789年"]$$, $$[0]$$, $$medium$$, $$1776年7月4日，大陆会议通过了《独立宣言》，宣告北美13个殖民地脱离英国独立。$$, ARRAY[$$美国历史$$,$$近代史$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_004$$, $$历史$$, $$single$$, $$中国古代科举制度正式创立于哪个朝代？$$, $$["汉朝", "隋朝", "唐朝", "宋朝"]$$, $$[1]$$, $$medium$$, $$隋炀帝设立进士科，标志着科举制度的正式形成。$$, ARRAY[$$古代史$$,$$政治制度$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_005$$, $$历史$$, $$single$$, $$世界上现存古代第一部比较完备的成文法典是？$$, $$["《汉谟拉比法典》", "《十二铜表法》", "《查士丁尼法典》", "《拿破仑法典》"]$$, $$[0]$$, $$hard$$, $$《汉谟拉比法典》是古巴比伦国王汉谟拉比颁布的一部法律，是现存古代第一部较完备的成文法典。$$, ARRAY[$$世界古代史$$,$$法律史$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "法学": 1.0, "管理学": 0.2, "哲学": 0.15}$$, 'batch'),
  ($$his_006$$, $$历史$$, $$single$$, $$郑和下西洋发生的朝代是？$$, $$["宋朝", "元朝", "明朝", "清朝"]$$, $$[2]$$, $$easy$$, $$明成祖朱棣时期，派遣郑和七下西洋，这是中国古代规模最大、船只最多、海员最多、时间最久的海上航行。$$, ARRAY[$$中国古代史$$,$$航海$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_007$$, $$历史$$, $$single$$, $$文艺复兴时期，其代表作有《蒙娜丽莎》《最后的晚餐》的巨匠是？$$, $$["米开朗基罗", "拉斐尔", "达·芬奇", "但丁"]$$, $$[2]$$, $$easy$$, $$达·芬奇是文艺复兴时期的人物，代表作《蒙娜丽莎》和《最后的晚餐》闻名于世。$$, ARRAY[$$世界史$$,$$文艺复兴$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_008$$, $$历史$$, $$single$$, $$第一次世界大战爆发的直接导火索是？$$, $$["萨拉热窝事件", "波士顿倾茶事件", "珍珠港事件", "慕尼黑阴谋"]$$, $$[0]$$, $$medium$$, $$1914年的萨拉热窝事件（奥匈帝国皇储斐迪南大公遇刺）是第一次世界大战的导火索。$$, ARRAY[$$近代史$$,$$一战$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_009$$, $$历史$$, $$single$$, $$“五四运动”爆发于哪一年？$$, $$["1911年", "1915年", "1919年", "1921年"]$$, $$[2]$$, $$easy$$, $$五四运动是1919年5月4日发生在北京的一场以青年学生为主的爱国运动。$$, ARRAY[$$中国近代史$$,$$学生运动$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.5, "文学": 0.2, "哲学": 0.15}$$, 'batch'),
  ($$his_010$$, $$历史$$, $$single$$, $$法国大革命中，雅各宾派专政的最高实际领导人是？$$, $$["拿破仑", "路易十六", "丹东", "罗伯斯庇尔"]$$, $$[3]$$, $$hard$$, $$雅各宾派是法国大革命的一支激进派，罗伯斯庇尔是其首领。$$, ARRAY[$$世界史$$,$$法国大革命$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_011$$, $$历史$$, $$single$$, $$世界上最早的纸币“交子”出现于中国的哪个时期？$$, $$["唐朝", "北宋", "南宋", "明朝"]$$, $$[1]$$, $$medium$$, $$北宋时期四川地区出现的“交子”是世界上最早的纸币。$$, ARRAY[$$中国古代史$$,$$经济史$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "经济学": 1.0, "管理学": 0.5, "哲学": 0.15}$$, 'batch'),
  ($$his_012$$, $$历史$$, $$single$$, $$戊戌变法的主要代表人物除了康有为，还有谁？$$, $$["林则徐", "李鸿章", "严复", "梁启超"]$$, $$[3]$$, $$easy$$, $$戊戌变法（百日维新）的主要领导人和代表人物是康有为、梁启超等人。$$, ARRAY[$$中国近代史$$,$$戊戌变法$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_013$$, $$历史$$, $$single$$, $$俄国十月革命爆发于公历的哪一年？$$, $$["1905年", "1914年", "1917年", "1922年"]$$, $$[2]$$, $$medium$$, $$俄国十月革命发生于俄历1917年10月（公历1917年11月）。$$, ARRAY[$$世界近代史$$,$$十月革命$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_014$$, $$历史$$, $$single$$, $$罗马帝国正式分裂为东西两部分是在哪一年？$$, $$["公元前27年", "公元395年", "公元476年", "公元1453年"]$$, $$[1]$$, $$hard$$, $$公元395年，罗马帝国皇帝狄奥多西一世将帝国平分给两个儿子，罗马帝国从此正式分裂为东西两部。$$, ARRAY[$$世界古代史$$,$$罗马帝国$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_015$$, $$历史$$, $$single$$, $$标志着中国近代史开端的事件是？$$, $$["鸦片战争", "第二次鸦片战争", "甲午中日战争", "八国联军侵华战争"]$$, $$[0]$$, $$easy$$, $$1840年爆发的第一次鸦片战争标志着中国逐渐沦为半殖民地半封建社会，是中国近代史的开端。$$, ARRAY[$$中国近代史$$,$$开端$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_016$$, $$历史$$, $$single$$, $$第二次世界大战的苏德战场和世界反法西斯战争的转折点是哪场战役？$$, $$["莫斯科保卫战", "斯大林格勒战役", "中途岛海战", "诺曼底登陆"]$$, $$[1]$$, $$medium$$, $$斯大林格勒战役的胜利不仅是苏德战场的转折点，也是整个二战的重大转折点。$$, ARRAY[$$世界史$$,$$二战$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_017$$, $$历史$$, $$single$$, $$被誉为“南美洲的解放者”的拉美独立运动领导人是？$$, $$["圣马丁", "玻利瓦尔", "伊达尔戈", "卡斯特罗"]$$, $$[1]$$, $$medium$$, $$西蒙·玻利瓦尔领导了南美洲北部的独立运动，被称为“南美解放者”。$$, ARRAY[$$世界史$$,$$拉美独立$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_018$$, $$历史$$, $$single$$, $$在中国历史上，“贞观之治”属于哪位皇帝的统治时期？$$, $$["汉武帝刘彻", "唐太宗李世民", "唐玄宗李隆基", "清圣祖玄烨"]$$, $$[1]$$, $$easy$$, $$“贞观”是唐太宗李世民的年号，“贞观之治”指他在位期间的清明政治与盛世局面。$$, ARRAY[$$中国古代史$$,$$贞观之治$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_019$$, $$历史$$, $$single$$, $$日本的明治维新开始于哪一年？$$, $$["1840年", "1853年", "1868年", "1894年"]$$, $$[2]$$, $$medium$$, $$1868年，日本开始了自上而下的资产阶级性质改革，即明治维新。$$, ARRAY[$$世界近现代史$$,$$日本史$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_020$$, $$历史$$, $$single$$, $$18世纪末法国大革命中颁布的重要纲领性文件是？$$, $$["《权利法案》", "《独立宣言》", "《人权宣言》", "《大宪章》"]$$, $$[2]$$, $$medium$$, $$1789年法国大革命期间颁布了《人权宣言》，而《权利法案》是英国的，《独立宣言》是美国的。$$, ARRAY[$$世界史$$,$$法国大革命$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_021$$, $$历史$$, $$single$$, $$发明了“活字印刷术”的北宋匠人是？$$, $$["蔡伦", "张衡", "毕昇", "沈括"]$$, $$[2]$$, $$medium$$, $$北宋庆历年间，平民毕昇发明了泥活字印刷术。$$, ARRAY[$$中国古代史$$,$$四大发明$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_022$$, $$历史$$, $$single$$, $$古巴比伦文明发源于“两河流域”，这两条河是？$$, $$["底格里斯河与幼发拉底河", "印度河与恒河", "尼罗河与刚果河", "长江与黄河"]$$, $$[0]$$, $$easy$$, $$美索不达米亚文明（两河文明）发源于底格里斯河和幼发拉底河流域。$$, ARRAY[$$世界古代史$$,$$文明溯源$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_023$$, $$历史$$, $$single$$, $$八国联军侵华战争发生在哪一年？$$, $$["1840年", "1860年", "1894年", "1900年"]$$, $$[3]$$, $$medium$$, $$1900年，英、美、法、德、俄、日、意、奥八国组成联军侵略中国。$$, ARRAY[$$中国近代史$$,$$晚清$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_024$$, $$历史$$, $$single$$, $$引发辛亥革命的武昌起义爆发于哪一年？$$, $$["1898年", "1901年", "1911年", "1919年"]$$, $$[2]$$, $$easy$$, $$1911年10月10日爆发的武昌起义标志着辛亥革命的开始。$$, ARRAY[$$中国近代史$$,$$辛亥革命$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_025$$, $$历史$$, $$single$$, $$英国工业革命开始的标志是哪项发明的出现？$$, $$["飞梭", "水力织布机", "改良蒸汽机", "蒸汽机车"]$$, $$[0]$$, $$hard$$, $$18世纪60年代，哈格里夫斯发明“珍妮机”，标志着英国工业革命的开始。$$, ARRAY[$$世界近现代史$$,$$工业革命$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "历史学": 0.5, "文学": 0.2, "哲学": 0.15}$$, 'batch'),
  ($$his_026$$, $$历史$$, $$single$$, $$“安史之乱”发生在哪个朝代？$$, $$["西汉", "东汉", "唐朝", "明朝"]$$, $$[2]$$, $$easy$$, $$安史之乱是唐朝玄宗末年至代宗初年由安禄山和史思明发动的叛乱，是唐朝由盛转衰的转折点。$$, ARRAY[$$中国古代史$$,$$历史事件$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_027$$, $$历史$$, $$multiple$$, $$下列属于中国古代“四大发明”的有？$$, $$["造纸术", "地动仪", "火药", "指南针"]$$, $$[0, 2, 3]$$, $$easy$$, $$中国古代四大发明是指造纸术、指南针、火药和印刷术。地动仪是张衡发明的，但不属于四大发明。$$, ARRAY[$$古代史$$,$$古代科技$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_028$$, $$历史$$, $$multiple$$, $$以下哪些国家是由法西斯主导的第二次世界大战“轴心国”阵营核心成员？$$, $$["纳粹德国", "苏联", "意大利王国", "大日本帝国"]$$, $$[0, 2, 3]$$, $$medium$$, $$二战期间的三大轴心国核心是德国、意大利和日本。苏联属于反法西斯同盟国阵营。$$, ARRAY[$$世界近现史$$,$$二战$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_029$$, $$历史$$, $$multiple$$, $$春秋战国时期，“战国七雄”包括以下哪几个诸侯国？$$, $$["齐国", "鲁国", "楚国", "秦国"]$$, $$[0, 2, 3]$$, $$medium$$, $$战国七雄分别为齐、楚、燕、韩、赵、魏、秦。鲁国不在七雄之列。$$, ARRAY[$$古代史$$,$$春秋战国$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_030$$, $$历史$$, $$multiple$$, $$以下哪些属于晚清政府被迫签订的不平等条约？$$, $$["《南京条约》", "《马关条约》", "《尼布楚条约》", "《辛丑条约》"]$$, $$[0, 1, 3]$$, $$hard$$, $$《尼布楚条约》是清朝康熙年间中俄在平等基础上签订的边界条约。其余三个均是在侵略战争失败后签订的不平等条约。$$, ARRAY[$$中国近代史$$,$$晚清条约$$]::text[], $${"法学": 0.8, "历史学": 0.6, "政治学": 0.5, "文学": 0.2, "哲学": 0.15}$$, 'batch'),
  ($$his_031$$, $$历史$$, $$multiple$$, $$第一次工业革命时期，主要的代表性发明有哪些？$$, $$["珍妮纺纱机", "内燃机", "改良蒸汽机", "蒸汽机车"]$$, $$[0, 2, 3]$$, $$medium$$, $$内燃机属于第二次工业革命的标志性产物，其余项均为第一次工业革命的重要发明。$$, ARRAY[$$世界近现代史$$,$$工业革命$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "历史学": 0.5, "文学": 0.2, "哲学": 0.15}$$, 'batch'),
  ($$his_032$$, $$历史$$, $$multiple$$, $$下列历史人物属于中国“三国时期”重要势力的奠基者或君主的有？$$, $$["曹魏-曹操", "蜀汉-刘备", "东吴-孙权", "西晋-司马炎"]$$, $$[0, 1, 2]$$, $$easy$$, $$司马炎建立西晋，标志着三国时代的终结；魏、蜀、吴的奠基者与君主分别是曹操(曹丕称帝)、刘备、孙权。$$, ARRAY[$$中国古代史$$,$$三国$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_033$$, $$历史$$, $$multiple$$, $$法国大革命时期活跃过的政治派别包括？$$, $$["斐扬派", "吉伦特派", "雅各宾派", "托利党"]$$, $$[0, 1, 2]$$, $$hard$$, $$斐扬派、吉伦特派和雅各宾派都是法国大革命时期的主要政治派别。托利党是英国的保守党前身。$$, ARRAY[$$世界史$$,$$法国大革命$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_034$$, $$历史$$, $$multiple$$, $$下列属于中国古代政治经济改革的有？$$, $$["商鞅变法", "王安石变法", "张居正改革", "明治维新"]$$, $$[0, 1, 2]$$, $$medium$$, $$明治维新是日本近代史的改革。商鞅(战国)、王安石(北宋)、张居正(明朝)均为中国古代著名的变法或改革。$$, ARRAY[$$古代史$$,$$古代改革$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_035$$, $$历史$$, $$multiple$$, $$冷战时期的“两极格局”中，处于针锋相对领导地位的两个超级大国是？$$, $$["美国", "英国", "法国", "苏联"]$$, $$[0, 3]$$, $$easy$$, $$二战后形成的冷战两极格局主要表现为以美国为首的资本主义阵营和以苏联为首的社会主义阵营之间的对立。$$, ARRAY[$$世界现代史$$,$$冷战$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_036$$, $$历史$$, $$single$$, $$中国古代历史上哪场战役被称为‘草木皆兵’的发生地？$$, $$["赤壁之战", "巨鹿之战", "淝水之战", "官渡之战"]$$, $$[2]$$, $$easy$$, $$淝水之战中前秦皇帝苻坚留下了风声鹤唳、草木皆兵的典故。$$, ARRAY[$$历史战役$$,$$魏晋南北朝$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_037$$, $$历史$$, $$single$$, $$以下哪位历史人物领导了‘戊戌变法’？$$, $$["王安石", "张居正", "康有为", "商鞅"]$$, $$[2]$$, $$easy$$, $$戊戌变法由康有为、梁启超等人倡导。$$, ARRAY[$$著名变法$$,$$晚清史$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_038$$, $$历史$$, $$single$$, $$第二次世界大战的欧洲战场转折点是哪场战役？$$, $$["斯大林格勒战役", "诺曼底登陆", "中途岛海战", "珍珠港事件"]$$, $$[0]$$, $$medium$$, $$斯大林格勒保卫战是苏德战场的转折点，也是二战欧洲战场的转折点。$$, ARRAY[$$二战史$$,$$转折战役$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$his_039$$, $$历史$$, $$single$$, $$冷战时期，美国为了遏制苏联的扩张，最短在欧洲推行的经济援助计划是？$$, $$["马歇尔计划", "杜鲁门主义", "北约组建", "华约组建"]$$, $$[0]$$, $$medium$$, $$马歇尔计划(欧洲复兴计划)是冷战初期美国援助西欧的计划。$$, ARRAY[$$冷战史$$,$$国际关系$$]::text[], $${"历史学": 1.0, "文学": 0.4, "哲学": 0.3}$$, 'batch'),
  ($$his_040$$, $$历史$$, $$single$$, $$秦始皇统一六国后，推行的文字标准是？$$, $$["大篆", "小篆", "隶书", "楷书"]$$, $$[1]$$, $$medium$$, $$秦始皇统一后，由李斯等人将大篆简化为小篆作为通用文字。$$, ARRAY[$$大一统$$,$$古代文化$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "哲学": 0.15}$$, 'batch'),
  ($$hot_001$$, $$时事热点$$, $$single$$, $$2024年的夏季奥运会在哪座城市举办？$$, $$["东京", "伦敦", "巴黎", "洛杉矶"]$$, $$[2]$$, $$easy$$, $$第33届夏季奥林匹克运动会于2024年在法国巴黎举行。$$, ARRAY[$$时事$$,$$奥运会$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "法学": 0.2, "经济学": 0.2, "工学": 0.05, "军事学": 0.15}$$, 'batch'),
  ($$hot_002$$, $$时事热点$$, $$single$$, $$近年来引发全球AI浪潮的ChatGPT，是由哪家公司开发的？$$, $$["Google", "Meta", "OpenAI", "Microsoft"]$$, $$[2]$$, $$easy$$, $$ChatGPT是受微软投资的OpenAI公司推出的大型语言模型产品。$$, ARRAY[$$AI$$,$$科技$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.4, "法学": 0.2, "经济学": 0.2, "历史学": 0.15, "军事学": 0.15, "教育学": 0.1}$$, 'batch'),
  ($$hot_003$$, $$时事热点$$, $$multiple$$, $$下列哪些是近年来在碳中和与新能源领域的热门概念或技术？$$, $$["特高压直流输电", "碳交易/碳配额", "固态电池", "蒸汽机复兴"]$$, $$[0, 1, 2]$$, $$medium$$, $$新能源与节能降碳是各国政策核心，摒弃高污染的旧式蒸汽机等技术。$$, ARRAY[$$新能源$$,$$碳中和$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.5, "经济学": 0.3, "日子人": 0.4, "法学": 0.2, "历史学": 0.15, "军事学": 0.15, "教育学": 0.1}$$, 'batch'),
  ($$hot_004$$, $$时事热点$$, $$single$$, $$世界首套获批上市的抗击COVID-19的mRNA疫苗主要由哪些公司开发？$$, $$["辉瑞/BioNTech 和 莫德纳", "强生 和 诺华", "阿斯利康 和 强生", "赛诺菲 和 葛兰素史克"]$$, $$[0]$$, $$medium$$, $$辉瑞和莫德纳(Moderna)是全球最早成功推出mRNA新冠疫苗的厂商。$$, ARRAY[$$医疗热点$$,$$公共卫生$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.4, "法学": 0.2, "经济学": 0.2, "历史学": 0.15, "工学": 0.05, "军事学": 0.15, "教育学": 0.1}$$, 'batch'),
  ($$hot_005$$, $$时事热点$$, $$single$$, $$2023年底，哪款由米哈游开发的二次元游戏在全球获得了TGA最佳移动游戏大奖？$$, $$["《原神》", "《崩坏：星穹铁道》", "《绝区零》", "《幻塔》"]$$, $$[1]$$, $$easy$$, $$《崩坏：星穹铁道》获得了2023年TGA最佳移动端游戏奖。$$, ARRAY[$$游戏热点$$,$$TGA$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3, "法学": 0.2, "经济学": 0.2, "历史学": 0.15, "军事学": 0.15, "教育学": 0.1}$$, 'batch'),
  ($$hot_006$$, $$时事热点$$, $$multiple$$, $$全球目前正面临哪些普遍性的严峻环境与气候问题？$$, $$["全球变暖导致极端天气频发", "海平面上升", "冰川加速融化", "臭氧层空洞完全消失"]$$, $$[0, 1, 2]$$, $$easy$$, $$臭氧层空洞近年来有恢复趋势，但环境危机依然体现在气候变暖及次生灾害。$$, ARRAY[$$环境气候$$,$$国际新闻$$]::text[], $${"理学": 0.8, "工学": 0.6, "农学": 0.5, "经济学": 0.3, "日子人": 0.4, "法学": 0.2, "历史学": 0.15, "军事学": 0.15, "教育学": 0.1}$$, 'batch'),
  ($$hot_007$$, $$时事热点$$, $$single$$, $$近年来，中国在航天领域建成的长期有人照料的国家级太空空间站名叫什么？$$, $$["和平号", "国际空间站", "天宫空间站", "神舟空间站"]$$, $$[2]$$, $$easy$$, $$中国自主建设并投入运营的基础空间设施命名为“天宫”。$$, ARRAY[$$中国航天$$,$$科技成就$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "日子人": 0.4, "法学": 0.2, "经济学": 0.2, "历史学": 0.15, "教育学": 0.1}$$, 'batch'),
  ($$hot_008$$, $$时事热点$$, $$single$$, $$在商业航天领域，首次实现运载火箭第一级垂直回收并重复使用的公司是？$$, $$["蓝色起源", "太空探索技术公司", "波音", "洛克希德·马丁"]$$, $$[1]$$, $$easy$$, $$埃隆·马斯克创立的SpaceX利用猎鹰9号火箭开创了商业火箭可回收的新纪元。$$, ARRAY[$$商业航天$$,$$SpaceX$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 1.0, "经济学": 0.6, "日子人": 0.4, "法学": 0.2, "历史学": 0.15, "教育学": 0.1}$$, 'batch'),
