  ($$hst_033$$, $$科技史$$, $$multiple$$, $$航天史上的重要里程碑$$, $$["加加林上天", "阿波罗登月", "空间站建立", "深海潜水器"]$$, $$[0, 1, 2]$$, $$easy$$, $$深海不属于航天$$, ARRAY[$$综合$$]::text[], $${"历史学": 0.7, "理学": 0.9, "工学": 0.9}$$, 'batch'),
  ($$hst_034$$, $$科技史$$, $$multiple$$, $$古希腊科学代表人物$$, $$["阿基米德", "亚里士多德", "毕达哥拉斯", "伽利略"]$$, $$[0, 1, 2]$$, $$medium$$, $$伽利略是文艺复兴后$$, ARRAY[$$综合$$]::text[], $${"历史学": 0.7, "理学": 0.9, "工学": 0.9}$$, 'batch'),
