  ($$ind_001$$, $$工业界常识$$, $$single$$, $$在机械工程中，用来降低转速并增加扭矩的装置通常是？$$, $$["离合器", "减速机", "联轴器", "变压器"]$$, $$[1]$$, $$easy$$, $$减速机通过齿轮传动比降低电机输出转速，同时成比例增加输出扭矩。$$, ARRAY[$$机械传动$$,$$减速机$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_002$$, $$工业界常识$$, $$multiple$$, $$下列哪些属于常见的机械传动方式？$$, $$["齿轮传动", "皮带传动", "链条传动", "红外传动"]$$, $$[0, 1, 2]$$, $$easy$$, $$齿轮、皮带和链条是典型的机械接触式或柔性传动。$$, ARRAY[$$机械原理$$,$$传动方式$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_003$$, $$工业界常识$$, $$single$$, $$在机械制图和加工中，用来表示零件尺寸允许变动范围的术语是？$$, $$["变形", "公差", "偏差", "应力"]$$, $$[1]$$, $$easy$$, $$公差是指实际尺寸允许的变动量，用于保证零件的互换性。$$, ARRAY[$$机械加工$$,$$公差$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_004$$, $$工业界常识$$, $$single$$, $$当零件承受交变应力时，即使应力低于材料的屈服极限，经过长时间循环后也会发生断裂，这种现象称为？$$, $$["金属蠕变", "材料疲劳", "冷作硬化", "弹性形变"]$$, $$[1]$$, $$medium$$, $$疲劳是金属在交变应力作用下发生的一种破坏。$$, ARRAY[$$材料力学$$,$$疲劳$$]::text[], $${"理学": 1.0, "工学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$ind_005$$, $$工业界常识$$, $$multiple$$, $$常见的轴承(Bearing)主要分为哪两大类？$$, $$["滚动轴承", "滑动轴承", "气浮轴承", "液体轴承"]$$, $$[0, 1]$$, $$easy$$, $$工业中最基本和常见的两大类是引入滚动体的滚动轴承和直接接触摩擦的滑动轴承。$$, ARRAY[$$机械部件$$,$$轴承$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_006$$, $$工业界常识$$, $$single$$, $$帕斯卡定律是哪种工业传动系统的理论基础？$$, $$["液压传动", "气压传动", "带传动", "齿轮传动"]$$, $$[0]$$, $$medium$$, $$密闭液体传递压强的帕斯卡原理是液压千斤顶和液压缸的基础。$$, ARRAY[$$液压$$,$$流体力学$$]::text[], $${"理学": 1.0, "工学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$ind_007$$, $$工业界常识$$, $$single$$, $$机加工中常说的CNC是指？$$, $$["控制网络通讯", "计算机数控", "中央节点控制器", "碳纳米涂层"]$$, $$[1]$$, $$easy$$, $$CNC机床是通过计算机程序控制刀具和工件运动来进行精密加工的设备。$$, ARRAY[$$机械加工$$,$$CNC$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_008$$, $$工业界常识$$, $$single$$, $$金属加工中，将金属加热到塑性状态后通过敲击或施加压力使其成型的工艺是？$$, $$["铸造", "切削", "锻造", "焊接"]$$, $$[2]$$, $$easy$$, $$锻造利用塑性变形改善晶粒结构，提高机械性能。$$, ARRAY[$$金属工艺$$,$$锻造$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_009$$, $$工业界常识$$, $$multiple$$, $$机械加工后的表面往往不是绝对光滑的。用来衡量表面微观不平度的指标通常用哪些参数表示？$$, $$["Ra", "Rz", "Vb", "T"]$$, $$[0, 1]$$, $$medium$$, $$Ra和Rz是衡量表面粗糙度的主要技术参数。$$, ARRAY[$$机械测量$$,$$表面粗糙度$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_010$$, $$工业界常识$$, $$single$$, $$工业设备维护中经常提到的 MTBF 是指？$$, $$["最大理论断裂力", "平均故障间隔时间", "最高温度容限", "最小弯曲半径"]$$, $$[1]$$, $$medium$$, $$MTBF是衡量产品/设备可靠性的关键指标。$$, ARRAY[$$工业维护$$,$$可靠性$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "理学": 0.25}$$, 'batch'),
  ($$ind_011$$, $$工业界常识$$, $$single$$, $$在自动控制系统中，PID控制器是应用最广泛的控制器。其中字母“I”代表什么作用？$$, $$["比例", "积分", "微分", "感应"]$$, $$[1]$$, $$medium$$, $$PID中的I代表积分环节，主要作用是消除系统的稳态误差。$$, ARRAY[$$自动控制$$,$$PID$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_012$$, $$工业界常识$$, $$multiple$$, $$工业自动化中，典型的闭环控制系统（Closed-loop control）必须包含哪些环节？$$, $$["反馈测量环节", "控制器", "执行机构", "随机干扰发生器"]$$, $$[0, 1, 2]$$, $$easy$$, $$传感器、控制器和执行机构构成了测量、决策、执行的闭环基本框架。$$, ARRAY[$$控制理论$$,$$闭环控制$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "工学": 0.5, "理学": 0.25, "管理学": 0.2}$$, 'batch'),
  ($$ind_013$$, $$工业界常识$$, $$single$$, $$PLC是现代工业自动化的核心设备之一，它的全称是？$$, $$["可编程逻辑控制器", "精确激光切割机", "相位锁定循环", "个人局域通信器"]$$, $$[0]$$, $$easy$$, $$PLC专用于工业环境的数字逻辑运算，控制开关量、模拟量等。$$, ARRAY[$$工业自动化$$,$$PLC$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "理学": 0.25}$$, 'batch'),
  ($$ind_014$$, $$工业界常识$$, $$single$$, $$在运动控制中，能将电脉冲信号转换成角位移或线位移，常用于开环控制精确定位的电机是？$$, $$["异步交流电机", "直流串励电机", "步进电机", "鼠笼式电机"]$$, $$[2]$$, $$medium$$, $$步进电机每接收一个脉冲就转动一个固定角度，适合廉价/开环精确控制。$$, ARRAY[$$电机$$,$$伺服控制$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_015$$, $$工业界常识$$, $$single$$, $$为了检测设备的旋转角度或速度，工业上常在电机轴上安装什么传感器？$$, $$["热电偶", "光电编码器", "应变片", "霍尔电流传感器"]$$, $$[1]$$, $$medium$$, $$编码器能将机械位移量转换成电信号，用于伺服电机的速度/位置反馈。$$, ARRAY[$$传感器$$,$$编码器$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_016$$, $$工业界常识$$, $$multiple$$, $$工业SCADA（数据采集与监视控制）系统通常在哪些场景中广泛应用？$$, $$["电力电网监控", "自来水管网及污水处理", "石油天然气管道", "单台家用洗衣机控制"]$$, $$[0, 1, 2]$$, $$easy$$, $$SCADA属于宏观大规模、分布式系统的数据采集与监控，不用于单一家用电器。$$, ARRAY[$$SCADA$$,$$工业软件$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.4, "管理学": 0.2}$$, 'batch'),
  ($$ind_017$$, $$工业界常识$$, $$single$$, $$在控制工程理论中，传递函数 (Transfer Function) 通常是在哪个数学变换域中定义的？$$, $$["时域", "频域", "复频域", "空域"]$$, $$[2]$$, $$hard$$, $$线性定常系统的传递函数定义为系统零初始条件下，输出拉氏变换与输入拉氏变换之比。$$, ARRAY[$$控制理论$$,$$传递函数$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "工学": 0.5, "理学": 0.25, "管理学": 0.2}$$, 'batch'),
  ($$ind_018$$, $$工业界常识$$, $$single$$, $$自动化工厂中提到的AGV是指什么？$$, $$["自动导引运输车", "增材制造玻璃", "先进气动阀门", "航空地球物理学"]$$, $$[0]$$, $$easy$$, $$AGV小车广泛应用于仓储物流和总装车间进行物料无人搬运。$$, ARRAY[$$机器人$$,$$物流自动化$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_019$$, $$工业界常识$$, $$multiple$$, $$工业4.0 (Industry 4.0) 概念的核心特征通常包括？$$, $$["物联网基础", "信息物理系统", "大数据与云计算", "完全倒退回蒸汽时代"]$$, $$[0, 1, 2]$$, $$easy$$, $$工业4.0被称为第四次工业革命，主张网络化、智能化、数据化的制造模式。$$, ARRAY[$$工业4.0$$,$$智能制造$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "理学": 0.25}$$, 'batch'),
  ($$ind_020$$, $$工业界常识$$, $$single$$, $$PWM是指在保持波形周期不变的情况下，通过改变脉冲宽度来控制输出电压/电流平均值的一种技术，其全称是？$$, $$["相位波调变", "脉冲宽度调制", "功率瓦数乘法器", "峰值波长混合"]$$, $$[1]$$, $$medium$$, $$PWM广泛应用于电机调速控制、电源逆变转换等电力电子领域。$$, ARRAY[$$电力电子$$,$$PWM$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_021$$, $$工业界常识$$, $$single$$, $$在齿轮传动中，为了防止因制造误差和热膨胀引起干涉卡死，齿轮啮合时非工作齿面间必须留有一定的间隙。这个间隙被称为？$$, $$["顶隙", "中心距", "齿侧间隙", "模数"]$$, $$[2]$$, $$hard$$, $$齿隙在正反转时会产生“死区”空程，是精密进给系统需要尽量克服的问题。$$, ARRAY[$$机械传动$$,$$齿侧间隙$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_022$$, $$工业界常识$$, $$multiple$$, $$对于工业机器人 (Industrial Robot)，按机构拓扑和运动坐标系，常见的分类有哪些？$$, $$["多关节型机器人", "SCARA机器人", "Delta并联机器人", "笛卡尔坐标机器人"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$这四种是工业生产中最主流的工业机器人硬件架构分类。$$, ARRAY[$$工业机器人$$,$$机器人分类$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "理学": 0.25}$$, 'batch'),
  ($$ind_023$$, $$工业界常识$$, $$single$$, $$液压泵中，利用一对相互啮合的齿轮的齿间容积的变化来输送液体的液压泵称为？$$, $$["柱塞泵", "叶片泵", "齿轮泵", "离心泵"]$$, $$[2]$$, $$medium$$, $$齿轮泵结构简单，属于容积式泵，是液压系统最基础的动力元件之一。$$, ARRAY[$$液压$$,$$齿轮泵$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_024$$, $$工业界常识$$, $$single$$, $$伺服控制系统中通常存在所谓的三环控制：位置环、速度环以及？$$, $$["电流/转矩环", "电压环", "频率环", "温度环"]$$, $$[0]$$, $$hard$$, $$伺服系统的三环闭环分别对应电流(内环)、速度(中环)、位置(外环)。$$, ARRAY[$$伺服$$,$$运动控制$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "工学": 0.5, "理学": 0.25, "管理学": 0.2}$$, 'batch'),
  ($$ind_025$$, $$工业界常识$$, $$single$$, $$在大规模流程工业（如石油化工厂、炼钢厂）中，用于控制成百上千个回路的集散控制系统简称为？$$, $$["DCS", "MES", "ERP", "CAD"]$$, $$[0]$$, $$medium$$, $$DCS是过程自动化(Process Automation)的主力武器，强调集中管理、分散控制。$$, ARRAY[$$流程工业$$,$$DCS$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "理学": 0.25}$$, 'batch'),
  ($$ind_026$$, $$工业界常识$$, $$single$$, $$用于测量微小形变，常粘贴于金属或弹性体表面，通过电阻变化来感应受力的传感器元件是？$$, $$["热敏电阻", "应变片", "压电陶瓷", "热电偶"]$$, $$[1]$$, $$medium$$, $$应变片是构成电子秤、测力传感器、扭矩传感器的核心基础元件。$$, ARRAY[$$传感器$$,$$应力测试$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_027$$, $$工业界常识$$, $$multiple$$, $$关于内燃机 (ICE) 的基本工作循环（以四冲程为例），包含下列哪些冲程？$$, $$["进气", "压缩", "做功/燃烧", "排气"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$标准的奥托循环/狄塞尔循环四冲程。也被戏称为吸气、挤压、爆炸、吐气 (Suck, Squeeze, Bang, Blow)。$$, ARRAY[$$发动机$$,$$热力学$$]::text[], $${"工学": 1.0, "理学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$ind_028$$, $$工业界常识$$, $$single$$, $$“数控机床中用来使工作台在各个方向上移动并克服很高摩擦载荷的一种具有高精度的螺纹传动元件是？”$$, $$["梯形丝杠", "滚珠丝杠", "皮带", "机架"]$$, $$[1]$$, $$medium$$, $$滚珠丝杠通过滚珠在螺纹滚道中滚动，把滑动摩擦变为滚动摩擦，传动效率及精度极高。$$, ARRAY[$$机械组件$$,$$数控机床$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_029$$, $$工业界常识$$, $$single$$, $$下列属于“增材制造 (Additive Manufacturing)”技术的是？$$, $$["车削加工", "铣削加工", "3D打印", "电火花线切割"]$$, $$[2]$$, $$easy$$, $$增材制造即3D打印，通过材料逐层累加成型；车铣属于传统的减材制造。$$, ARRAY[$$先进制造$$,$$3D打印$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "理学": 0.25}$$, 'batch'),
  ($$ind_030$$, $$工业界常识$$, $$multiple$$, $$工业控制网络（现场总线/工业以太网）中，由于对时间确定性要求极高，常使用哪些专门设计的工业通讯协议？$$, $$["EtherCAT", "PROFINET", "Modbus", "HTTP网页协议"]$$, $$[0, 1, 2]$$, $$medium$$, $$工业现场要求硬实时微秒级响应，HTTP是通用互联网协议不具备确定性实时性。$$, ARRAY[$$工业网络$$,$$协议$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "日子人": 1.0, "文学": 0.2, "理学": 0.25}$$, 'batch'),
  ($$ind_031$$, $$工业界常识$$, $$single$$, $$材料力学中，描述材料在弹性变形阶段，应力与应变之间成正比关系的定律是？$$, $$["胡克定律", "牛顿冷却定律", "法拉第电磁感应定律", "麦克斯韦方程组"]$$, $$[0]$$, $$easy$$, $$弹性极限内，应力σ = 弹性模量E × 应变ε。$$, ARRAY[$$材料力学$$,$$胡克定律$$]::text[], $${"理学": 1.0, "工学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$ind_032$$, $$工业界常识$$, $$single$$, $$大型机械中普遍使用“联轴器 (Coupling)”，其主要作用是？$$, $$["降低转速并增大扭矩", "将两根轴连接起来以传递扭矩/旋转运动", "切断或接合动力", "限制机械温度"]$$, $$[1]$$, $$easy$$, $$联轴器用于轴与轴的连接；能在运行中随时分离的是离合器。$$, ARRAY[$$机械传动$$,$$联轴器$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_033$$, $$工业界常识$$, $$single$$, $$PID调节中，哪一种环节能对误差的变化趋势做出提前反应，有“预测”的效果从而改善系统动态特性？$$, $$["比例", "积分", "微分", "前馈"]$$, $$[2]$$, $$medium$$, $$微分环节(Derivative)响应误差的变化率，起到阻尼预判的作用。$$, ARRAY[$$自动控制$$,$$PID$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_034$$, $$工业界常识$$, $$multiple$$, $$气动系统中常见的基础气动三大件（气动辅助元件）通常指？$$, $$["分水滤气器", "减压阀", "油雾器", "气动马达"]$$, $$[0, 1, 2]$$, $$medium$$, $$即常说的F.R.L三联件，用于净化压缩空气、调节压力并润滑气动元件。$$, ARRAY[$$气动$$,$$FRL$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_035$$, $$工业界常识$$, $$single$$, $$用来防止流体介质倒流（逆流）的阀门被称为？$$, $$["止回阀", "安全阀", "减压阀", "节流阀"]$$, $$[0]$$, $$easy$$, $$止回阀依靠介质自身的流动来自动开闭瓣膜，阻止介质向反方向倒流。$$, ARRAY[$$流体控制$$,$$阀门$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_036$$, $$工业界常识$$, $$single$$, $$飞机在平飞巡航时，要保持平衡需要四个力的互相抵消；升力对抗重力，而推动飞机向前的推力（Thrust）必须对抗什么是？$$, $$["空气阻力", "向心力", "科里奥利力", "核动力"]$$, $$[0]$$, $$easy$$, $$飞机的基本受力是推力平衡阻力，升力平衡重力。$$, ARRAY[$$航空$$,$$飞行原理$$]::text[], $${"工学": 1.0, "理学": 0.6, "日子人": 0.3, "管理学": 0.2}$$, 'batch'),
  ($$ind_037$$, $$工业界常识$$, $$multiple$$, $$固定翼飞机的三大主操纵面（用来控制滚转、俯仰、偏航）包括？$$, $$["副翼", "升降舵", "方向舵", "起落架轮胎"]$$, $$[0, 1, 2]$$, $$medium$$, $$这三个气动舵面分布在机翼、水平尾翼和垂直尾翼上，控制飞机姿态。$$, ARRAY[$$航空工程$$,$$飞行控制$$]::text[], $${"工学": 1.0, "理学": 0.6, "日子人": 0.3, "管理学": 0.2}$$, 'batch'),
  ($$ind_038$$, $$工业界常识$$, $$single$$, $$描述飞行器飞行速度相对于当地音速比值的无量纲参数是？$$, $$["雷诺数", "马赫数", "牛顿数", "法拉第常数"]$$, $$[1]$$, $$easy$$, $$马赫数大于1即突破音速，发生超音速飞行。$$, ARRAY[$$空气动力学$$,$$马赫数$$]::text[], $${"理学": 1.0, "工学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$ind_039$$, $$工业界常识$$, $$single$$, $$现代大型民航客机（如波音737、空客A320）最常使用哪种喷气式发动机，因其高亚音速下燃油经济性良好？$$, $$["涡轮喷气发动机", "涡轮风扇发动机", "冲压发动机", "活塞发动机"]$$, $$[1]$$, $$medium$$, $$涡扇发动机具有较高的涵道比(Bypass ratio)，油耗和噪音均比纯涡喷低很多。$$, ARRAY[$$航空发动机$$,$$涡扇$$]::text[], $${"工学": 1.0, "理学": 0.6, "日子人": 0.3, "管理学": 0.2}$$, 'batch'),
  ($$ind_040$$, $$工业界常识$$, $$single$$, $$关于液体火箭发动机方程“齐奥尔科夫斯基火箭方程”，其揭示了火箭可以达到的理想速度主要取决于（喷气速度）和什么参数的比值？$$, $$["火箭的长宽比", "火箭初始总质量与推进剂耗尽后质量", "发射场的纬度", "天气温度"]$$, $$[1]$$, $$hard$$, $$火箭方程揭示了核心在于燃料占比质量比。$$, ARRAY[$$航天$$,$$火箭方程$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 0.2}$$, 'batch'),
  ($$ind_041$$, $$工业界常识$$, $$multiple$$, $$下列关于人造卫星轨道的描述，正确的有哪些？$$, $$["LEO指低地球轨道", "GEO指地球静止轨道，卫星运行周期与地球自转一致", "所有商业通信卫星都在距离地面不到500公里的轨道", "航天器发射到太空是不需要达到特定速度的"]$$, $$[0, 1]$$, $$medium$$, $$GEO（地球同步静止轨道）在赤道上空大约36000公里处。$$, ARRAY[$$航天轨道$$,$$卫星$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 0.2}$$, 'batch'),
  ($$ind_042$$, $$工业界常识$$, $$single$$, $$使航天器克服地球引力，能够环绕地球不掉下来的最小发射速度（又称环绕速度）被称为？$$, $$["第一宇宙速度", "第二宇宙速度", "第三宇宙速度", "光速"]$$, $$[0]$$, $$easy$$, $$第一宇宙速度是在地球表面附近环绕地球做匀速圆周运动所需的速度。$$, ARRAY[$$天体物理$$,$$宇宙速度$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_043$$, $$工业界常识$$, $$single$$, $$常被航空航天界定义为“地球大气层与外层空间（太空）的边界线”（高度约100公里/62英里处）被称为？$$, $$["普朗克极限", "卡门线", "拉格朗日边界", "钱学森弹道底端"]$$, $$[1]$$, $$medium$$, $$卡门线在这个高度由于空气过于稀薄，必须达到轨道速度才能维持飞行。$$, ARRAY[$$航天$$,$$卡门线$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 0.2}$$, 'batch'),
  ($$ind_044$$, $$工业界常识$$, $$single$$, $$用于记录飞机飞行参数、语音等数据的“黑匣子 (Black Box)”，在现实中为了便于空难搜救寻找，通常被涂装成什么颜色？$$, $$["黑色", "白色", "亮橙色 / 红色", "迷彩色"]$$, $$[2]$$, $$easy$$, $$虽然叫黑匣子，但外表是极其醒目的橙红/亮橙色并贴有反光条。$$, ARRAY[$$航空$$,$$黑匣子$$]::text[], $${"工学": 1.0, "理学": 0.6, "日子人": 0.3, "管理学": 0.2}$$, 'batch'),
  ($$ind_045$$, $$工业界常识$$, $$single$$, $$直升机尾部通常安装有一个小型的尾桨 (Tail rotor)，这个尾桨的主要物理作用是？$$, $$["为了让直升机飞得更快", "抵消主旋翼转动给机身带来的反扭矩", "控制直升机的升降", "产生雷达波干扰"]$$, $$[1]$$, $$medium$$, $$如果没有尾桨抵消反扭矩，机身会和主旋翼向相反方向不停打转。$$, ARRAY[$$直升机$$,$$飞行原理$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_046$$, $$工业界常识$$, $$multiple$$, $$拉格朗日点被广泛用于放置深空探测望远镜。下列哪些点位于地球公转轨道所在的直线上？$$, $$["L1", "L2", "L3", "L8"]$$, $$[0, 1, 2]$$, $$hard$$, $$例如JWST部署在地日系L2点（背光面），SOHO观测卫星在L1点。L1, L2, L3均通过两星体中心连线。$$, ARRAY[$$航天$$,$$拉格朗日点$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 0.2}$$, 'batch'),
  ($$ind_047$$, $$工业界常识$$, $$single$$, $$大疆等消费级四旋翼/多旋翼无人机，不使用传统的倾斜盘与舵面，主要是通过调节什么参数来控制无人机的飞行姿态？$$, $$["通过挥动鸭翼", "通过动态改变各个电机的转速产生推力差", "靠发射气体推进", "改变电池电流方向反转所有的电机"]$$, $$[1]$$, $$medium$$, $$多旋翼仅依靠高速电调精确调整每个螺旋桨转速来改变姿态。$$, ARRAY[$$无人机$$,$$飞行控制$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_048$$, $$工业界常识$$, $$single$$, $$民航干线客机通常在此段大气层飞行（其特点是不易形成对流云雨），能够保证飞行平稳并节省燃料？$$, $$["对流层", "平流层底部", "中间层", "电离层"]$$, $$[1]$$, $$medium$$, $$万米左右刚好跨入平流层下部，气象条件极其平稳。$$, ARRAY[$$航空$$,$$大气层$$]::text[], $${"工学": 1.0, "理学": 0.6, "日子人": 0.3, "管理学": 0.2}$$, 'batch'),
  ($$ind_049$$, $$工业界常识$$, $$single$$, $$近年来由SpaceX主导建设的“星链 (Starlink)”属于哪一种类型的卫星星座？$$, $$["地球静止高轨通信卫星", "中地球轨道导航系统", "低轨宽带通信互联卫星星座", "深空无线电阵列"]$$, $$[2]$$, $$easy$$, $$星链部署在500公里左右的近地轨道以降低延迟和提升带宽。$$, ARRAY[$$航天$$,$$星链$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 0.2}$$, 'batch'),
  ($$ind_050$$, $$工业界常识$$, $$single$$, $$太空站里的宇航员之所以看起来呈现“失重”状态漂浮，真正原因是？$$, $$["太空中没有地球引力了", "太空内部抽真空了", "太空站和宇航员都在绕地球作自由落体运动，引力充当了向心力", "太空中质量消失了"]$$, $$[2]$$, $$medium$$, $$这不是由于零引力，而是因为轨道微重力环境（不断落向中心又因为水平速度足够快而错过）。$$, ARRAY[$$航天$$,$$失重$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 0.2}$$, 'batch'),
  ($$ind_051$$, $$工业界常识$$, $$single$$, $$潜艇能够实现上浮和下沉，其基本的物理原理是调节什么物理量从而改变潜艇自身受到的重力浮力平衡？$$, $$["潜艇的整体长度", "潜艇压水舱内的水和空气比例", "螺旋桨旋转的速度", "潜艇外部海水的含盐量"]$$, $$[1]$$, $$easy$$, $$通过水泵向压水舱注水增加自重下沉，充高压空气排水上浮。$$, ARRAY[$$船舶$$,$$浮力$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_052$$, $$工业界常识$$, $$multiple$$, $$航空母舰舰载机的起降技术主要分为哪几类？$$, $$["滑跃起飞", "蒸汽/电磁弹射起飞", "垂直/短距起降", "直接从水下发射"]$$, $$[0, 1, 2]$$, $$easy$$, $$弹射、滑跃、垂直起降是航母舰载机主流起落方式。$$, ARRAY[$$军工$$,$$航母$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_053$$, $$工业界常识$$, $$single$$, $$现代多数商船的船体侧面有一组涂装的水平线，表明在不同季节/水域允许吃水的最大界限，这条标记线被称为？$$, $$["日界线", "卡门线", "载重线或普利姆索尔线", "吃水平等线"]$$, $$[2]$$, $$medium$$, $$Plimsoll为防止超载引发海难而推动的强制标准线标识。$$, ARRAY[$$航海工程$$,$$载重线$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_054$$, $$工业界常识$$, $$single$$, $$在水下航行时，现代潜艇无法使用无线电雷达探测距离，最依赖的探测设备是什么？$$, $$["GPS", "光学潜望镜", "声呐系统", "激光雷达"]$$, $$[2]$$, $$easy$$, $$无线电水下衰减极快，声波能远距离传播因此使用声呐。$$, ARRAY[$$海洋工程$$,$$声波探测$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_055$$, $$工业界常识$$, $$single$$, $$水利工程中，为了让船舶跨越巨大的大坝水位落差，通常依靠连通器原理采用哪种建筑物过渡？$$, $$["吊篮提升机", "离心水泵抽吸", "船闸", "滑道冲行"]$$, $$[2]$$, $$easy$$, $$船闸通过连通器原理，将水位升高或降低让船只过渡。$$, ARRAY[$$水利工程$$,$$船闸$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_056$$, $$工业界常识$$, $$single$$, $$现代常规动力潜艇中使用的 AIP 系统，它的主要功能是？$$, $$["提供核动力", "不依赖空气推进 ，增加水下潜航时间不需浮出换气", "全自动驾驶", "吸收雷达波隐身防护"]$$, $$[1]$$, $$medium$$, $$AIP增强了常规潜艇的隐蔽能力，典型的有斯特林发动机或燃料电池。$$, ARRAY[$$造船$$,$$AIP$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.3, "管理学": 0.2}$$, 'batch'),
  ($$ind_057$$, $$工业界常识$$, $$multiple$$, $$关于全球卫星导航系统 (GNSS)，目前国际上得到联合国认可的四大核心系统包括？$$, $$["美国 GPS", "俄罗斯 GLONASS", "中国 北斗", "欧洲 伽利略"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$这四大卫星导航系统组成了当今人类GNSS的绝对主力基础设施。$$, ARRAY[$$航天$$,$$导航$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 0.2}$$, 'batch'),
  ($$ind_058$$, $$工业界常识$$, $$single$$, $$船舶工程中，为减少船只航行时由于水浪造成的侧面横滚幅度，底部通常会装有什么结构？$$, $$["龙骨 / 减摇鳍", "大号雨刷", "喷水推进器", "浮动气囊"]$$, $$[0]$$, $$medium$$, $$减摇鳍及稳定舭龙骨是抵御波浪侧倾的常用部件。$$, ARRAY[$$造船工程$$,$$减摇鳍$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_059$$, $$工业界常识$$, $$single$$, $$在空气动力学中，通过上方流速快压强小、下方流速慢压强大来定性解释机翼升力（虽然不完全准确），这常归类于哪个著名的原理？$$, $$["阿基米德原理", "伯努利原理", "欧拉方程", "麦克斯韦方程"]$$, $$[1]$$, $$easy$$, $$伯努利定理表达了无粘性流体的流速和压强关系。$$, ARRAY[$$空气动力学$$,$$伯努利原理$$]::text[], $${"理学": 1.0, "工学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$ind_060$$, $$工业界常识$$, $$multiple$$, $$外太空环境极端恶劣，航天器的设计必须考虑应对下列哪些挑战？$$, $$["强烈的电离辐射", "太阳直射面与背光面的极大热温差", "近似真空环境引起的材料出气释气放电", "微陨石和太空碎片撞击"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$太空环境极其恶劣，需要热控、防辐射等多重设计保障。$$, ARRAY[$$航天工程$$,$$空间环境$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 0.2}$$, 'batch'),
  ($$ind_061$$, $$工业界常识$$, $$single$$, $$1903年，标志着世界上第一次受控的、带动力重于空气的飞行器持续飞行是由谁完成的？$$, $$["莱特兄弟", "波音", "西奥多·冯·卡门", "桑托斯·杜蒙"]$$, $$[0]$$, $$easy$$, $$莱特兄弟发明的“飞行者一号”是世界上公认的第一架实用飞机。$$, ARRAY[$$航空史$$,$$莱特兄弟$$]::text[], $${"工学": 1.0, "理学": 0.6, "日子人": 0.3, "管理学": 0.2}$$, 'batch'),
  ($$ind_062$$, $$工业界常识$$, $$single$$, $$在大型液体火箭中，综合比冲极高，但非常难以储存（需极低温维持液态）的推进剂绝佳组合是？$$, $$["汽油和柴油", "液氧/液氢", "常温水", "酒精"]$$, $$[1]$$, $$medium$$, $$氢氧发动机有极高比冲，是长五芯级、航天飞机主引擎等的燃料首选。$$, ARRAY[$$火箭$$,$$推进剂$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 0.2}$$, 'batch'),
  ($$ind_063$$, $$工业界常识$$, $$multiple$$, $$下列哪些装备成就，标志着中国在深海深地探测和载人航天器领域的里程碑？$$, $$["长征五号大型运载火箭服役", "嫦娥任务成功进行月球背面取样", "天宫空间站全面建成", "“奋斗者”号全海深载人潜水器下潜马里亚纳海沟"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$这些均代表着我国在此领域的前沿自主技术成就。$$, ARRAY[$$中国科技$$,$$大国重器$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "理学": 0.25}$$, 'batch'),
  ($$ind_064$$, $$工业界常识$$, $$single$$, $$深潜器要想下潜上万米深度（如马里亚纳海沟底层），工程上必须要攻克的最核心物理环境挑战是？$$, $$["抵御极其巨大的水体强压", "应对超高的几百摄氏度水温", "在海水中遭到鲨鱼啃食", "找不到方向"]$$, $$[0]$$, $$easy$$, $$每下潜10米大约增加1个大气压，一万米深度约等于1000个大气压。$$, ARRAY[$$深潜$$,$$抗压$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_065$$, $$工业界常识$$, $$single$$, $$在半导体制造流程中，被称为精密加工工业皇冠上的明珠的核“印刷机”设备是？$$, $$["注塑机", "光刻机", "大型锻压机", "回旋加速器"]$$, $$[1]$$, $$easy$$, $$光刻机通过极短波长光源将掩膜图形缩微投影在晶圆光刻胶上。$$, ARRAY[$$半导体$$,$$光刻机$$]::text[], $${"工学": 1.0, "理学": 0.8, "管理学": 0.2}$$, 'batch'),
  ($$ind_066$$, $$工业界常识$$, $$single$$, $$成功实现第一级火箭反推垂直着陆回收并彻底商业化的航天公司是？$$, $$["波音", "SpaceX", "洛克希德·马丁", "维珍银河"]$$, $$[1]$$, $$easy$$, $$SpaceX猎鹰9号火箭的垂直着陆回收大幅度降低了发射成本。$$, ARRAY[$$航天$$,$$商业火箭$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 1.0, "经济学": 0.6}$$, 'batch'),
  ($$ind_067$$, $$工业界常识$$, $$multiple$$, $$关于新能源载具动力，除了EV纯蓄电池路线外，很多企业还在投入研发利用化学反应直接将高纯度（轻质燃料）气体转化成电能的装置，这个技术一般涉及？$$, $$["烧煤", "氢燃料电池", "燃料电池催化", "燃烧室点火爆炸驱动风扇"]$$, $$[1, 2]$$, $$medium$$, $$主流以PEMFC氢燃料电池为主，利用氢氧复合产水和电能驱动电动机。$$, ARRAY[$$新能源$$,$$氢能$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_068$$, $$工业界常识$$, $$single$$, $$冶金大高炉炼铁中，加入焦炭的核心化学作用不仅是发热燃烧，更重要的是为反应提供？$$, $$["铁水的甜度", "一氧化碳和碳作为强还原剂，将氧化铁还原成铁", "让铁水透明", "阻止凝固"]$$, $$[1]$$, $$easy$$, $$焦炭在高温下提供碳还原剂把矿石提炼成单质铁。$$, ARRAY[$$冶金$$,$$炼铁$$]::text[], $${"工学": 1.0, "理学": 0.5, "管理学": 0.4}$$, 'batch'),
  ($$ind_069$$, $$工业界常识$$, $$single$$, $$现代动车组（EMU）与普通绿皮机车牵引火车最大的物理区别（动力的分布方式上）在于？$$, $$["车身重", "采用了动力分散式，有多节车厢自身带有驱动电机", "能在水面开", "不用铁路"]$$, $$[1]$$, $$easy$$, $$动车组动力单元分布在多节编组车身底盘的电机上，加减速效率极高且分布均匀。$$, ARRAY[$$交通轨道$$,$$动车组$$]::text[], $${"工学": 1.0, "日子人": 0.8, "军事学": 0.4, "管理学": 0.2, "理学": 0.25}$$, 'batch'),
  ($$ind_070$$, $$工业界常识$$, $$single$$, $$开发并维持全球最大的GPS卫星导航系统运行的国家主导方是？$$, $$["俄罗斯", "英国", "美国", "中国"]$$, $$[2]$$, $$easy$$, $$GPS（Global Positioning System）是美国主导建设的成熟军用及民用导航系统。$$, ARRAY[$$航天$$,$$GPS$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "管理学": 0.2}$$, 'batch'),
  ($$law_001$$, $$法律常识$$, $$single$$, $$在整个国家的法律体系中，具有最高法律效力的大法是？$$, $$["民法典", "刑法", "宪法", "行政诉讼法"]$$, $$[2]$$, $$easy$$, $$宪法是国家的根本大法，具有最高的法律效力，其他法律均不得与宪法相抵触。$$, ARRAY[$$基础法学$$,$$宪法$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_002$$, $$法律常识$$, $$single$$, $$刑法中“法无明文规定不为罪，法无明文规定不处罚”体现了哪一基本原则？$$, $$["罪责刑相适应原则", "罪刑法定原则", "无罪推定原则", "平等适用刑法原则"]$$, $$[1]$$, $$easy$$, $$这是罪刑法定原则的核心表述，限制国家刑罚权，保障公民权利。$$, ARRAY[$$刑法$$,$$基本原则$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_003$$, $$法律常识$$, $$single$$, $$被称为“社会生活百科全书”，旨在全面规范民事主体人身关系和财产关系的是？$$, $$["劳动法", "治安管理处罚法", "民事诉讼法", "中华人民共和国民法典"]$$, $$[3]$$, $$easy$$, $$《民法典》涵盖了物权、合同、人格权、婚姻家庭、继承、侵权责任等方面，被称为社会生活的百科全书。$$, ARRAY[$$民法$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_004$$, $$法律常识$$, $$single$$, $$在现代法治国家中，一个人在被法庭最终判决有罪之前，应当被视为无罪。这一原则被称为？$$, $$["司法独立", "无罪推定", "罪疑从无", "正当防卫"]$$, $$[1]$$, $$easy$$, $$无罪推定指的是任何人在未经过合法且公开的审判定罪之前，在法律上被推定为无罪。$$, ARRAY[$$司法原则$$]::text[], $${"法学": 1.0, "管理学": 0.3}$$, 'batch'),
  ($$law_005$$, $$法律常识$$, $$single$$, $$我国法定继承的第一顺序继承人不包括？$$, $$["配偶", "子女", "兄弟姐妹", "父母"]$$, $$[2]$$, $$medium$$, $$依照我国继承法规定，配偶、子女、父母是第一顺序继承人；兄弟姐妹属于第二顺序继承人。$$, ARRAY[$$民法$$,$$继承$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_006$$, $$法律常识$$, $$single$$, $$关于“正当防卫”，下列说法正确的是？$$, $$["对无论什么侵害都可以采取致命防卫", "防卫行为应当是对正在进行的不法侵害进行", "防卫时可以顺带对侵害人家属进行攻击", "哪怕对方已经停止侵害并逃跑，也可以追上去继续防卫"]$$, $$[1]$$, $$medium$$, $$正当防卫必须是对正在进行的不法侵害采取，防卫不能明显超过必要限度，且不能针对无关人员或已停止的侵害。$$, ARRAY[$$刑法$$,$$正当防卫$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_007$$, $$法律常识$$, $$single$$, $$我国法律规定，完全民事行为能力人的年龄分界线通常是？$$, $$["14周岁", "16周岁", "18周岁", "20周岁"]$$, $$[2]$$, $$easy$$, $$18周岁以上的自然人为成年人，是完全民事行为能力人。部分16周岁以上以自己劳动收入为主要来源的可视为完全民事行为能力人。$$, ARRAY[$$民法$$,$$民事行为能力$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_008$$, $$法律常识$$, $$single$$, $$公民发现所在企业存在严重的违法排污行为且危害公众利益，向环保部门进行举报，这种行为体现了法律上的？$$, $$["起诉权", "言论自由", "申诉权", "检举、控告权"]$$, $$[3]$$, $$medium$$, $$向国家机关反映他人违法事实的行为属于宪法所赋予的检举、控告全。$$, ARRAY[$$宪法$$,$$公民权利$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_009$$, $$法律常识$$, $$single$$, $$一般情况下，普通的民事诉讼时效期限为（自权利人知道或应当知道权利受到损害之日起计）？$$, $$["一年", "两年", "三年", "五年"]$$, $$[2]$$, $$hard$$, $$《民法典》第一百八十八条规定，向人民法院请求保护民事权利的诉讼时效期间为三年，法律另有规定的除外。$$, ARRAY[$$诉讼法$$,$$诉讼时效$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_010$$, $$法律常识$$, $$single$$, $$知识产权中的“著作权”（版权），对于自然人的作品，其财产权的保护期通常为？$$, $$["作者有生之年加死后10年", "作者有生之年加死后50年", "无期限，永远拥有", "作品发表后的20年"]$$, $$[1]$$, $$medium$$, $$多数国家及我国著作权法规定，自然人作品的财产权保护期截止于作者死亡后第50年的12月31日。$$, ARRAY[$$知识产权$$,$$著作权$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_011$$, $$法律常识$$, $$single$$, $$“法人”在法律上是指？$$, $$["企业的法定代表人", "负责制定法律的人员", "具有民事权利能力和民事行为能力，依法独立享有民事权利和承担民事义务的组织", "法国国籍的人"]$$, $$[2]$$, $$easy$$, $$法人不是自然人，而是一种拟制的法律主体，指依法成立的公司、机构等组织。$$, ARRAY[$$民法$$,$$法人$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_012$$, $$法律常识$$, $$single$$, $$公司雇佣员工应当签订书面劳动合同，若用人单位自用工之日起超过一个月不满一年未与劳动者订立书面劳动合同，依法应当向劳动者每月支付多少工资？$$, $$["正常工资", "基本生活费", "两倍的工资", "三倍的工资"]$$, $$[2]$$, $$hard$$, $$《劳动合同法》第82条规定，用人单位逾期未签订书面劳动合同的，应当向劳动者每月支付二倍的工资。$$, ARRAY[$$劳动法$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_013$$, $$法律常识$$, $$single$$, $$依照刑法规定，被判处“缓刑”的意思是？$$, $$["推迟判决的时间", "延期缴纳罚金", "暂缓执行其原本被判处的刑罚，如果在考验期内没有犯新罪或严重违规，原判刑罚就不再执行", "在监狱里通过缓和劳动服刑"]$$, $$[2]$$, $$medium$$, $$缓刑是对被判处拘役或者三年以下有期徒刑的犯罪分子，在一定考验期内暂缓执行原判刑罚的制度。$$, ARRAY[$$刑法$$,$$缓刑$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_014$$, $$法律常识$$, $$single$$, $$在遇到具体行政行为（如被工商局或交警行政处罚）不服时，公民在提起行政诉讼前，通常可以先向上级行政机关申请？$$, $$["行政仲裁", "行政复议", "立案侦查", "刑事申诉"]$$, $$[1]$$, $$medium$$, $$对行政机关的具体行政行为不服，可以依法申请行政机关内部的审查，即行政复议。$$, ARRAY[$$行政法$$,$$复议$$]::text[], $${"法学": 1.0, "管理学": 0.3}$$, 'batch'),
  ($$law_015$$, $$法律常识$$, $$single$$, $$知识产权中的发明专利权，在我国的法定保护期限通常为多少年？（自申请日起算）$$, $$["10年", "15年", "20年", "50年"]$$, $$[2]$$, $$hard$$, $$我国《专利法》规定，发明专利权的期限为二十年，实用新型为十年，外观设计为十五年。$$, ARRAY[$$知识产权$$,$$专利$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_016$$, $$法律常识$$, $$single$$, $$对于未成年人的刑事责任年龄，已满多少周岁但不满18周岁的人犯罪，应当从轻或者减轻处罚？$$, $$["12周岁", "14周岁", "16周岁", "上述各项有责年龄段均适用"]$$, $$[3]$$, $$hard$$, $$根据我国《刑法》第17条，已满12或14或16不满18周岁的人犯罪，应当从轻或者减轻处罚（无论在哪个需负刑事责任的分界线，只要不满18岁均应从轻或减轻）。$$, ARRAY[$$刑法$$,$$刑事责任年龄$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_017$$, $$法律常识$$, $$single$$, $$中国法院系统普遍实行的审级制度是？$$, $$["一审终审制", "两审终审制", "三审终审制", "复核终审制"]$$, $$[1]$$, $$medium$$, $$我国大多数普通民事、刑事和行政诉讼案件实行两审终审制，二审法院的判决、裁定即为发生法律效力的最终裁判。$$, ARRAY[$$诉讼法$$,$$法院程序$$]::text[], $${"法学": 1.0, "管理学": 0.2, "工学": 1.0, "理学": 0.8}$$, 'batch'),
  ($$law_018$$, $$法律常识$$, $$single$$, $$公民发现有人正在实施抢劫，挺身而出将其制服，导致犯罪嫌疑人受轻伤。这种行为属于？$$, $$["故意伤害罪", "防卫过当", "见义勇为", "寻衅滋事"]$$, $$[2]$$, $$easy$$, $$对正在进行行凶、杀人、抢劫等严重危及人身安全的暴力犯罪采取防卫行为，造成不法侵害人伤亡的，不属于防卫过当，不负刑事责任。$$, ARRAY[$$刑法$$,$$见义勇为$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_019$$, $$法律常识$$, $$multiple$$, $$通常所说的知识产权包含哪几个最核心的组成部分？$$, $$["著作权", "专利权", "商标权", "继承权"]$$, $$[0, 1, 2]$$, $$easy$$, $$知识产权主要包括著作权及其邻接权，以及工业产权（如商标权、专利权）。继承权属于普通的民事权。$$, ARRAY[$$知识产权$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_020$$, $$法律常识$$, $$multiple$$, $$依据刑法，法定刑罚中的“主刑”包括了以下哪些种类？$$, $$["管制", "拘役", "有期徒刑与无期徒刑", "死刑"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$我国刑法中的主刑分为：管制、拘役、有期徒刑、无期徒刑、死刑。剥夺政治权利、没收财产等属于附加刑。$$, ARRAY[$$刑法$$,$$主刑$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_021$$, $$法律常识$$, $$multiple$$, $$婚姻法（民法典婚姻家庭编）规定，有哪些情形的婚姻是自始无效的？$$, $$["重婚的", "有禁止结婚的亲属关系的", "未到法定婚龄的", "双方性格不合经常吵架的"]$$, $$[0, 1, 2]$$, $$medium$$, $$性格不合可以协议或诉讼离婚，但不构成婚姻自始“无效”的法定事由。重婚、近亲和不到年龄均属于无效情形。$$, ARRAY[$$婚姻法$$,$$无效婚姻$$]::text[], $${"法学": 1.0, "管理学": 0.3}$$, 'batch'),
  ($$law_022$$, $$法律常识$$, $$multiple$$, $$根据法定程序，剥夺他人人身自由的“治安拘留”和“刑事拘留”的主要区别在于？$$, $$["适用的法律依据不同", "严厉程度不同，针对的行为性质不同", "做出决定的机关完全不同", "最长羁押时间限制不同"]$$, $$[0, 1, 3]$$, $$hard$$, $$治安拘留针对普通违法行为，刑事拘留针对涉嫌犯罪的嫌疑人；依据法律与拘留时间均不同。但两者通常均由公安机关执行并做出（尽管刑事拘留属于刑事强制措施的初期）。$$, ARRAY[$$行政法$$,$$刑事法$$]::text[], $${"法学": 1.0, "管理学": 0.3}$$, 'batch'),
  ($$law_023$$, $$法律常识$$, $$multiple$$, $$承担民事责任的方式主要包括哪些？$$, $$["停止侵害，排除妨碍", "赔偿损失", "赔礼道歉", "判处有期徒刑"]$$, $$[0, 1, 2]$$, $$medium$$, $$判处有期徒刑是刑事制裁（刑事责任），其余均为典型的民事责任承担方式。$$, ARRAY[$$民法$$,$$民事责任$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_024$$, $$法律常识$$, $$multiple$$, $$在我国，如果一个劳动合同存在以下哪些情形，会被认定为无效劳动合同？$$, $$["以欺诈、胁迫的手段订立的", "用人单位免除自己的法定责任、排除劳动者权利的", "违反法律、行政法规强制性规定的", "签合同时员工带了黑色眼镜"]$$, $$[0, 1, 2]$$, $$easy$$, $$劳动法明确规定因欺诈胁迫、排除劳工核心权益、违反国家强制法规的条款和合同无效。戴眼镜不影响合同效力。$$, ARRAY[$$劳动法$$,$$劳动合同$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_025$$, $$法律常识$$, $$multiple$$, $$宪法规定了公民的基本权利，总体上可以划分为？$$, $$["平等权", "政治权利和自由", "宗教信仰自由与人身自由", "社会经济权利和文化教育权利"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$这四大类涵盖了《宪法》第二章中列举的全体中国公民享有的核心基本基本权利体系。$$, ARRAY[$$宪法$$,$$基本权利$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_026$$, $$法律常识$$, $$single$$, $$《中华人民共和国劳动法》规定，国家实行劳动者每日工作时间不超过多少小时的工时制度？$$, $$["6小时", "8小时", "9小时", "10小时"]$$, $$[1]$$, $$easy$$, $$《劳动法》规定，国家实行按每日工作时间不超过八小时、平均每周工作时间不超过四十四小时的工时制度。$$, ARRAY[$$劳动法$$,$$法律普及$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_027$$, $$法律常识$$, $$single$$, $$《中华人民共和国民法典》被誉为‘社会生活的百科全书’，它于哪一年起正式施行？$$, $$["2019年", "2020年", "2021年", "2022年"]$$, $$[2]$$, $$medium$$, $$《中华人民共和国民法典》于2021年1月1日起施行。$$, ARRAY[$$民法典基础$$,$$中国法$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$law_028$$, $$法律常识$$, $$single$$, $$某作家创作了一部畅销小说，根据版权法规定，其著作权的保护期通常为作者终生及其死亡后多少年？$$, $$["20年", "30年", "50年", "70年"]$$, $$[2]$$, $$medium$$, $$多数国家(包括中国)的著作权法规定，财产权利保护期为作者终生及死亡后50年。$$, ARRAY[$$知识产权法$$,$$著作权保护$$]::text[], $${"法学": 1.0, "管理学": 0.2}$$, 'batch'),
  ($$lit_001$$, $$文学$$, $$single$$, $$被誉为“世界短篇小说巨匠”的法国作家是？$$, $$["莫泊桑", "契诃夫", "欧·亨利", "巴尔扎克"]$$, $$[0]$$, $$easy$$, $$莫泊桑是法国优秀的批判现实主义作家，与契诃夫、欧·亨利并称为“世界三大短篇小说巨匠”。$$, ARRAY[$$外国文学$$,$$小说$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_002$$, $$文学$$, $$single$$, $$中国古典四大名著中，成书时间最晚的是？$$, $$["《三国演义》", "《水浒传》", "《西游记》", "《红楼梦》"]$$, $$[3]$$, $$easy$$, $$《红楼梦》成书于清朝乾隆年间，是四大名著中成书时间最晚的一部。$$, ARRAY[$$中国古典文学$$,$$四大名著$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_003$$, $$文学$$, $$single$$, $$诺贝尔文学奖获得者加西亚·马尔克斯的代表作《百年孤独》属于哪个文学流派？$$, $$["批判现实主义", "浪漫主义", "魔幻现实主义", "荒诞派"]$$, $$[2]$$, $$medium$$, $$《百年孤独》是拉美魔幻现实主义文学的代表作。$$, ARRAY[$$拉美文学$$,$$文学流派$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_004$$, $$文学$$, $$single$$, $$唐代著名诗人李白被称为？$$, $$["诗圣", "诗仙", "诗鬼", "诗佛"]$$, $$[1]$$, $$easy$$, $$李白被称为“诗仙”，杜甫为“诗圣”，李贺为“诗鬼”，王维为“诗佛”。$$, ARRAY[$$中国古典文学$$,$$唐诗$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_005$$, $$文学$$, $$single$$, $$列夫·托尔斯泰的哪部作品以拿破仑入侵俄罗斯为背景？$$, $$["《安娜·卡列尼娜》", "《复活》", "《战争与和平》", "《死魂灵》"]$$, $$[2]$$, $$medium$$, $$《战争与和平》以1812年卫国战争为中心，反映了19世纪初俄罗斯的社会风貌。$$, ARRAY[$$俄国文学$$,$$小说$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_006$$, $$文学$$, $$single$$, $$《诗经》按音乐性质可分为哪三部分？$$, $$["赋、比、兴", "风、雅、颂", "乐、歌、辞", "诗、词、赋"]$$, $$[1]$$, $$medium$$, $$“风、雅、颂”是按音乐性质划分的《诗经》三大类，“赋、比、兴”则是其主要的表现手法。$$, ARRAY[$$中国古典文学$$,$$诗经$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_007$$, $$文学$$, $$single$$, $$莎士比亚的喜剧名作《威尼斯商人》中，吝啬鬼的形象是谁？$$, $$["夏洛克", "阿巴贡", "葛朗台", "泼留希金"]$$, $$[0]$$, $$medium$$, $$夏洛克是《威尼斯商人》中的高利贷者。阿巴贡是莫里哀笔下人物，葛朗台是巴尔扎克笔下人物，泼留希金是果戈里笔下人物。$$, ARRAY[$$英国文学$$,$$戏剧$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_008$$, $$文学$$, $$single$$, $$“人生若只如初见，何事秋风悲画扇”是清代哪位词人的名句？$$, $$["纳兰性德", "蒲松龄", "曹雪芹", "龚自珍"]$$, $$[0]$$, $$medium$$, $$这句词出自清代著名词人纳兰性德的《木兰花·拟古决绝词柬友》。$$, ARRAY[$$中国古典文学$$,$$清词$$]::text[], $${"文学": 1.0, "历史学": 0.4, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_009$$, $$文学$$, $$single$$, $$提出“冰山理论”，认为文学创作要“简洁而富有暗示性”的美国作家是？$$, $$["马克·吐温", "海明威", "菲茨杰拉德", "福克纳"]$$, $$[1]$$, $$hard$$, $$欧内斯特·海明威提出了著名的“冰山理论”，强调文字的内敛和力量。$$, ARRAY[$$美国文学$$,$$文学理论$$]::text[], $${"文学": 1.0, "历史学": 0.5, "哲学": 1.0, "法学": 0.3, "艺术学": 0.15}$$, 'batch'),
  ($$lit_010$$, $$文学$$, $$single$$, $$中国第一部现代白话文小说是鲁迅的哪部作品？$$, $$["《呐喊》", "《阿Q正传》", "《狂人日记》", "《祝福》"]$$, $$[2]$$, $$easy$$, $$1918年发表的《狂人日记》是中国第一部现代白话文小说。$$, ARRAY[$$中国现代文学$$,$$鲁迅$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_011$$, $$文学$$, $$single$$, $$古希腊神话中，特洛伊战争的史诗文献主要由谁创作？$$, $$["柏拉图", "亚里士多德", "荷马", "索福克勒斯"]$$, $$[2]$$, $$easy$$, $$古希腊的盲诗人荷马创作了《荷马史诗》（《伊利亚特》和《奥德赛》），记录了特洛伊战争及战后故事。$$, ARRAY[$$世界近代文学$$,$$古希腊$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_012$$, $$文学$$, $$single$$, $$获得1968年诺贝尔文学奖的日本名篇《雪国》《千只鹤》《古都》的作者是？$$, $$["夏目漱石", "三岛由纪夫", "川端康成", "大江健三郎"]$$, $$[2]$$, $$hard$$, $$川端康成是日本第一位诺贝尔文学奖得主，代表作为《雪国》等。$$, ARRAY[$$日本文学$$,$$诺贝尔文学奖$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_013$$, $$文学$$, $$single$$, $$法国作家雨果宏大的“人间喜剧”式多卷本小说的总称是？$$, $$["《悲惨世界》", "《人间喜剧》", "《巴黎圣母院》", "《幻灭》"]$$, $$[1]$$, $$medium$$, $$注意陷阱：虽然标题引述了“人间喜剧”式，但《人间喜剧》是巴尔扎克的小说总集。雨果的代表作是《悲惨世界》《巴黎圣母院》等。$$, ARRAY[$$法国文学$$,$$文学常识$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_014$$, $$文学$$, $$single$$, $$“四史”之中，由司马迁所撰写的一部被鲁迅誉为“史家之绝唱，无韵之离骚”的是？$$, $$["《汉书》", "《史记》", "《后汉书》", "《三国志》"]$$, $$[1]$$, $$easy$$, $$司马迁撰写的《史记》是中国第一部纪传体通史，文学和史学价值极高。$$, ARRAY[$$中国古典文学$$,$$史书$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_015$$, $$文学$$, $$single$$, $$20世纪存在主义文学的重要作品《等待戈多》是一部？$$, $$["诗歌", "长篇小说", "散文", "荒诞派戏剧"]$$, $$[3]$$, $$hard$$, $$塞缪尔·贝克特的《等待戈多》是荒诞派戏剧的经典代表作。$$, ARRAY[$$西方现代主义$$,$$戏剧$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "文学": 0.5, "艺术学": 0.15}$$, 'batch'),
  ($$lit_016$$, $$文学$$, $$multiple$$, $$以下哪些作品属于莎士比亚的“四大悲剧”？$$, $$["《哈姆雷特》", "《奥赛罗》", "《李尔王》", "《麦克白》"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$莎士比亚的四大悲剧正是《哈姆雷特》《奥赛罗》《李尔王》《麦克白》。$$, ARRAY[$$英国文学$$,$$莎士比亚$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_017$$, $$文学$$, $$multiple$$, $$以下属于中国古代“建安文学”代表人物“三曹”的有哪些？$$, $$["曹操", "曹丕", "曹植", "曹冲"]$$, $$[0, 1, 2]$$, $$easy$$, $$“三曹”指东汉末年建安时期的著名诗人曹操及其子曹丕、曹植。$$, ARRAY[$$中国古典文学$$,$$文学人物$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_018$$, $$文学$$, $$multiple$$, $$关于欧洲文艺复兴时期文学“三杰”，一般指的是哪几位？$$, $$["但丁", "薄伽丘", "彼特拉克", "莎士比亚"]$$, $$[0, 1, 2]$$, $$medium$$, $$文艺复兴前三杰（文学三杰）指的是生活在意大利的但丁、彼特拉克和薄伽丘。$$, ARRAY[$$外国文学$$,$$文艺复兴$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_019$$, $$文学$$, $$multiple$$, $$下列属于鲁迅小说集的是？$$, $$["《呐喊》", "《彷徨》", "《故事新编》", "《朝花夕拾》"]$$, $$[0, 1, 2]$$, $$hard$$, $$《呐喊》《彷徨》《故事新编》是鲁迅的三部小说集；《朝花夕拾》是回忆性散文集。$$, ARRAY[$$现代文学$$,$$鲁迅$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_020$$, $$文学$$, $$multiple$$, $$世界文学史上的四大吝啬鬼形象分别出自哪些作家的作品？$$, $$["莎士比亚", "莫里哀", "巴尔扎克", "果戈里"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$分别是莎士比亚的夏洛克、莫里哀的阿巴贡、巴尔扎克的葛朗台、果戈里的泼留希金。$$, ARRAY[$$外国文学$$,$$文学形象$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_021$$, $$文学$$, $$single$$, $$中国古典四大名著中，由吴承恩创作的是？$$, $$["西游记", "水浒传", "红楼梦", "三国演义"]$$, $$[0]$$, $$easy$$, $$《西游记》作者是明代小说家吴承恩。$$, ARRAY[$$四大名著$$,$$古典文学$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_022$$, $$文学$$, $$single$$, $$被誉为‘诗鬼’的唐代诗人是？$$, $$["李白", "杜甫", "李贺", "白居易"]$$, $$[2]$$, $$medium$$, $$李贺因其诗作奇诡瑰丽，被称为诗鬼。$$, ARRAY[$$古诗词$$,$$唐代人物$$]::text[], $${"文学": 1.0, "历史学": 0.4, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_023$$, $$文学$$, $$single$$, $$魔幻现实主义的代表作《百年孤独》的作者是？$$, $$["海明威", "加西亚·马尔克斯", "雨果", "卡夫卡"]$$, $$[1]$$, $$medium$$, $$哥伦比亚作家加西亚·马尔克斯创作了《百年孤独》。$$, ARRAY[$$外国文学$$,$$诺贝尔文学奖$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lit_024$$, $$文学$$, $$single$$, $$下列属于莎士比亚‘四大悲剧’的是？$$, $$["《仲夏夜之梦》", "《威尼斯商人》", "《哈姆雷特》", "《罗密欧与朱丽叶》"]$$, $$[2]$$, $$medium$$, $$莎四大悲剧为《哈姆雷特》《奥赛罗》《李尔王》《麦克白》。《罗密欧与朱丽叶》不是四大之一。$$, ARRAY[$$外国戏剧$$,$$莎士比亚$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.3, "哲学": 0.2}$$, 'batch'),
  ($$lit_025$$, $$文学$$, $$single$$, $$鲁迅所创作的第一部白话文日记体小说是？$$, $$["《阿Q正传》", "《狂人日记》", "《药》", "《故乡》"]$$, $$[1]$$, $$medium$$, $$1918年发表的《狂人日记》是中国现代文学史上第一篇白话文小说。$$, ARRAY[$$现当代文学$$,$$鲁迅$$]::text[], $${"文学": 1.0, "历史学": 0.3, "艺术学": 0.15, "哲学": 0.1}$$, 'batch'),
  ($$lng_001$$, $$语言学与文字$$, $$single$$, $$世界上使用母语人数最多的语言是？$$, $$["英语", "汉语", "西班牙语", "阿拉伯语"]$$, $$[1]$$, $$easy$$, $$如果仅按“母语（第一语言）”人口计算，汉语使用人数最多，超过10亿人。$$, ARRAY[$$语言学概况$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_002$$, $$语言学与文字$$, $$single$$, $$英语属于哪一个主要语系？$$, $$["印欧语系", "汉藏语系", "乌拉尔语系", "阿尔泰语系"]$$, $$[0]$$, $$easy$$, $$英语属于印欧语系 -> 日耳曼语族 -> 西日耳曼语支。$$, ARRAY[$$语系$$,$$英语$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_003$$, $$语言学与文字$$, $$single$$, $$现代汉语普通话中，基本声调有几个（不计算轻声）？$$, $$["3个", "4个", "5个", "6个"]$$, $$[1]$$, $$easy$$, $$现代汉语普通话有阴平、阳平、上声、去声四个基本声调。$$, ARRAY[$$语音学$$,$$汉语$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_004$$, $$语言学与文字$$, $$single$$, $$提出“语言的普遍文法 / 生成语法（Generative Grammar）”理论，被誉为“现代语言学之父”之一的美国学者是？$$, $$["索绪尔", "乔姆斯基", "布龙菲尔德", "皮亚杰"]$$, $$[1]$$, $$medium$$, $$诺姆·乔姆斯基的生成语法理论对20世纪的语言学、认知心理学产生了革命性的影响。$$, ARRAY[$$生成语法$$,$$乔姆斯基$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_005$$, $$语言学与文字$$, $$single$$, $$《普通语言学教程》的作者，被视为现代结构主义语言学奠基人的瑞士语言学家是？$$, $$["乔姆斯基", "索绪尔", "威廉·琼斯", "斯瓦迪士"]$$, $$[1]$$, $$medium$$, $$费尔迪南·德·索绪尔（Ferdinand de Saussure）区分了“语言”和“言语”，是结构主义的始祖。$$, ARRAY[$$结构主义$$,$$索绪尔$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "文学": 0.5}$$, 'batch'),
  ($$lng_006$$, $$语言学与文字$$, $$single$$, $$目前所知世界上最古老的成熟文字系统之一，由古代苏美尔人发明的是？$$, $$["象形文字", "楔形文字", "甲骨文", "玛雅文字"]$$, $$[1]$$, $$easy$$, $$公元前3000多年前两河流域的苏美尔人发明了楔形文字（Cuneiform），是已知最古老的文字之一。$$, ARRAY[$$古文字$$,$$楔形文字$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_007$$, $$语言学与文字$$, $$single$$, $$古埃及主要使用的文字记录系统是？$$, $$["拉丁字母", "楔形文字", "圣书体", "线性文字A"]$$, $$[2]$$, $$easy$$, $$古埃及人使用神圣的象形文字（Hieroglyphs），后来演化出僧侣体和世俗体。$$, ARRAY[$$古埃及$$,$$象形文字$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_008$$, $$语言学与文字$$, $$single$$, $$1799年法国士兵在埃及发现的哪块石碑，最终由商博良破译，成为了解构古埃及象形文字的关键钥匙？$$, $$["汉谟拉比法典石碑", "罗塞塔石碑", "贝希斯敦铭文", "美索不达米亚刻碑"]$$, $$[1]$$, $$medium$$, $$罗塞塔石碑（Rosetta Stone）上刻有古埃及象形文、古埃及世俗体和古希腊文三种文本，商博良借此成功破译了古埃及文字。$$, ARRAY[$$罗塞塔石碑$$,$$考古$$]::text[], $${"工学": 0.8, "艺术学": 0.8, "历史学": 0.4, "文学": 0.5}$$, 'batch'),
  ($$lng_009$$, $$语言学与文字$$, $$single$$, $$汉字造字和用字的基本规律在古代被总结为“六书”，其中“日”、“月”、“水”、“火”属于哪一种造字法？$$, $$["指事", "象形", "会意", "形声"]$$, $$[1]$$, $$easy$$, $$象形是通过描绘事物的形状特征来造字的，如日月水火。$$, ARRAY[$$汉字$$,$$六书$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_010$$, $$语言学与文字$$, $$single$$, $$“江”、“河”、“树”、“清”这些汉字，一半表意一半表音，在“六书”中属于？$$, $$["象形", "转注", "假借", "形声"]$$, $$[3]$$, $$easy$$, $$形声字由表示意义范畴的“形旁”和表示发音的“声旁”组合而成，汉字中绝大多数属于形声字。$$, ARRAY[$$汉字$$,$$形声$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_011$$, $$语言学与文字$$, $$single$$, $$被誉为世界上最成功的的人工语言，由波兰眼科医生柴门霍夫创造的是？$$, $$["克林贡语", "世界语", "瓦雷利亚语", "伊多语"]$$, $$[1]$$, $$medium$$, $$世界语是1887年创造的国际辅助语，旨在消除国际语言交流障碍。$$, ARRAY[$$人工语言$$,$$世界语$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_012$$, $$语言学与文字$$, $$single$$, $$西班牙语、法语、意大利语、葡萄牙语等统统源自于古代的哪种语言体系？$$, $$["古希腊语", "古梵语", "罗曼语族", "日耳曼语谱系"]$$, $$[2]$$, $$medium$$, $$它们同属于印欧语系下的罗曼语族（Roman languages），都是由罗马帝国时期的通俗拉丁语演变而来的。$$, ARRAY[$$语族$$,$$拉丁语$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_013$$, $$语言学与文字$$, $$single$$, $$日语的表记系统非常复杂，主要包括假名和？$$, $$["韩文", "拉丁字母", "汉字", "西里尔字母"]$$, $$[2]$$, $$easy$$, $$日文书写系统主要由平假名、片假名以及汉字（Kanji）构成。$$, ARRAY[$$日语$$,$$书写系统$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_014$$, $$语言学与文字$$, $$single$$, $$韩文（谚文/Hangul）是在朝鲜王朝哪位国王在位时期主导创制的？$$, $$["高宗", "世宗大王", "英祖", "光海君"]$$, $$[1]$$, $$medium$$, $$1443年，朝鲜世宗大王李祹组织学者创制了科学系统的表音文字“训民正音”（即谚文）。$$, ARRAY[$$韩文$$,$$世宗$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_015$$, $$语言学与文字$$, $$single$$, $$按照句子内部词序的类型学分类（Typology），“主语-谓语-宾语”(SVO) 是英语和现代汉语的常见语序，而日语通常使用的是？$$, $$["S-V-O", "V-S-O", "S-O-V", "O-V-S"]$$, $$[2]$$, $$hard$$, $$日语、韩语、突厥语族多采用 S-O-V（主-宾-谓）语序结构，如“我(S)苹果(O)吃(V)”。$$, ARRAY[$$语言类型学$$,$$语序$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_016$$, $$语言学与文字$$, $$multiple$$, $$语系是按照语言的起源祖属划分的，以下语言属于印欧语系 (Indo-European) 的有？$$, $$["俄语", "印地语", "土耳其语", "库尔德语"]$$, $$[0, 1]$$, $$hard$$, $$俄语属印欧斯拉夫语族，印地语属印欧印度-伊朗语族。土耳其语属突厥语系或阿尔泰语系（争议较大，但肯定不属印欧）。$$, ARRAY[$$印欧语系$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_017$$, $$语言学与文字$$, $$multiple$$, $$汉藏语系包含了东亚和东南亚的众多语言。以下属于该语系的有？$$, $$["汉语", "藏语", "缅甸语", "阿拉伯语"]$$, $$[0, 1, 2]$$, $$medium$$, $$阿拉伯语属于闪含语系（亚非语系）。汉、藏、缅均为汉藏语系。泰语在较老教材属汉藏，现代多划入壮侗语系。$$, ARRAY[$$汉藏语系$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_018$$, $$语言学与文字$$, $$multiple$$, $$关于语言的形态学分类，世界上的语言大致可分为孤立语、黏着语、屈折语和多式综合语。汉语属于典型的？英语表现为何种倾向？$$, $$["汉语是典型的孤立语", "汉语是典型的黏着语", "英语是一种具有一定孤立语趋势的屈折语", "英语是完全的多式综合语"]$$, $$[0, 2]$$, $$hard$$, $$汉语几乎没有词形屈折变化，依靠词序和虚词表意，是孤立语。英语源自屈折语，但历史演化中丢失了大量屈折变化，转向分析语/孤立语倾向。$$, ARRAY[$$形态学$$,$$语言分类$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_019$$, $$语言学与文字$$, $$multiple$$, $$拼音文字系统按照发音单位可以区分为不同的类型，主要包括？$$, $$["全音素文字", "音节文字", "辅音音素文字", "象形文字"]$$, $$[0, 1, 2]$$, $$hard$$, $$象形文字是以图形表意的体系，不属于纯粹的拼音/表音系统。$$, ARRAY[$$文字系统类型$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$lng_020$$, $$语言学与文字$$, $$multiple$$, $$语音学（Phonetics）通常研究人类发音的哪几个维度？$$, $$["发音语音学", "声学语音学", "听觉语音学", "文学修辞手法"]$$, $$[0, 1, 2]$$, $$medium$$, $$语音学包含发音、声学和听觉三大分支。修辞是文学或语用学范畴。$$, ARRAY[$$语音学$$]::text[], $${"文学": 1.0, "历史学": 0.4}$$, 'batch'),
  ($$log_001$$, $$逻辑学与思维法则$$, $$single$$, $$有人说-0-‘你不支持我的观点，你就是我的敌人’，这种非黑即白的论调通常属于哪种逻辑谬误？$$, $$["滑坡谬误", "虚假两难", "稻草人谬误", "诉诸权威"]$$, $$[1]$$, $$easy$$, $$忽略了中间立场的虚假选择。$$, ARRAY[$$逻辑学$$,$$逻辑谬误$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "理学": 0.3}$$, 'batch'),
