  ($$math_001$$, $$数学常识$$, $$single$$, $$圆周率 π 是一个什么数？$$, $$["有理数", "无理数", "虚数", "整数"]$$, $$[1]$$, $$easy$$, $$圆周率 π 是一个无限不循环小数，属于无理数。$$, ARRAY[$$基础数学$$,$$数系$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_002$$, $$数学常识$$, $$single$$, $$在直角三角形中，斜边平方等于两直角边平方和，这一定理在中国被称为？$$, $$["泰勒斯定理", "费马大定理", "勾股定理", "欧拉定理"]$$, $$[2]$$, $$easy$$, $$这即为勾股定理（毕达哥拉斯定理），勾三股四弦五。$$, ARRAY[$$几何$$,$$定理$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_003$$, $$数学常识$$, $$single$$, $$自然对数的底数 e 的近似值约等于？$$, $$["1.414", "2.718", "3.141", "1.618"]$$, $$[1]$$, $$medium$$, $$自然对数底数 e 约等于 2.71828。$$, ARRAY[$$微积分$$,$$常数$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_004$$, $$数学常识$$, $$single$$, $$一元二次方程 ax^2 + bx + c = 0 (a≠0) 有两个不相等实数根的条件是？$$, $$["b^2 - 4ac > 0", "b^2 - 4ac = 0", "b^2 - 4ac < 0", "b^2 + 4ac > 0"]$$, $$[0]$$, $$easy$$, $$判别式 Δ = b^2 - 4ac > 0 时，方程有两个不相等实根。$$, ARRAY[$$代数$$,$$方程$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_005$$, $$数学常识$$, $$single$$, $$在概率论中，不可能事件的概率等于？$$, $$["-1", "0", "0.5", "1"]$$, $$[1]$$, $$easy$$, $$不可能发生的事件，其概率为 0。$$, ARRAY[$$概率论$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_006$$, $$数学常识$$, $$single$$, $$微积分学的基础是？$$, $$["集合论", "泛函分析", "极限理论", "群论"]$$, $$[2]$$, $$medium$$, $$极限是微积分的基础概念，导数、积分等都是通过极限定义的。$$, ARRAY[$$微积分$$,$$极限$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_007$$, $$数学常识$$, $$single$$, $$被称为“数学王子”，在数论、代数、统计等方面有巨大贡献的德国数学家是？$$, $$["艾萨克·牛顿", "莱昂哈德·欧拉", "卡尔·弗里德里希·高斯", "戈特弗里德·莱布尼茨"]$$, $$[2]$$, $$easy$$, $$高斯被誉为“数学王子”，与阿基米德、牛顿齐名。$$, ARRAY[$$数学史$$,$$高斯$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_008$$, $$数学常识$$, $$single$$, $$正态分布曲线的形状呈什么形式？$$, $$["U型曲线", "钟形曲线", "V型曲线", "直线"]$$, $$[1]$$, $$medium$$, $$正态分布的密度函数图像呈中间高、两边低的对称钟形，因此也叫钟形曲线。$$, ARRAY[$$概率统计$$,$$分布$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_009$$, $$数学常识$$, $$single$$, $$函数 f(x) = sin(x) 的导数是？$$, $$["cos", "-sin", "-cos", "tan"]$$, $$[0]$$, $$medium$$, $$正弦函数的导数是余弦函数，即 (sin x)' = cos x。$$, ARRAY[$$微积分$$,$$导数$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_010$$, $$数学常识$$, $$single$$, $$线性代数中，如果矩阵A与矩阵B相乘得单位矩阵（AB=I），则B是A的？$$, $$["转置矩阵", "逆矩阵", "伴随矩阵", "正交矩阵"]$$, $$[1]$$, $$medium$$, $$根据逆矩阵的定义，若矩阵 A 可逆，且 AB = BA = I，则 B 为 A 的逆矩阵。$$, ARRAY[$$线性代数$$,$$矩阵$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_011$$, $$数学常识$$, $$single$$, $$欧拉恒等式 e^(iπ) + 1 = 0 中，i 代表什么？$$, $$["自然对数的底", "真数", "虚数单位", "非零整数"]$$, $$[2]$$, $$medium$$, $$在这里，i 代表虚数单位，满足 i^2 = -1。$$, ARRAY[$$复变函数$$,$$欧拉公式$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_012$$, $$数学常识$$, $$single$$, $$“哥德巴赫猜想”被誉为数学皇冠上的明珠，它的核心内容是关于什么的研究？$$, $$["素数", "矩阵", "几何图形", "微积分"]$$, $$[0]$$, $$medium$$, $$哥德巴赫猜想是数论中存在最久的未解问题之一，主要探讨偶数与素数的关系。$$, ARRAY[$$数论$$,$$猜想$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_013$$, $$数学常识$$, $$single$$, $$在三维笛卡尔坐标系中，两点(x1,y1,z1)和(x2,y2,z2)之间的距离公式基础是？$$, $$["海伦公式", "勾股定理", "欧拉公式", "柯西不等式"]$$, $$[1]$$, $$medium$$, $$空间两点距离公式是通过两次应用勾股定理推导出来的。$$, ARRAY[$$解析几何$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_014$$, $$数学常识$$, $$single$$, $$微积分学中，定积分在几何上的一个主要应用是求？$$, $$["曲线的切线斜率", "函数的极值点", "曲线下的面积", "图形的对称轴"]$$, $$[2]$$, $$easy$$, $$导数主要用来求斜率/变化率等，定积分的一个基本几何意义是求曲线下方的面积。$$, ARRAY[$$微积分$$,$$几何意义$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_015$$, $$数学常识$$, $$single$$, $$如果一个序列的后一项与前一项的比值为常数，这个序列被称为？$$, $$["等差数列", "等比数列", "斐波那契数列", "调和数列"]$$, $$[1]$$, $$easy$$, $$比值为常数的是等比数列，差值为常数的是等差数列。$$, ARRAY[$$代数$$,$$数列$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_016$$, $$数学常识$$, $$single$$, $$下列集合中，哪一个是不可数集？$$, $$["自然数集", "整数集", "有理数集", "实数集"]$$, $$[3]$$, $$hard$$, $$康托尔的对角线论证法证明了实数集是不可数的，而自然数、整数、有理数集都是可数的。$$, ARRAY[$$集合论$$,$$实分析$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_017$$, $$数学常识$$, $$single$$, $$在拓扑学中，莫比乌斯环的一个显著特征是它具有几个面？$$, $$["1个", "2个", "3个", "4个"]$$, $$[0]$$, $$hard$$, $$莫比乌斯环是一种拓扑学结构，它只有一个面（表面）和一个边界。$$, ARRAY[$$拓扑学$$,$$几何$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_018$$, $$数学常识$$, $$single$$, $$在信息论中，用于衡量信息不确定性的概念是？$$, $$["方差", "熵", "期望", "协方差"]$$, $$[1]$$, $$hard$$, $$香农借鉴了热力学中的“熵”概念，用来表示信息量的不确定性，称为信息熵。$$, ARRAY[$$信息论$$,$$香农$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_019$$, $$数学常识$$, $$single$$, $$求解线性方程组的一种经典初等变换算法（消元法）通常以哪位数学家命名？$$, $$["牛顿", "高斯", "欧拉", "泰勒"]$$, $$[1]$$, $$medium$$, $$高斯消元法是线性代数中解线性方程组的经典算法。$$, ARRAY[$$线性代数$$,$$算法$$]::text[], $${"工学": 1.0, "理学": 0.8, "经济学": 0.3, "管理学": 0.15}$$, 'batch'),
  ($$math_020$$, $$数学常识$$, $$single$$, $$哪一门数学分支主要研究离散结构，也是计算机科学的重要数学基础？$$, $$["实变函数", "泛函分析", "离散数学", "复变函数"]$$, $$[2]$$, $$easy$$, $$离散数学（包括图论、逻辑、组合数学等）是研究离散结构的，是计算机科学的核心基础。$$, ARRAY[$$离散数学$$,$$计算机数学$$]::text[], $${"工学": 1.0, "理学": 0.8, "经济学": 0.3, "管理学": 0.15}$$, 'batch'),
  ($$math_021$$, $$数学常识$$, $$single$$, $$下列哪个著名的未解决/已解决难题涉及到地图着色？$$, $$["四色定理", "费马大定理", "黎曼猜想", "庞加莱猜想"]$$, $$[0]$$, $$medium$$, $$四色定理证明了任何平面地图只需四种颜色就能使相邻区域不重色。$$, ARRAY[$$图论$$,$$数学定理$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_022$$, $$数学常识$$, $$single$$, $$行列式的值如果在交换两行后，其符号会如何变化？$$, $$["不变", "变为开方", "变为负号", "变为倒数"]$$, $$[2]$$, $$medium$$, $$根据行列式的性质，交换任意两行（或两列），行列式的值变号。$$, ARRAY[$$线性代数$$,$$行列式$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_023$$, $$数学常识$$, $$single$$, $$17世纪发明了微积分的两位数学大师是？$$, $$["牛顿和莱布尼茨", "笛卡尔和费马", "欧拉和高斯", "拉格朗日和泰勒"]$$, $$[0]$$, $$easy$$, $$艾萨克·牛顿和戈特弗里德·莱布尼茨分别独立创立了微积分。$$, ARRAY[$$微积分$$,$$数学史$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_024$$, $$数学常识$$, $$multiple$$, $$下列哪些属于初等函数？$$, $$["多项式函数", "指数函数", "三角函数", "狄利克雷函数"]$$, $$[0, 1, 2]$$, $$medium$$, $$初等函数包括幂函数、指数、对数、三角和反三角函数以及它们经过有限次四则运算和复合而成的函数。狄利克雷函数不是初等函数。$$, ARRAY[$$微积分$$,$$函数$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_025$$, $$数学常识$$, $$multiple$$, $$在三维欧几里得空间中，以下哪些图形属于正多面体（柏拉图立体）？$$, $$["正四面体", "正六面体", "正八面体", "正十面体"]$$, $$[0, 1, 2]$$, $$hard$$, $$共有五种正多面体：正四、六、八、十二、二十面体。不存在“正十面体”。$$, ARRAY[$$立体几何$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_026$$, $$数学常识$$, $$multiple$$, $$概率论中，如果两个事件A和B相互独立，则下列等式正确的是？$$, $$["P = PP", "P = P >0)", "P = P + P", "P = P"]$$, $$[0, 1]$$, $$hard$$, $$事件独立则联合概率等于边缘概率乘积，条件概率等于无条件概率。P(A∪B) = P(A)+P(B)仅在A和B互斥时成立。$$, ARRAY[$$概率论$$,$$计算$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_027$$, $$数学常识$$, $$multiple$$, $$以下哪些概念是微积分中的积分方法？$$, $$["换元积分法", "分部积分法", "高斯消元法", "最小二乘法"]$$, $$[0, 1]$$, $$easy$$, $$换元积分和分部积分是求不定积分和定积分的两种基本方法；后两者属于线性代数和数值分析范畴。$$, ARRAY[$$微积分$$,$$积分法$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_028$$, $$数学常识$$, $$multiple$$, $$线性代数中，对于一个 n 阶方阵，下列哪些情况意味着该方阵是不可逆的（奇异的）？$$, $$["行列式为 0", "满秩", "矩阵中存在两行元素互为比例", "矩阵有一个特征值为 0"]$$, $$[0, 2, 3]$$, $$hard$$, $$满秩意味着可逆；行列式为0、某特征值为0、以及行（列）线性相关（如存在比例）都意味着矩阵降秩、不可逆。$$, ARRAY[$$线性代数$$,$$矩阵性质$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_029$$, $$数学常识$$, $$multiple$$, $$下列属于统计学中“描述性统计”常用指标的有？$$, $$["平均数", "中位数", "泰勒展开式", "标准差"]$$, $$[0, 1, 3]$$, $$easy$$, $$平均数、中位数和标准差都是描述数据集中趋势和离散程度的统计指标。泰勒展开式属于微积分中的级数展开。$$, ARRAY[$$统计学$$,$$基础指标$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$math_030$$, $$数学常识$$, $$multiple$$, $$著名的数学常数包括哪些？$$, $$["圆周率 π", "自然对数底 e", "光速 c", "黄金分割率 φ"]$$, $$[0, 1, 3]$$, $$medium$$, $$π、e、φ是数学常数，光速c是物理常数。$$, ARRAY[$$数学常数$$]::text[], $${"理学": 1.0, "工学": 0.8, "经济学": 0.6, "管理学": 0.3}$$, 'batch'),
  ($$med_001$$, $$医学与健康$$, $$single$$, $$人体中最大、最长的骨头是？$$, $$["脊柱骨", "股骨", "胫骨", "肱骨"]$$, $$[1]$$, $$easy$$, $$大腿骨（股骨）是人体最长最重的管状骨。$$, ARRAY[$$解剖学$$,$$骨骼$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_002$$, $$医学与健康$$, $$single$$, $$成年人体内正常血压值，收缩压（高压）的正常范围一般约为？$$, $$["60-80 mmHg", "90-120 mmHg", "130-150 mmHg", "140-160 mmHg"]$$, $$[1]$$, $$easy$$, $$人体理想血压是收缩压<120mmHg，舒张压<80mmHg。$$, ARRAY[$$基础医学$$,$$血压$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_003$$, $$医学与健康$$, $$single$$, $$胃液呈强酸性主要是因为其中含有哪种酸？$$, $$["硫酸", "盐酸", "硝酸", "碳酸"]$$, $$[1]$$, $$easy$$, $$胃壁细胞分泌盐酸（胃酸），能杀菌并激活胃蛋白酶原。$$, ARRAY[$$消化系统$$,$$生理学$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_004$$, $$医学与健康$$, $$single$$, $$控制体温、食欲以及内分泌的“人体稳态调节中枢”位于大脑的哪个部位？$$, $$["小脑", "脑干", "下丘脑", "大脑皮层"]$$, $$[2]$$, $$medium$$, $$下丘脑(Hypothalamus)在维持机体内部环境稳定和调节内分泌中起核心作用。$$, ARRAY[$$神经内分泌$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_005$$, $$医学与健康$$, $$single$$, $$缺碘最容易引起的病症是？$$, $$["糖尿病", "地方性甲状腺肿", "再生障碍性贫血", "夜盲症"]$$, $$[1]$$, $$easy$$, $$碘是合成甲状腺激素的原料，缺碘引起代偿性甲状腺肿大开发（大脖子病）。$$, ARRAY[$$营养缺乏症$$,$$甲状腺$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.5, "理学": 0.2}$$, 'batch'),
  ($$med_006$$, $$医学与健康$$, $$single$$, $$人类心脏共有几个腔室？$$, $$["两个", "三个", "四个", "五个"]$$, $$[2]$$, $$easy$$, $$人类心脏有四个腔，即左心房、左心室、右心房、右心室。$$, ARRAY[$$解剖学$$,$$循环系统$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_007$$, $$医学与健康$$, $$single$$, $$血液中携带氧气的蛋白是？$$, $$["白蛋白", "血红蛋白", "血纤维蛋白", "球蛋白"]$$, $$[1]$$, $$easy$$, $$红细胞中的血红蛋白（Hb）能与氧结合进行氧气运输。$$, ARRAY[$$生理学$$,$$血液$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_008$$, $$医学与健康$$, $$single$$, $$抗生素主要用于治疗由哪种病原微生物引起的疾病？$$, $$["病毒", "细菌", "真菌", "寄生虫"]$$, $$[1]$$, $$easy$$, $$抗生素专指能破坏细菌生理过程以杀灭或抑制细菌的一类物质，对病毒无效。$$, ARRAY[$$药理学$$,$$抗生素$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_009$$, $$医学与健康$$, $$single$$, $$心肺复苏术(CPR)中，胸外按压与人工呼吸的标准比例一般被建议为？$$, $$["15:1", "15:2", "30:2", "5:1"]$$, $$[2]$$, $$medium$$, $$目前的急救指南普遍推荐对于成人患者，CPR应以30次胸外按压接2次人工呼吸（30:2）的比例进行。$$, ARRAY[$$急救知识$$,$$CPR$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3, "理学": 0.2}$$, 'batch'),
  ($$med_010$$, $$医学与健康$$, $$single$$, $$被誉为“近代微生物学之父”，并发明了巴氏消毒法及狂犬疫苗的科学家是？$$, $$["弗莱明", "科赫", "巴斯德", "李斯特"]$$, $$[2]$$, $$medium$$, $$路易·巴斯德(Louis Pasteur)奠定了现代微生物学、免疫学的基础。$$, ARRAY[$$医学史$$,$$微生物学$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_011$$, $$医学与健康$$, $$single$$, $$人体中最大最复杂的关节是？$$, $$["肩关节", "髋关节", "膝关节", "腕关节"]$$, $$[2]$$, $$medium$$, $$膝关节需承受人体大部分重量并完成屈伸等复杂动作，结构最为复杂。$$, ARRAY[$$运动解剖$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.6, "教育学": 1.0, "历史学": 0.3}$$, 'batch'),
  ($$med_012$$, $$医学与健康$$, $$single$$, $$在眼球结构中，负责感光并最终将光信号转化为神经电信号的是？$$, $$["角膜", "晶状体", "视网膜", "虹膜"]$$, $$[2]$$, $$easy$$, $$视网膜上分布有感光细胞（视杆细胞和视锥细胞）。$$, ARRAY[$$感觉器官$$,$$视觉$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_013$$, $$医学与健康$$, $$single$$, $$引起肺结核的病原体是？$$, $$["肺炎链球菌", "结核分枝杆菌", "流感病毒", "冠状病毒"]$$, $$[1]$$, $$medium$$, $$结核分枝杆菌可以通过空气飞沫传播感染肺部，引起肺结核（痨病）。$$, ARRAY[$$传染病学$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_014$$, $$医学与健康$$, $$single$$, $$下列不属于免疫系统“天然屏障”（第一道防线）的是？$$, $$["皮肤", "胃酸", "粘膜", "淋巴结中的T细胞"]$$, $$[3]$$, $$medium$$, $$T细胞属于特异性免疫（第三道防线）；皮肤粘膜和它们的分泌物属于非特异性的第一道屏障。$$, ARRAY[$$免疫学系统$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_015$$, $$医学与健康$$, $$single$$, $$骨质疏松的发生往往与体内缺乏哪种常量元素有关？$$, $$["铁", "碘", "钙", "锌"]$$, $$[2]$$, $$easy$$, $$钙是构成骨骼的主要成分，缺钙是骨质疏松的重要病因之一。$$, ARRAY[$$营养健康$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.5, "理学": 0.2}$$, 'batch'),
  ($$med_016$$, $$医学与健康$$, $$single$$, $$导致人类发生疟疾的主要病原体属于？$$, $$["病毒", "细菌", "原虫", "真菌"]$$, $$[2]$$, $$medium$$, $$疟疾是由按蚊传播的单细胞寄生原虫——疟原虫引起的传染病。$$, ARRAY[$$寄生虫学$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_017$$, $$医学与健康$$, $$single$$, $$在临床血常规检查中，若白细胞数量显著升高，通常提示体内可能发生了？$$, $$["贫血", "凝血功能障碍", "感染或炎症", "低血糖"]$$, $$[2]$$, $$medium$$, $$白细胞是人体免疫防线的兵器，感染细菌等病原体时通常会大幅增生。$$, ARRAY[$$医学检验$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_018$$, $$医学与健康$$, $$single$$, $$人体哪一个器官具有强大的再生能力，甚至被切除一半后还能逐渐恢复体积？$$, $$["心脏", "肝脏", "肺", "肾脏"]$$, $$[1]$$, $$medium$$, $$肝脏拥有独特的细胞代偿分裂能力，即便被切除一部分也能再生长回复所需功能。$$, ARRAY[$$解剖学$$,$$脏器$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_019$$, $$医学与健康$$, $$single$$, $$心电图(ECG)上代表心室除极过程的波形群体是？$$, $$["P波", "QRS波群", "T波", "U波"]$$, $$[1]$$, $$hard$$, $$P波代表心房除极，QRS波群反映心室肌除极的电位变化，T波代表心室复极。$$, ARRAY[$$心电生理$$,$$体检检查$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_020$$, $$医学与健康$$, $$single$$, $$现代解剖学中，人体有左、右排布的两脏器，哪个器官右侧相比左侧通常更为短粗且有三叶？$$, $$["肾脏", "肺", "脑半球", "甲状腺"]$$, $$[1]$$, $$hard$$, $$肺脏结构中，右肺分为上中下三叶并且较宽短（因肝脏顶起）；左肺只有两叶并且因心脏侵占偏长窄。$$, ARRAY[$$脏器解剖$$,$$呼吸系统$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_021$$, $$医学与健康$$, $$single$$, $$痛风的发作通常与体内哪种物质代谢异常导致其结晶沉积在关节处有关？$$, $$["乳酸", "酮体", "尿酸", "草酸"]$$, $$[2]$$, $$medium$$, $$体内嘌呤代谢紊乱导致尿酸浓度过高析出结晶在关节，引发痛风性关节炎。$$, ARRAY[$$代谢疾病$$,$$痛风$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_022$$, $$医学与健康$$, $$single$$, $$关于阿茨海默症(Alzheimer's disease)，其典型的病理特征是在脑内形成？$$, $$["血栓", "淀粉样蛋白斑块和神经原纤维硬结", "脑积水", "脑膜严重发炎"]$$, $$[1]$$, $$hard$$, $$β-淀粉样蛋白沉积形成的老年斑以及Tau蛋白过度磷酸化形成的神经原纤维缠结，是此症的主要病理特点。$$, ARRAY[$$神经内科$$,$$老年病$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_023$$, $$医学与健康$$, $$multiple$$, $$下列哪些疾病主要是由病毒感染引发的？$$, $$["流行性感冒", "艾滋病", "乙型肝炎", "肺结核"]$$, $$[0, 1, 2]$$, $$medium$$, $$肺结核是由结核分枝杆菌引起的。流感、艾滋病(HIV)和乙肝(HBV)皆为病毒感染。$$, ARRAY[$$传染病学$$,$$病毒$$]::text[], $${"理学": 1.0, "医学": 0.8, "农学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_024$$, $$医学与健康$$, $$multiple$$, $$世界卫生组织（WHO）健康概念主要包括？$$, $$["身体形态完好", "躯体健康", "心理健康", "社会适应良好"]$$, $$[1, 2, 3]$$, $$medium$$, $$WHO将健康定义为不仅是没有疾病，而且是躯体健康、心理健康和社会适应能力的完好状态。$$, ARRAY[$$健康常识$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_025$$, $$医学与健康$$, $$multiple$$, $$在注射给药方式中，常见的途径有？$$, $$["皮下注射", "肌肉注射", "静脉注射", "口服吸入"]$$, $$[0, 1, 2]$$, $$easy$$, $$吸入属于呼吸道给药。常见的注射方式有静脉注射(IV)，肌肉注射(IM)等。$$, ARRAY[$$护理基础$$,$$给药方式$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 0.3}$$, 'batch'),
  ($$med_026$$, $$医学与健康$$, $$multiple$$, $$人体消化系统中，负责吸收营养物质的主要器官包括？$$, $$["胃", "小肠", "大肠", "肝脏"]$$, $$[0, 1, 2]$$, $$medium$$, $$胃粘膜能吸收部分水和酒精；小肠是营养吸收的主要区域；大肠可以吸收剩余的水分和无机物。肝脏是代谢器官。$$, ARRAY[$$消化系统$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_027$$, $$医学与健康$$, $$multiple$$, $$糖尿病（Diabetes）分为多种类型，主要有？$$, $$["1型糖尿病", "2型糖尿病", "妊娠期糖尿病", "3型糖尿病"]$$, $$[0, 1, 2]$$, $$medium$$, $$目前临床上常见的分型包括1型、2型、特殊类型和妊娠期糖尿病。没有3型（甲亢转化）。$$, ARRAY[$$内分泌系统$$,$$糖尿病$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_028$$, $$医学与健康$$, $$multiple$$, $$被称为人体的“三大营养素”（提供能量）的是哪些？$$, $$["碳水化合物", "脂肪", "蛋白质", "维生素"]$$, $$[0, 1, 2]$$, $$easy$$, $$维生素虽重要但不提供能量。宏量营养素三大提供热能的即糖类、脂类、蛋白质。$$, ARRAY[$$生化营养$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.5, "理学": 0.2}$$, 'batch'),
  ($$med_029$$, $$医学与健康$$, $$multiple$$, $$癌症（恶性肿瘤）的主要治疗手段通常包括以下哪些？$$, $$["手术切除", "化学治疗", "放射治疗", "靶向治疗与免疫治疗"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$现代肿瘤学采用综合治疗，手术、放化疗及靶向和免疫治疗都是常见手段。$$, ARRAY[$$肿瘤学$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_030$$, $$医学与健康$$, $$multiple$$, $$人体血液中主要的血细胞成分分为？$$, $$["红细胞", "白细胞", "血小板", "血浆"]$$, $$[0, 1, 2]$$, $$medium$$, $$血细胞指有形成分即红白细胞及血小板。血浆属于血液的液体基质不属于血细胞。$$, ARRAY[$$血液学$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_031$$, $$医学与健康$$, $$single$$, $$心肺复苏(CPR)操作中，成人胸外按压与人工呼吸的比例通常建议为？$$, $$["15:2", "30:2", "15:1", "30:1"]$$, $$[1]$$, $$medium$$, $$对于成人，单人或双人心肺复苏的按压通气比推荐为30:2。$$, ARRAY[$$急救尝试$$,$$急救医学$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3, "理学": 0.2}$$, 'batch'),
  ($$med_032$$, $$医学与健康$$, $$single$$, $$目前公认的全球主要的性传播疾病中，哪一种由人类免疫缺陷病毒引起？$$, $$["艾滋病", "梅毒", "淋病", "生殖器疱疹"]$$, $$[0]$$, $$easy$$, $$艾滋病(AIDS)是由HIV(人类免疫缺陷病毒)引起的。$$, ARRAY[$$传染病防护$$,$$公共卫生$$]::text[], $${"医学": 1.0, "理学": 0.4, "日子人": 0.6}$$, 'batch'),
  ($$med_033$$, $$医学与健康$$, $$single$$, $$遇到突发火灾，以下逃生方法错误的是？$$, $$["使用湿毛巾捂住口鼻", "低姿弯腰前行", "乘坐电梯快速下楼", "从安全通道撤离"]$$, $$[2]$$, $$easy$$, $$火灾时可能会断电，乘坐电梯极易被困或者遇到烟囱效应，十分危险。$$, ARRAY[$$生存技能$$,$$应急避险$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3, "理学": 0.2}$$, 'batch'),
  ($$mem_001$$, $$网络梗知识$$, $$single$$, $$网络流行语“YYDS”代表什么意思？$$, $$["永远都是", "永远单身", "永远滴神", "营业大厦"]$$, $$[2]$$, $$easy$$, $$YYDS是“永远滴神”的拼音首字母缩写。$$, ARRAY[$$网络用语$$,$$缩写$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_002$$, $$网络梗知识$$, $$single$$, $$“奥利给”这个词最早是在用来表达什么情感的？$$, $$["愤怒", "悲伤", "赞美加油、给力", "惊讶"]$$, $$[2]$$, $$easy$$, $$“奥利给”是“给力奥”的倒读，最初在视频中用于打气加油。$$, ARRAY[$$梗$$,$$流行语$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_003$$, $$网络梗知识$$, $$multiple$$, $$下列哪些属于经典的“废话文学”？$$, $$["听君一席话，胜听一席话", "蝉的翅膀非常薄，到底有多薄呢？薄如蝉翼", "如果你是我朋友，那你就是我朋友", "今天天气真好"]$$, $$[0, 1, 2]$$, $$easy$$, $$废话文学的精髓在于用一本正经的语气说出没有提供任何新信息的话。$$, ARRAY[$$废话文学$$,$$搞笑梗$$]::text[], $${"文学": 1.0, "历史学": 0.3, "日子人": 1.0}$$, 'batch'),
  ($$mem_004$$, $$网络梗知识$$, $$single$$, $$B站弹幕中常说的“前方高能”一般意味着？$$, $$["前面有高压电", "视频即将出现高潮、震撼或恐怖的画面", "前面有人在进行化学实验", "前面是高耗能区域"]$$, $$[1]$$, $$easy$$, $$用于提醒观众做好心理准备迎接视频重点。$$, ARRAY[$$B站$$,$$弹幕文化$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_005$$, $$网络梗知识$$, $$single$$, $$“CPU”在近年的网络语境中，常被作为哪个词的谐音或代称来表示“精神控制”？$$, $$["PUA", "KTV", "PPT", "UFO"]$$, $$[0]$$, $$easy$$, $$最初源于某明星口误将PUA说成了CPU，后逐渐演变为一种网络调侃代称。$$, ARRAY[$$网络用语$$,$$谐音梗$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_006$$, $$网络梗知识$$, $$single$$, $$网络梗“泰裤辣”的谐音是？$$, $$["太酷了", "泰国很辣", "太苦了", "裤子太辣"]$$, $$[0]$$, $$easy$$, $$源自某说唱歌手在演唱会上的口音发音，表示“太酷了”。$$, ARRAY[$$谐音梗$$,$$说唱用语$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_007$$, $$网络梗知识$$, $$multiple$$, $$以下哪些是“四大四大”中的网络缩写造词？$$, $$["XSWL - 笑死我了", "U1S1 - 有一说一", "YYSY - 永远是你", "AWSL - 啊我死了"]$$, $$[0, 1, 3]$$, $$easy$$, $$YYSY通常代表“有一说一”，而非“永远是你”。$$, ARRAY[$$缩写梗$$,$$拼音缩写$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_008$$, $$网络梗知识$$, $$single$$, $$“尊嘟假嘟”在网络语境中模仿了什么的口音？$$, $$["四川口音", "小猫小狗等可爱动物/萌宠拟人化口音", "上海方言", "外国人口音"]$$, $$[1]$$, $$easy$$, $$源自一位有着特殊可爱发音习惯的博主，指代“真的假的”。$$, ARRAY[$$口音梗$$,$$流行语$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_009$$, $$网络梗知识$$, $$single$$, $$“绝绝子”最早常用来形容？$$, $$["极度糟糕", "极度好、极度绝美", "断绝关系", "绝对不可能"]$$, $$[1]$$, $$easy$$, $$多用于饭圈夸赞自家偶像，意为太厉害了、太美了。$$, ARRAY[$$饭圈语$$,$$夸赞$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_010$$, $$网络梗知识$$, $$single$$, $$“依托答辩”是以下哪个词语的谐音？$$, $$["一座大桥", "一坨大便", "一次答辩", "一团打扮"]$$, $$[1]$$, $$easy$$, $$因为避免直接打出不雅词汇，网友使用谐音代替，常形容极差的作品或游戏。$$, ARRAY[$$谐音梗$$,$$负面评价$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_011$$, $$网络梗知识$$, $$multiple$$, $$在游戏和网络直播中，“菜鸡”和“云玩家”通常指？$$, $$["非常厉害的玩家", "技术很差的玩家", "只看不玩、纸上谈兵的人", "擅长种菜的人"]$$, $$[1, 2]$$, $$easy$$, $$菜鸡指技术差，“云玩家”指自己不玩但爱指点江山的人。$$, ARRAY[$$游戏梗$$,$$直播术语$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3, "文学": 0.2}$$, 'batch'),
  ($$mem_012$$, $$网络梗知识$$, $$single$$, $$“退退退”这个梗源自谁？$$, $$["张大大", "某大妈和击剑男子的街头争吵", "李佳琦", "王境泽"]$$, $$[1]$$, $$easy$$, $$源于一段新闻视频中大妈面对击剑男边跺脚边喊“退！退！退！”以表示驱赶恶灵般的操作。$$, ARRAY[$$短视频梗$$,$$社会新闻梗$$]::text[], $${"日子人": 1.0, "文学": 0.3, "法学": 0.8, "管理学": 0.6}$$, 'batch'),
  ($$mem_013$$, $$网络梗知识$$, $$single$$, $$名场面“真香”出自哪个节目？$$, $$["《爸爸去哪儿》", "《奔跑吧兄弟》", "《变形计》", "《非诚勿扰》"]$$, $$[2]$$, $$easy$$, $$王境泽在《变形计》中从绝不吃一口饭到端起碗称赞“真香”，成为经典打脸梗。$$, ARRAY[$$综艺梗$$,$$真香定律$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_014$$, $$网络梗知识$$, $$single$$, $$“鸡你太美”这句流行语是由哪首歌的歌词空耳而来的？$$, $$["《只因你太美》", "《大碗宽面》", "《情人》", "《无感》"]$$, $$[0]$$, $$easy$$, $$源于蔡徐坤《只因你太美》歌曲中“只因”连读产生的空耳。$$, ARRAY[$$空耳梗$$,$$人物梗$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_015$$, $$网络梗知识$$, $$multiple$$, $$梗“元芳，你怎么看”出自哪部电视剧？$$, $$["《神探狄仁杰》", "《包青天》", "《大宋提刑官》", "《少年包青天》"]$$, $$[0]$$, $$easy$$, $$狄仁杰遇到案情常询问李元芳的意见，成为网络询问他人看法的流行语。$$, ARRAY[$$影视梗$$,$$经典语录$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_016$$, $$网络梗知识$$, $$single$$, $$英雄联盟玩家常说的“祖安人”现在在网络上多代指？$$, $$["祖国安康的人", "极具文采、擅长用粗鄙语言疯狂输出的网民", "某地少数民族", "热爱和平的人"]$$, $$[1]$$, $$medium$$, $$因为英雄联盟祖安大区频发激烈互喷，后被引申为擅长骂战的键盘侠。$$, ARRAY[$$游戏梗$$,$$群体称呼$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3, "文学": 0.3, "法学": 0.8, "管理学": 0.6}$$, 'batch'),
  ($$mem_017$$, $$网络梗知识$$, $$single$$, $$遇到无法理解的奇葩视频，网友经常会在弹幕刷“地铁，_____，手机”？$$, $$["老人", "小孩", "女人", "男人"]$$, $$[0]$$, $$easy$$, $$“地铁老人手机”表情包常用来表达看到辣眼睛或者无法理解事物时的迷惑表情。$$, ARRAY[$$表情包梗$$,$$常识语$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_018$$, $$网络梗知识$$, $$multiple$$, $$“凡尔赛文学”的特点通常包括？$$, $$["用最低调的话炫最高调的耀", "明贬暗褒", "自问自答", "直接大声炫耀"]$$, $$[0, 1, 2]$$, $$easy$$, $$凡尔赛文学精髓在于不经意的炫耀，看似抱怨实则显摆。$$, ARRAY[$$文学体裁梗$$,$$凡尔赛$$]::text[], $${"文学": 1.0, "历史学": 0.3, "日子人": 1.0}$$, 'batch'),
  ($$mem_019$$, $$网络梗知识$$, $$single$$, $$“打工人，打工魂，打工都是人上人”这句话体现了怎样的情绪？$$, $$["极度自豪", "对打工生活的自我调侃与黑色幽默", "完全的绝望", "想当老板"]$$, $$[1]$$, $$easy$$, $$打工人语录是一种自嘲，用激昂的口号掩盖生活的辛酸。$$, ARRAY[$$打工人$$,$$网络语录$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_020$$, $$网络梗知识$$, $$single$$, $$如果在评论区看到“他在第五层”，这里的“层”是指？$$, $$["楼层", "段位/境界", "智商", "心理阴影"]$$, $$[1]$$, $$easy$$, $$“千层饼”梗，意为你以为他在第一层，其实他在第五层（境界/套路非常深）。$$, ARRAY[$$游戏竞技梗$$,$$千层饼$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3, "文学": 0.2}$$, 'batch'),
  ($$mem_021$$, $$网络梗知识$$, $$single$$, $$梗“大意了，没有闪”出自谁之口？$$, $$["马保国", "马云", "雷军", "东星耀扬"]$$, $$[0]$$, $$medium$$, $$太极雷雷/马保国之流在比武被打败后找借口的经典语录，后用于调侃自己没防备。$$, ARRAY[$$人物梗$$,$$武术梗$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_022$$, $$网络梗知识$$, $$multiple$$, $$以下哪些是形容“非常努力、极度内卷”的网络词汇？$$, $$["卷王", "躺平", "肝帝", "佛系"]$$, $$[0, 2]$$, $$easy$$, $$卷王和肝帝都形容极其拼命的人；躺平和佛系则是相反的消极/不争态度。$$, ARRAY[$$内卷$$,$$网络流行语$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_023$$, $$网络梗知识$$, $$single$$, $$“我看不懂，但我大受震撼”这句话出自谁？$$, $$["周星驰", "吴京", "李安", "沈腾"]$$, $$[2]$$, $$medium$$, $$源自导演李安早年接受采访时谈及某部电影《处女泉》时的评价。$$, ARRAY[$$访谈梗$$,$$名人名言$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_024$$, $$网络梗知识$$, $$single$$, $$吃瓜群众常说的“塌房了”意味着？$$, $$["房子真的倒了", "喜欢的偶像爆出严重负面新闻或绯闻", "股市下跌", "网站服务器崩溃"]$$, $$[1]$$, $$easy$$, $$饭圈用语，形容明星人设崩塌，粉丝犹如自家房子塌了一样心碎。$$, ARRAY[$$饭圈用语$$,$$塌房$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_025$$, $$网络梗知识$$, $$multiple$$, $$网络词语“种草”和“拔草”分别是什么意思？$$, $$["种草：被分享后产生了购买欲", "种草：去野外植树", "拔草：打消了购买欲或者终于买到了", "拔草：清理花园"]$$, $$[0, 2]$$, $$easy$$, $$“种草”是产生购买欲，“拔草”可以是买到手解毒了，或者看了差评彻底放弃。$$, ARRAY[$$美妆语$$,$$购物梗$$]::text[], $${"艺术学": 1.0, "日子人": 1.0, "历史学": 0.3, "文学": 0.2}$$, 'batch'),
  ($$mem_026$$, $$网络梗知识$$, $$single$$, $$形容视频剪辑非常流畅完美，毫无违和感，弹幕常发的内容是？$$, $$["百万剪辑师", "德芙", "好卡", "穿帮了"]$$, $$[1]$$, $$easy$$, $$源自德芙巧克力广告“尽享丝滑”，用来形容视频转场过渡非常顺滑。$$, ARRAY[$$弹幕文化$$,$$赞美词$$]::text[], $${"文学": 1.0, "历史学": 0.4, "日子人": 0.5}$$, 'batch'),
  ($$mem_027$$, $$网络梗知识$$, $$single$$, $$梗“潘嘎之交”中的两位主人公是？$$, $$["潘金莲和西门庆", "潘长江和嘎子", "潘石屹和嘎子", "潘玮柏和嘎子"]$$, $$[1]$$, $$easy$$, $$潘长江曾劝谢孟伟水很深别带货，结果转头自己去带货，被网友戏称为“潘嘎之交”。$$, ARRAY[$$直播梗$$,$$成语新解$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_028$$, $$网络梗知识$$, $$multiple$$, $$当有人说“夺笋啊”，他的意思可能是？$$, $$["多损啊", "太损了，太坏了", "想要吃竹笋", "赞美对方"]$$, $$[0, 1]$$, $$easy$$, $$夺笋是“多损”的谐音，形容对方说话做事调侃别人毫不留情。$$, ARRAY[$$谐音梗$$,$$吐槽$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_029$$, $$网络梗知识$$, $$single$$, $$梗图“柴犬Doge”被全球网民配以各种文本，常常表达？$$, $$["深沉", "嘲讽、精神污染、内心独白", "极度开心", "悲伤"]$$, $$[1]$$, $$easy$$, $$Doge表情搭配彩色Comic Sans字体，通常用来表现魔性的内心吐槽。$$, ARRAY[$$外网梗$$,$$Meme$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_030$$, $$网络梗知识$$, $$single$$, $$“小丑竟是我自己”通常在什么时候使用？$$, $$["演马戏前", "发现自己自作多情、白费功夫而感到尴尬自嘲时", "万圣节装扮时", "看到别人翻车时"]$$, $$[1]$$, $$easy$$, $$常用于舔狗被拒绝或者一厢情愿后突然醒悟时的自嘲。$$, ARRAY[$$自嘲梗$$,$$小丑语录$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_031$$, $$网络梗知识$$, $$multiple$$, $$弹幕里的“前方名场面”意味着？$$, $$["即将出现经典到被无数人铭记的片段", "前面有大量弹幕", "视频即将结束", "即将出现非常搞笑或震撼的镜头"]$$, $$[0, 3]$$, $$easy$$, $$名场面指值得反复观看的经典片段。$$, ARRAY[$$弹幕语$$,$$B站$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
