  ($$mem_035$$, $$网络梗知识$$, $$single$$, $$人们说的“海王”一词除了指代超级英雄外，常用来形容？$$, $$["捕鱼高手", "拥有众多暧昧备胎或同时交往多人的花心大萝卜", "游泳游得快的人", "海军指挥官"]$$, $$[1]$$, $$easy$$, $$“本以为游进了哥哥的鱼塘，没想到哥哥是个海王”，指广撒网、多线培养感情的人。$$, ARRAY[$$情感梗$$,$$人设$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_036$$, $$网络梗知识$$, $$single$$, $$在鬼畜视频中，葛平的哪句台词最为洗脑？$$, $$["我来组成头部", "我是超威蓝猫！", "你太不要脸了", "真香"]$$, $$[1]$$, $$medium$$, $$配音演员葛平早年曾在见面会上说“小朋友们大家好，我是配音演员葛平……我是超威蓝猫！”，成为中国鬼畜界鼻祖素材之一。$$, ARRAY[$$鬼畜文化$$,$$B站历史$$]::text[], $${"日子人": 1.0, "文学": 0.4, "历史学": 1.0, "军事学": 0.3}$$, 'batch'),
  ($$mem_037$$, $$网络梗知识$$, $$multiple$$, $$梗“年轻人耗子尾汁”中，“耗子尾汁”的意思是？$$, $$["老鼠尾巴流出的汁水", "好自为之", "劝告对方注意自己的行为", "一道菜名"]$$, $$[1, 2]$$, $$easy$$, $$马保国语录，“好自为之”的奇怪发音变成了“耗子尾汁”。$$, ARRAY[$$谐音梗$$,$$马保国语录$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_038$$, $$网络梗知识$$, $$single$$, $$有人对你说“给你加个鸡腿”代表？$$, $$["想请你吃饭", "认为你做得很棒，需要奖励", "嫌你太瘦", "要扣你工资"]$$, $$[1]$$, $$easy$$, $$剧组跑龙套演得好导演会加盒饭加鸡腿，引申为鼓励和嘉奖。$$, ARRAY[$$生活梗$$,$$表扬$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_039$$, $$网络梗知识$$, $$single$$, $$梗“岚语”源自哪个明星在综艺或直播里的言论风格？$$, $$["王一博", "秦岚", "张兰", "王耀庆"]$$, $$[2]$$, $$medium$$, $$秦岚因电视剧中声带受损产生独特的电音嗓，被称为“电音朵拉”或“岚语”。$$, ARRAY[$$明星梗$$,$$文娱$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
