  ($$mem_041$$, $$网络梗知识$$, $$multiple$$, $$经常用来回复“我很无聊/这也太扯了/什么情况”的表情包主角有？$$, $$["黑人问号", "流汗黄豆", "微笑", "狂笑柴犬"]$$, $$[0, 1, 2]$$, $$easy$$, $$问号脸、流汗黄豆、微信死亡微笑常代表无语、疑惑或敷衍。$$, ARRAY[$$表情包$$,$$网络礼仪$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_042$$, $$网络梗知识$$, $$single$$, $$缩写“gkd”代表什么？$$, $$["滚开点", "搞快点", "公开点", "高考试卷"]$$, $$[1]$$, $$easy$$, $$源于贴吧等论坛求资源时的急躁催促，意为“搞快点”。$$, ARRAY[$$缩写梗$$,$$拼音$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_043$$, $$网络梗知识$$, $$single$$, $$《甄嬛传》中，华妃的名台词“贱人就是____”？$$, $$["长情", "多情", "矫情", "无情"]$$, $$[2]$$, $$easy$$, $$“贱人就是矫情”成为了怼人装柔弱的经典表情包名言。$$, ARRAY[$$影视梗$$,$$电视剧名场面$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_044$$, $$网络梗知识$$, $$multiple$$, $$梗“电子电子榨菜”指的是什么？$$, $$["可以在手机上吃的咸菜", "吃饭时观看的能下饭的视频、文章或音频节目", "能够增加食欲的娱乐内容", "一种新型化肥"]$$, $$[1, 2]$$, $$easy$$, $$像榨菜一样用来下饭的电子视频内容，如《甄嬛传》、《武林外传》或热门探店视频。$$, ARRAY[$$生活梗$$,$$影视习惯$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_045$$, $$网络梗知识$$, $$single$$, $$当我们形容一个人“社恐”，在当下的网络环境更倾向于指？$$, $$["由于社会引起的恐怖", "社交恐惧症，不愿意出门社交、害怕社交场合", "反社会人格", "擅长恐吓别人"]$$, $$[1]$$, $$easy$$, $$缩写为“社交恐惧”，泛指不喜欢与人打交道的内向状态。$$, ARRAY[$$人群标签$$,$$缩写梗$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_046$$, $$网络梗知识$$, $$single$$, $$网络用语“集美”通常是哪个词的谐音？$$, $$["集中美丽", "姐妹", "集市买东西", "一种艺术品"]$$, $$[1]$$, $$easy$$, $$源于某网红发音不清，将粉丝“姐妹们”喊成“集美们”。$$, ARRAY[$$网红梗$$,$$谐音$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_047$$, $$网络梗知识$$, $$multiple$$, $$经常被网友评为“洗脑神曲”特征有哪些？$$, $$["旋律简单重复", "歌词魔性容易记住", "极度伤感深沉", "节奏感强"]$$, $$[0, 1, 3]$$, $$easy$$, $$洗脑神曲大多旋律和歌词重复度高、节奏感极强，让人听完脑内不断盘旋。$$, ARRAY[$$音乐梗$$,$$流行趋势$$]::text[], $${"艺术学": 1.0, "日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_048$$, $$网络梗知识$$, $$single$$, $$梗“雨女无瓜”的谐音意思其实是？$$, $$["下雨天女性没有瓜", "与你无关", "雨停了再吃瓜", "遇到女生没法吃瓜"]$$, $$[1]$$, $$easy$$, $$源自《巴啦啦小魔仙》游乐王子的口音“与你无关”。$$, ARRAY[$$谐音梗$$,$$童年回忆$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_049$$, $$网络梗知识$$, $$single$$, $$有人说“爷青回”，这表达了什么感情？$$, $$["爷爷的青春回来了", "爷的青春回来了", "又老了一岁", "长辈回来了"]$$, $$[1]$$, $$easy$$, $$看到曾经熟悉、喜欢的事物回归或重现，感叹自己的青春回忆又被唤醒了。$$, ARRAY[$$情感梗$$,$$怀旧$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$mem_050$$, $$网络梗知识$$, $$single$$, $$以下哪项是B站曾经的年度弹幕？$$, $$["破防了", "真香", "奥利给", "666"]$$, $$[0]$$, $$medium$$, $$“破防了”曾是B站2021年度弹幕，表示心理防线被攻破。$$, ARRAY[$$B站文化$$,$$年度词汇$$]::text[], $${"文学": 1.0, "历史学": 0.4, "日子人": 0.5}$$, 'batch'),
  ($$mil_001$$, $$现代军事常识$$, $$single$$, $$中国人民解放军现役军衔中，将官分为哪几个级别？$$, $$["上将、中将、少将、准将", "上将、中将、少将", "大将、上将、中将、少将", "元帅、将、校"]$$, $$[1]$$, $$medium$$, $$我军现行军衔制中，将官设上将、中将、少将三级。$$, ARRAY[$$军事常识$$,$$军衔$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_002$$, $$现代军事常识$$, $$single$$, $$现代战斗机通常所说的“五代机”的显著特征不包括？$$, $$["隐身能力", "超音速巡航", "超机动性", "自带核武器"]$$, $$[3]$$, $$medium$$, $$“4S”标准通常为隐形、超音速巡航、超机动性、超级信息优势，不必然带核武。$$, ARRAY[$$武器装备$$,$$战机$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.15}$$, 'batch'),
  ($$mil_003$$, $$现代军事常识$$, $$multiple$$, $$航空母舰的主要作战力量是？$$, $$["舰炮", "舰载机", "护航驱逐舰", "核动力系统"]$$, $$[1]$$, $$easy$$, $$航母的核心打击与防御力量是依附在其上的各种舰载机群。$$, ARRAY[$$海军$$,$$航母$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_004$$, $$现代军事常识$$, $$single$$, $$洲际弹道导弹（ICBM）的射程通常大于？$$, $$["1000公里", "3000公里", "5000公里", "8000公里"]$$, $$[3]$$, $$medium$$, $$国际上通常将射程大于8000公里的弹道导弹称为洲际弹道导弹。$$, ARRAY[$$战略武器$$,$$导弹$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.15}$$, 'batch'),
  ($$mil_005$$, $$现代军事常识$$, $$single$$, $$被誉为“陆战之王”的武器装备是？$$, $$["火炮", "主战坦克", "武装直升机", "步兵战车"]$$, $$[1]$$, $$easy$$, $$坦克集火力、防护和机动性于一身，被称为陆战之王。$$, ARRAY[$$陆军$$,$$坦克$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.15}$$, 'batch'),
  ($$mil_006$$, $$现代军事常识$$, $$single$$, $$GPS全球定位系统最初是哪个国家军方研发的？$$, $$["美国", "俄罗斯", "中国", "英国"]$$, $$[0]$$, $$easy$$, $$GPS由美国国防部研制和维护的全球卫星导航定位系统。$$, ARRAY[$$卫星导航$$,$$军史$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "历史学": 0.15}$$, 'batch'),
  ($$mil_007$$, $$现代军事常识$$, $$multiple$$, $$核武器“三位一体”核打击能力指的是能够通过哪些平台发射核武器？$$, $$["陆基洲际导弹", "战略核潜艇", "战略轰炸机", "太空空间站"]$$, $$[0, 1, 2]$$, $$medium$$, $$陆基导弹、海基核潜艇与空基战略轰炸机构成了三位一体核力量。$$, ARRAY[$$战略威慑$$,$$核武器$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 1.0, "历史学": 0.15}$$, 'batch'),
  ($$mil_008$$, $$现代军事常识$$, $$single$$, $$现代海军舰艇用来探测水下目标（如潜艇）的主要设备是？$$, $$["雷达", "激光测距仪", "声呐", "磁探仪"]$$, $$[2]$$, $$easy$$, $$海水对电磁波衰减极大，声波在水中传播远，因此声呐是探测水下目标的核心设备。$$, ARRAY[$$反潜$$,$$声呐$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_009$$, $$现代军事常识$$, $$single$$, $$我国自己研制的大型军用运输机代号是？$$, $$["运-8", "运-9", "运-20", "伊尔-76"]$$, $$[2]$$, $$medium$$, $$运-20（代号：胖妞）是中国自主研发的新一代军用大型运输机。$$, ARRAY[$$中国军工$$,$$空军$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_010$$, $$现代军事常识$$, $$multiple$$, $$在现代军事概念中，C4ISR系统首字母C代表的四项是指什么？$$, $$["Command", "Control", "Communications", "Computers"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$C4代表指挥、控制、通信、计算机；ISR代表情报、监视、侦察。$$, ARRAY[$$军事现代化$$,$$信息化战略$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_011$$, $$现代军事常识$$, $$single$$, $$巡航导弹与弹道导弹的主要区别在于？$$, $$["威力更大", "飞行轨迹一直处于大气层内并且有翼面提供升力", "只能发射核弹", "速度突破第一宇宙速度"]$$, $$[1]$$, $$medium$$, $$巡航导弹依靠空气动力在大气层内飞行，可贴地飞行躲避雷达，而弹道导弹大部分轨迹在大气层外。$$, ARRAY[$$导弹技术$$,$$装备原理$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.15}$$, 'batch'),
  ($$mil_012$$, $$现代军事常识$$, $$single$$, $$“隐身战机”能够“隐身”的主要原理是？$$, $$["肉眼看不见", "雷达波反射面积极小", "不发出声音", "不会被红外线探测"]$$, $$[1]$$, $$medium$$, $$主要通过外形设计和吸波涂层，使敌方雷达接收到的回波极弱。$$, ARRAY[$$隐身技术$$,$$战斗机$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_013$$, $$现代军事常识$$, $$multiple$$, $$下列哪些属于大规模杀伤性武器(WMD)？$$, $$["核武器", "生物武器", "化学武器", "常规高爆航弹"]$$, $$[0, 1, 2]$$, $$easy$$, $$核生化(NBC)武器属于大规模杀伤性武器，公约严厉限制其使用。$$, ARRAY[$$WMD$$,$$军控$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_014$$, $$现代军事常识$$, $$single$$, $$潜艇在水下潜航时补充氧气并排放废气或充电，可使用的伸出水面的管子叫？$$, $$["潜望镜", "通气管", "排气扇", "声纳浮标"]$$, $$[1]$$, $$medium$$, $$通气管可以让常规潜艇在水下较浅深度运转柴油机充电和换气。$$, ARRAY[$$潜艇$$,$$海军装备$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_015$$, $$现代军事常识$$, $$single$$, $$世界两大主要的卫星导航系统除了美国的GPS外，中国的是？$$, $$["格洛纳斯", "伽利略", "北斗卫星导航系统", "天通一号"]$$, $$[2]$$, $$easy$$, $$中国自主建设的全球卫星导航系统名为北斗（BDS）。$$, ARRAY[$$北斗导航$$,$$航天$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "历史学": 0.15}$$, 'batch'),
  ($$mil_016$$, $$现代军事常识$$, $$multiple$$, $$装甲车辆防护手段除了增加装甲厚度，现代主流坦克通常还会安装什么来防破甲弹？$$, $$["反应装甲", "复合装甲", "主动防御系统", "木头假人"]$$, $$[0, 1, 2]$$, $$hard$$, $$反应装甲内部有炸药可炸乱射流、复合装甲拥有更强物理抗性，主动防御可提前拦截弹药。$$, ARRAY[$$装甲防护$$,$$坦克$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.15}$$, 'batch'),
  ($$mil_017$$, $$现代军事常识$$, $$single$$, $$现代精确制导武器被广泛称为？$$, $$["地毯式轰炸武器", "智能弹药/精确制导弹药", "生化弹药", "破片杀伤弹"]$$, $$[1]$$, $$easy$$, $$利用制导系统直接命中目标，大大减少了火力浪费和附带损伤。$$, ARRAY[$$精确制导$$,$$现代战争$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.5, "工学": 0.3, "理学": 0.15}$$, 'batch'),
  ($$mil_018$$, $$现代军事常识$$, $$single$$, $$目前世界上排水量最大、搭载舰载机最多的现役航空母舰级别属于哪个国家？$$, $$["俄罗斯", "英国", "中国", "美国"]$$, $$[3]$$, $$easy$$, $$美国海军的福特级和尼米兹级核动力航空母舰是现今满载排水量最巨大的级别。$$, ARRAY[$$海军$$,$$航母霸权$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_019$$, $$现代军事常识$$, $$multiple$$, $$中国人民解放军的三大条令是指？$$, $$["内务条令", "纪律条令", "队列条令", "作战条令"]$$, $$[0, 1, 2]$$, $$easy$$, $$三大条令分别是内务、纪律、队列条令，是军队正规化建设基本法规。$$, ARRAY[$$建军原则$$,$$部队条令$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_020$$, $$现代军事常识$$, $$single$$, $$军用直升机按照用途划分，专门用来对地攻击的称为？$$, $$["运输直升机", "武装直升机", "搜救直升机", "预警直升机"]$$, $$[1]$$, $$easy$$, $$如阿帕奇、武直-10，专门挂载反坦克导弹、火箭弹进行近地火力支援。$$, ARRAY[$$陆航$$,$$直升机$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_021$$, $$现代军事常识$$, $$single$$, $$核潜艇之所以被称为“战略大杀器”，其最突出的优势在于？$$, $$["航速快", "造价便宜", "潜航时间极长、隐蔽性极高", "载员多"]$$, $$[2]$$, $$medium$$, $$核动力不需要空气，可以极长时间在深海潜伏并随时发起毁灭性打击。$$, ARRAY[$$核威慑$$,$$海军战术$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.5, "历史学": 0.15}$$, 'batch'),
  ($$mil_022$$, $$现代军事常识$$, $$multiple$$, $$现代空战中最常用的空对空导弹制导方式有哪几种？$$, $$["红外寻的制导", "雷达制导", "线导", "星光制导"]$$, $$[0, 1]$$, $$hard$$, $$近距格斗弹多用红外制导，中距拦截弹多用主动或半主动雷达制导。$$, ARRAY[$$空战$$,$$导弹制导$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.15}$$, 'batch'),
  ($$mil_023$$, $$现代军事常识$$, $$single$$, $$在排雷防爆任务中，扫雷兵穿的厚重特殊服装叫什么？$$, $$["防弹衣", "宇航服", "排爆服", "防火服"]$$, $$[2]$$, $$easy$$, $$排爆服能防御炸弹爆炸产生的破片、冲击波和高温火焰，极为厚重。$$, ARRAY[$$扫雷工程$$,$$排爆$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_024$$, $$现代军事常识$$, $$single$$, $$无人机（UAV）在现代战争中大放异彩，其主要优势不包括什么？$$, $$["零人员伤亡风险", "持续侦查留空时间长", "能像货机一样运载步兵突击", "造价及维护成本往往更低"]$$, $$[2]$$, $$medium$$, $$无人机体积和属性决定目前主要用于情报、监视、精确打击，不用于大规模人员输送。$$, ARRAY[$$无人机作战$$,$$新型装备$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_025$$, $$现代军事常识$$, $$multiple$$, $$现代突击步枪通常具有哪些特点？$$, $$["发射中间型威力枪弹/小口径步枪弹", "能够实施全自动火力射击", "重量在3-4公斤便于携行", "枪膛内没有任何膛线"]$$, $$[0, 1, 2]$$, $$medium$$, $$突击步枪结合了冲锋枪的猛烈火力和步枪的威力，有膛线，使用新型枪弹。$$, ARRAY[$$轻武器$$,$$单兵装备$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.15}$$, 'batch'),
  ($$mil_026$$, $$现代军事常识$$, $$single$$, $$防弹背心内部主要的防弹材料层通常使用的是什么特殊纤维？$$, $$["纯棉帆布", "凯夫拉纤维或超高分子量聚乙烯", "玻璃纤维", "普通尼龙"]$$, $$[1]$$, $$medium$$, $$凯夫拉(芳纶)或UHMWPE纤维具有高抗张强度，能吸收和耗散子弹动能。$$, ARRAY[$$防护材料$$,$$单兵防具护甲$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "历史学": 0.15}$$, 'batch'),
  ($$mil_027$$, $$现代军事常识$$, $$single$$, $$火箭军（原第二炮兵）是中国人民解放军的什么军种？$$, $$["陆军防空兵", "特种部队", "战略导弹部队核心力量", "防化部队"]$$, $$[2]$$, $$easy$$, $$中国人民解放军火箭军负责中国战略威慑与核常兼备的导弹库打击能力。$$, ARRAY[$$火箭军$$,$$兵种常识$$]::text[], $${"工学": 1.0, "理学": 0.8, "军事学": 0.5, "历史学": 0.15}$$, 'batch'),
  ($$mil_028$$, $$现代军事常识$$, $$multiple$$, $$预警机在空战中的主要作用是？$$, $$["充当空中指挥所", "利用大型雷达远程探测敌方目标", "空投炸弹", "为空战机群提供数据链指挥"]$$, $$[0, 1, 3]$$, $$medium$$, $$预警机俗称“空中帅印”，携带庞大雷达并协调指挥战机，自身通常不载炸弹。$$, ARRAY[$$空战体系$$,$$预警机$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_029$$, $$现代军事常识$$, $$single$$, $$军事演习中用来代表假想敌“红军的对手”通常被称为什么军？$$, $$["白军", "蓝军", "紫军", "黑军"]$$, $$[1]$$, $$easy$$, $$我军及许多国家演习中，红军代表己方部队，蓝军代表假想敌部队。$$, ARRAY[$$军事演习$$,$$对抗常识$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$mil_030$$, $$现代军事常识$$, $$single$$, $$近防炮（如中国的1130近防炮或美国的密集阵）主要用于？$$, $$["远程轰炸岸边", "末端拦截来袭的反舰导弹", "对轰潜艇", "发射鱼雷"]$$, $$[1]$$, $$medium$$, $$近程防御武器系统依靠极高的射速形成弹幕，是舰艇最后的反导防御防线。$$, ARRAY[$$海军系统$$,$$防空武器$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "历史学": 0.15}$$, 'batch'),
  ($$mov_001$$, $$电影与戏剧$$, $$single$$, $$1895年，一般被公认为放映了世界第一批电影，标志着电影正式诞生的法国兄弟是？$$, $$["莱特兄弟", "卢米埃尔兄弟", "蒙哥尔费兄弟", "格林兄弟"]$$, $$[1]$$, $$easy$$, $$奥古斯特·卢米埃尔和路易·卢米埃尔兄弟在巴黎首映影片（如《火车进站》），被视为现代电影纪元的开始。$$, ARRAY[$$电影史$$,$$诞生$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_002$$, $$电影与戏剧$$, $$single$$, $$美国电影艺术与科学学院奖通常被简称为什么奖？这是全球电影界最高荣誉之一。$$, $$["金球奖", "金熊奖", "奥斯卡金像奖", "戛纳金棕榈奖"]$$, $$[2]$$, $$easy$$, $$奥斯卡奖即美国电影艺术与科学学院奖（Academy Awards）。$$, ARRAY[$$电影奖项$$,$$奥斯卡$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_003$$, $$电影与戏剧$$, $$single$$, $$在戏剧史上，创作了《哈姆雷特》、《罗密欧与朱丽叶》等传世悲剧的英国伟大剧作家是？$$, $$["萧伯纳", "莎士比亚", "莫里哀", "奥斯卡·王尔德"]$$, $$[1]$$, $$easy$$, $$威廉·莎士比亚是文艺复兴时期欧洲最伟大的戏剧家。$$, ARRAY[$$戏剧史$$,$$莎士比亚$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_004$$, $$电影与戏剧$$, $$single$$, $$拍摄了《阿凡达》、《泰坦尼克号》，并在电影技术（3D、特效）上屡创革命的导演是？$$, $$["史蒂文·斯皮尔伯格", "克里斯托弗·诺兰", "詹姆斯·卡梅隆", "彼得·杰克逊"]$$, $$[2]$$, $$easy$$, $$詹姆斯·卡梅隆导演的这两部作品均长踞全球影史票房榜首。$$, ARRAY[$$导演$$,$$商业电影$$]::text[], $${"管理学": 1.0, "经济学": 0.6, "艺术学": 0.5, "文学": 0.2}$$, 'batch'),
  ($$mov_005$$, $$电影与戏剧$$, $$single$$, $$常常被视为黑色幽默、非线性叙事大师，代表作有《低俗小说》(Pulp Fiction) 的美国导演是？$$, $$["昆汀·塔伦蒂诺", "马丁·斯科塞斯", "科波拉", "大卫·芬奇"]$$, $$[0]$$, $$medium$$, $$昆汀·塔伦蒂诺以其极具风格的暴力美学、环形叙事和大量致敬流行文化的元素著称。$$, ARRAY[$$导演$$,$$昆汀$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_006$$, $$电影与戏剧$$, $$single$$, $$电影《千与千寻》、《龙猫》的导演，日本吉卜力工作室的核心创办人是？$$, $$["新海诚", "宫崎骏", "庵野秀明", "押井守"]$$, $$[1]$$, $$easy$$, $$宫崎骏是全球最著名的动画电影大师之一，其作品风格深邃且画面优美。$$, ARRAY[$$动画电影$$,$$吉卜力$$]::text[], $${"艺术学": 1.0, "历史学": 0.2, "文学": 0.2}$$, 'batch'),
  ($$mov_007$$, $$电影与戏剧$$, $$single$$, $$在经典戏剧理论中，源自古希腊的亚里士多德《诗学》，要求戏剧剧情的时间、地点、情节保持高度一致性，这被称为？$$, $$["三一律", "第四面墙", "间离效果", "斯坦尼斯拉夫斯基体系"]$$, $$[0]$$, $$medium$$, $$三一律（Three Unities）要求一出戏只能有一个主要情节，发生在同一地点，在一天内完成。$$, ARRAY[$$戏剧理论$$,$$三一律$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 0.5, "文学": 0.2}$$, 'batch'),
  ($$mov_008$$, $$电影与戏剧$$, $$single$$, $$常常被表演系学生奉为圭臬的“体验派”表演体系（要求演员从内心真实体验角色情感）是由哪位戏剧大师建立的？$$, $$["布莱希特", "梅耶荷德", "斯坦尼斯拉夫斯基", "契诃夫"]$$, $$[2]$$, $$hard$$, $$斯坦尼斯拉夫斯基体系是现代现实主义表演艺术的基础，对好莱坞“方法派”亦有深远影响。$$, ARRAY[$$表演体系$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_009$$, $$电影与戏剧$$, $$single$$, $$1927年推出的《爵士歌手》(The Jazz Singer) 在电影史上具有里程碑意义的原因是？$$, $$["它是第一部彩色电影", "它是第一部有声商业长片电影", "它是第一部票房破亿的电影", "它是第一部完全数字拍摄的电影"]$$, $$[1]$$, $$medium$$, $$《爵士歌手》利用Vitaphone技术实现了同步声音和部分对白，标志着无声电影时代的终结起步。$$, ARRAY[$$电影史$$,$$有声电影$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_010$$, $$电影与戏剧$$, $$single$$, $$电影蒙太奇（Montage）技术，即通过不同镜头的剪辑拼接产生出新的含义，这一理论主要是在哪个国家的电影运动中被高度发展和系统化的？$$, $$["美国", "法国", "苏联", "意大利"]$$, $$[2]$$, $$hard$$, $$苏联蒙太奇学派（如爱森斯坦的《战舰波将金号》和库里肖夫效应）在电影语法上做出了革命性贡献。$$, ARRAY[$$电影理论$$,$$蒙太奇$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 0.5, "文学": 0.2}$$, 'batch'),
  ($$mov_011$$, $$电影与戏剧$$, $$single$$, $$被誉为中国戏曲最高成就之一的“昆曲”发源于我国的哪个地区？$$, $$["北京", "四川", "江苏昆山一带", "河南"]$$, $$[2]$$, $$medium$$, $$昆曲发源于元末明初的江苏苏州昆山一带，被称为“百戏之祖”。$$, ARRAY[$$中国戏曲$$,$$昆曲$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_012$$, $$电影与戏剧$$, $$single$$, $$电影《霸王别姬》、《活着》的导演是？$$, $$["张艺谋", "陈凯歌", "冯小刚", "李安"]$$, $$[1]$$, $$easy$$, $$陈凯歌执导的《霸王别姬》荣获1993年戛纳金棕榈奖，是中国影史丰碑之作。$$, ARRAY[$$华语电影$$,$$第五代导演$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_013$$, $$电影与戏剧$$, $$single$$, $$科幻史诗巨作《银翼杀手》(Blade Runner，1982) 与《异形》(Alien) 的导演是？$$, $$["雷德利·斯科特", "史蒂文·斯皮尔伯格", "乔治·卢卡斯", "丹尼斯·维伦纽瓦"]$$, $$[0]$$, $$medium$$, $$英国导演雷德利·斯科特（Ridley Scott）凭借这两部电影及后续的《角斗士》享誉全球。$$, ARRAY[$$科幻电影$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_014$$, $$电影与戏剧$$, $$single$$, $$以下哪一部电影不属于弗朗西斯·福特·科波拉执导的经典黑帮题材系列？$$, $$["《教父 1》", "《教父 2》", "《教父 3》", "《美国往事》"]$$, $$[3]$$, $$medium$$, $$《美国往事》(Once Upon a Time in America) 是赛尔乔·莱昂内执导的经典黑帮电影。$$, ARRAY[$$经典电影$$,$$黑帮片$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_015$$, $$电影与戏剧$$, $$single$$, $$戏剧舞台术语中的“打破第四面墙”是指？$$, $$["一种真实的舞美爆破特效", "剧场没有后墙，向露天开放", "演员与观众直接交流，打破了假想中的隔离屏障", "谢幕时全体鞠躬"]$$, $$[2]$$, $$easy$$, $$第四面墙是传统镜框式舞台观众与演员之间那道看不见的墙。打破它意味着角色跳出虚构环境与现实观众互动。$$, ARRAY[$$戏剧术语$$,$$表现手法$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_016$$, $$电影与戏剧$$, $$multiple$$, $$欧洲三大国际电影节是指？$$, $$["法国戛纳国际电影节", "德国柏林国际电影节", "意大利威尼斯国际电影节", "日本东京国际电影节"]$$, $$[0, 1, 2]$$, $$easy$$, $$戛纳（金棕榈）、柏林（金熊）和威尼斯（金狮）并称为欧洲三大电影节、世界三大艺术电影节。$$, ARRAY[$$电影节$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_017$$, $$电影与戏剧$$, $$multiple$$, $$现代电影拍摄中，为了呈现特定视觉效果，常用到的技术有？$$, $$["CGI", "动作捕捉", "绿幕/蓝幕抠像技术", "停止所有胶片洗影"]$$, $$[0, 1, 2]$$, $$easy$$, $$现代特效大量依赖CGI、动捕和绿幕抠像。胶片洗影只是传统洗印流程，现在多用数字格式，且停止洗影不等于一种视觉技术。$$, ARRAY[$$电影技术$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_018$$, $$电影与戏剧$$, $$multiple$$, $$世界三大古老戏剧文化通常指的是？$$, $$["古希腊悲喜剧", "印度梵剧", "中国戏曲", "美国百老汇音乐剧"]$$, $$[0, 1, 2]$$, $$hard$$, $$古希腊剧、印度梵剧和中国戏曲（汉族）被称为世界三大古老戏剧文化。百老汇是近现代娱乐形式。$$, ARRAY[$$戏剧史$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_019$$, $$电影与戏剧$$, $$multiple$$, $$黑泽明是日本最伟大的电影天皇之一。以下哪些电影是他的执导作品？$$, $$["《罗生门》", "《七武士》", "《乱》", "《东京物语》"]$$, $$[0, 1, 2]$$, $$medium$$, $$《东京物语》是另一位日本影史大师小津安二郎的代表作。$$, ARRAY[$$外国电影$$,$$黑泽明$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mov_020$$, $$电影与戏剧$$, $$multiple$$, $$中国传统的国粹“京剧”，其角色的基本行当按照性别、年龄、性格、身份等划分为哪四大类？$$, $$["生", "旦", "净", "丑"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$生旦净丑是京剧最基础的四大行当（其中生是男性，旦是女性，净是花脸，丑是喜剧角色）。$$, ARRAY[$$中国戏曲$$,$$京剧$$]::text[], $${"艺术学": 1.0, "文学": 0.4}$$, 'batch'),
  ($$mus_001$$, $$音乐常识$$, $$single$$, $$被誉为“音乐之父”，其复调音乐作品达到了古典对位法巅峰的德国作曲家是？$$, $$["莫扎特", "贝多芬", "巴赫", "柴可夫斯基"]$$, $$[2]$$, $$easy$$, $$约翰·塞巴斯蒂安·巴赫是巴洛克时期的集大成者，被尊称为“西方音乐之父”。$$, ARRAY[$$巴洛克音乐$$,$$巴赫$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_002$$, $$音乐常识$$, $$single$$, $$维也纳古典乐派的代表人物之一，以其极高天赋被称为“音乐神童”的奥地利作曲家是？$$, $$["舒伯特", "李斯特", "贝多芬", "莫扎特"]$$, $$[3]$$, $$easy$$, $$沃尔夫冈·阿玛多伊斯·莫扎特展现出了惊人的早慧天赋，是古典主义时期最重要的作曲家之一。$$, ARRAY[$$古典主义$$,$$莫扎特$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 1.0}$$, 'batch'),
  ($$mus_003$$, $$音乐常识$$, $$single$$, $$创作了《第五交响曲（命运）》、《第九交响曲（合唱）》，在双耳失聪后仍坚持创作的音乐巨匠是？$$, $$["肖邦", "勃拉姆斯", "贝多芬", "瓦格纳"]$$, $$[2]$$, $$easy$$, $$路德维希·凡·贝多芬是古典主义向浪漫主义过渡的核心人物，其《命运》交响曲举世闻名。$$, ARRAY[$$古典主义$$,$$贝多芬$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 1.0}$$, 'batch'),
  ($$mus_004$$, $$音乐常识$$, $$single$$, $$被誉为“钢琴诗人”的浪漫主义时期波兰著名作曲家是？$$, $$["肖邦", "李斯特", "门德尔松", "舒曼"]$$, $$[0]$$, $$easy$$, $$弗雷德里克·肖邦的绝大部分作品都是为钢琴创作的，充满了诗意与细腻的情感。$$, ARRAY[$$浪漫主义$$,$$肖邦$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 0.5}$$, 'batch'),
  ($$mus_005$$, $$音乐常识$$, $$single$$, $$以炫技著称，被称为“钢琴之王”的匈牙利作曲家是？$$, $$["肖邦", "弗朗茨·李斯特", "拉赫玛尼诺夫", "帕格尼尼"]$$, $$[1]$$, $$medium$$, $$李斯特不仅是伟大的作曲家，更是拥有无与伦比炫技能力的钢琴家。$$, ARRAY[$$浪漫主义$$,$$李斯特$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 0.5}$$, 'batch'),
  ($$mus_006$$, $$音乐常识$$, $$single$$, $$创作了百年经典芭蕾舞剧《天鹅湖》、《胡桃夹子》的俄国作曲家是？$$, $$["柴可夫斯基", "斯特拉文斯基", "肖斯塔科维奇", "林姆斯基-高沙可夫"]$$, $$[0]$$, $$easy$$, $$柴可夫斯基的音乐极具旋律优美感和俄罗斯民族风情，是古典芭蕾音乐的巅峰。$$, ARRAY[$$俄罗斯音乐$$,$$柴可夫斯基$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_007$$, $$音乐常识$$, $$single$$, $$西洋乐器中的“乐器之王”通常指的是哪一种键盘乐器？$$, $$["小提琴", "管风琴", "钢琴", "大竖琴"]$$, $$[2]$$, $$easy$$, $$钢琴音域宽广、表现力丰富，既能担任独奏，也能作为伴奏或协奏，被称为乐器之王。（管风琴音量巨大但不若钢琴普及）$$, ARRAY[$$乐器$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_008$$, $$音乐常识$$, $$single$$, $$小提琴（Violin）在交响乐团中属于哪个乐器组？$$, $$["木管乐器组", "铜管乐器组", "弦乐器组", "打击乐器组"]$$, $$[2]$$, $$easy$$, $$无论是小提琴、中提琴还是大提琴、低音提琴，均通过琴弓摩擦琴弦发声，属于弦乐器(Strings)。$$, ARRAY[$$交响乐团$$,$$编制$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_009$$, $$音乐常识$$, $$single$$, $$流行音乐中，“R&B”全称是Rhythm and Blues，它的中文译名通常是？$$, $$["摇滚乐", "节奏布鲁斯", "说唱乐", "乡村音乐"]$$, $$[1]$$, $$easy$$, $$R&B结合了爵士乐、福音音乐和布鲁斯音乐的特点，译为节奏布鲁斯。$$, ARRAY[$$流行音乐$$,$$R&B$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_010$$, $$音乐常识$$, $$single$$, $$以下哪种记谱法使用五条平行的横线，通过不同形状和位置的符号来记录音高和节奏？$$, $$["简谱", "工尺谱", "五线谱", "吉他六线谱"]$$, $$[2]$$, $$easy$$, $$五线谱是目前世界上通行最广的记录带音高和节奏音乐的记谱系统。$$, ARRAY[$$音乐基础$$,$$记谱法$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_011$$, $$音乐常识$$, $$single$$, $$现代标准的交响乐团中，通常不包含下列哪种乐器作为常驻标准编制？$$, $$["长笛", "圆号", "电吉他", "定音鼓"]$$, $$[2]$$, $$easy$$, $$电吉他是现代流行/摇滚乐队的常见配置，很少作为古典交响乐团的常驻标准编制。$$, ARRAY[$$交响乐团$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_012$$, $$音乐常识$$, $$single$$, $$通常我们所称的“美声唱法”源自哪个国家的Bel Canto？$$, $$["意大利", "法国", "德国", "俄罗斯"]$$, $$[0]$$, $$medium$$, $$Bel Canto意为“美丽的歌唱”，起源于17世纪的意大利，是声乐艺术的重要流派。$$, ARRAY[$$声乐$$,$$美声$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_013$$, $$音乐常识$$, $$single$$, $$中国古代十大名曲之一的《高山流水》其背后典故与哪两个历史人物的知音之交有关？$$, $$["伯牙与钟子期", "管仲与鲍叔牙", "嵇康与鲍照", "孔子与颜回"]$$, $$[0]$$, $$medium$$, $$伯牙善鼓琴，钟子期善听，二人成就了“高山流水觅知音”的千古佳话。$$, ARRAY[$$中国古典音乐$$,$$古琴曲$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_014$$, $$音乐常识$$, $$single$$, $$音乐的“三要素”指的是？$$, $$["音高、音长、音色", "旋律、和声、节奏", "独奏、重奏、交响", "作词、作曲、编曲"]$$, $$[1]$$, $$medium$$, $$一般认为，构成西方传统调性音乐最基本的三个层次是旋律(Melody)、节奏(Rhythm)与和声(Harmony)。$$, ARRAY[$$音乐理论$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 1.0}$$, 'batch'),
  ($$mus_015$$, $$音乐常识$$, $$single$$, $$在五线谱开头，常用一个形似“花体G”的符号来确定中央C左侧G音的位置。这个符号被称为？$$, $$["低音谱号", "中音谱号", "高音谱号", "休止符"]$$, $$[2]$$, $$medium$$, $$高音谱号（Treble Clef/G-clef）常用于提琴、长笛等高音乐器的记谱。$$, ARRAY[$$乐理$$,$$谱号$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_016$$, $$音乐常识$$, $$single$$, $$被普遍认为是第一部真正意义上的西方歌剧，由蒙特威尔第创作的是？$$, $$["《魔笛》", "《卡门》", "《奥菲欧》", "《游吟诗人》"]$$, $$[2]$$, $$hard$$, $$首演于1607年的《奥菲欧》被认为是音乐史上第一部成熟的歌剧杰作。$$, ARRAY[$$歌剧$$,$$蒙特威尔第$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_017$$, $$音乐常识$$, $$single$$, $$“十二平均律”是把一个八度音程平均分为十二个半音。西方最早系统论述并在键盘乐器上实践这一调律方法的是巴赫，而在中国古代，则是由明代哪位皇家学者最先提出了精确的数学计算结果？$$, $$["沈括", "朱载堉", "宋应星", "徐光启"]$$, $$[1]$$, $$hard$$, $$明代律学家朱载堉在其《律学新说》中，首创了基于“新法密率”的十二平均律计算方法。$$, ARRAY[$$音乐史$$,$$十二平均律$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_018$$, $$音乐常识$$, $$single$$, $$德彪西（Debussy）的音乐因其朦胧、模糊的和声与色彩描写，常常被称为哪个流派的代表？$$, $$["古典主义音乐", "表现主义音乐", "印象主义音乐", "电子音乐"]$$, $$[2]$$, $$hard$$, $$正如绘画中的印象派，德彪西在音乐上摆脱调性束缚，通过音响色彩创作了印象主义音乐（如《牧神午后前奏曲》）。$$, ARRAY[$$印象主义$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 0.5}$$, 'batch'),
  ($$mus_019$$, $$音乐常识$$, $$single$$, $$标准钢琴共有多少个琴键？$$, $$["61个", "76个", "88个", "101个"]$$, $$[2]$$, $$medium$$, $$现代标准大钢琴有88个琴键（52个白键和36个黑键）。$$, ARRAY[$$乐器$$,$$钢琴$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_020$$, $$音乐常识$$, $$multiple$$, $$古典四大乐派中，通常所说的“维也纳古典乐派”三大代表人物包括？$$, $$["海顿", "莫扎特", "贝多芬", "巴赫"]$$, $$[0, 1, 2]$$, $$easy$$, $$海顿（交响乐之父）、莫扎特和贝多芬并称维也纳古典乐派三杰。巴赫是更早的巴洛克时期。$$, ARRAY[$$古典主义$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "艺术学": 0.5}$$, 'batch'),
  ($$mus_021$$, $$音乐常识$$, $$multiple$$, $$管弦乐团中（Orchestra），下列哪些乐器属于“木管乐器组”(Woodwinds)？$$, $$["双簧管", "单簧管", "长笛", "长号"]$$, $$[0, 1, 2]$$, $$medium$$, $$长号（以及圆号、小号、大号）是通过嘴唇震动金属吹嘴发声的，属于铜管乐器组(Brass)。$$, ARRAY[$$乐器编制$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_022$$, $$音乐常识$$, $$multiple$$, $$爵士乐（Jazz）是19世纪末20世纪初发祥于美国的一种独特的音乐体系。其最核心的音乐特征通常包括？$$, $$["即兴演奏", "切分音和摇摆节奏", "严格按谱一成不变", "布鲁斯音阶"]$$, $$[0, 1, 3]$$, $$medium$$, $$爵士乐的灵魂在于自由即兴，绝非死板地遵守谱面。$$, ARRAY[$$音乐类型$$,$$爵士乐$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_023$$, $$音乐常识$$, $$multiple$$, $$人声声乐的分类通常按照音区来划分。成年人的基本声部包括？$$, $$["女高音", "女中音 / 女低音", "男高音", "男中音 / 男低音"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$这是标准的混声合唱或歌剧声部全覆盖划分。$$, ARRAY[$$声乐分类$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_024$$, $$音乐常识$$, $$multiple$$, $$著名歌剧《图兰朵》(Turandot) 的相关事实包括？$$, $$["由意大利作曲家普契尼创作", "故事背景设定在中国古代", "名曲《今夜无人入睡》 出自此歌剧", "它是一部摇滚音乐剧"]$$, $$[0, 1, 2]$$, $$hard$$, $$《图兰朵》是普契尼的经典传统歌剧杰作，不是现代摇滚音乐剧。$$, ARRAY[$$歌剧$$,$$普契尼$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$mus_025$$, $$音乐常识$$, $$multiple$$, $$下列关于音乐体裁的描述，正确的有？$$, $$["奏鸣曲通常是为一两件乐器创作的室内乐", "协奏曲通常指一件或多件独奏乐器与管弦乐团协同演奏的曲目", "交响曲是由大型管弦乐队演奏的大型套曲", "进行曲通常只有极其缓慢悲伤的节奏"]$$, $$[0, 1, 2]$$, $$hard$$, $$进行曲最初为军队行进伴奏，节奏一般威武雄壮、步伐坚定（通常为2/4或4/4拍），并不总是缓慢悲伤。$$, ARRAY[$$音乐体裁$$]::text[], $${"艺术学": 1.0}$$, 'batch'),
  ($$myt_001$$, $$神话与民间传说$$, $$single$$, $$希腊神-0-话中的众神之王是？$$, $$["阿波罗", "波塞冬", "宙斯", "哈迪斯"]$$, $$[2]$$, $$easy$$, $$宙斯是奥林匹斯山的主宰。$$, ARRAY[$$希腊神话$$,$$神祇$$]::text[], $${"文学": 0.8, "历史学": 0.6, "哲学": 0.4}$$, 'batch'),
  ($$myt_002$$, $$神话与民间传说$$, $$single$$, $$北欧神-1-话中，标志着世界末日的灾难被称为？$$, $$["诸神黄昏", "诺亚方舟", "大洪水", "末日审判"]$$, $$[0]$$, $$easy$$, $$诸神黄昏(Ragnarök)带来众神陨落与世界毁灭。$$, ARRAY[$$北欧神话$$,$$末日$$]::text[], $${"文学": 0.8, "历史学": 0.6, "哲学": 0.4}$$, 'batch'),
  ($$myt_003$$, $$神话与民间传说$$, $$multiple$$, $$下列哪-2-些属于中国上古神话中的创世/救世人物？$$, $$["盘古", "女娲", "伏羲", "共工"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$这些均是中国神话初期的核心神祇。$$, ARRAY[$$中国神话$$,$$创世$$]::text[], $${"文学": 0.8, "历史学": 0.6, "哲学": 0.4}$$, 'batch'),
