  ($$nch_001$$, $$一些猎奇小众知识$$, $$single$$, $$在桌面角色扮演游戏（TRPG）中，“DND”通常是指什么规则？$$, $$["龙与地下城", "黑暗与死亡", "命运与骰子", "黑夜传说"]$$, $$[0]$$, $$easy$$, $$DND是史上最著名的TRPG系统。$$, ARRAY[$$TRPG$$,$$DND$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_002$$, $$一些猎奇小众知识$$, $$single$$, $$克苏鲁呼唤（COC）跑团中，玩家最害怕失去的属性通常是哪一个（归零会导致角色发疯）？$$, $$["力量", "理智值", "敏捷", "体质"]$$, $$[1]$$, $$easy$$, $$SAN值（Sanity）掉光意味着调查员陷入永久疯狂，通常游戏结束。$$, ARRAY[$$TRPG$$,$$COC$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_003$$, $$一些猎奇小众知识$$, $$multiple$$, $$在跑团中，负责设计剧情、扮演NPC、裁定规则的主持人通常被称为？$$, $$["KP", "DM", "GM", "PC"]$$, $$[0, 1, 2]$$, $$easy$$, $$GM是统称，DM是DND特有，KP是COC特有。PC是玩家。$$, ARRAY[$$TRPG$$,$$术语$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_004$$, $$一些猎奇小众知识$$, $$single$$, $$TRPG中常说的“车卡”是指什么行为？$$, $$["偷走别人的角色", "开车旅行", "创建新角色卡", "结束游戏"]$$, $$[2]$$, $$easy$$, $$车卡指的是根据规则填写角色属性面板。$$, ARRAY[$$TRPG$$,$$术语$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_005$$, $$一些猎奇小众知识$$, $$single$$, $$DND 5E规则中，最核心用于检定是否成功的骰子是哪一种？$$, $$["d4", "d6", "d10", "d20"]$$, $$[3]$$, $$easy$$, $$20面骰（d20）是判定攻击、技能、豁免的核心骰子。$$, ARRAY[$$TRPG$$,$$DND$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_006$$, $$一些猎奇小众知识$$, $$single$$, $$跑团俗语中，“大成功”在COC规则（百分骰）下通常是指掷出了什么数字？$$, $$["100", "01", "50", "20"]$$, $$[1]$$, $$medium$$, $$在COC的百分骰向下检定中，越低越好，1通常是大成功。DND则是20大成功。$$, ARRAY[$$TRPG$$,$$COC$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_007$$, $$一些猎奇小众知识$$, $$multiple$$, $$TRPG玩家群体中，常说的“刁民”通常指哪些行为习惯的玩家？$$, $$["严格遵守剧情设定的玩家", "故意破坏主持人剧情走向的玩家", "对NPC烧杀抢掠为所欲为的玩家", "帮助别人车卡的玩家"]$$, $$[1, 2]$$, $$medium$$, $$刁民指不按常理出牌、喜欢钻漏洞或搞破坏的玩家。$$, ARRAY[$$TRPG$$,$$黑话$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_008$$, $$一些猎奇小众知识$$, $$single$$, $$在跑团中，“Meta-gaming（超游）”是指什么不被鼓励的行为？$$, $$["扮演法师角色", "使用玩家本人知道但角色不可能知道的信息做出决定", "长时间不说话", "购买昂贵的金属骰子"]$$, $$[1]$$, $$medium$$, $$超游破坏了角色扮演的沉浸感。$$, ARRAY[$$TRPG$$,$$术语$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_009$$, $$一些猎奇小众知识$$, $$single$$, $$DND阵营九宫格中，既不偏向善良也不偏向邪恶，既不偏向守序也不偏向混乱的阵营是？$$, $$["绝对中立", "混乱善良", "守序邪恶", "混乱邪恶"]$$, $$[0]$$, $$easy$$, $$绝对中立者只凭本能或自然法则行事。$$, ARRAY[$$TRPG$$,$$阵营$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_010$$, $$一些猎奇小众知识$$, $$single$$, $$COC跑团中经常提到的“模组”是指什么？$$, $$["游戏的背景音乐", "骰子的材质", "主持人使用的一个完整故事剧本", "玩家的职业"]$$, $$[2]$$, $$medium$$, $$模组（Module/Scenario）是提供给主持人带领玩家探险的剧本。$$, ARRAY[$$TRPG$$,$$模组$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_011$$, $$一些猎奇小众知识$$, $$single$$, $$“Vtuber”全称Virtual YouTuber，通常中文被称为？$$, $$["虚拟偶像/虚拟主播", "全息投影", "语音助手", "声优"]$$, $$[0]$$, $$easy$$, $$Vtuber是以虚拟形象在视频网站活动的创作者。$$, ARRAY[$$V圈$$,$$VTuber$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_012$$, $$一些猎奇小众知识$$, $$single$$, $$Vocaloid家族中最具全球知名度的双马尾虚拟歌手是？$$, $$["巡音流歌", "初音未来", "洛天依", "镜音连"]$$, $$[1]$$, $$easy$$, $$初音未来是VOCALOID衍生文化中最具代表性的角色。$$, ARRAY[$$Vocaloid$$,$$初音$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_013$$, $$一些猎奇小众知识$$, $$multiple$$, $$V圈粉丝常用的弹幕“kksk”通常是什么意思的罗马音缩写？$$, $$["这里喜欢", "快快上课", "看看谁哭", "表示赞赏和喜爱某一片段"]$$, $$[0, 3]$$, $$medium$$, $$kksk是“ここすき”的缩写，常用于表达对某段直播内容的喜爱。$$, ARRAY[$$V圈$$,$$黑话$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_014$$, $$一些猎奇小众知识$$, $$single$$, $$中国最具代表性的中文VOCALOID虚拟歌手（代表作《达拉崩吧》等）是？$$, $$["星尘", "言和", "洛天依", "乐正绫"]$$, $$[2]$$, $$easy$$, $$洛天依是中国人气最高的Vsinger。$$, ARRAY[$$Vocaloid$$,$$中文V家$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_015$$, $$一些猎奇小众知识$$, $$single$$, $$常常由Vtuber本人或字幕组剪辑的，提炼长时间直播中搞笑、高能片段的短视频被称为？$$, $$["生肉", "熟肉", "切片", "录播"]$$, $$[2]$$, $$easy$$, $$切片是推广Vtuber最有效的内容形式。$$, ARRAY[$$V圈$$,$$切片$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_016$$, $$一些猎奇小众知识$$, $$multiple$$, $$在VTuber文化中，“中之人”或者“魂”是指？$$, $$["为虚拟形象提供声音的主播本人", "在幕后操纵模型动作的演员", "负责画画的画师", "公司的老板"]$$, $$[0, 1]$$, $$medium$$, $$中之人（中の人）指扮演该虚拟角色的真实人类。$$, ARRAY[$$V圈$$,$$术语$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_017$$, $$一些猎奇小众知识$$, $$single$$, $$当某个虚拟主播宣布“毕业”时，这通常意味着什么？$$, $$["她考上了大学", "她将停止活动并引退", "她换了新衣服", "她要开始学习了"]$$, $$[1]$$, $$easy$$, $$“毕业”是偶像或Vtuber体面结束职业生涯的委婉说法。$$, ARRAY[$$V圈$$,$$毕业$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_018$$, $$一些猎奇小众知识$$, $$single$$, $$VOCALOID软件的本质是一种什么样的工具？$$, $$["视频剪辑软件", "3D动画制作软件", "人声合成引擎", "修图软件"]$$, $$[2]$$, $$easy$$, $$它可以根据用户输入的旋律和歌词合成出人声。$$, ARRAY[$$Vocaloid$$,$$合成$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_019$$, $$一些猎奇小众知识$$, $$single$$, $$在V圈，粉丝们常称呼为主播绘制虚拟形象Live2D立绘的画师为？$$, $$["妈妈 / 爸爸", "经纪人", "神仙", "模型师"]$$, $$[0]$$, $$easy$$, $$因为赋予了形象，粉丝和V本人通常会尊称画师为“妈妈（亲妈）”。$$, ARRAY[$$V圈$$,$$术语$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_020$$, $$一些猎奇小众知识$$, $$single$$, $$粉丝在观看偶像演唱会或Vtuber 3D live时，跟随节奏挥舞荧光棒的动作体系被称为？$$, $$["太极", "打call", "广播体操", "咏春"]$$, $$[1]$$, $$easy$$, $$打call源自日本御宅文化，是应援文化的一部分。$$, ARRAY[$$偶像应援$$,$$打call$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_021$$, $$一些猎奇小众知识$$, $$single$$, $$“三坑”通常指代哪三种容易让年轻人在此花费大量金钱的服饰爱好？$$, $$["汉服、Lolita、JK制服", "西装、燕尾服、夹克", "女仆装、水手服、和服", "运动服、休闲服、睡衣"]$$, $$[0]$$, $$easy$$, $$这也是“破产三姐妹”一词的由来。$$, ARRAY[$$三坑$$,$$服饰$$]::text[], $${"艺术学": 1.0, "日子人": 0.8, "历史学": 0.3}$$, 'batch'),
  ($$nch_022$$, $$一些猎奇小众知识$$, $$single$$, $$在JK制服文化中，“水手服”衣领上的几条线被称为？$$, $$["领带", "襟线", "领结", "褶子"]$$, $$[1]$$, $$medium$$, $$襟线是水手服领子上的重要装饰特征，如一本线、二本线等。$$, ARRAY[$$三坑$$,$$JK制服$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_023$$, $$一些猎奇小众知识$$, $$multiple$$, $$汉服圈中，常常会极其在意和区分的两个概念是？$$, $$["山正", "形制", "衣服有多贵", "衣服是哪个品牌的拉链"]$$, $$[0, 1]$$, $$easy$$, $$汉服圈对版权（山正）和历史形制考究非常看重。$$, ARRAY[$$三坑$$,$$汉服$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_024$$, $$一些猎奇小众知识$$, $$single$$, $$Lolita服饰（洛丽塔）主要受到历史上哪种欧洲服饰风格的影响？$$, $$["古罗马", "维多利亚时代与洛可可风格", "现代极简风", "包豪斯风格"]$$, $$[1]$$, $$medium$$, $$Lolita大量吸收了洛可可和维多利亚时期的蕾丝、荷叶边元素。$$, ARRAY[$$三坑$$,$$Lolita$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_025$$, $$一些猎奇小众知识$$, $$single$$, $$在Lolita圈内，带有小熊、草莓、甜点等可爱印花图案，颜色多为粉色或浅色的风格被称为？$$, $$["Cla系", "Goth系", "Sweet系", "Punk系"]$$, $$[2]$$, $$easy$$, $$甜系（Sweet Lolita）是大众最容易认出的经典Lo裙风格。$$, ARRAY[$$三坑$$,$$Lolita$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_026$$, $$一些猎奇小众知识$$, $$single$$, $$购买JK制服时，常说的“轮褶”、“箱褶”指的是这件衣服哪个部位的工艺？$$, $$["领子", "袖口", "裙子自身的打褶方式", "袜子的花纹"]$$, $$[2]$$, $$medium$$, $$不同打褶方式是JK百褶裙的重要分类标准。$$, ARRAY[$$三坑$$,$$JK制服$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_027$$, $$一些猎奇小众知识$$, $$multiple$$, $$汉服中著名的“马面裙”属于哪个朝代的代表性女性服饰之一？$$, $$["唐朝", "宋朝", "明朝", "清朝初期"]$$, $$[2, 3]$$, $$hard$$, $$马面裙在明清时期高度流行，特别是明代。$$, ARRAY[$$三坑$$,$$汉服$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_028$$, $$一些猎奇小众知识$$, $$single$$, $$三坑文化中，由店家通过网络放出定金链接，根据定金数量进行生产后再补尾款发货的常见销售模式被称为？$$, $$["现货掉落", "意向金选款", "预售/开团", "众筹"]$$, $$[2]$$, $$easy$$, $$由于小众服饰生产成本和库存压力大，主要采取开团预售制。$$, ARRAY[$$三坑$$,$$消费模式$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_029$$, $$一些猎奇小众知识$$, $$single$$, $$Lolita圈内，为了让裙角完美撑起呈现出华丽的钟形或A字形弧度，必须穿在裙子里面的配件是？$$, $$["裙撑", "南瓜裤", "紧身胸衣", "丝袜"]$$, $$[0]$$, $$easy$$, $$裙撑是赋予Lo裙灵魂轮廓的关键。$$, ARRAY[$$三坑$$,$$Lolita$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_030$$, $$一些猎奇小众知识$$, $$single$$, $$非JK制服设计，仅仅是为了模仿日常穿着而粗制滥造的形似裙子常被圈内贬称为？$$, $$["正统JK", "软妹服", "地球人服饰", "制服"]$$, $$[1]$$, $$medium$$, $$通常指那些加入过多非制服元素但又想蹭热度的日常裙装。$$, ARRAY[$$三坑$$,$$JK制服$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_031$$, $$一些猎奇小众知识$$, $$single$$, $$SCP基金会的核心理念口号是？$$, $$["保护、收容、控制", "发现、毁灭、遗忘", "和平、爱、拯救", "研究、实验、发表"]$$, $$[0]$$, $$easy$$, $$SCP的缩写代表了基金会控制异常事物，保护人类的目标。$$, ARRAY[$$SCP$$,$$基金会$$]::text[], $${"经济学": 1.0, "管理学": 0.5, "日子人": 0.5}$$, 'batch'),
  ($$nch_032$$, $$一些猎奇小众知识$$, $$multiple$$, $$SCP文档中，异常项目常被分为哪些基本的收容等级？$$, $$["Safe", "Euclid", "Keter", "Thaumiel"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$这些是SCP基金会体系中最基础的几个项目等级。$$, ARRAY[$$SCP$$,$$收容等级$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_033$$, $$一些猎奇小众知识$$, $$single$$, $$在都市传说 / 网络怪谈中，“后室 (The Backrooms)”的最经典的一层（Level 0）具有什么显著特征？$$, $$["发黄的老旧壁纸、潮湿的荧光灯嗡嗡声、无限延伸的空房间", "无尽的黑暗星空", "充满马里奥怪物的城堡", "到处都是丧尸的城市"]$$, $$[0]$$, $$easy$$, $$这是Backrooms最知名的起源形象（Liminal space 阈限空间现象）。$$, ARRAY[$$怪谈$$,$$Backrooms$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_034$$, $$一些猎奇小众知识$$, $$single$$, $$SCP-173 是一尊雕像，如果人们移开视线或眨眼，它会怎么做？$$, $$["变成一滩泥", "立刻以极高的速度移动并扭断人的脖子", "开始唱歌", "消失在空气中"]$$, $$[1]$$, $$easy$$, $$173是基金会最早也是最著名的SCP项目之一。$$, ARRAY[$$SCP$$,$$SCP-173$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_035$$, $$一些猎奇小众知识$$, $$single$$, $$近年来互联网上流行一种“不要看月亮”之类的怪谈体裁，通过发布一系列充满矛盾或诡异警告的守则来营造恐怖感，被称为？$$, $$["规则类怪谈", "童话故事", "幽默笑话", "科普说明文"]$$, $$[0]$$, $$easy$$, $$典型的如《动物园守则》通过违和的规则设定细思极恐。$$, ARRAY[$$怪谈$$,$$规则类$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_036$$, $$一些猎奇小众知识$$, $$single$$, $$SCP基金会中，常被用作消耗品、负责执行大多数危险实验和探索任务的死刑犯人员被称为？$$, $$["O5议会", "研究员", "MTF特遣队", "D级人员"]$$, $$[3]$$, $$easy$$, $$D级人员是基金会的底层“耗材”。$$, ARRAY[$$SCP$$,$$D级人员$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_037$$, $$一些猎奇小众知识$$, $$multiple$$, $$下列哪些属于经典的国外Creepypasta（都市怪谈/网络恐怖故事）角色？$$, $$["瘦长鬼影", "杀手杰夫", "微笑狗", "孙悟空"]$$, $$[0, 1, 2]$$, $$medium$$, $$西方的creepypasta文化催生了一大批这类虚拟恐怖形象。$$, ARRAY[$$怪谈$$,$$Creepypasta$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_038$$, $$一些猎奇小众知识$$, $$single$$, $$SCP-049（疫医）最热衷于做的事情是？$$, $$["给人开出昂贵的药方", "触碰并杀死他认为感染了某种不存在的“瘟疫”的人，然后把他们改造成僵尸", "传播黑死病病毒", "解剖动物"]$$, $$[1]$$, $$medium$$, $$049是一个形似中世纪鸟嘴医生的实体。$$, ARRAY[$$SCP$$,$$SCP-049$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_039$$, $$一些猎奇小众知识$$, $$single$$, $$在Backrooms（后室）设定中，如果不小心“切出”（Noclip）了现实世界的边界，就会怎样？$$, $$["掉入后室空间", "飞向太空", "游戏闪退", "身体分解"]$$, $$[0]$$, $$easy$$, $$Noclip原本是游戏里穿模的指令，被借用来形容掉入这个恐怖异空间。$$, ARRAY[$$怪谈$$,$$后室$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_040$$, $$一些猎奇小众知识$$, $$single$$, $$SCP基金会设定中，掌管基金会最高权力的神秘委员会是？$$, $$["机动特遣队", "伦理委员会", "O5议会", "联合国大会"]$$, $$[2]$$, $$medium$$, $$O5议会由13名最高权限者组成，掌握着基金会的所有秘密。$$, ARRAY[$$SCP$$,$$O5议会$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_041$$, $$一些猎奇小众知识$$, $$single$$, $$在球鞋爱好者（Sneakerhead）圈内，AJ通常是指哪个著名系列？$$, $$["Air Jordan", "Adidas Jump", "Asics Jogger", "Air Jet"]$$, $$[0]$$, $$easy$$, $$乔丹系列是奠定潮鞋圈文化的鼻祖之一。$$, ARRAY[$$潮鞋$$,$$AJ$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_042$$, $$一些猎奇小众知识$$, $$multiple$$, $$抽签购买限量款球鞋时，鞋圈常说的“陪跑”和“中签”分别指什么？$$, $$["陪跑指没抽中", "中签指获得了购买资格", "陪跑指去田径场跑步", "中签指被签子扎了"]$$, $$[0, 1]$$, $$easy$$, $$由于抢购机器人的存在和极低中奖率，“陪跑”是大多数人的宿命。$$, ARRAY[$$潮鞋$$,$$黑话$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_043$$, $$一些猎奇小众知识$$, $$single$$, $$著名品牌 Supreme 的标志经典红底白字Logo，被粉丝戏称为什么？$$, $$["红白机", "Box Logo", "红绿灯", "警示牌"]$$, $$[1]$$, $$easy$$, $$Box Logo是潮牌历史上最有辨识度和溢价的标识之一。$$, ARRAY[$$潮牌$$,$$Supreme$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_044$$, $$一些猎奇小众知识$$, $$single$$, $$潮流盲盒/潮玩圈常说的“隐藏款/大隐/小隐”，其核心消费心理是利用了？$$, $$["买彩票般的随机惊喜感", "便宜的价格", "实用的功能", "对视力的保护"]$$, $$[0]$$, $$easy$$, $$隐藏款由于抽中概率极低，往往在二手市场具有极高溢价。$$, ARRAY[$$潮玩$$,$$盲盒$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_045$$, $$一些猎奇小众知识$$, $$single$$, $$潮鞋设计中很火的由日本设计师阿部千登势主导的品牌 sacai 典型的设计语言是？$$, $$["极简性冷淡风", "拼接、解构、双重重叠元素", "全是铆钉", "发光LED"]$$, $$[1]$$, $$medium$$, $$sacai与耐克的联名鞋往往具有著名的解构堆叠设计特征。$$, ARRAY[$$潮鞋$$,$$设计$$]::text[], $${"艺术学": 1.0, "工学": 0.4, "日子人": 0.5}$$, 'batch'),
  ($$nch_046$$, $$一些猎奇小众知识$$, $$single$$, $$在街头潮流圈，美国著名的艺术家 KAWS 代表性创作的玩偶形象最典型的特征是？$$, $$["眼睛是半月形", "眼睛是两个大XX", "没有嘴巴", "手里拿着刀"]$$, $$[1]$$, $$easy$$, $$XX眼是KAWS所有Companion玩偶的标志性符号。$$, ARRAY[$$潮玩$$,$$KAWS$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_047$$, $$一些猎奇小众知识$$, $$multiple$$, $$炒卖限量球鞋和潮牌的人，在圈内通常被称为？$$, $$["黄牛", "鞋贩子 / 贩子", "Reseller", "老实人"]$$, $$[0, 1, 2]$$, $$easy$$, $$随着资本介入，Resell已经成为一个巨大的二级市场。$$, ARRAY[$$潮鞋$$,$$Reseller$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_048$$, $$一些猎奇小众知识$$, $$single$$, $$阿迪达斯与著名rapper侃爷（Kanye West）合作推出的风靡全球的系列鞋款被称为？$$, $$["Yeezy", "Dunk", "NMD", "Superstar"]$$, $$[0]$$, $$easy$$, $$Yeezy以其极具辨识度的侧透和舒适的Boost鞋底曾制霸潮鞋市场。$$, ARRAY[$$潮鞋$$,$$Yeezy$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_049$$, $$一些猎奇小众知识$$, $$single$$, $$一双球鞋在二手平台被称为“原盒原漆套现、无瑕疵未试穿”，通常用哪个缩写来表示其为全新未使用状态？$$, $$["DS", "Used", "VNDS", "NWT"]$$, $$[0]$$, $$medium$$, $$Deadstock在潮服鞋圈特定指完全全新、未试穿如同封存的状态。$$, ARRAY[$$潮鞋$$,$$Deadstock$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_050$$, $$一些猎奇小众知识$$, $$single$$, $$潮流玩具积木熊的著名品牌是源自日本Medicomo Toy的什么？$$, $$["POP MART", "BE@RBRICK", "LEGO", "高达"]$$, $$[1]$$, $$medium$$, $$BE@RBRICK经常与各路大牌和艺术家联名，是殿堂级的潮玩。$$, ARRAY[$$潮玩$$,$$积木熊$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_051$$, $$一些猎奇小众知识$$, $$single$$, $$Furry（兽迷）亚文化主要围绕什么主题展开？$$, $$["真实生活中的宠物饲养", "拟人化动物角色", "远古恐龙化石研究", "毛发护理体验"]$$, $$[1]$$, $$easy$$, $$Furry的核心是对具有人类心智和行为特征的动物实体的喜爱。$$, ARRAY[$$Furry$$,$$定义$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_052$$, $$一些猎奇小众知识$$, $$single$$, $$Furry圈内常常指代成员自己设定的专属拟人化动物形象的词语是？$$, $$["身份证", "兽设", "宠设", "毛设"]$$, $$[1]$$, $$easy$$, $$结合了Furry和Persona，是玩家在社区中的虚拟分身。$$, ARRAY[$$Furry$$,$$兽设$$]::text[], $${"理学": 0.8, "农学": 0.5, "日子人": 0.5}$$, 'batch'),
  ($$nch_053$$, $$一些猎奇小众知识$$, $$multiple$$, $$下列哪些动物是Furry圈内非常常见的兽设物种？$$, $$["狼/犬科", "狐狸", "猫科", "龙/龙兽"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$犬科和狐狸占据了圈内非常大的比例（被戏称为泛滥的犬科）。$$, ARRAY[$$Furry$$,$$物种$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_054$$, $$一些猎奇小众知识$$, $$single$$, $$在大型的Furry展会（如MW、极兽聚）上，玩家穿着完整的动物拟人布偶装四处活动，这种服装被称为？$$, $$["布娃娃", "特摄服", "兽装", "Cosplay"]$$, $$[2]$$, $$easy$$, $$一件精良的全套兽装造价往往非常昂贵（动辄上万）。$$, ARRAY[$$Furry$$,$$兽装$$]::text[], $${"理学": 0.8, "农学": 0.5, "日子人": 0.5}$$, 'batch'),
  ($$nch_055$$, $$一些猎奇小众知识$$, $$single$$, $$不穿全套兽装，如果仅仅佩戴一个兽耳发箍和一条尾巴，这类装扮在二次元偏向哪种属性，而不是硬核Furry？$$, $$["机甲控", "兽耳娘/兽娘", "硬核Furry", "肌肉控"]$$, $$[1]$$, $$medium$$, $$Furry强调动物保留兽脸肌理比例，而兽耳娘主体依然完全是人类。$$, ARRAY[$$Furry$$,$$兽耳$$]::text[], $${"理学": 0.8, "农学": 0.5, "日子人": 0.5}$$, 'batch'),
  ($$nch_056$$, $$一些猎奇小众知识$$, $$single$$, $$在推特或画师平台上，专门接受其他兽迷委托有偿绘制他们设定的行为称为？$$, $$["讨饭", "接稿 / 约稿", "化缘", "走穴"]$$, $$[1]$$, $$easy$$, $$Furry圈的画师通过接稿形成了庞大成熟的同人经济圈。$$, ARRAY[$$Furry$$,$$Commission$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_057$$, $$一些猎奇小众知识$$, $$multiple$$, $$Furry兽装的风格根据头骨材质和眼睛设计主要可以分为哪几种典型风格？$$, $$["卡通/动漫风", "写实风", "半卡通风", "隐形风"]$$, $$[0, 1, 2]$$, $$medium$$, $$卡通风有巨大的2D眼睛，写实风则采用树脂假眼并且有极强的拟真毛发和牙齿。$$, ARRAY[$$Furry$$,$$兽装风格$$]::text[], $${"理学": 0.8, "农学": 0.5, "日子人": 0.5}$$, 'batch'),
  ($$nch_058$$, $$一些猎奇小众知识$$, $$single$$, $$Furry圈对别人毛茸茸的毛皮设定常常产生触觉上的向往，衍生出一个喜爱抚摸、拥抱的特有圈内行为叫？$$, $$["毛聚", "吸毛 / 抱抱", "剃毛", "剪毛"]$$, $$[1]$$, $$easy$$, $$展会上常有提供Free Hug的兽装表演者。$$, ARRAY[$$Furry$$,$$行为$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_059$$, $$一些猎奇小众知识$$, $$single$$, $$由于Fursuit内部极其闷热，兽装扮演者必不可少的维持生命体征的隐藏装备通常是？$$, $$["背着氧气面罩", "头骨内安装的微型排风小风扇", "内置微波炉", "全身静脉注射降温"]$$, $$[1]$$, $$medium$$, $$大多数兽头的嘴部或鼻子内部会暗藏散热风扇。$$, ARRAY[$$Furry$$,$$兽装制作$$]::text[], $${"理学": 0.8, "农学": 0.5, "日子人": 0.5}$$, 'batch'),
  ($$nch_060$$, $$一些猎奇小众知识$$, $$single$$, $$以拟人化高中动物角色为班底的著名悬疑群像题材漫画/动画作品是？$$, $$["《疯狂动物城》", "《动物狂想曲 / BEASTARS》", "《猫和老鼠》", "《喜羊羊与灰太狼》"]$$, $$[1]$$, $$easy$$, $$BEASTARS深刻探讨了肉食与草食拟人动物间的社会伦理，在圈内大热。$$, ARRAY[$$Furry$$,$$作品$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_061$$, $$一些猎奇小众知识$$, $$single$$, $$在电子游戏速通（Speedrun）中，分类为“Any%”意思是？$$, $$["必须杀死所有敌人", "只要能最快通关即可，不限制完成度及跳关", "100%全收集通关", "必须0杀敌通关"]$$, $$[1]$$, $$easy$$, $$Any%是追求极限通关时间的最热门且破坏游戏最严重的跑法。$$, ARRAY[$$速通$$,$$Any%$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_062$$, $$一些猎奇小众知识$$, $$multiple$$, $$速通分类中“100%”跑法通常要求玩家做到哪些？$$, $$["获得所有的收集品", "完成所有主线和支线任务", "解锁所有能力", "跳入虚空直接触发结局"]$$, $$[0, 1, 2]$$, $$easy$$, $$100%通关要求按游戏内定义的满完成度来通关，极其考验规划路线。$$, ARRAY[$$速通$$,$$100%$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_063$$, $$一些猎奇小众知识$$, $$single$$, $$在速通中利用游戏的漏洞或代码缺陷直接穿墙、跳跃大段流程的技巧统称为？$$, $$["外挂", "Glitches", "MOD", "修改器"]$$, $$[1]$$, $$easy$$, $$Glitches是速通文化的重要核心之一，许多速通是在欣赏代码毁灭的艺术。$$, ARRAY[$$速通$$,$$Glitches$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_064$$, $$一些猎奇小众知识$$, $$single$$, $$TAS速通 (Tool-Assisted Speedrun) 是指什么？$$, $$["找代练帮忙通关", "用物理工具按键盘", "利用模拟器和逐帧输入工具，达到人类手速难以企及的无失误极限通关", "通过打电话向开发者求助"]$$, $$[2]$$, $$easy$$, $$TAS通过录制脚本创造理论极限，更像是一种科研而非人工竞技。$$, ARRAY[$$速通$$,$$TAS$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_065$$, $$一些猎奇小众知识$$, $$single$$, $$利用游戏内存溢出漏洞或特定操作，将某些物品的代码强行改为结局通关触发器，此类极其硬核的底层邪道手法通常被称为？$$, $$["暴力破解", "内存操纵 / 任意代码执行", "游戏重置", "锁血"]$$, $$[1]$$, $$hard$$, $$ACE(Arbitrary Code Execution) 是部分老游戏Any%速通里的终极武器（如宝可梦、马里奥）。$$, ARRAY[$$速通$$,$$ACE$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_066$$, $$一些猎奇小众知识$$, $$multiple$$, $$著名的每年举办两次，为慈善组织筹款的全球最大速通大会是？$$, $$["SGDQ", "AGDQ", "E3", "TGA"]$$, $$[0, 1]$$, $$easy$$, $$GDQ系列活动是世界速通选手的盛大派对。$$, ARRAY[$$速通$$,$$GDQ$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_067$$, $$一些猎奇小众知识$$, $$single$$, $$“OOB”是速通中频繁出现的一个术语缩写，它的全称是？$$, $$["Out Of Bounds", "Only One Button", "On Our Back", "Over Over Bang"]$$, $$[0]$$, $$medium$$, $$进入OOB就能无视原本的空气墙和房间阻挡。$$, ARRAY[$$速通$$,$$OOB$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_068$$, $$一些猎奇小众知识$$, $$single$$, $$如果速通类别标明了“Glitchless”，意味着玩家在通关过程中？$$, $$["必须使用所有的Bug", "禁止使用任何Bug漏洞和邪道，必须按开发者预期的正常途径通关", "没有时间限制", "必须闭着眼睛打"]$$, $$[1]$$, $$easy$$, $$这属于“正常游玩的最快速”挑战。$$, ARRAY[$$速通$$,$$Glitchless$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_069$$, $$一些猎奇小众知识$$, $$single$$, $$某些游戏由于RNG（随机数生成器）极大地影响通关速度，速通玩家会通过特定复杂的开局输入来操控随机结果，这被称为？$$, $$["背板", "乱数操作", "黑客入侵", "修改器"]$$, $$[1]$$, $$medium$$, $$通过背下极其复杂的微操让系统生成特定的怪物掉落或暴击。$$, ARRAY[$$速通$$,$$RNG$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_070$$, $$一些猎奇小众知识$$, $$single$$, $$速通排行榜平台最权威的全球数据库网站是？$$, $$["Twitch", "Speedrun.com", "IGN", "Steam"]$$, $$[1]$$, $$easy$$, $$几乎所有游戏的速通世界纪录审核和排行都在此网站记录。$$, ARRAY[$$速通$$,$$网站$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_071$$, $$一些猎奇小众知识$$, $$single$$, $$业余无线电爱好者的通用英文绰号是？$$, $$["Geek", "Ham", "Hacker", "Nerd"]$$, $$[1]$$, $$easy$$, $$全世界的业余无线电爱好者都骄傲地自称为火腿(Ham)。$$, ARRAY[$$无线电$$,$$Ham$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_072$$, $$一些猎奇小众知识$$, $$multiple$$, $$在中国想要合法操作发射业余无线电台（对讲机），必须具备哪两项手续文件？$$, $$["电台设备购买小票", "电台执照", "$操作证 $", "$播音员主持人证$"]$$, $$[1, 2]$$, $$medium$$, $$必须人有操作证、机有电台执照（人机双证），否则就是非法的“黑飞/黑电台”。$$, ARRAY[$$无线电$$,$$法规$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_073$$, $$一些猎奇小众知识$$, $$single$$, $$业余无线电中，用来代表呼叫者的唯一全球识别代码（如BG1XXX）称为？$$, $$["IP地址", "呼号", "手机号", "密码"]$$, $$[1]$$, $$easy$$, $$呼号由各国家无线电管理机构分配，前缀代表国家和地区。$$, ARRAY[$$无线电$$,$$呼号$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_074$$, $$一些猎奇小众知识$$, $$single$$, $$火腿们常在交谈结束时说“73”，在CW电报语言中这代表什么意思？$$, $$["再见 / 致以最美好的祝愿", "我的电没电了", "我生气了", "请安静"]$$, $$[0]$$, $$medium$$, $$73是全球Ham界通用的美好道别用语。$$, ARRAY[$$无线电$$,$$礼用语$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_075$$, $$一些猎奇小众知识$$, $$single$$, $$在无网无信号的深山里，许多越野爱好者依赖哪种频率段的电磁波通过电离层反射实现跨省市甚至跨国的超远距离通联？$$, $$["UHF极高频", "VHF超高频", "HF短波", "5G信号"]$$, $$[2]$$, $$medium$$, $$短波电台（HF）可以通过天波（电离层反射）实现跨国通联。$$, ARRAY[$$无线电$$,$$短波$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_076$$, $$一些猎奇小众知识$$, $$single$$, $$EDC圈子（Everyday Carry）核心崇尚的是什么文化？$$, $$["每天背100公斤的东西健身", "挑选和搭配每天随身携带的小物件，以备不时之需和生活美学", "每天带不同的宠物出门", "研究如何徒手劈砖"]$$, $$[1]$$, $$easy$$, $$EDC爱好兼顾了男性的机械工具浪漫和日常实用主义。$$, ARRAY[$$EDC$$,$$定义$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_077$$, $$一些猎奇小众知识$$, $$multiple$$, $$EDC玩家背包中非常热门的“多功能工具钳（Multi-tool）”的两个最著名代表品牌是？$$, $$["Leatherman", "Victorinox", "Rolex", "Bvlgari"]$$, $$[0, 1]$$, $$easy$$, $$莱泽曼和维氏瑞士军刀几乎垄断了高端民用多功能工具市场。$$, ARRAY[$$EDC$$,$$工具钳$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_078$$, $$一些猎奇小众知识$$, $$single$$, $$由于国内刀具管制非常严格，国内EDC玩家经常随身把玩的、且完全不带锋利刃口纯粹用来练手部动作的玩具刀被称为？$$, $$["太刀", "蝴蝶刀 / 甩刀", "菜刀", "指甲刀"]$$, $$[1]$$, $$medium$$, $$蝴蝶梳、蝴蝶钝刀因其可以展现华丽的翻转技巧而受到年轻人欢迎。$$, ARRAY[$$EDC$$,$$甩刀$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_079$$, $$一些猎奇小众知识$$, $$single$$, $$EDC圈内玩家非常喜爱由钛合金、黄铜或锆合金等金属制成减压小玩具，下列属于此类减压玩具的是？$$, $$["指尖陀螺", "金属推牌 / 啪啪币", "由于磁铁吸引而发出清脆声音的金属滚筒", "以上都是"]$$, $$[3]$$, $$easy$$, $$这些都是EDC圈风靡的高溢价金属解压EDC玩具。$$, ARRAY[$$EDC$$,$$解压玩具$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_080$$, $$一些猎奇小众知识$$, $$single$$, $$在EDC高级小手电领域，“流明 (Lumen)”这个单位常用来衡量手电筒的什么指标？$$, $$["电池容量", "光通量", "重量", "射电频率"]$$, $$[1]$$, $$easy$$, $$流明数越高，通常手电在宏观视觉上显得越亮。$$, ARRAY[$$EDC$$,$$爆闪手电$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_081$$, $$一些猎奇小众知识$$, $$single$$, $$在三阶魔方还原中，“CFOP”高级玩法公式的第一个字母C代表什么？$$, $$["Center", "Cross", "Corner", "Color"]$$, $$[1]$$, $$easy$$, $$CFOP分别是Cross、F2L、OLL、PLL。$$, ARRAY[$$魔方$$,$$CFOP$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_082$$, $$一些猎奇小众知识$$, $$single$$, $$WCA（世界魔方协会）官方认可的正式比赛项目中，目前由谁保持着三阶魔方单次还原的绝对难以置信的世界纪录（截至2023年3.13秒）？$$, $$["菲神", "麦神", "王宇轩", "小众AI"]$$, $$[1]$$, $$medium$$, $$Max Park在2023年打破了三阶世界纪录跃至3秒时代边缘。$$, ARRAY[$$魔方$$,$$世界纪录$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_083$$, $$一些猎奇小众知识$$, $$multiple$$, $$转笔（Pen Spinning）中的四大基础基本招式（Fundamental）包含哪些？$$, $$["ThumbAround", "Sonic", "Charge", "FingerPass"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$这四招是全球公认转笔新手必须入门的基础地基。$$, ARRAY[$$转笔$$,$$基础招式$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_084$$, $$一些猎奇小众知识$$, $$single$$, $$专属为转笔而打造、并且通常两端平衡配重无法写字的非正常用笔，在圈内被称为？$$, $$["钢笔", "毛笔", "专用笔", "荧光笔"]$$, $$[2]$$, $$easy$$, $$玩家通常利用各种笔的笔盖、笔胶、笔杆进行改装平衡得到Pen Mod。$$, ARRAY[$$转笔$$,$$专用笔$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_085$$, $$一些猎奇小众知识$$, $$single$$, $$在竞技叠杯（Speed Stacks）运动中，最高殿堂级的循环花式（Cycle）总共由几个阶段的叠装和收杯组成？$$, $$["1个阶段", "3个阶段", "5个", "10个"]$$, $$[1]$$, $$medium$$, $$Cycle（花式循环）是杯子花式最多也最具观赏性的项目。$$, ARRAY[$$速叠杯$$,$$Cycle$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_086$$, $$一些猎奇小众知识$$, $$single$$, $$盲拧三阶魔方时，选手记忆使用的主要方法逻辑是将魔方的状态转化为？$$, $$["数字死记硬背", "拼音或字母对，进而联想成中文词汇/故事宫殿", "颜色直接硬想", "求助场外指导"]$$, $$[1]$$, $$medium$$, $$通过“字母对”转化成一个个具象的名词记忆法是现代盲拧的核心原理。$$, ARRAY[$$魔方$$,$$盲拧$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_087$$, $$一些猎奇小众知识$$, $$single$$, $$转笔中，连续不断地在手指间施展同一招式、形成永动机般无限循环连招的技巧统称为？$$, $$["Aerial", "Continuous", "Wiper", "Inf"]$$, $$[1]$$, $$easy$$, $$Continuous（连转）由于视觉效果华丽，也是老手的重要考核指标之一。$$, ARRAY[$$转笔$$,$$连招$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_088$$, $$一些猎奇小众知识$$, $$single$$, $$速叠杯运动中，使用的杯子底部通常会有几个孔，这些孔的作用是？$$, $$["为了省材料", "防止空气阻力，避免杯子粘在一起或空气排不出去，加快叠落速度", "为了漏水", "为了能看清对面"]$$, $$[1]$$, $$easy$$, $$排气孔是专业竞技叠杯能以零点几秒极速收叠的物理学基础。$$, ARRAY[$$速叠杯$$,$$硬件$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.5}$$, 'batch'),
  ($$nch_089$$, $$一些猎奇小众知识$$, $$multiple$$, $$下列哪些魔方属于WCA赛事的官方正式项目？$$, $$["二阶魔方", "斜转", "金字塔魔方", "九百阶魔方"]$$, $$[0, 1, 2]$$, $$easy$$, $$截至目前WCA未列入过高的超高阶魔方（目前最高只有普通赛里的7x7x7）。$$, ARRAY[$$魔方$$,$$WCA$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_090$$, $$一些猎奇小众知识$$, $$single$$, $$手指滑板（Fingerboard/滑板手指化）中，完成弹跳动作跳上台阶的最核心、最基础的招式是？$$, $$["Ollie", "Kickflip", "Grind", "Grab"]$$, $$[0]$$, $$medium$$, $$源自真实滑板，Ollie是利用后指点板让板面腾空飞起的地基招式。$$, ARRAY[$$手指滑板$$,$$Ollie$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_091$$, $$一些猎奇小众知识$$, $$single$$, $$摄影中所谓的“曝光三要素”包括以下哪些？ (部分多选)$$, $$["光圈", "快门速度", "焦距", "ISO"]$$, $$[0, 1, 3]$$, $$easy$$, $$光圈、快门速度、ISO共同决定了照片的最终曝光量。$$, ARRAY[$$摄影$$,$$曝光三要素$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_092$$, $$一些猎奇小众知识$$, $$multiple$$, $$机械键盘轴体中，经典的Cherry“青轴”和“红轴”的区别主要在于？$$, $$["青轴有强烈的段落感和两段发声", "红轴是直上直下没有手感顿挫的线性轴", "青轴必须插电才能用", "红轴专为打字设计，没有声音"]$$, $$[0, 1]$$, $$easy$$, $$手感反馈（段落还是线性）是机械键盘核心的区别所在。$$, ARRAY[$$机械键盘$$,$$轴体$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_093$$, $$一些猎奇小众知识$$, $$single$$, $$电脑CPU中，被玩家调侃为“牙膏厂”的是哪个品牌？$$, $$["AMD", "Intel", "Qualcomm", "Apple"]$$, $$[1]$$, $$easy$$, $$Intel曾因好几代产品性能提升微弱（“挤牙膏”）而被玩家戏称。$$, ARRAY[$$PC硬件$$,$$Intel$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.5}$$, 'batch'),
  ($$nch_094$$, $$一些猎奇小众知识$$, $$single$$, $$对于专业单反/微单摄影，照片存储为了后期极大空间，通常必须开启什么格式？$$, $$["JPEG", "PNG", "RAW", "BMP"]$$, $$[2]$$, $$easy$$, $$RAW记录了传感器原始数据，后期动态范围宽宽广无损。$$, ARRAY[$$摄影$$,$$RAW格式$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_095$$, $$一些猎奇小众知识$$, $$single$$, $$显示器参数中的“144Hz”或“240Hz”表示什么？$$, $$["屏幕的颜色数量", "屏幕的刷新率", "显示器使用的电压", "显示器的厚度"]$$, $$[1]$$, $$easy$$, $$Hz代表刷新率，数值越高高帧率游戏画面越流畅。$$, ARRAY[$$PC外设$$,$$刷新率$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_096$$, $$一些猎奇小众知识$$, $$single$$, $$在音频玄学中，Hi-Fi发烧友用来说明新耳机需要长时间播放来让振膜状态达到最佳的术语是？$$, $$["热机", "煲机", "通电", "洗碟"]$$, $$[1]$$, $$medium$$, $$煲机是指通过较长时间放音，使发声结构磨合。$$, ARRAY[$$HiFi$$,$$听音观$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_097$$, $$一些猎奇小众知识$$, $$multiple$$, $$在显卡（GPU）领域中，目前NVIDIA的RTX系列显卡主打的核心卖点技术包括？$$, $$["光线追踪", "DLSS", "声波悬浮", "自带核武器"]$$, $$[0, 1]$$, $$easy$$, $$光追和利用AI补帧提升帧率的DLSS是现代英伟达显卡的两大招牌技术。$$, ARRAY[$$显卡$$,$$RTX$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_098$$, $$一些猎奇小众知识$$, $$single$$, $$相机镜头“定焦镜头”相较于“变焦镜头”最大的劣势是？$$, $$["光圈做不大", "画质很差", "无法通过转动环改变焦距，只能靠拍摄者双腿走动", "体积一定会很大很大"]$$, $$[2]$$, $$easy$$, $$定焦即焦距恒定（如50mm），俗称变焦靠走，但画质和光圈通常优于同价位变焦。$$, ARRAY[$$摄影$$,$$镜头$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_099$$, $$一些猎奇小众知识$$, $$single$$, $$键盘客制化中，很多玩家会使用一种润滑脂（如杜邦105/205）去涂抹键盘轴体的内部，这称为？$$, $$["精洗", "润轴", "抛光", "镀膜"]$$, $$[1]$$, $$easy$$, $$手工润轴能极大程度降低摩擦杂音（沙沙声）并让按压更顺滑。$$, ARRAY[$$客制化键盘$$,$$润轴$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_100$$, $$一些猎奇小众知识$$, $$single$$, $$很多音响发烧友经常被圈外人调侃的一个老梗是说听得出电网的电是不一样的，那个梗叫做？$$, $$["只有风电最好听", "水电偏冷，火电偏暖，核电背景深邃", "太阳能有阳光味", "电池没有声音"]$$, $$[1]$$, $$medium$$, $$“火电暖水电冷”这个老梗极大讽刺了过度脱离物理常识的玄学听音观。$$, ARRAY[$$HiFi$$,$$梗$$]::text[], $${"日子人": 1.0, "文学": 0.2}$$, 'batch'),
  ($$nch_101$$, $$一些猎奇小众知识$$, $$single$$, $$铁路迷在“运转”（指体验和拍摄列车）时，常说到的黑话里，“套跑”是指什么？$$, $$["跑步追火车", "逃票", "一列车底在一天内交替执行两个或多个不同车次的任务", "抢机车"]$$, $$[2]$$, $$medium$$, $$为了提高资源利用率，同一个车厢编组可能跑到终点后变个车次继续开。$$, ARRAY[$$铁道迷$$,$$套跑$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_102$$, $$一些猎奇小众知识$$, $$single$$, $$中国铁路客运中，“Z”字头的列车通常被称为什么？$$, $$["高铁", "动车", "直达特快", "快速列车"]$$, $$[2]$$, $$easy$$, $$Z代表“直”，为直达特快旅客列车。$$, ARRAY[$$铁路$$,$$车次$$]::text[], $${"工学": 0.6, "日子人": 0.8}$$, 'batch'),
  ($$nch_103$$, $$一些猎奇小众知识$$, $$multiple$$, $$下列哪些中国的高铁站是知名的“巨无霸”超级枢纽高铁站？$$, $$["上海虹桥站", "郑州东站", "南京东站", "西安东站"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$这几个都是中国庞大的高铁十字网络核心节点车站。$$, ARRAY[$$铁路枢纽$$,$$高铁站$$]::text[], $${"工学": 1.0, "日子人": 0.8, "军事学": 0.4, "管理学": 0.2}$$, 'batch'),
  ($$nch_104$$, $$一些猎奇小众知识$$, $$single$$, $$公交迷群体中，常常会热衷于拍摄一款经典公交车退役前的最后几天运行，这一行为被称作？$$, $$["送退役 / 追末末班", "接新车", "清洗", "大修"]$$, $$[0]$$, $$easy$$, $$车迷会聚集在退役前的末班车上告别时代。$$, ARRAY[$$公交系统$$,$$公交迷$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_105$$, $$一些猎奇小众知识$$, $$single$$, $$列车行驶在铁轨上，中国国家标准铁路（准轨）以及世界大部分国家采用的轨距是多宽？$$, $$["1000mm", "1435mm", "1520mm", "1676mm"]$$, $$[1]$$, $$easy$$, $$1435毫米被称为国际标准轨距。$$, ARRAY[$$铁道工程$$,$$轨距$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_106$$, $$一些猎奇小众知识$$, $$single$$, $$在公交枢纽或大城市主干道上推行的“BRT”是指什么系统？$$, $$["地下铁道", "共享自行车", "快速公交系统", "轮渡系统"]$$, $$[2]$$, $$easy$$, $$BRT通过专用的公交路权、封闭式站台等实现公交高运量快速流动。$$, ARRAY[$$公交系统$$,$$BRT$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_107$$, $$一些猎奇小众知识$$, $$multiple$$, $$铁路信号中，“三灯四显示”信号系统里，为了指示前面区间占用情况给司机预警，会有哪几种颜色组合？$$, $$["绿", "黄绿", "黄", "红"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$绿（前方空两闭塞）、黄绿（空一个半）、黄（下一个红）、红（绝对停车）。$$, ARRAY[$$铁路$$,$$信号机$$]::text[], $${"工学": 0.6, "日子人": 0.8}$$, 'batch'),
  ($$nch_108$$, $$一些猎奇小众知识$$, $$single$$, $$国内铁道迷讨论电力机车时常说的“韶山”系列（SS），其主要是哪家巨头机车厂负责最初研制和主导生产的？$$, $$["长春客车", "唐山客车", "株洲电力机车厂", "戚墅堰机车厂"]$$, $$[2]$$, $$medium$$, $$株机被称为中国电力机车之都。$$, ARRAY[$$铁路$$,$$韶山系列机车$$]::text[], $${"工学": 0.6, "日子人": 0.8}$$, 'batch'),
  ($$nch_109$$, $$一些猎奇小众知识$$, $$single$$, $$近年来引发大量中国铁道迷关注和拍摄的“复兴号”CR200J动车组，因为其标志性的绿色涂装，被车迷调侃地称为？$$, $$["绿巨人", "东北虎", "青蛙", "原谅车"]$$, $$[0]$$, $$medium$$, $$CR200J是取代传统机车牵引车底的新型160km/h集中动力动车组。$$, ARRAY[$$铁道迷$$,$$动车组$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "日子人": 0.5}$$, 'batch'),
  ($$nch_110$$, $$一些猎奇小众知识$$, $$single$$, $$中国铁路爱好者常去拍摄火车通过的立交桥、跨线桥或铁路旁安全距离的地方，一蹲就是好几个小时的风雨无阻的行为被戏称作？$$, $$["钓鱼", "打猎", "蹲绿皮", "放羊"]$$, $$[0]$$, $$medium$$, $$车迷们为了拍摄特定的稀有车底，像钓鱼的人一样长时间等候耐心十足。$$, ARRAY[$$铁道迷$$,$$拍车$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_111$$, $$一些猎奇小众知识$$, $$single$$, $$音乐游戏谱面中经常提到的“BPM”是指什么？$$, $$["按键数", "每分钟节拍数 代表歌曲快慢", "显示器亮度", "血条长度"]$$, $$[1]$$, $$easy$$, $$BPM数值越大代表音乐节奏通常越快越密集。$$, ARRAY[$$音游$$,$$BPM$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_112$$, $$一些猎奇小众知识$$, $$multiple$$, $$音游圈内所谓的“全白”、“AP(All Perfect)”意味着什么？$$, $$["按键全失误", "没有任何Bad或Miss", "所有击打不仅没有断连，而且全都是最高级精确度判定！", "游戏画面变白"]$$, $$[1, 2]$$, $$easy$$, $$AP（All Perfect / 理论值）是指玩家展现了机械般的精确度，拿到了当前谱面的绝对满分。$$, ARRAY[$$音游$$,$$AP$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_113$$, $$一些猎奇小众知识$$, $$single$$, $$在知名街机音游《maimai》（舞萌）中，玩家之间常将这台机器的形状戏称为？$$, $$["微波炉", "大彩电", "洗衣机", "滚筒干燥机"]$$, $$[2]$$, $$easy$$, $$因其圆形屏幕、发光环以及舱门造型极像正面滚筒洗衣机。$$, ARRAY[$$音游$$,$$街机$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_114$$, $$一些猎奇小众知识$$, $$single$$, $$手游音游玩家常采用的操作流派通常被分为“拇指流（手持用两只大拇指打）”和什么流派（放在桌面上打）？$$, $$["舌头流", "多指流", "眼动流", "脚踩流"]$$, $$[1]$$, $$easy$$, $$平放多指流能打出拇指无法处理的多押谱面。$$, ARRAY[$$音游$$,$$操作流派$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_115$$, $$一些猎奇小众知识$$, $$single$$, $$游戏里掉下的判定音符（Notes），如果不止需要点击，还需要玩家一直按住不放直到其结束，这种音符通常被称为？$$, $$["Tap", "Flick", "Hold", "Slide"]$$, $$[2]$$, $$easy$$, $$Hold代表必须长按住的音符段。$$, ARRAY[$$音游$$,$$游戏元素$$]::text[], $${"理学": 1.0, "工学": 0.6, "日子人": 1.0, "艺术学": 0.3}$$, 'batch'),
  ($$nch_116$$, $$一些猎奇小众知识$$, $$multiple$$, $$著名日本音游大厂KONAMI旗下主导的BEMANI街机音乐游戏系列包括哪些？$$, $$["beatmania IIDX", "Sound Voltex", "Jubeat", "osu!"]$$, $$[0, 1, 2]$$, $$medium$$, $$osu!是著名民间同人键盘鼠标音游平台而非Konami街机。$$, ARRAY[$$音游$$,$$BEMANI$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_117$$, $$一些猎奇小众知识$$, $$single$$, $$雷亚游戏（Rayark）开发的，在全球范围内极具影响力的下落式移动端音乐游戏（其界面有一根上下移动的扫描线）是？$$, $$["Cytus / Cytus II", "Deemo", "Arcaea", "Muse Dash"]$$, $$[0]$$, $$medium$$, $$Cytus系列使用了标志性的上下扫描判定线而非传统的下落式轨道。$$, ARRAY[$$移动音游$$,$$雷亚$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_118$$, $$一些猎奇小众知识$$, $$single$$, $$《Beat Saber》（节奏空间）是一款由于玩家手持光剑切砍飞来方块而火遍全球的音乐游戏，其依托的游戏设备平台是？$$, $$["GameBoy", "VR", "跳舞毯", "街机方向盘"]$$, $$[1]$$, $$easy$$, $$BS是VR领域历史销量最高、最出圈的运动健身级音游。$$, ARRAY[$$VR音游$$,$$Beat Saber$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_119$$, $$一些猎奇小众知识$$, $$single$$, $$很多音游（如《Arcaea》《PHIGROS》）除了最外显的判定线和下落键之外，还有悬浮在空中的、需要跟随划动的特殊音符，这种被戏称为底大欺客的要素是？$$, $$["跳台", "蛇/蛇轨", "地雷", "黑屏"]$$, $$[1]$$, $$medium$$, $$蛇轨跨越屏幕空间，极其考验双手的交叉和走位。$$, ARRAY[$$音游$$,$$谱面$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$nch_120$$, $$一些猎奇小众知识$$, $$single$$, $$当玩家面对变态难度的音游谱面，发现手速和反应无法处理时，眼花缭乱的手指失控在屏幕上瞎按一气的行为常被自嘲为？$$, $$["糊", "搓面团 / 擦玻璃", "微操", "精准格挡"]$$, $$[1]$$, $$easy$$, $$因为乱滑看起来像在卖力擦屏幕。$$, ARRAY[$$音游$$,$$黑话$$]::text[], $${"日子人": 1.0}$$, 'batch'),
  ($$net_001$$, $$互联网与网络$$, $$single$$, $$在OSI七层模型中，负责路径选择和路由的是哪一层？$$, $$["物理层", "数据链路层", "网络层", "传输层"]$$, $$[2]$$, $$medium$$, $$网络层主要设备是路由器，负责数据包从源到目的地的路由。$$, ARRAY[$$OSI模型$$,$$网络层$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.45, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_002$$, $$互联网与网络$$, $$single$$, $$Web浏览器访问网页时，默认使用的HTTP协议通信端口是？$$, $$["21", "22", "80", "443"]$$, $$[2]$$, $$easy$$, $$HTTP默认端口为80，HTTPS默认端口为443。$$, ARRAY[$$协议$$,$$HTTP$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_003$$, $$互联网与网络$$, $$single$$, $$哪个协议是互联网基础，负责在网络中传输数据包而不保证送达的可靠性？$$, $$["TCP", "IP", "FTP", "SMTP"]$$, $$[1]$$, $$medium$$, $$IP(互联网协议)提供无连接、不可靠的数据报投递服务；TCP在此之上保证可靠性。$$, ARRAY[$$TCP/IP$$,$$IP协议$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_004$$, $$互联网与网络$$, $$single$$, $$用于将域名（如 www.google.com）转换为IP地址的系统服务是？$$, $$["DHCP", "DNS", "NAT", "VPN"]$$, $$[1]$$, $$easy$$, $$DNS（域名系统）即网络中的电话簿，负责域名到IP的解析。$$, ARRAY[$$DNS$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_005$$, $$互联网与网络$$, $$single$$, $$局域网(LAN)中最广泛使用的有线网络标准技术是？$$, $$["蓝牙", "以太网", "光纤通道", "LTE"]$$, $$[1]$$, $$easy$$, $$以太网(Ethernet)是使用跨度最广的局域网技术规范。$$, ARRAY[$$局域网$$,$$以太网$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_006$$, $$互联网与网络$$, $$single$$, $$URL的全拼是指Uniform Resource Locator，中文常称为什么？$$, $$["超级网关", "统一资源定位符", "文件传输协议", "虚拟局域网"]$$, $$[1]$$, $$easy$$, $$URL即统一资源定位符，即俗称的网页地址(网址)。$$, ARRAY[$$Web$$,$$URL$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_007$$, $$互联网与网络$$, $$single$$, $$在TCP三次握手中，客户端发送的首个同步报文段标志位是？$$, $$["ACK", "SYN", "FIN", "RST"]$$, $$[1]$$, $$hard$$, $$第一次握手客户端发送SYN(同步序列编号)标志报文，请求建立连接。$$, ARRAY[$$TCP/IP$$,$$三次握手$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_008$$, $$互联网与网络$$, $$single$$, $$Wi-Fi的商标名通常指代电气电子工程师学会的哪一项无线标准？$$, $$["IEEE 802.3", "IEEE 802.11", "IEEE 802.15", "IEEE 802.16"]$$, $$[1]$$, $$hard$$, $$802.11家族是无线局域网标准，被广泛认证运用为Wi-Fi。$$, ARRAY[$$无线网络$$,$$Wi-Fi$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.45, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_009$$, $$互联网与网络$$, $$single$$, $$家用路由器通常具有自动为内部设备分配IP地址的功能，该功能依赖的协议是？$$, $$["DHCP", "DNS", "HTTP", "ICMP"]$$, $$[0]$$, $$medium$$, $$DHCP（动态主机配置协议）自动分配IP、子网掩码和默认网关。$$, ARRAY[$$网络协议$$,$$DHCP$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.45, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_010$$, $$互联网与网络$$, $$single$$, $$MAC地址（物理地址）通常包含几位二进制并且常以十六进制表示？$$, $$["32位", "48位", "64位", "128位"]$$, $$[1]$$, $$hard$$, $$MAC地址是48位的，一般被表示为6组两个十六进制字符（如00:1A:2B:3C:4D:5E）。$$, ARRAY[$$链路层$$,$$MAC$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_011$$, $$互联网与网络$$, $$single$$, $$HTTPS比HTTP多出一个安全层，这通常是指？$$, $$["TCP", "SSL/TLS", "IPsec", "SSH"]$$, $$[1]$$, $$medium$$, $$HTTPS全称HTTP over SSL/TLS，利用加密算法保证传输信息的安全防窃听。$$, ARRAY[$$网络安全$$,$$HTTPS$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.45, "文学": 0.2, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_012$$, $$互联网与网络$$, $$single$$, $$用于发送电子邮件的标准协议主要是？$$, $$["POP3", "IMAP", "SMTP", "SNMP"]$$, $$[2]$$, $$medium$$, $$简单邮件传输协议 (SMTP) 用于发信。POP3和IMAP用于收信。$$, ARRAY[$$电子邮件$$,$$SMTP$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_013$$, $$互联网与网络$$, $$single$$, $$IPv6的地址长度是多少位？$$, $$["32", "64", "128", "256"]$$, $$[2]$$, $$medium$$, $$IPv6将IPv4的32位扩充到了128位，号称可以给地球上每粒沙子分配一个IP。$$, ARRAY[$$网络基础$$,$$IPv6$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.45, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_014$$, $$互联网与网络$$, $$single$$, $$在CMD终端测试主机间网络连通性的日常命令（运用ICMP协议）是？$$, $$["ipconfig", "netstat", "ping", "arp"]$$, $$[2]$$, $$easy$$, $$Ping命令通过发送ICMP回显请求并等待响应来测试网络连通性。$$, ARRAY[$$网络命令$$,$$Ping$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.45, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_015$$, $$互联网与网络$$, $$single$$, $$局域网内的设备为了获得公网服务的应答，常将内部的私有IP映射为网关的公网IP，这个技术叫？$$, $$["NAT", "DMZ", "VLAN", "CDN"]$$, $$[0]$$, $$medium$$, $$NAT技术允许多台设备共享一个或少量公网IP从而缓解IPv4枯竭。$$, ARRAY[$$网络配置$$,$$NAT$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.45, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_016$$, $$互联网与网络$$, $$single$$, $$VPN的全称是指？$$, $$["虚拟局域网", "虚拟专用网络", "虚拟专用服务器", "文件传输网"]$$, $$[1]$$, $$easy$$, $$VPN即Virtual Private Network（虚拟专用网络），用于建立加密安全的网络隧道。$$, ARRAY[$$网络连接$$,$$VPN$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.45, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_017$$, $$互联网与网络$$, $$single$$, $$万维网即World Wide Web（WWW）的发明者是？$$, $$["蒂姆·伯纳斯-李", "文顿·瑟夫", "马克·扎克伯格", "拉里·佩奇"]$$, $$[0]$$, $$medium$$, $$伯纳斯-李于1989年发明了万维网，提出了HTTP、HTML和首个浏览器概念。$$, ARRAY[$$互联网史$$,$$WWW$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_018$$, $$互联网与网络$$, $$single$$, $$将前端网络内容分发到离用户更近的边缘服务器以加速访问速度的服务系统是？$$, $$["DNS", "BGP", "CDN", "SQL"]$$, $$[2]$$, $$medium$$, $$内容分发网络（CDN）能够避开互联网上有可能影响数据传输速度的瓶颈和环节环节，加速网站访问。$$, ARRAY[$$网络架构$$,$$CDN$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.45, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_019$$, $$互联网与网络$$, $$single$$, $$P2P下载（如BitTorrent）全称是？$$, $$["Peer-to-Peer", "Point-to-Point", "Person-to-Person", "Pay-to-Play"]$$, $$[0]$$, $$easy$$, $$对等网络(Peer-to-Peer)，指网络中各节点既是客户端也是服务端互相传输文件。$$, ARRAY[$$下载技术$$,$$P2P$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_020$$, $$互联网与网络$$, $$single$$, $$光纤通信中，保证光信号能够沿光纤无严重泄漏向前传输的物理原理是光线在纤芯和包层界面上的？$$, $$["折射", "全反射", "干涉", "衍射"]$$, $$[1]$$, $$medium$$, $$光纤芯的折射率高，光由光密进光疏发生全反射，信号得以前进且无甚能量损失。$$, ARRAY[$$通信传输$$,$$光纤$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_021$$, $$互联网与网络$$, $$single$$, $$一般情况下，192.168.x.x网段属于？$$, $$["公有IP网段", "私有IP网段", "多播网段", "组播网段"]$$, $$[1]$$, $$easy$$, $$按照RFC标准，192.168开头是经典的C类私有IP地址段。$$, ARRAY[$$IP地址$$,$$私网$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_022$$, $$互联网与网络$$, $$single$$, $$云计算模式中，提供运行环境和开发工具给消费者的服务模式称为？$$, $$["IaaS", "PaaS", "SaaS", "DaaS"]$$, $$[1]$$, $$hard$$, $$IaaS提供软硬件资源底座；PaaS提供环境、库；SaaS直接提供应用软件。$$, ARRAY[$$云计算$$,$$PaaS$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_023$$, $$互联网与网络$$, $$multiple$$, $$在TCP/IP协议栈中，传输层的主要协议包括？$$, $$["TCP", "UDP", "IP", "HTTP"]$$, $$[0, 1]$$, $$medium$$, $$传输大类中主将有面向可靠连接的TCP协议和面向无连接的尽力投递协议UDP。$$, ARRAY[$$网络协议栈$$,$$传输层$$]::text[], $${"日子人": 1.0, "文学": 0.2, "工学": 0.45, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_024$$, $$互联网与网络$$, $$multiple$$, $$下列哪些属于局域网或短距离通信常用的无线技术？$$, $$["Wi-Fi", "蓝牙", "NFC", "BGP"]$$, $$[0, 1, 2]$$, $$easy$$, $$BGP是核心骨干网自治系统间的外部网关路由协议，不是短距无线电通信。$$, ARRAY[$$无线技术$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_025$$, $$互联网与网络$$, $$multiple$$, $$从应用层看，下列协议中主要采用TCP协议来进行数据传输服务的有？$$, $$["HTTP", "FTP", "DNS", "SSH"]$$, $$[0, 1, 3]$$, $$hard$$, $$网页HTTP、文件FTP、安全登录SSH都需要可靠连接故使用TCP；DNS普通查询通常用UDP提升速度。$$, ARRAY[$$应用层$$,$$TCP$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_026$$, $$互联网与网络$$, $$multiple$$, $$构成一个基本的网络数据包(Packet)，其至少需要包括哪些关键部分信息？$$, $$["源IP地址", "目的IP地址", "负载数据", "显示器的分辨率设定"]$$, $$[0, 1, 2]$$, $$easy$$, $$IP头部须有源和目的地址标识来源和去向，以及携带的有效荷载。$$, ARRAY[$$数据包$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_027$$, $$互联网与网络$$, $$multiple$$, $$关于光纤宽带相比于传统铜双绞线的优势，正确的是？$$, $$["传输带宽更大", "抗电磁干扰性极强", "信号衰减更慢，距离可以更远", "极其容易弯折布线且无损"]$$, $$[0, 1, 2]$$, $$medium$$, $$光纤主要是玻璃石英抗干扰大带宽长距离；但其质脆忌讳过度弯折，易折断导致光漏损。$$, ARRAY[$$传输介质$$,$$光纤$$]::text[], $${"工学": 0.9, "日子人": 0.3, "管理学": 0.1, "理学": 0.5}$$, 'batch'),
  ($$net_028$$, $$互联网与网络$$, $$multiple$$, $$常见的HTTP响应状态码中，代表客户端或服务端有错误的是哪些系列？$$, $$["1xx", "2xx", "4xx", "5xx"]$$, $$[2, 3]$$, $$medium$$, $$4xx通常是客户端请求错误(如未找到页面)，5xx代表服务端出现内部错误。$$, ARRAY[$$网页开发$$,$$HTTP状态码$$]::text[], $${"工学": 1.0, "理学": 0.8, "日子人": 0.15, "管理学": 0.05}$$, 'batch'),
  ($$net_029$$, $$互联网与网络$$, $$multiple$$, $$防火墙 (Firewall) 在电脑网络安全里的主要作用是？$$, $$["抵御和隔离外部未授权访问", "根据访问控制规则封堵危险IP或端口数据", "杀除计算机内的所有木马", "内部网络与外部互联的审控大门"]$$, $$[0, 1, 3]$$, $$medium$$, $$防火墙主要是内外阻断隔离控制门，而非杀毒软件（杀软才是主要杀木马手段）。$$, ARRAY[$$网络安全$$,$$防火墙$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.45, "文学": 0.2, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$net_030$$, $$互联网与网络$$, $$multiple$$, $$当前互联网架构下防范和缓解DDoS（分布式拒绝服务攻击）的常见方法包括？$$, $$["扩大网络总接入带宽", "使用CDN分流流量", "高防IP清洗流量", "把电脑主机搬到更安全的物理机房"]$$, $$[0, 1, 2]$$, $$hard$$, $$网络攻击是流量层面的，物理机房搬迁解决不了网络层的拥堵堵塞。$$, ARRAY[$$网络安全$$,$$DDoS$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.45, "文学": 0.2, "管理学": 0.05, "理学": 0.25}$$, 'batch'),
  ($$oly_001$$, $$奥运与赛事$$, $$single$$, $$现代奥林匹克运动会的创始人是谁？$$, $$["萨马兰奇", "顾拜旦", "罗格", "巴赫"]$$, $$[1]$$, $$easy$$, $$皮埃尔·德·顾拜旦（Pierre de Coubertin）是法国教育家，现代奥林匹克运动的发起人。$$, ARRAY[$$奥运史$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_002$$, $$奥运与赛事$$, $$single$$, $$第一届现代奥林匹克运动会于1896年在哪个城市举办？$$, $$["巴黎", "伦敦", "雅典", "罗马"]$$, $$[2]$$, $$easy$$, $$为了向前现代奥运（古希腊）致敬，首届现代奥运会在希腊雅典举行。$$, ARRAY[$$现代奥运$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_003$$, $$奥运与赛事$$, $$single$$, $$奥林匹克标志五环不包括什么颜色？$$, $$["蓝色", "黄色", "紫色", "红色"]$$, $$[2]$$, $$easy$$, $$奥运五环的颜色为蓝、黄、黑、绿、红。没有紫色。$$, ARRAY[$$奥运标志$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_004$$, $$奥运与赛事$$, $$single$$, $$奥林匹克格言（Motto）原始版本是“更快、更高、更强”，在2021年新加入的词是？$$, $$["更美", "更团结", "更和平", "更智慧"]$$, $$[1]$$, $$easy$$, $$2021年国际奥委会为应对全球挑战，将格言更新为“更快、更高、更强——更团结”(Faster, Higher, Stronger - Together)。$$, ARRAY[$$奥运格言$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_005$$, $$奥运与赛事$$, $$single$$, $$北京在哪里一年成功举办了夏季奥林匹克运动会？$$, $$["2000年", "2004年", "2008年", "2012年"]$$, $$[2]$$, $$easy$$, $$第29届夏季奥运会于2008年8月8日在中国北京开幕。$$, ARRAY[$$北京奥运$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_006$$, $$奥运与赛事$$, $$single$$, $$创造“双奥之城”历史（既举办过夏季奥运会又举办过冬季奥运会的城市）是？$$, $$["伦敦", "洛杉矶", "北京", "东京"]$$, $$[2]$$, $$easy$$, $$北京在2008年举办夏季奥运会，在2022年举办冬季奥运会，是全球首个双奥之城。$$, ARRAY[$$冬奥会$$,$$北京$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_007$$, $$奥运与赛事$$, $$single$$, $$国际奥委会（IOC）的总部设在哪个国家？$$, $$["法国", "美国", "希腊", "瑞士"]$$, $$[3]$$, $$medium$$, $$国际奥林匹克委员会总部位于瑞士的洛桑。$$, ARRAY[$$国际奥委会$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_008$$, $$奥运与赛事$$, $$single$$, $$夏季奥运会和冬季奥运会目前是交替举行，它们之间的间隔期通常为？$$, $$["一年", "两年", "三年", "四年"]$$, $$[1]$$, $$easy$$, $$自1994年起，夏季奥运会和冬奥会错开举办，每两年轮流逢办一届。$$, ARRAY[$$奥运周期$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_009$$, $$奥运与赛事$$, $$single$$, $$足球界最高荣誉也是最高规格的国际赛事“国际足联世界杯比赛”是由哪个组织主办？$$, $$["国际奥委会", "国际足联", "欧足联", "国家体委"]$$, $$[1]$$, $$easy$$, $$世界杯（World Cup）是由国际足球联合会(FIFA)举办的最高水平足球赛事。$$, ARRAY[$$足球$$,$$世界杯$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_010$$, $$奥运与赛事$$, $$single$$, $$第一届足球世界杯于1930年在哪个国家举办？$$, $$["巴西", "英国", "意大利", "乌拉圭"]$$, $$[3]$$, $$medium$$, $$首届男足世界杯在乌拉圭举办，东道主乌拉圭也夺得了那届的冠军。$$, ARRAY[$$世界杯史$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_011$$, $$奥运与赛事$$, $$single$$, $$在奥运史上，一人单届奥运会狂揽8枚游泳金牌的传奇运动员是？$$, $$["索普", "菲尔普斯", "孙杨", "波波夫"]$$, $$[1]$$, $$easy$$, $$美国游泳天才迈克尔·菲尔普斯在2008年北京奥运会上豪取8金，打破了施皮茨的单届历史纪录。$$, ARRAY[$$游泳$$,$$飞鱼$$]::text[], $${"理学": 0.8, "农学": 0.5, "教育学": 0.25, "历史学": 0.1, "日子人": 0.15}$$, 'batch'),
  ($$oly_012$$, $$奥运与赛事$$, $$single$$, $$男子100米短跑的世界纪录（9.58秒）是由哪位运动员保持的？$$, $$["加特林", "鲍威尔", "尤塞恩·博尔特", "苏炳添"]$$, $$[2]$$, $$easy$$, $$牙买加飞人博尔特在2009年柏林世锦赛上跑出了9.58秒的惊人成绩。$$, ARRAY[$$田径$$,$$短跑$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_013$$, $$奥运与赛事$$, $$single$$, $$历史上夺下世界杯冠军次数最多的国家队是（共被称为“五星”球队）？$$, $$["德国", "意大利", "阿根廷", "巴西"]$$, $$[0]$$, $$easy$$, $$巴西男足分别于1958, 1962, 1970, 1994, 2002获得世界杯冠军$$, ARRAY[$$世界杯$$,$$巴西$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_014$$, $$奥运与赛事$$, $$single$$, $$冬季奥林匹克运动会的最传统强项之一，在冰面上掷石饼以撞击靶心的团队运动是？$$, $$["冰壶", "冰球", "短道速滑", "花样滑冰"]$$, $$[0]$$, $$easy$$, $$冰壶（Curling）也被称为冰上溜石，被称为“冰上国际象棋”。$$, ARRAY[$$冬奥会$$,$$冰壶$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_015$$, $$奥运与赛事$$, $$single$$, $$夺得2022年卡塔尔男足世界杯冠军的国家队是？$$, $$["法国", "阿根廷", "克罗地亚", "巴西"]$$, $$[1]$$, $$easy$$, $$阿根廷队在梅西的带领下，在决赛击败法国夺得该届冠军。$$, ARRAY[$$足球世界杯$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_016$$, $$奥运与赛事$$, $$single$$, $$在所有奥运项目中，最长的常规田径竞赛跑项目是？$$, $$["10000米", "半程马拉松", "男子50公里竞走", "马拉松长跑"]$$, $$[2]$$, $$easy$$, $$50公里竞走曾经是奥运最长田径项目，超过马拉松的42.195km，虽近期赛事有结构调整，但历史长径中最长者仍是50k竞走。$$, ARRAY[$$田径长路$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_017$$, $$奥运与赛事$$, $$single$$, $$现代奥运会上会采集奥运圣火，火种采集仪式通常在哪个国家的赫拉神庙进行？$$, $$["意大利", "法国", "希腊", "西班牙"]$$, $$[2]$$, $$easy$$, $$每届奥运会的火种都会在希腊奥林匹亚遗址的赫拉神庙前由女祭司用凹面镜引太阳光点燃。$$, ARRAY[$$奥运火炬$$,$$希腊$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_018$$, $$奥运与赛事$$, $$single$$, $$第一位在奥运会上获得金牌的中国运动员是？$$, $$["李宁", "许海峰", "刘翔", "伏明霞"]$$, $$[1]$$, $$easy$$, $$许海峰在1984年洛杉矶奥运会上夺得男子自选手枪射击金牌，实现中国奥运金牌零的突破。$$, ARRAY[$$中国奥运史$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_019$$, $$奥运与赛事$$, $$single$$, $$中国女排首次夺得奥运会金牌是在哪一届奥运会上？$$, $$["1984年洛杉矶", "2004年雅典", "2016年里约", "1988年汉城"]$$, $$[0]$$, $$medium$$, $$中国女排在1984年击败美国队首次拿到奥运金牌，并开启五连冠时代的传奇高峰。$$, ARRAY[$$中国女排$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_020$$, $$奥运与赛事$$, $$single$$, $$奥运会游泳正式比赛所用长池的长度是？$$, $$["25米", "50米", "100米", "200米"]$$, $$[1]$$, $$easy$$, $$标准的奥运标准竞赛泳池长50米，而“短池”赛事则为25米。$$, ARRAY[$$游泳池$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_021$$, $$奥运与赛事$$, $$single$$, $$世界第一大冰雪运动赛事NHL是什么赛事的英文缩写？$$, $$["国家冰球联盟", "全球花滑大奖赛", "极限高山滑雪", "冰壶世界杯"]$$, $$[0]$$, $$medium$$, $$NHL（National Hockey League）是北美国家冰球联盟的简称。$$, ARRAY[$$冰球$$,$$冬季赛事$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_022$$, $$奥运与赛事$$, $$single$$, $$欧洲杯（欧洲足球锦标赛）的比赛周期通常是多少年一届？$$, $$["两年", "三年", "四年", "五年"]$$, $$[2]$$, $$easy$$, $$欧洲杯像世界杯一样，每四年举办一届。$$, ARRAY[$$足球赛$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_023$$, $$奥运与赛事$$, $$single$$, $$亚洲规模最大的综合性运动会是？$$, $$["东亚运动会", "全运会", "亚运会", "东南亚运动会"]$$, $$[2]$$, $$easy$$, $$亚运会 (Asian Games) 是亚洲体坛最大的综合盛会。$$, ARRAY[$$亚运会$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_024$$, $$奥运与赛事$$, $$single$$, $$奥运会的比赛项目中唯一一项允许男女选手无差别同场竞技的独特项目是？$$, $$["射箭", "马术", "帆船", "击剑"]$$, $$[1]$$, $$hard$$, $$马术是奥运会赛场上真正不分性别的比赛，男女骑士及马匹在同一标准下公平角逐。$$, ARRAY[$$奥运特别规则$$,$$马术$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_025$$, $$奥运与赛事$$, $$single$$, $$在体操世界杯或奥运会竞技体操中，“鞍马”、“吊环”是男项还是女项专属？$$, $$["男子独有项目", "女子独有项目", "男女均可参加的混合单项", "男女都可以但标准大不同"]$$, $$[0]$$, $$medium$$, $$竞技体操男子有六项（自由操、鞍马、吊环、跳马、双杠、单杠），女子四项（跳马、高低杠、平衡木、自由操）。$$, ARRAY[$$体操$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_026$$, $$奥运与赛事$$, $$single$$, $$网球协会杯（如男子戴维斯杯，女子网球团体赛则称为？）$$, $$["汤姆斯杯", "尤伯杯", "比利·简·金杯", "苏迪曼杯"]$$, $$[2]$$, $$hard$$, $$汤杯尤杯是羽毛球。女子网球国家队团体赛叫比利简金杯（过去叫联合会杯），男子则是戴维斯杯。$$, ARRAY[$$网球团体赛$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_027$$, $$奥运与赛事$$, $$single$$, $$被称为世界一级方程式锦标赛（F1）皇冠上的明珠，唯一在纯正城市街道进行的极其狭窄的夜战/海滨大奖赛通常是指？$$, $$["意大利蒙扎大奖赛", "摩纳哥大奖赛", "比利时大奖赛", "中国上海大奖赛"]$$, $$[1]$$, $$medium$$, $$摩纳哥蒙特卡洛赛道是极其著名的纯街道赛，以惊险、华丽、极难超越闻名。$$, ARRAY[$$F1大奖赛$$,$$摩纳哥$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_028$$, $$奥运与赛事$$, $$single$$, $$NBA的总冠军奖杯名为？$$, $$["大力神杯", "文斯·伦巴第杯", "拉里·奥布莱恩杯", "斯坦利杯"]$$, $$[2]$$, $$hard$$, $$NBA总冠军杯名为拉里·奥布莱恩杯；大力神杯是足球世界杯的；文斯伦巴第是NFL超级碗的；斯坦利杯是NHL冰球的。$$, ARRAY[$$NBA历史奖项$$]::text[], $${"历史学": 1.0, "文学": 0.4, "军事学": 0.3, "教育学": 0.25, "日子人": 0.15}$$, 'batch'),
  ($$oly_029$$, $$奥运与赛事$$, $$single$$, $$羽毛球最高水平的世界男子团体锦标赛叫什么杯？$$, $$["汤姆斯杯", "尤伯杯", "苏迪曼杯", "斯韦思林杯"]$$, $$[0]$$, $$medium$$, $$羽毛球男团叫汤姆斯杯，女团叫尤伯杯，男女混合叫苏迪曼杯。斯韦思林是乒乓球男团的。$$, ARRAY[$$羽毛球赛事$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_030$$, $$奥运与赛事$$, $$single$$, $$在奥运举重比赛中，通常分为哪两个具体动作计算总成绩？$$, $$["抓举和挺举", "侧举和前举", "深蹲和硬拉", "直接上举一段式"]$$, $$[0]$$, $$easy$$, $$奥运会举重包括抓举(Snatch)和挺举(Clean and Jerk)两部分，二者重量合起即为总成绩。$$, ARRAY[$$举重$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_031$$, $$奥运与赛事$$, $$multiple$$, $$奥林匹克五环代表了世界上五个不同大洲的团结。以下选项中哪些是五环所包含的大洲含义（不分具体颜色）？$$, $$["欧洲", "亚洲", "大洋洲与美洲", "南极洲"]$$, $$[0, 1, 2]$$, $$medium$$, $$五环代表：欧洲大陆、亚洲、非洲、大洋洲和美洲大板块。南极洲无人定居，未计算在列（五洲交界）。$$, ARRAY[$$奥运象征$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_032$$, $$奥运与赛事$$, $$multiple$$, $$夏季奥运会中经典的“大项”（Sport）包含哪些？$$, $$["田径", "游泳", "体操", "攀岩"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$田径游泳体操是传统三大项，攀岩等在近期（东京、巴黎）已经作为正式大项增列入奥运。$$, ARRAY[$$奥运比赛项目$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_033$$, $$奥运与赛事$$, $$multiple$$, $$近些年（指2000以后的时代），以下哪些项目是奥运会夏季或冬季新增加的年轻化、都市化比赛项目？$$, $$["滑板", "冲浪", "霹雳舞", "拔河"]$$, $$[0, 1, 2]$$, $$medium$$, $$国际奥委会为了吸引年轻观众，在2020东京和2024巴黎奥运会引入了滑板、冲浪、攀岩和霹雳舞等。$$, ARRAY[$$奥运时代改革$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_034$$, $$奥运与赛事$$, $$multiple$$, $$哪些国家或城市举办过夏季奥林匹克运动会？$$, $$["中国北京", "英国伦敦", "日本东京", "印度新德里"]$$, $$[0, 1, 2]$$, $$easy$$, $$新德里尚未举办过奥运会，而是举办过英联邦运动会和亚运会。$$, ARRAY[$$举办城市$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_035$$, $$奥运与赛事$$, $$multiple$$, $$以下世界名将中，哪些是在田径或游泳之外的领域取得跨时代统治力的运动员？$$, $$["林丹", "罗尼·奥沙利文", "西蒙·拜尔斯", "刘翔"]$$, $$[0, 1, 2]$$, $$easy$$, $$刘翔是田径运动员。林丹、奥沙利文和拜尔斯分别在非田径/游泳项目达成了传奇成就。$$, ARRAY[$$运动员名人堂$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_036$$, $$奥运与赛事$$, $$multiple$$, $$如果一名运动员在奥运会上获得一块奖牌，它通常意味着？$$, $$["极高的个人荣誉及国家的自豪", "其竞技水平位列该届全球赛事前三名", "会自动终身获得国际奥委会全额大笔退休金", "如果检出兴奋剂，奖牌将被剥夺"]$$, $$[0, 1, 3]$$, $$medium$$, $$拿到奥运奖牌是巨大荣誉（世界前三），违规会被剥夺。但是国际奥委会并未向获奖选手发放终身退休金（部分国家自身会有奖励）。$$, ARRAY[$$奖牌制度$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_037$$, $$奥运与赛事$$, $$multiple$$, $$四大网球满贯赛事中，分别在哪些不同的场地上进行角逐？$$, $$["红土场", "草地球场", "硬地球场", "人工冰场"]$$, $$[0, 1, 2]$$, $$easy$$, $$法网是红土；温网是草地；澳网和美网是硬地。网球不在冰面上进行。$$, ARRAY[$$网球满贯$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_038$$, $$奥运与赛事$$, $$multiple$$, $$关于残疾人奥林匹克运动会（Paralympics），以下说法正确的是？$$, $$["它专为身心或智力缺陷的运动员设立", "通常在夏季/冬季奥运会闭幕后，在同一个举办城市举行", "有着和健全奥运完全相同的举办理念和赛事管理标准结构", "由于商业不佳，它几年才举办一次并不定期"]$$, $$[0, 1]$$, $$hard$$, $$自1988年起，残奥会不仅与奥运会同年同城举办，甚至在很多赛事管理规制、分级规则上非常特殊，这不等于“完全相同结构”，而是有一套复杂的医学分级法。$$, ARRAY[$$残奥会$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$oly_039$$, $$奥运与赛事$$, $$multiple$$, $$世界杯（男足）历史上曾夺得过两次及以上冠军的国家队有？$$, $$["乌拉圭", "法国", "意大利", "荷兰"]$$, $$[0, 1, 2]$$, $$hard$$, $$乌拉圭两次，法国两次（1998, 2018），意大利四次，荷兰未曾夺冠（三次无冕之王）。$$, ARRAY[$$足球世界杯$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3}$$, 'batch'),
  ($$oly_040$$, $$奥运与赛事$$, $$multiple$$, $$中国乒乓球在奥运赛场上长期称霸。以下哪些人物是中国乒坛大满贯/奥运冠军选手？$$, $$["邓亚萍", "张怡宁", "马龙", "李隼"]$$, $$[0, 1, 2]$$, $$medium$$, $$邓亚萍、张怡宁、马龙均是划时代的大满冠球员。李隼虽是金牌教练但作为运动员并未拿到奥运冠军大满贯。$$, ARRAY[$$中国乒乓球$$]::text[], $${"教育学": 0.5, "历史学": 0.2, "日子人": 0.3}$$, 'batch'),
  ($$pet_001$$, $$宠物与动物行为学$$, $$single$$, $$狗在感-0-到高兴和兴奋时，尾巴通常会怎么做？$$, $$["紧紧夹在两腿之间", "笔直僵硬挺立", "轻快地左右摇摆", "蜷缩成一团"]$$, $$[2]$$, $$easy$$, $$左右或画圈摇摆通常代表放松和愉悦。$$, ARRAY[$$行为学$$,$$犬类$$]::text[], $${"日子人": 1.0, "农学": 0.6, "生物学": 0.4, "医学": 0.15}$$, 'batch'),
