  ($$pet_019$$, $$宠物与动物行为学$$, $$single$$, $$狗在感-18-到高兴和兴奋时，尾巴通常会怎么做？$$, $$["紧紧夹在两腿之间", "笔直僵硬挺立", "轻快地左右摇摆", "蜷缩成一团"]$$, $$[2]$$, $$easy$$, $$左右或画圈摇摆通常代表放松和愉悦。$$, ARRAY[$$行为学$$,$$犬类$$]::text[], $${"日子人": 1.0, "农学": 0.6, "生物学": 0.4, "医学": 0.15}$$, 'batch'),
  ($$pet_020$$, $$宠物与动物行为学$$, $$single$$, $$狗在感-19-到高兴和兴奋时，尾巴通常会怎么做？$$, $$["紧紧夹在两腿之间", "笔直僵硬挺立", "轻快地左右摇摆", "蜷缩成一团"]$$, $$[2]$$, $$easy$$, $$左右或画圈摇摆通常代表放松和愉悦。$$, ARRAY[$$行为学$$,$$犬类$$]::text[], $${"日子人": 1.0, "农学": 0.6, "生物学": 0.4, "医学": 0.15}$$, 'batch'),
  ($$phi_001$$, $$哲学常识$$, $$single$$, $$古希腊哲学的核心被誉为“雅典三杰”或师徒三代的思想家是？$$, $$["泰勒斯、阿那克西曼德、赫拉克利特", "苏格拉底、柏拉图、亚里士多德", "伊壁鸠鲁、芝诺、卢克莱修", "巴门尼德、普罗泰戈拉、高尔吉亚"]$$, $$[1]$$, $$easy$$, $$苏格拉底是柏拉图的老师，而柏拉图又是亚里士多德的老师，这三人奠定了西方哲学的根基。$$, ARRAY[$$古希腊哲学$$,$$雅典三杰$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_002$$, $$哲学常识$$, $$single$$, $$提出“认识你自己”（Know thyself），采用“产婆术”（辩证问答法）来探求真理的古希腊哲学家是？$$, $$["柏拉图", "毕达哥拉斯", "苏格拉底", "第欧根尼"]$$, $$[2]$$, $$easy$$, $$苏格拉底不留著述，依靠街头辩论（精神助产术）引导人们反思自我和美德。$$, ARRAY[$$古希腊$$,$$苏格拉底$$]::text[], $${"哲学": 1.0, "法学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$phi_003$$, $$哲学常识$$, $$single$$, $$提出“理念论”（Theory of Forms/Ideas）并通过《理想国》中的“洞穴比喻”来阐释现象世界与理念世界关系的哲学家是？$$, $$["亚里士多德", "柏拉图", "康德", "黑格尔"]$$, $$[1]$$, $$medium$$, $$柏拉图认为现实世界只是完美理念世界的不完美倒影，这一思想深入西方哲学骨髓。$$, ARRAY[$$柏拉图$$,$$理念论$$]::text[], $${"哲学": 1.0, "法学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$phi_004$$, $$哲学常识$$, $$single$$, $$被马克思称为“古代最伟大的思想家”，创立了形式逻辑体系，并在物理、生物、伦理等多个领域做出了系统分类的哲学家是？$$, $$["泰勒斯", "恩培多克勒", "亚里士多德", "阿基米德"]$$, $$[2]$$, $$medium$$, $$亚里士多德是百科全书式的学者，在《工具论》中奠定了传统形式逻辑（三段论）的基础。$$, ARRAY[$$亚里士多德$$,$$逻辑学$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_005$$, $$哲学常识$$, $$single$$, $$近代法国哲学家笛卡尔（Descartes）提出的一句确立认识论主体基点的著名命题是？$$, $$["我思故我在", "人是万物的尺度", "知识就是力量", "存在就是被感知"]$$, $$[0]$$, $$easy$$, $$“我思故我在”(Cogito, ergo sum) 意味着“我正在思考”这一行为本身证明了“我”的存有，是笛卡尔普遍怀疑后找到的坚实支点。$$, ARRAY[$$近代哲学$$,$$笛卡尔$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_006$$, $$哲学常识$$, $$single$$, $$强调经验是知识唯一来源，主张人心犹如“白板”(Tabula rasa)等待经验在上面刻画的英国经验主义哲学家是？$$, $$["弗兰西斯·培根", "大卫·休谟", "约翰·洛克", "托马斯·霍布斯"]$$, $$[2]$$, $$medium$$, $$洛克在《人类理智论》中系统阐述了白板说，是英国经验主义的核心人物。$$, ARRAY[$$经验主义$$,$$洛克$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_007$$, $$哲学常识$$, $$single$$, $$将一切知识划分为“事实问题”和“观念关系”，从而对因果律的必然性提出毁灭性怀疑的苏格兰启蒙哲学家是？$$, $$["约翰·洛克", "大卫·休谟", "乔治·贝克莱", "亚当·斯密"]$$, $$[1]$$, $$hard$$, $$大卫·休谟将经验主义推向极致，提出了休谟问题（归纳问题），严重挑战了科学知识的因果必然性。$$, ARRAY[$$休谟$$,$$怀疑论$$]::text[], $${"哲学": 1.0, "法学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$phi_008$$, $$哲学常识$$, $$single$$, $$德国古典哲学的开创者，试图调和理性主义与经验主义危机，撰写了三大批判（纯粹理性、实践理性、判断力）的是？$$, $$["莱布尼茨", "斯宾诺莎", "伊曼努尔·康德", "黑格尔"]$$, $$[2]$$, $$medium$$, $$康德通过“人作为认识的主体主动构建客体现象规律”实现了哲学中的“哥白尼式革命”。$$, ARRAY[$$康德$$,$$三大批判$$]::text[], $${"哲学": 1.0, "法学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$phi_009$$, $$哲学常识$$, $$single$$, $$提出“绝对精神”作为万物基底，并通过“正、反、合”的辩证法阐述历史与逻辑发展的哲学家是？$$, $$["叔本华", "黑格尔", "尼采", "马克思"]$$, $$[1]$$, $$medium$$, $$黑格尔的客观唯心主义辩证法体系是德国古典哲学的集大成与最高峰。$$, ARRAY[$$黑格尔$$,$$辩证法$$]::text[], $${"哲学": 1.0, "法学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$phi_010$$, $$哲学常识$$, $$single$$, $$卡尔·马克思批判地吸收了德国古典哲学，创立的哲学体系被称为？$$, $$["历史唯物主义与辩证唯物主义", "经验唯心主义", "机械唯物论", "存在主义"]$$, $$[0]$$, $$easy$$, $$马克思颠倒了黑格尔的唯心主义体系，创立了基于物质生产实践的历史唯物主义与辩证唯物主义。$$, ARRAY[$$马克思主义哲学$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_011$$, $$哲学常识$$, $$single$$, $$提出“上帝已死”、“超人”理念，对后世存在主义和后现代主义产生极其深远影响的唯意志论哲学家是？$$, $$["叔本华", "克尔凯郭尔", "弗里德里希·尼采", "海德格尔"]$$, $$[2]$$, $$medium$$, $$尼采激烈批判西方传统基督教道德和形而上学，主张重估一切价值体系的权力意志。$$, ARRAY[$$尼采$$,$$存在主义先驱$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_012$$, $$哲学常识$$, $$single$$, $$法国哲学家让-保罗·萨特是20世纪哪一哲学流派的领军人物，他提出“存在先于本质”？$$, $$["现象学", "结构主义", "逻辑实证主义", "存在主义"]$$, $$[3]$$, $$easy$$, $$萨特的“存在先于本质”意为人生来没有先定的目的或本性（对无神论存在主义而言），人通过自由选择来塑造自我本质。$$, ARRAY[$$存在主义$$,$$萨特$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_013$$, $$哲学常识$$, $$single$$, $$中国先秦哲学中，提出“道法自然”、“无为而治”，主张柔能克刚的学派是？$$, $$["儒家", "道家", "法家", "墨家"]$$, $$[1]$$, $$easy$$, $$老子、庄子代表的道家思想核心是顺应自然规律、减损人为干预。$$, ARRAY[$$中国哲学$$,$$道家$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_014$$, $$哲学常识$$, $$single$$, $$中国儒家学派创始人孔子的核心思想概念是？$$, $$["兼爱、非攻", "仁、礼", "理气核心", "刑名法术"]$$, $$[1]$$, $$easy$$, $$孔子思想以“仁”（内在的爱与同情）和“礼”（外在的规范秩序）为核心。$$, ARRAY[$$中国哲学$$,$$儒家$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_015$$, $$哲学常识$$, $$single$$, $$提出“白马非马”这一著名哲学命题以探讨名实逻辑的先秦学派代表人物公孙龙，属于哪一家？$$, $$["名家", "杂家", "阴阳家", "农家"]$$, $$[0]$$, $$medium$$, $$名家以擅长辩论和逻辑分析著称，“白马非马”通过割裂个性与共性的关系来进行诡辩或逻辑辨析。$$, ARRAY[$$中国哲学$$,$$名家$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_016$$, $$哲学常识$$, $$single$$, $$宋明理学中，提出“心外无理”、“心外无物”与“知行合一”的心学集大成者是？$$, $$["程颢", "朱熹", "陆九渊", "王守仁"]$$, $$[3]$$, $$medium$$, $$明代大儒王阳明集心学之大成，提出了致良知、知行合一等影响深远的心学体系。$$, ARRAY[$$中国哲学$$,$$阳明心学$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_017$$, $$哲学常识$$, $$single$$, $$在伦理学领域，由边沁创立，经密尔（J.S. Mill）完善，主张一个行为是否道德取决于它是否带来“最大多数人的最大幸福”的理论是？$$, $$["德性伦理学", "义务论", "功利主义", "契约论"]$$, $$[2]$$, $$hard$$, $$功利主义（也译作效益主义）是一种以实际结果（幸福总和增量）作为道德唯一标准的理论。$$, ARRAY[$$伦理学$$,$$功利主义$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_018$$, $$哲学常识$$, $$single$$, $$以语言和逻辑分析为核心，主张拒斥形而上学假问题，在20世纪极大影响了英美哲学的传统被称为？$$, $$["诠释学", "分析哲学", "后现代主义", "新托马斯主义"]$$, $$[1]$$, $$hard$$, $$分析哲学发源于弗雷格、罗素、早期的维特根斯坦，强调用精密的逻辑和语言分析代替模糊的思辨形而上学。$$, ARRAY[$$分析哲学$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_019$$, $$哲学常识$$, $$single$$, $$提出语言像一种“游戏”，词语的意义在于其在使用过程中的语境（“语义即使用”）的哲学家是？$$, $$["海德格尔", "列维-斯特劳斯", "路德维希·维特根斯坦", "威廉·詹姆斯"]$$, $$[2]$$, $$hard$$, $$后期的维特根斯坦在其《哲学研究》中批判了自己早期的图像论，提出了“语言游戏”和家族相似等概念。$$, ARRAY[$$维特根斯坦$$,$$语言哲学$$]::text[], $${"军事学": 1.0, "工学": 0.6, "理学": 0.3, "哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_020$$, $$哲学常识$$, $$multiple$$, $$在哲学认识论的基本分野中，探讨人类认知起源的两大主流阵营通常是？$$, $$["经验主义", "理性主义", "虚无主义", "犬儒主义"]$$, $$[0, 1]$$, $$medium$$, $$近代早期的认识论争论主要在英国经验派和大陆理性派之间展开。后两者属于人生观上的态度流派。$$, ARRAY[$$认识论$$]::text[], $${"哲学": 1.0, "法学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$phi_021$$, $$哲学常识$$, $$multiple$$, $$斯多葛学派（Stoicism）是古罗马时期非常流行的哲学学派，其代表人物有？$$, $$["塞内卡", "爱比克泰德", "马可·奥勒留", "伊壁鸠鲁"]$$, $$[0, 1, 2]$$, $$hard$$, $$伊壁鸠鲁创立了伊壁鸠鲁学派（强调享乐、避痛），与强调克制欲望、顺应理性和命运的斯多葛学派是对立的。前三位均为晚期斯多葛代表人物。$$, ARRAY[$$斯多葛学派$$]::text[], $${"哲学": 1.0, "法学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$phi_022$$, $$哲学常识$$, $$multiple$$, $$伦理学中常见的三大基本理论框架包括？$$, $$["后果论 / 功利主义", "道德直觉", "义务论", "德性伦理学"]$$, $$[0, 2, 3]$$, $$hard$$, $$行为的后果(功利)、行为的动机准则(义务)、以及行为主体的品行(德行)构成了现代伦理学争论的三大维度。$$, ARRAY[$$伦理学三大维度$$]::text[], $${"哲学": 1.0, "法学": 0.3, "历史学": 0.3}$$, 'batch'),
  ($$phi_023$$, $$哲学常识$$, $$multiple$$, $$中国先秦法家的集大成者韩非子提出君主驾驭国家的“三把刀”是？$$, $$["法", "术", "势", "仁"]$$, $$[0, 1, 2]$$, $$medium$$, $$法家讲究严刑峻法与君主集权，批判儒家的“仁政”是不现实的迂腐之谈。因此法、术、势是核心。$$, ARRAY[$$法家$$,$$中国哲学$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phi_024$$, $$哲学常识$$, $$multiple$$, $$近代政治哲学中，构建了“社会契约论”核心概念以论证国家合法性起源的学者有？$$, $$["托马斯·霍布斯", "约翰·洛克", "让-雅克·卢梭", "阿奎那"]$$, $$[0, 1, 2]$$, $$medium$$, $$霍、洛、卢三人虽对自然状态结论不同，但都是通过设定虚拟自然状态与交出权利的社会契约来论定国家合法性的关键人物。阿奎那是中世纪神学家。$$, ARRAY[$$政治哲学$$,$$社会契约论$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.8, "管理学": 0.6, "文学": 0.3}$$, 'batch'),
  ($$phi_025$$, $$哲学常识$$, $$multiple$$, $$后现代主义（Postmodernism）通常对启蒙时代以来的哪些观念抱有强烈的怀疑和解构态度？$$, $$["宏大叙事 / 普遍真理", "理性的绝对客观性", "主体的统一性与连贯性", "多元文化和个体差异"]$$, $$[0, 1, 2]$$, $$hard$$, $$后门现代哲学家（如福柯、利奥塔、德里达）解构了普遍真理、绝对客观和统一主体，反而鼓吹和推崇多元文化、边缘性。因此怀疑的是前三项。$$, ARRAY[$$后现代主义$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3}$$, 'batch'),
  ($$phy_001$$, $$物理常识$$, $$single$$, $$相对论的提出者是？$$, $$["牛顿", "爱因斯坦", "伽利略", "玻尔"]$$, $$[1]$$, $$easy$$, $$阿尔伯特·爱因斯坦提出了狭义和广义相对论。$$, ARRAY[$$相对论$$,$$著名科学家$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_002$$, $$物理常识$$, $$single$$, $$在国际单位制中，力的单位是？$$, $$["焦耳", "瓦特", "牛顿", "帕斯卡"]$$, $$[2]$$, $$easy$$, $$力的国际单位是牛顿(N)。焦耳是能量单位，瓦特是功率单位，帕斯卡是压强单位。$$, ARRAY[$$物理单位$$,$$力学$$]::text[], $${"理学": 1.0, "工学": 1.0, "军事学": 0.15}$$, 'batch'),
  ($$phy_003$$, $$物理常识$$, $$single$$, $$真空中光速大约为每秒多少千米？$$, $$["30万", "3万", "300万", "340"]$$, $$[0]$$, $$easy$$, $$真空中光速约为3×10^8 m/s，即30万公里每秒。$$, ARRAY[$$光学$$,$$常数$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_004$$, $$物理常识$$, $$single$$, $$牛顿第一定律又称为什么定律？$$, $$["万有引力定律", "惯性定律", "能量守恒定律", "作用与反作用定律"]$$, $$[1]$$, $$easy$$, $$牛顿第一定律指出物体在不受外力作用时保持静止或匀速直线运动状态，因此又称惯性定律。$$, ARRAY[$$力学$$,$$牛顿定律$$]::text[], $${"理学": 1.0, "工学": 1.0, "军事学": 0.15}$$, 'batch'),
  ($$phy_005$$, $$物理常识$$, $$single$$, $$以下哪种电磁波的波长最短？$$, $$["无线电波", "可见光", "X射线", "伽马射线"]$$, $$[3]$$, $$medium$$, $$在电磁波谱中，伽马射线的波长最短，频率最高，能量最大。$$, ARRAY[$$电磁波$$,$$电磁学$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_006$$, $$物理常识$$, $$single$$, $$发现电磁感应现象的物理学家是？$$, $$["法拉第", "麦克斯韦", "安培", "库仑"]$$, $$[0]$$, $$medium$$, $$迈克尔·法拉第于1831年发现了电磁感应现象。$$, ARRAY[$$电磁学$$,$$物理学史$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_007$$, $$物理常识$$, $$single$$, $$声音在以下哪种介质中传播速度最快？$$, $$["真空", "空气", "水", "钢铁"]$$, $$[3]$$, $$easy$$, $$声音在固体中传播速度最快，液体次之，气体较慢，真空中无法传播。$$, ARRAY[$$声学$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_008$$, $$物理常识$$, $$single$$, $$能量守恒和转化定律通常统称为热力学的第几定律？$$, $$["第零定律", "第一定律", "第二定律", "第三定律"]$$, $$[1]$$, $$medium$$, $$热力学第一定律即能量守恒与转化定律。$$, ARRAY[$$热力学$$,$$定律$$]::text[], $${"理学": 1.0, "工学": 1.0, "军事学": 0.15}$$, 'batch'),
  ($$phy_009$$, $$物理常识$$, $$single$$, $$当物体以宇宙速度运动时，第二宇宙速度的数值约为？$$, $$["7.9 km/s", "11.2 km/s", "16.7 km/s", "29.8 km/s"]$$, $$[1]$$, $$medium$$, $$第一宇宙速度约7.9km/s，第二宇宙速度(逃逸速度)约11.2km/s，第三宇宙速度约16.7km/s。$$, ARRAY[$$天体物理$$,$$逃逸速度$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_010$$, $$物理常识$$, $$single$$, $$提出“薛定谔的猫”思想实验，以旨在证明量子力学在宏观条件下的不完备性的是哪位科学家？$$, $$["爱因斯坦", "玻尔", "薛定谔", "海森堡"]$$, $$[2]$$, $$easy$$, $$埃尔温·薛定谔提出了这一个著名的微观与宏观相联系的思想实验。$$, ARRAY[$$量子力学$$,$$思想实验$$]::text[], $${"理学": 1.0, "工学": 1.0, "哲学": 1.0, "历史学": 0.5, "法学": 0.3, "军事学": 0.15}$$, 'batch'),
  ($$phy_011$$, $$物理常识$$, $$single$$, $$描述理想气体在等温条件下，压强与体积成反比关系的定律是？$$, $$["查理定律", "玻意耳定律", "盖-吕萨克定律", "阿伏伽德罗定律"]$$, $$[1]$$, $$medium$$, $$玻意耳定律表明，在定量定温下，理想气体的体积与压强成反比。$$, ARRAY[$$热学$$,$$气体定律$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_012$$, $$物理常识$$, $$single$$, $$用以描述黑洞表面边界（即光也无法逃逸的界限）的概念是？$$, $$["吸积盘", "事件视界", "奇点", "喷流"]$$, $$[1]$$, $$medium$$, $$事件视界是指黑洞的最外层边界，任何物质包括光一旦越过将无法逃离。$$, ARRAY[$$天体物理$$,$$黑洞$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_013$$, $$物理常识$$, $$single$$, $$万有引力常数G的精确测量首次是由谁完成的？$$, $$["牛顿", "伽利略", "卡文迪许", "开普勒"]$$, $$[2]$$, $$hard$$, $$英国物理学家卡文迪许利用扭秤实验首次比较精确地测出了万有引力常数。$$, ARRAY[$$力学$$,$$引力$$]::text[], $${"理学": 1.0, "工学": 1.0, "军事学": 0.15}$$, 'batch'),
  ($$phy_014$$, $$物理常识$$, $$single$$, $$经典力学中，物体的动能公式是？$$, $$["E = mgh", "E = mc^2", "E = 1/2 mv^2", "E = Fs"]$$, $$[2]$$, $$easy$$, $$经典力学中动能的表达式是 1/2 mv^2。$$, ARRAY[$$力学$$,$$公式$$]::text[], $${"理学": 1.0, "工学": 1.0, "军事学": 0.15}$$, 'batch'),
  ($$phy_015$$, $$物理常识$$, $$single$$, $$以下哪种物理现象证明了光具有粒子性？$$, $$["光的衍射", "光电效应", "光的干涉", "光的偏振"]$$, $$[1]$$, $$medium$$, $$爱因斯坦用光量子假说成功解释了光电效应，证明了光的粒子性；而衍射、干涉证明了波动性。$$, ARRAY[$$量子光学$$,$$光电效应$$]::text[], $${"理学": 1.0, "工学": 0.45, "军事学": 0.15}$$, 'batch'),
  ($$phy_016$$, $$物理常识$$, $$single$$, $$交流电的频率在中国和多数欧洲国家的标准工业电网中通常是？$$, $$["50Hz", "60Hz", "110Hz", "220Hz"]$$, $$[0]$$, $$medium$$, $$中国和多数欧洲国家的标准频率是50Hz，而美国和部分地区是60Hz。$$, ARRAY[$$电学$$,$$日常生活$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_017$$, $$物理常识$$, $$single$$, $$热力学第二定律有一种表述是，孤立系统的什么物理量总是趋向于增加？$$, $$["内能", "温度", "焓", "熵"]$$, $$[3]$$, $$hard$$, $$热力学第二定律指出，孤立系统自发过程的熵总是增加的（熵增原理）。$$, ARRAY[$$热力学$$,$$熵$$]::text[], $${"理学": 1.0, "工学": 1.0, "军事学": 0.15}$$, 'batch'),
  ($$phy_018$$, $$物理常识$$, $$single$$, $$根据光的折射定律（斯涅尔定律），光线从光疏介质进入光密介质，折射角与入射角相比会？$$, $$["变大", "变小", "不变", "有可能变大也有可能变小"]$$, $$[1]$$, $$medium$$, $$光疏进光密，折射率增加，速度减慢，光线向法线偏折，折射角变小。$$, ARRAY[$$光学$$,$$折射$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_019$$, $$物理常识$$, $$single$$, $$原子核的主要组成部分是？$$, $$["电子和质子", "质子和中子", "中子和电子", "纯质子"]$$, $$[1]$$, $$easy$$, $$原子核由带正电的质子和不带电的中子组成（除氕外）。周边是电子。$$, ARRAY[$$原子物理$$]::text[], $${"理学": 1.0, "工学": 0.45, "军事学": 0.15}$$, 'batch'),
  ($$phy_020$$, $$物理常识$$, $$single$$, $$在电路中，欧姆定律表明通过一段导体的电流与什么成正比？$$, $$["电压", "电阻", "电功率", "电容"]$$, $$[0]$$, $$easy$$, $$欧姆定律：I = U/R，电流与该导体两端电压成正比，与电阻成反比。$$, ARRAY[$$电学$$,$$欧姆定律$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_021$$, $$物理常识$$, $$single$$, $$超导材料在低于其临界温度时，除了电阻为零外，还具有什么显著特性？$$, $$["铁磁性", "抗磁性", "高硬度", "绝缘性"]$$, $$[1]$$, $$hard$$, $$超导体低于临界温度时具有完全抗磁性（即迈斯纳效应），能排斥内部磁场。$$, ARRAY[$$固体物理$$,$$超导$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_022$$, $$物理常识$$, $$single$$, $$描述流体流速大处压强小、流速小处压强大的著名原理是？$$, $$["阿基米德原理", "伯努利原理", "帕斯卡原理", "托里拆利定律"]$$, $$[1]$$, $$medium$$, $$伯努利原理是流体力学中的重要原理，解释了飞机升力等现象。$$, ARRAY[$$流体力学$$,$$伯努利原理$$]::text[], $${"理学": 1.0, "工学": 1.0, "军事学": 0.15}$$, 'batch'),
  ($$phy_023$$, $$物理常识$$, $$multiple$$, $$以下哪几位物理学家对经典电磁学理论有突出贡献，且名字被用作电磁学单位？$$, $$["安培", "伏特", "特斯拉", "开尔文"]$$, $$[0, 1, 2]$$, $$medium$$, $$安培(电流)、伏特(电压)、特斯拉(磁感应强度)都是电磁学单位且为物理学家名。开尔文是热力学温度单位。$$, ARRAY[$$电磁学$$,$$物理单位$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_024$$, $$物理常识$$, $$multiple$$, $$经典力学中，具有守恒性质的基本物理量在特定条件下包括？$$, $$["动量", "角动量", "能量", "加速度"]$$, $$[0, 1, 2]$$, $$easy$$, $$物理学三大基本守恒定律：能量守恒、动量守恒和角动量守恒。加速度不具有普遍的守恒律。$$, ARRAY[$$力学$$,$$守恒定律$$]::text[], $${"理学": 1.0, "工学": 1.0, "军事学": 0.15}$$, 'batch'),
  ($$phy_025$$, $$物理常识$$, $$multiple$$, $$下列属于基本粒子中的“轻子”的有？$$, $$["电子", "光子", "中微子", "夸克"]$$, $$[0, 2]$$, $$hard$$, $$电子和中微子属于轻子。夸克是组成强子的粒子；光子是玻色子，不是轻子。$$, ARRAY[$$粒子物理$$,$$轻子$$]::text[], $${"理学": 1.0, "工学": 0.45, "军事学": 0.15}$$, 'batch'),
  ($$phy_026$$, $$物理常识$$, $$multiple$$, $$关于宇宙大爆炸理论，下列哪些观测现象提供了有力支持？$$, $$["哈勃定律", "宇宙微波背景辐射", "轻元素丰度", "光电效应"]$$, $$[0, 1, 2]$$, $$hard$$, $$星系退行、宇宙微波背景辐射和原初核合成产生的轻元素丰度是大爆炸理论的三大观测支柱。光电效应支持量子论。$$, ARRAY[$$宇宙学$$,$$大爆炸$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_027$$, $$物理常识$$, $$multiple$$, $$下面哪些现象说明光具有波动性质？$$, $$["干涉", "衍射", "偏振", "康普顿效应"]$$, $$[0, 1, 2]$$, $$medium$$, $$光的双缝干涉、薄膜干涉、衍射以及偏振（说明是横波）都证明了光的波动性。康普顿效应证明了粒子性。$$, ARRAY[$$光学$$,$$光波$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_028$$, $$物理常识$$, $$multiple$$, $$摩擦力根据其相对运动状态可以分为哪几种？$$, $$["静摩擦力", "滑动摩擦力", "滚动摩擦力", "引力"]$$, $$[0, 1, 2]$$, $$easy$$, $$摩擦力通常分为这三类：静摩擦、滑动摩擦和滚动摩擦。引力是另一种基本相互作用。$$, ARRAY[$$力学$$,$$摩擦力$$]::text[], $${"理学": 1.0, "工学": 1.0, "军事学": 0.15}$$, 'batch'),
  ($$phy_029$$, $$物理常识$$, $$multiple$$, $$自然界已知的四种基本相互作用力包括？$$, $$["引力相互作用", "电磁相互作用", "强相互作用", "弱相互作用"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$这四大基本相互作用力支配着宇宙从微观粒子到宏观天体的所有物理现象。$$, ARRAY[$$基础物理$$,$$自然力$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$phy_030$$, $$物理常识$$, $$multiple$$, $$以下哪几种状态属于物质的常见状态或特殊状态？$$, $$["固态", "液态", "等离子态", "玻色-爱因斯坦凝聚态"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$除了常见的固液气，等离子态、玻色-爱因斯坦凝聚态等也是物质的物理状态。$$, ARRAY[$$热学$$,$$物态$$]::text[], $${"理学": 1.0, "工学": 0.9, "军事学": 0.3}$$, 'batch'),
  ($$pol_001$$, $$政治制度$$, $$single$$, $$提出“三权分立”学说的著名法国启蒙思想家是？$$, $$["卢梭", "伏尔泰", "孟德斯鸠", "马基雅维利"]$$, $$[2]$$, $$easy$$, $$孟德斯鸠在《论法的精神》中系统阐述了立法、行政、司法三权分立与制衡的原则。$$, ARRAY[$$政治学说史$$,$$三权分立$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_002$$, $$政治制度$$, $$single$$, $$英国实施的政体形式被称为？$$, $$["总统制共和制", "君主专制", "议会制君主立宪制", "半总统制"]$$, $$[2]$$, $$easy$$, $$英国没有成文宪法，但是世界上最早确立内阁对议会负责、君主作为虚位元首的议会制君主立宪制国家。$$, ARRAY[$$国家政体$$,$$君主立宪$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_003$$, $$政治制度$$, $$single$$, $$美国实行的主要国家政体是？$$, $$["总统制共和制", "议会制共和制", "委员会制", "军政合一政体"]$$, $$[0]$$, $$easy$$, $$美国是典型的总统制共和制国家，总统既是国家元首又是政府首脑，直接领导行政部门，不对国会负责但受其制约。$$, ARRAY[$$国家政体$$,$$美国$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_004$$, $$政治制度$$, $$single$$, $$在美国的大选中，总统并非由全国选民普选票总数直接决定，而是通过一种特殊的间接选举制度，该制度称为？$$, $$["议会推选制", "选举人团制度", "最高法院任命制", "抽签制"]$$, $$[1]$$, $$medium$$, $$美国总统选举实行选举人团制度，各州的选举人票多数归属于在该州普选获胜的候选人（赢者通吃）。$$, ARRAY[$$选举制度$$,$$美国$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_005$$, $$政治制度$$, $$single$$, $$我国最高国家权力机关是？$$, $$["最高人民法院", "国务院", "全国人民代表大会", "全国政治协商会议"]$$, $$[2]$$, $$easy$$, $$《中华人民共和国宪法》规定，中华人民共和国全国人民代表大会是最高国家权力机关。$$, ARRAY[$$中国政治制度$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_006$$, $$政治制度$$, $$single$$, $$在西方政治语境下，“弹劾”（Impeachment）过程通常是指？$$, $$["总统罢免某个内阁部长", "法院否决议会的提议", "立法机关对涉嫌犯罪或严重渎职的政府高级官员发起指控并审判的程序", "民众收回对市长的选举投票"]$$, $$[2]$$, $$medium$$, $$弹劾是立法机关追究总统、高级官员或法官严重违规行为的特殊司法政治程序。$$, ARRAY[$$政治机制$$,$$弹劾$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_007$$, $$政治制度$$, $$single$$, $$下列哪个国家是实行极其分权、拥有较强州自治权利的“联邦制”（Federalism）国家？$$, $$["法国", "日本", "德国", "美国"]$$, $$[3]$$, $$easy$$, $$美国由50个州和一个联邦直辖特区组成，各州享有高度的立法、行政独立权，是典型联邦制。$$, ARRAY[$$国家结构形式$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_008$$, $$政治制度$$, $$single$$, $$在一国范围内，除了中央政府保留国防外交互联网等权力，把大量内政权交给相对独立的基层地方共同体。法国、英国和日本的国家结构属于哪一种与联邦制对应的形式？$$, $$["单一制", "邦联制", "无政府主义", "寡头制"]$$, $$[0]$$, $$medium$$, $$单一制国家（如中、法、日）的权力归中央统一拥有，地方政府的权力是由中央授予而非宪法固有的。$$, ARRAY[$$单一制$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_009$$, $$政治制度$$, $$single$$, $$伊朗等一些中东国家中，由宗教领袖掌握国家最高权力，国家法律建立在宗教教义之上的政体被称为？$$, $$["封建专制政体", "政教合一政体", "世俗立宪制", "军政府独裁"]$$, $$[1]$$, $$medium$$, $$伊朗实行政教合一的伊斯兰共和国体制，最高教席领袖拥有极大甚至决定性的权力。$$, ARRAY[$$政体$$,$$政教合一$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_010$$, $$政治制度$$, $$single$$, $$在内阁制（议会制）国家中，实际掌握国家行政大权并制定政策的职位通常是？$$, $$["国王/女皇", "总统", "总理或首相", "大议长"]$$, $$[2]$$, $$medium$$, $$在议会制国家（如英国、德国、日本），虚位元首不掌握实权，实际政府最高行政长官是总理或首相。$$, ARRAY[$$行政长官$$,$$内阁制$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_011$$, $$政治制度$$, $$single$$, $$“寡头政治”（Oligarchy）主要特征是？$$, $$["一人独裁统治全面事务", "少数掌握大量财富或军事资源的人垄断国家权力", "全民通过直接投票决定国家政策", "没有任何政府管理机构"]$$, $$[1]$$, $$medium$$, $$寡头政治源于古希腊语，指由少数特权阶级或家族集团（寡头）共同统治的政体。$$, ARRAY[$$寡头政治$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_012$$, $$政治制度$$, $$single$$, $$历史上限制英国王权，奠定“王在法下”的近代宪政思想基础的重要文件是？$$, $$["《汉谟拉比法典》", "1215年《大宪章》", "《独立宣言》", "《拿破仑法典》"]$$, $$[1]$$, $$hard$$, $$英国大宪章强迫英王约翰签署，首次确认了君主权力也必须受到封建法律制约的原则。$$, ARRAY[$$宪政史$$,$$大宪章$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_013$$, $$政治制度$$, $$single$$, $$西方两党制最典型的代表是以民主党和共和党两党长期交替执政的国家是？$$, $$["英国", "法国", "美国", "德国"]$$, $$[3]$$, $$easy$$, $$美国是典型的的两党制国家。英国虽然主要是保守党和工党博弈，但常有第三方自由民主党或苏格兰民族党崛起且属于议会制。$$, ARRAY[$$政党制度$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_014$$, $$政治制度$$, $$single$$, $$某些重大立法或主权独立问题上，跳过代议机政府，直接让全体符合资格的公民通过投票做出最终决定的方式是？$$, $$["全民公投", "议院辩论", "行政命令", "抽签决定"]$$, $$[0]$$, $$easy$$, $$全民公决是直接民主的一种实施手段，常用于解决国家结构变化（如脱欧公投）、宪法修正等重大事件。$$, ARRAY[$$民主机制$$]::text[], $${"日子人": 1.0, "工学": 0.3, "艺术学": 0.3, "法学": 0.4, "哲学": 0.3, "历史学": 0.2}$$, 'batch'),
  ($$pol_015$$, $$政治制度$$, $$single$$, $$在选举系统中，议席的分配严格按照各政党在全国或选区所获总选票的百分比来进行分配的制度被称为？$$, $$["多数代表制", "比例代表制", "选举人团制", "禅让制"]$$, $$[1]$$, $$hard$$, $$比例代表制（Proportional Representation）能够让小党在议会中获得与选票相符的席位，体现了更严格的党派代表度。$$, ARRAY[$$选举制度$$,$$比例代表制$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_016$$, $$政治制度$$, $$multiple$$, $$“三权分立”理论中所谓的三权通常包含？$$, $$["立法权", "行政权", "司法权", "铸币权"]$$, $$[0, 1, 2]$$, $$easy$$, $$三权是指制定法律的代码(立法权)、执行政策和管理的政府(行政权)与独立裁决争议的法院(司法权)。$$, ARRAY[$$三权分立$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_017$$, $$政治制度$$, $$multiple$$, $$下列国家中属于联邦制国家的有？$$, $$["俄罗斯", "美国", "德国", "澳大利亚"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$俄、美、德、澳均为由多个州/邦/共和国组成的联邦制国家。它们的次级行政区有显著的自治权。$$, ARRAY[$$国家体系$$,$$联邦制$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_018$$, $$政治制度$$, $$multiple$$, $$常见的现代国家政体类型可以细分为以下哪些结构？$$, $$["总统制共和制", "议会制共和制", "君主立宪制", "部落酋长联盟"]$$, $$[0, 1, 2]$$, $$medium$$, $$部落酋长制并不是现代意义上的主权国家的主流成文代议或共和立宪政体。前三项为标准的现代国家政体形式。$$, ARRAY[$$政权形式$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_019$$, $$政治制度$$, $$multiple$$, $$在中国政治生态和机构中，“两会”是指哪两个重要会议？$$, $$["全国人民代表大会", "中国共产党全国代表大会", "中国人民政治协商会议", "中央经济工作会议"]$$, $$[0, 2]$$, $$easy$$, $$“全国两会”即全国人大与全国政协的统称，通常每年春季同步举行。$$, ARRAY[$$中国政治$$,$$两会$$]::text[], $${"法学": 0.8, "哲学": 0.6, "历史学": 0.4}$$, 'batch'),
  ($$pol_020$$, $$政治制度$$, $$multiple$$, $$国家制度中常常需要平衡“民主”和“效率”，以下体现了或者融合了间接民主代表机制的做法有？$$, $$["雅典城邦式的全体男性公民广场大会宣判", "选民投票选出议员，议员在议会代表选民修法", "按照所支持政党来选举由该党精英代理执政", "由几千民众随机抽号组建陪审团决定战事"]$$, $$[1, 2]$$, $$hard$$, $$代议制（选议员或政党）属于间接民主；广场大会和大规模抽签属于古代纯粹直接民主形态。$$, ARRAY[$$民主理论$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.4}$$, 'batch'),
  ($$psy_001$$, $$心理学常识$$, $$single$$, $$首先建立世界上第一个心理学实验室，被誉为科学心理学诞生标志的科学家是？$$, $$["弗洛伊德", "冯特", "皮亚杰", "马斯洛"]$$, $$[1]$$, $$easy$$, $$威廉·冯特于1879年在莱比锡大学建立了世界上第一个心理学实验室。$$, ARRAY[$$心理学史$$,$$冯特$$]::text[], $${"教育学": 0.8, "理学": 0.5, "医学": 0.5, "管理学": 0.15}$$, 'batch'),
  ($$psy_002$$, $$心理学常识$$, $$single$$, $$精神分析学派的创立者是谁？$$, $$["荣格", "阿德勒", "华生", "弗洛伊德"]$$, $$[3]$$, $$easy$$, $$西格蒙德·弗洛伊德是精神分析学派的创始人。$$, ARRAY[$$心理学史$$,$$精神分析$$]::text[], $${"教育学": 0.8, "理学": 0.5, "医学": 0.5, "管理学": 0.15}$$, 'batch'),
  ($$psy_003$$, $$心理学常识$$, $$single$$, $$巴甫洛夫通过狗的唾液分泌实验提出了什么理论？$$, $$["操作性条件反射", "经典条件反射", "社会学习理论", "认知心理学"]$$, $$[1]$$, $$medium$$, $$巴甫洛夫发现了条件反射的规律，提出经典条件反射理论。$$, ARRAY[$$行为主义$$,$$条件反射$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "教育学": 0.4, "理学": 0.3, "医学": 0.2, "管理学": 0.15}$$, 'batch'),
  ($$psy_004$$, $$心理学常识$$, $$single$$, $$首创需要层次理论，将人的需求分为生理、安全、爱与归属、尊重、自我实现五层的是？$$, $$["罗杰斯", "班杜拉", "马斯洛", "斯金纳"]$$, $$[2]$$, $$easy$$, $$亚伯拉罕·马斯洛提出了著名的需求层次理论。$$, ARRAY[$$人本主义$$,$$马斯洛$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "教育学": 0.4, "理学": 0.3, "医学": 0.2, "管理学": 0.15}$$, 'batch'),
  ($$psy_005$$, $$心理学常识$$, $$single$$, $$认知失调理论是由哪位心理学家提出的？$$, $$["费斯汀格", "勒温", "奥尔波特", "海德"]$$, $$[0]$$, $$medium$$, $$莱昂·费斯汀格于1957年提出了认知失调理论，用于解释人们态度与行为不一致时的心理状态。$$, ARRAY[$$社会心理学$$,$$认知失调$$]::text[], $${"法学": 0.8, "管理学": 0.6, "文学": 0.3, "教育学": 0.8, "理学": 0.5, "医学": 0.5}$$, 'batch'),
  ($$psy_006$$, $$心理学常识$$, $$single$$, $$斯金纳箱实验主要验证了哪种心理学机制？$$, $$["经典条件反射", "操作性条件反射", "完形心理学", "建构主义"]$$, $$[1]$$, $$medium$$, $$斯金纳通过老鼠杠杆实验等，提出并验证了操作性条件反射理论。$$, ARRAY[$$行为主义$$]::text[], $${"哲学": 1.0, "历史学": 0.5, "法学": 0.3, "教育学": 0.4, "理学": 0.3, "医学": 0.2, "管理学": 0.15}$$, 'batch'),
  ($$psy_007$$, $$心理学常识$$, $$single$$, $$马太效应（Matthew Effect）在社会心理学中通常指？$$, $$["近墨者黑", "旁观者效应", "赢家通吃、强者愈强", "破窗效应"]$$, $$[2]$$, $$medium$$, $$马太效应指强者愈强、弱者愈弱的现象，广泛应用在心理学和社会学领域。$$, ARRAY[$$心理学效应$$]::text[], $${"教育学": 0.8, "理学": 0.5, "医学": 0.5, "管理学": 0.15}$$, 'batch'),
  ($$psy_008$$, $$心理学常识$$, $$single$$, $$“旁观者效应”（或“责任分散效应”）核心指出？$$, $$["旁观者越多，救助行为越可能发生", "旁观者越多，个体提供帮助的概率越低", "个人的行为不受环境影响", "看到他人受伤会产生移情"]$$, $$[1]$$, $$easy$$, $$旁观者效应指出，紧急情况下旁观者数量越多，每个人感到自己应负的责任就越少，救助概率降低。$$, ARRAY[$$社会心理学$$]::text[], $${"法学": 0.8, "管理学": 0.6, "文学": 0.3, "教育学": 0.8, "理学": 0.5, "医学": 0.5}$$, 'batch'),
  ($$psy_009$$, $$心理学常识$$, $$single$$, $$人类短时记忆的广度一般为多少个组块（Chucks）？$$, $$["3±1", "7±2", "12±2", "无限"]$$, $$[1]$$, $$medium$$, $$米勒（George Miller）提出人类短时记忆的容量大约为7±2个组块。$$, ARRAY[$$认知心理学$$,$$记忆$$]::text[], $${"教育学": 0.8, "理学": 0.5, "医学": 0.5, "管理学": 0.15}$$, 'batch'),
  ($$psy_010$$, $$心理学常识$$, $$single$$, $$提出儿童认知发展四阶段论（感知运动阶段、前运算阶段、具体运算阶段、形式运算阶段）的是？$$, $$["皮亚杰", "维果斯基", "埃里克森", "科尔伯格"]$$, $$[0]$$, $$medium$$, $$让·皮亚杰是发展心理学的大师，提出了著名的儿童认知发展阶段论。$$, ARRAY[$$发展心理学$$,$$皮亚杰$$]::text[], $${"教育学": 0.8, "理学": 0.5, "医学": 0.5, "管理学": 0.15}$$, 'batch'),
  ($$psy_011$$, $$心理学常识$$, $$single$$, $$艾宾浩斯遗忘曲线表明遗忘的进程是怎样的？$$, $$["匀速遗忘", "先慢后快", "先快后慢", "突然全部遗忘"]$$, $$[2]$$, $$easy$$, $$艾宾浩斯的无意义音节记忆实验得出：遗忘的速度是先快后慢，逐渐趋于平缓。$$, ARRAY[$$记忆规律$$,$$艾宾浩斯$$]::text[], $${"教育学": 0.8, "理学": 0.6, "医学": 0.4, "管理学": 0.3}$$, 'batch'),
  ($$psy_012$$, $$心理学常识$$, $$multiple$$, $$以下哪些心理学流派被称为心理学史上的前三大势力？$$, $$["精神分析学派", "行为主义学派", "人本主义学派", "进化心理学"]$$, $$[0, 1, 2]$$, $$medium$$, $$行为主义被称为第一势力，精神分析是第二势力，人本主义被称为第三势力。$$, ARRAY[$$心理学流派$$]::text[], $${"教育学": 0.8, "理学": 0.5, "医学": 0.5, "管理学": 0.15}$$, 'batch'),
  ($$psy_013$$, $$心理学常识$$, $$multiple$$, $$人格特征的“大五人格”模型（Big Five）包括哪些维度？$$, $$["外向性", "宜人性", "神经质或情绪不稳定性", "压抑性"]$$, $$[0, 1, 2]$$, $$hard$$, $$“大五”包含经验开放性、尽责性(宜人性)、外向性、神经质和严谨性（责任心）。压抑性不是大五人格的一个独立基本维度。$$, ARRAY[$$人格心理学$$,$$大五$$]::text[], $${"教育学": 0.8, "理学": 0.5, "医学": 0.5, "管理学": 0.15}$$, 'batch'),
  ($$psy_014$$, $$心理学常识$$, $$multiple$$, $$自我防御机制是由精神分析流派提出，常见的心理防御机制包括？$$, $$["否认", "投射", "升华", "倒退"]$$, $$[0, 1, 2, 3]$$, $$hard$$, $$自我防御机制指自我用来减轻焦虑的潜意识心理策略，这些选项全部属于常见的防御手段。$$, ARRAY[$$精神分析$$,$$防御机制$$]::text[], $${"教育学": 0.8, "理学": 0.5, "医学": 0.5, "管理学": 0.15}$$, 'batch'),
  ($$psy_015$$, $$心理学常识$$, $$multiple$$, $$心理学研究方法通常有哪些种类？$$, $$["实验法", "观察法", "调查法", "个案法"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$心理学通过极其多样的实证方法如实验、观察、问卷调查、深度个案分析等进行研究。$$, ARRAY[$$研究方法$$]::text[], $${"教育学": 0.8, "理学": 0.6, "医学": 0.4, "管理学": 0.3}$$, 'batch'),
  ($$psy_016$$, $$心理学常识$$, $$single$$, $$以下哪项是弗洛伊德精神分析学派中提出的人格结构理论？$$, $$["生理、心理、社会", "本我、自我、超我", "认知、情感、意志", "内倾、外倾"]$$, $$[1]$$, $$medium$$, $$弗洛伊德认为人格由本我(Id)、自我(Ego)、超我(Superego)构成。$$, ARRAY[$$流派$$,$$精神分析$$]::text[], $${"教育学": 0.8, "理学": 0.5, "医学": 0.5, "管理学": 0.15}$$, 'batch'),
  ($$psy_017$$, $$心理学常识$$, $$single$$, $$日常生活中，我们常说的‘晕轮效应’(光环效应)属于哪种心理学现象？$$, $$["认知偏差", "情绪失调", "记忆遗忘", "动机冲突"]$$, $$[0]$$, $$medium$$, $$晕轮效应是指在人际知觉中所形成的以点概面或以偏概全的主观印象，是一种认知偏差。$$, ARRAY[$$认知心理学$$,$$应用尝试$$]::text[], $${"教育学": 0.8, "理学": 0.5, "医学": 0.5, "管理学": 0.15}$$, 'batch'),
  ($$saf_001$$, $$日常生活与安全$$, $$single$$, $$油锅起火时，最安全的灭火方法是？$$, $$["泼水灭火", "盖上锅盖", "打开抽油烟机", "撒面粉"]$$, $$[1]$$, $$easy$$, $$盖锅盖能隔绝燃烧需要的氧气。泼水和撒面粉易引起爆炸或火势扩大。$$, ARRAY[$$消防$$,$$防灾$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_002$$, $$日常生活与安全$$, $$single$$, $$发生火灾时，在室内如何逃生最安全？$$, $$["乘坐电梯", "直立奔跑", "低姿势匍匐前进", "躲在衣柜里"]$$, $$[2]$$, $$easy$$, $$火灾时有毒烟气会向上升，低姿态匍匐能减少吸入有毒气体。$$, ARRAY[$$消防$$,$$逃生$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_003$$, $$日常生活与安全$$, $$multiple$$, $$下列哪些属于干粉灭火器的正确使用步骤？$$, $$["拔掉保险销", "握住喷管对准火焰根部", "向上抛掷", "按下压把喷射"]$$, $$[0, 1, 3]$$, $$medium$$, $$干粉灭火器使用口诀'一提二拔三握四压'，要对准火焰根部喷射。$$, ARRAY[$$消防$$,$$灭火器$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_004$$, $$日常生活与安全$$, $$single$$, $$家用电器起火时，第一步应该做什么？$$, $$["泼水", "用湿毛巾盖住", "切断电源", "用灭火器喷射"]$$, $$[2]$$, $$easy$$, $$电器起火首要是切断电源，防止触电和火势蔓延。$$, ARRAY[$$电器安全$$,$$消防$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_005$$, $$日常生活与安全$$, $$single$$, $$电动车充电的最佳地点是？$$, $$["楼道内", "室内客厅", "室外集中充电桩", "封闭阳台"]$$, $$[2]$$, $$easy$$, $$电动车火灾蔓延快、毒气大，必须在室外规范的充电桩充电。$$, ARRAY[$$消防安全$$,$$电动车$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 1.0, "军事学": 0.4, "管理学": 0.2}$$, 'batch'),
  ($$saf_006$$, $$日常生活与安全$$, $$single$$, $$如果发现煤气泄漏，以下哪个行为是不能做的？$$, $$["开窗通风", "立刻拨打电话报警", "关闭煤气阀门", "敲击管道查看"]$$, $$[1]$$, $$easy$$, $$在泄漏区域拨打电话可能产生电火花引发爆炸，应到室外安全区域拨打。$$, ARRAY[$$煤气安全$$,$$防灾$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_007$$, $$日常生活与安全$$, $$single$$, $$被热水烫伤后，正确的紧急处理方法第一步是？$$, $$["涂抹牙膏", "涂抹酱油", "用流动的冷水冲洗", "挑破水泡"]$$, $$[2]$$, $$easy$$, $$烫伤后应立即用冷水冲洗降温，减轻深层组织损伤。$$, ARRAY[$$急救$$,$$健康$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_008$$, $$日常生活与安全$$, $$multiple$$, $$遇到有人心搏骤停倒地，急救链的关键环节包括？$$, $$["立即拨打急救电话", "进行心肺复苏", "使用AED", "喂水和食物"]$$, $$[0, 1, 2]$$, $$medium$$, $$急救链包括呼救、CPR、AED和高级生命支持，不可给失去意识的人喂食水防止窒息。$$, ARRAY[$$急救$$,$$CPR$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_009$$, $$日常生活与安全$$, $$single$$, $$关于AED(自动体外除颤器)的使用，以下说法正确的是？$$, $$["只能由医生使用", "会电击所有患者", "开机后根据语音提示操作即可", "需要先测血压"]$$, $$[2]$$, $$easy$$, $$AED是为非专业人员设计的“傻瓜”除颤器，语音提示明确。$$, ARRAY[$$AED$$,$$急救$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_010$$, $$日常生活与安全$$, $$single$$, $$骨折后进行肢体固定，主要是为了？$$, $$["止血", "防止骨折端刺伤血管和神经", "减轻关节肿胀", "促进骨缝愈合"]$$, $$[1]$$, $$easy$$, $$固定能限制断骨活动，防止二次损伤并减轻疼痛。$$, ARRAY[$$急救$$,$$骨折$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_011$$, $$日常生活与安全$$, $$single$$, $$动脉出血的特征是？$$, $$["血液呈暗红色，缓缓流出", "血液呈鲜红色，喷射状", "血液呈暗红色，渗出", "血液呈粉红色"]$$, $$[1]$$, $$easy$$, $$动脉血压力高、含氧量高，所以呈鲜红色且喷射或随心跳涌出。$$, ARRAY[$$创伤救护$$,$$急救$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_012$$, $$日常生活与安全$$, $$multiple$$, $$哪些是海姆立克急救法（腹部冲击法）的适用对象？$$, $$["气道完全异物梗阻的清醒成人", "一岁以下婴儿", "气道梗阻的儿童", "无意识的孕妇"]$$, $$[0, 2]$$, $$medium$$, $$一岁婴儿和孕妇、极度肥胖者及无意识者有特殊方法，正常清醒成人和儿童适用该法。$$, ARRAY[$$海姆立克$$,$$急救$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_013$$, $$日常生活与安全$$, $$single$$, $$乘坐飞机时，安全指示灯亮起，如果在厕所内应？$$, $$["立刻返回座位", "站在原地不动", "立即回到座位系好安全带，若来不及则抓紧厕所扶手", "继续使用"]$$, $$[2]$$, $$easy$$, $$遇到颠簸需立刻固定身体，若无法回座，在洗手间也要抓紧扶手低姿态。$$, ARRAY[$$航空安全$$,$$出行$$]::text[], $${"工学": 1.0, "理学": 0.6, "日子人": 1.0, "医学": 0.8}$$, 'batch'),
  ($$saf_014$$, $$日常生活与安全$$, $$single$$, $$发生地震时，若身处高楼内，应优先选择躲避在？$$, $$["阳台或窗边", "承重墙墙角或卫生间等开间小的地方", "电梯内", "床底下"]$$, $$[1]$$, $$medium$$, $$开间小、有承重墙、有水源的区域更容易形成生存空间。$$, ARRAY[$$地震逃生$$,$$防灾$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_015$$, $$日常生活与安全$$, $$multiple$$, $$驾车在高速公路上发生故障或事故，应遵循的原则是？$$, $$["车靠边", "人撤离", "即报警", "在车内等待救援"]$$, $$[0, 1, 2]$$, $$easy$$, $$“车靠边、人撤离、即报警”是高速公路事故处理的九字警句。$$, ARRAY[$$交通安全$$,$$驾驶$$]::text[], $${"工学": 0.6, "日子人": 1.0, "医学": 0.8}$$, 'batch'),
  ($$saf_016$$, $$日常生活与安全$$, $$single$$, $$行人过马路时，如果人行横道绿灯闪烁，说明？$$, $$["可以慢走通过", "已进入人行横道的加快通过，未进入的停止", "所有行人必须停下", "可以跑着过去"]$$, $$[1]$$, $$easy$$, $$绿灯闪烁代表即将变为红灯，应加快通过或停止进入。$$, ARRAY[$$交通安全$$,$$交规$$]::text[], $${"工学": 0.6, "日子人": 1.0, "医学": 0.8}$$, 'batch'),
  ($$saf_017$$, $$日常生活与安全$$, $$single$$, $$如果车辆落水，自救的最佳时机是？$$, $$["等水完全淹没车辆后", "刚落水，车内外水位差较小的几秒钟", "水漫过车门的一半时", "水淹没到脖子时"]$$, $$[1]$$, $$medium$$, $$刚落水时车门容易打开，或者利用安全锤砸破车窗玻璃逃生。$$, ARRAY[$$车辆安全$$,$$逃生$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_018$$, $$日常生活与安全$$, $$single$$, $$关于夜间驾驶，以下哪种做法可能引起危险？$$, $$["在照明良好的市区路段开启远光灯", "超车时变换远近光灯", "在视线不良的无照明路段开启远光灯", "会车时提前切换为近光灯"]$$, $$[0]$$, $$easy$$, $$市区道路开启远光灯会使对向驾驶员瞬间致盲，容易引发事故。$$, ARRAY[$$夜间驾驶$$,$$交通$$]::text[], $${"工学": 0.6, "日子人": 0.8, "医学": 0.15}$$, 'batch'),
  ($$saf_019$$, $$日常生活与安全$$, $$multiple$$, $$以下哪些食品由于可能发芽变绿产生龙葵素，不宜食用？$$, $$["土豆", "发芽的马铃薯", "青番茄", "洋葱"]$$, $$[0, 1]$$, $$easy$$, $$发芽变绿的土豆含有大量龙葵素，有毒不可食用。$$, ARRAY[$$食品安全$$,$$饮食$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_020$$, $$日常生活与安全$$, $$single$$, $$野生蘑菇中毒的根本原理主要是？$$, $$["重金属超标", "农药残留", "含有强烈的自然毒素如鹅膏毒肽", "细菌污染"]$$, $$[2]$$, $$medium$$, $$致命毒蘑菇含有如鹅膏毒肽等生物毒素，致死率极高且无特效药。$$, ARRAY[$$食品安全$$,$$中毒$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_021$$, $$日常生活与安全$$, $$single$$, $$在预防食物中毒时，肉类和家禽的烹饪温度至少应达到？$$, $$["50℃", "60℃", "71℃及以上", "100℃必须煮一小时"]$$, $$[2]$$, $$medium$$, $$USDA建议禽肉至少到达165℉(74℃)，肉类中心也应达到71℃以上以杀灭有害菌。$$, ARRAY[$$食品卫生$$,$$烹饪$$]::text[], $${"日子人": 1.0, "农学": 0.4, "医学": 0.2, "工学": 0.1}$$, 'batch'),
  ($$saf_022$$, $$日常生活与安全$$, $$multiple$$, $$下列哪些习惯有助于预防生熟食交叉污染？$$, $$["生熟食物使用同一把菜刀", "处理生肉后彻底洗手", "生肉存放在冰箱下层", "使用不同的案板切生肉和熟食"]$$, $$[1, 2, 3]$$, $$easy$$, $$生肉存放下层可防止血水滴落污染其他食物，必须分案板和刀具。$$, ARRAY[$$食品卫生$$,$$常识$$]::text[], $${"日子人": 1.0, "医学": 0.3, "工学": 0.2}$$, 'batch'),
  ($$saf_023$$, $$日常生活与安全$$, $$single$$, $$对于过期食品，正确的处理态度应该是？$$, $$["只要没异味就能吃", "加热煮熟后就可以吃", "无论状态如何，丢弃或不再食用", "直接喂给宠物"]$$, $$[2]$$, $$easy$$, $$超出保质期食品安全无法保证，不应食用更不应喂给宠物。$$, ARRAY[$$食品安全$$,$$保质期$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_024$$, $$日常生活与安全$$, $$single$$, $$遇到电话推销，对方要求提供验证码或者银行卡密码，正确的做法是？$$, $$["配合提供", "只提供验证码", "立刻挂断，不提供任何验证码、密码", "询问对方公司名字后再给"]$$, $$[2]$$, $$easy$$, $$任何机构不会在电话中要求提供密码或验证码，绝不透露。$$, ARRAY[$$电信诈骗$$,$$防骗$$]::text[], $${"日子人": 1.0, "医学": 0.3, "工学": 0.2}$$, 'batch'),
  ($$saf_025$$, $$日常生活与安全$$, $$multiple$$, $$以下典型的“杀猪盘”诈骗特征包括哪些？$$, $$["突然的网络恋爱或交友", "带你投资理财或博彩", "高额无风险收益", "前期小额盈利后诱导大额投入"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$这四项都是杀猪盘的核心套路。$$, ARRAY[$$反诈$$,$$杀猪盘$$]::text[], $${"日子人": 1.0, "医学": 0.3, "工学": 0.2}$$, 'batch'),
  ($$saf_026$$, $$日常生活与安全$$, $$single$$, $$发现自己的身份证遗失，应该第一时间？$$, $$["发朋友圈寻找", "到公安机关挂失/补办，可登报声明", "不管它", "自己打印一张复印件"]$$, $$[1]$$, $$easy$$, $$必须及时由公安机关挂失，防止被不法分子冒用。$$, ARRAY[$$证件安全$$,$$日常$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_027$$, $$日常生活与安全$$, $$single$$, $$接到自称“公检法”要求把钱转入“安全账户”的电话，这是？$$, $$["办案需要", "常规流程", "典型的电信诈骗", "反洗钱调查"]$$, $$[2]$$, $$easy$$, $$公检法没有所谓的“安全账户”，也绝不会电话要求转账。$$, ARRAY[$$反诈骗$$,$$安全$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_028$$, $$日常生活与安全$$, $$multiple$$, $$哪些密码设置习惯是不安全的？$$, $$["生日组合", "所有账号使用同一个密码", "123456或qwerty", "包含大小写字母和符号的不规律字符串"]$$, $$[0, 1, 2]$$, $$easy$$, $$弱口令和多平台复用极易被撞库破解。$$, ARRAY[$$网络安全$$,$$防黑客$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3, "文学": 0.2}$$, 'batch'),
  ($$saf_029$$, $$日常生活与安全$$, $$single$$, $$购买家用灭火器时，通常最适合家庭通用的是？$$, $$["二氧化碳灭火器", "ABC干粉灭火器", "泡沫灭火器", "清水型灭火器"]$$, $$[1]$$, $$easy$$, $$ABC干粉可以扑灭固体、液体、气体及带电设备初起火灾，家庭最适用。$$, ARRAY[$$消防器材$$,$$生活用品$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_030$$, $$日常生活与安全$$, $$single$$, $$若不慎将水银体温计打碎，处理散落水银的最佳方法是？$$, $$["用吸尘器吸走", "用扫帚扫破", "用纸板或注射器收集，放入密闭容器中", "直接冲入下水道"]$$, $$[2]$$, $$medium$$, $$水银易挥发且有毒，不可用扫帚和吸尘器(会加速挥发)，需密闭且作为有害垃圾处理。$$, ARRAY[$$居家安全$$,$$有毒物$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_031$$, $$日常生活与安全$$, $$single$$, $$使用燃气热水器洗澡时，引发一氧化碳中毒的主要原因是？$$, $$["水温过高", "燃气泄漏", "通风不良导致燃烧不充分，产生并积聚一氧化碳", "天然气本身有毒"]$$, $$[2]$$, $$medium$$, $$无烟道或排风不畅时，燃气不完全燃烧即产生致命的一氧化碳。$$, ARRAY[$$燃气安全$$,$$中毒$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_032$$, $$日常生活与安全$$, $$multiple$$, $$在山区游玩突遇暴雨和泥石流，应该如何逃生？$$, $$["顺着沟谷往下跑", "向两侧高处山坡跑去", "爬上树去", "躲在巨石后"]$$, $$[1]$$, $$medium$$, $$泥石流顺着沟谷冲刷，必须向垂直于沟谷的两侧高处逃离。$$, ARRAY[$$自然灾害$$,$$地质灾害$$,$$逃生$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_033$$, $$日常生活与安全$$, $$single$$, $$乘坐公交车时遇到突发火灾，车门无法开启时该怎么做？$$, $$["等待司机处理", "跳出车窗外", "使用安全锤击碎车窗玻璃四个角逃生", "用力推扯车门"]$$, $$[2]$$, $$easy$$, $$安全锤击打钢化玻璃的四角最容易击碎，可迅速开辟逃生通道。$$, ARRAY[$$公交安全$$,$$逃生$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_034$$, $$日常生活与安全$$, $$single$$, $$夏季中暑时，最严重的表现形式是？$$, $$["先兆中暑", "热痉挛", "热射病", "热衰竭"]$$, $$[2]$$, $$hard$$, $$热射病体温可达40℃以上，体内器官受损，致死率高。$$, ARRAY[$$医疗急救$$,$$夏天避暑$$]::text[], $${"医学": 1.0, "理学": 0.5, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_035$$, $$日常生活与安全$$, $$multiple$$, $$正确的止血带使用原则包括？$$, $$["扎在伤口近心端", "每隔一段时间要松开放松几分钟", "记录绑扎时间", "可以用铁丝代替"]$$, $$[0, 1, 2]$$, $$medium$$, $$止血带需要定时放松防坏死，且必须标记时间，铁丝易切断组织不能用。$$, ARRAY[$$创伤$$,$$急救$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_036$$, $$日常生活与安全$$, $$single$$, $$被猫狗等动物咬伤后，最首要的处理措施是？$$, $$["立刻打狂犬疫苗", "用嘴吸出毒血", "用肥皂水和流动水交替冲洗伤口15分钟以上", "包扎伤口"]$$, $$[2]$$, $$medium$$, $$就医前彻底冲洗伤口能大幅度减少病毒附着，是第一步救命措施。$$, ARRAY[$$动物咬伤$$,$$狂犬病$$]::text[], $${"理学": 0.8, "农学": 0.5, "日子人": 0.5, "医学": 0.15, "工学": 0.1}$$, 'batch'),
  ($$saf_037$$, $$日常生活与安全$$, $$single$$, $$对于溺水者，救上岸后发现其失去呼吸心跳，首先应进行？$$, $$["控水", "立刻进行心肺复苏术", "掐人中", "用毯子保温等待急救车"]$$, $$[1]$$, $$medium$$, $$溺水急救不要浪费时间控水，应尽早进行心肺复苏，恢复心跳和供氧。$$, ARRAY[$$溺水急救$$,$$CPR$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_038$$, $$日常生活与安全$$, $$multiple$$, $$安全帽在建筑工地佩戴时，需要注意哪些细节？$$, $$["下颚带必须扣紧", "帽子可以歪带", "缓冲衬垫完整", "可以用普通的塑料帽代替"]$$, $$[0, 2]$$, $$easy$$, $$安全帽必须戴正且扣紧下颚带，内部缓冲结构完整才能起保护作用。$$, ARRAY[$$劳保用品$$,$$施工安全$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_039$$, $$日常生活与安全$$, $$single$$, $$购买防晒霜时，SPF值代表的是？$$, $$["防UVA的时间", "防晒伤的保护指数", "防水时间", "防黑指数"]$$, $$[1]$$, $$medium$$, $$SPF是防晒指数，主要对抗UVB，防晒黑看PA值(对抗UVA)。$$, ARRAY[$$防晒$$,$$生活常识$$]::text[], $${"日子人": 1.0, "医学": 0.3, "工学": 0.2}$$, 'batch'),
  ($$saf_040$$, $$日常生活与安全$$, $$single$$, $$存放化学清洁剂的正确做法是？$$, $$["放在下层橱柜且不加锁", "和食品混合存放", "标识清晰并存放在儿童接触不到的高处", "随意放置"]$$, $$[2]$$, $$easy$$, $$化学品防误服的核心是远离儿童和标签清晰。$$, ARRAY[$$居家存放$$,$$儿童安全$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_041$$, $$日常生活与安全$$, $$multiple$$, $$哪些表现可能是脑卒中（中风）的早期信号？$$, $$["口角歪斜", "一侧肢体无力或麻木", "言语不清或理解困难", "突发剧烈头痛"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$中风120口诀：1张脸歪，2只胳膊无力，0(聆)听说话不清。$$, ARRAY[$$急救$$,$$中风$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_042$$, $$日常生活与安全$$, $$single$$, $$在雾霾天外出，哪种口罩防护效果最好？$$, $$["医用外科口罩", "棉布口罩", "N95/KN95防颗粒物口罩", "活性炭口罩"]$$, $$[2]$$, $$easy$$, $$含有静电非织造滤层的N95级能有效过滤微小颗粒物(PM2.5)。$$, ARRAY[$$雾霾$$,$$口罩$$]::text[], $${"日子人": 1.0, "医学": 0.3, "工学": 0.2}$$, 'batch'),
  ($$saf_043$$, $$日常生活与安全$$, $$single$$, $$如何判断灭火器是否处于有效工作压力状态？$$, $$["看外观新旧", "压力表指针指向绿色区域", "摇晃听声音", "看生产日期即可"]$$, $$[1]$$, $$easy$$, $$指针在绿色区域表示压力正常；红色压力不足，黄色压力偏高。$$, ARRAY[$$消防安全$$,$$灭火器查验$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_044$$, $$日常生活与安全$$, $$multiple$$, $$防止儿童意外坠楼的有效措施有？$$, $$["安装儿童安全窗锁或窗网", "阳台不放置可供攀爬的杂物", "家长保持持续看护", "告诉孩子别去窗边就行了"]$$, $$[0, 1, 2]$$, $$easy$$, $$孩子没有安全概念，“告诉孩子”不能作为实质的防护手段，必须通过物理限制和看护。$$, ARRAY[$$儿童安全$$,$$防坠$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_045$$, $$日常生活与安全$$, $$single$$, $$发生煤气中毒时，首先应？$$, $$["将患者就地平躺", "喂水喝", "迅速打开门窗通风并将患者移至空气新鲜处", "拨打110"]$$, $$[2]$$, $$easy$$, $$脱离中毒环境和吸入新鲜空气是最优先的急救措施。$$, ARRAY[$$急救$$,$$中毒处理$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_046$$, $$日常生活与安全$$, $$single$$, $$使用微波炉加热食品时，不能使用什么材质的容器？$$, $$["陶瓷", "耐热玻璃", "带金属边的碗碟", "微波炉专用塑料容器"]$$, $$[2]$$, $$easy$$, $$微波遇到金属会反射甚至产生火花电弧，极易损坏设备或引起火灾。$$, ARRAY[$$家电安全$$,$$微波炉$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_047$$, $$日常生活与安全$$, $$multiple$$, $$下列哪些行为违反了个人信息保护原则？$$, $$["随意丢弃快递面单", "在不明小问卷上留下真实身份、手机号", "复印身份证时加注'仅限办理XX业务使用'", "在维修电脑前不删除私人照片"]$$, $$[0, 1, 3]$$, $$easy$$, $$保护个人信息要销毁面单、谨慎留存并保护硬盘隐私。加注水印是正确的做法。$$, ARRAY[$$隐私保护$$,$$信息安全$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_048$$, $$日常生活与安全$$, $$single$$, $$遇到电梯故障被困轿厢内，首先应该？$$, $$["用力扒门", "在里面大声呼救并乱跳", "按下电梯内的紧急呼叫按钮与外界联系", "从顶部天窗爬出"]$$, $$[2]$$, $$easy$$, $$按紧急呼叫器求助并耐心等待是最安全的做法，扒门爬天窗极易坠井。$$, ARRAY[$$电梯安全$$,$$自救$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_049$$, $$日常生活与安全$$, $$single$$, $$地铁内万一发生火灾，如何撤离？$$, $$["顺风方向跑", "迎着新鲜空气方向低头弯腰撤离", "躲在座位底下", "拉开车门跳车"]$$, $$[1]$$, $$medium$$, $$地铁隧道为管道布局，逆风跑能避开被气流吹来的有毒烟雾。$$, ARRAY[$$地铁逃生$$,$$消防$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_050$$, $$日常生活与安全$$, $$multiple$$, $$常见的毒品伪装形式可能包括？$$, $$["“奶茶”粉", "“跳跳糖”", "“邮票”", "“可乐”饮料"]$$, $$[0, 1, 2, 3]$$, $$medium$$, $$新型毒品常伪装成日常零食饮料，警惕陌生人给的此类物品。$$, ARRAY[$$禁毒$$,$$自我保护$$]::text[], $${"日子人": 1.0, "医学": 0.3, "工学": 0.2}$$, 'batch'),
  ($$saf_051$$, $$日常生活与安全$$, $$single$$, $$为了预防雷击，在雷雨天在室外不正确的是？$$, $$["不在大树下避雨", "不打有金属尖的雨伞", "跑到空旷高地", "停止水上活动"]$$, $$[2]$$, $$easy$$, $$空旷高地会让人成为突出的导体，更容易遭雷击。$$, ARRAY[$$防雷$$,$$极端天气$$]::text[], $${"日子人": 1.0, "医学": 0.3, "工学": 0.2}$$, 'batch'),
  ($$saf_052$$, $$日常生活与安全$$, $$single$$, $$冬季室内取暖时，如果空气非常干燥容易引发什么问题？$$, $$["二氧化碳过多", "呼吸道黏膜干燥、易起静电", "室温过高", "缺氧"]$$, $$[1]$$, $$easy$$, $$过度干燥使得黏膜屏障减弱易感冒，同时也容易引发静电。$$, ARRAY[$$健康$$,$$过冬$$]::text[], $${"日子人": 1.0, "医学": 0.3, "工学": 0.2}$$, 'batch'),
  ($$saf_053$$, $$日常生活与安全$$, $$multiple$$, $$以下哪些是心脏病发作时的常见症状？$$, $$["胸部压迫性疼痛并可能放射至左肩背", "大汗淋漓", "呼吸急促", "左手中指刺痛"]$$, $$[0, 1, 2]$$, $$medium$$, $$胸痛伴冷汗、放射痛是缺血性心脏病典型特征。$$, ARRAY[$$急救$$,$$心脏病$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_054$$, $$日常生活与安全$$, $$single$$, $$被黄蜂蛰伤后，由于其毒液为碱性，可涂抹什么缓解？$$, $$["肥皂水", "氨水", "食醋等弱酸性液体", "牙膏"]$$, $$[2]$$, $$hard$$, $$黄蜂(马蜂)毒液偏碱性可用酸性液体中和，蜜蜂毒液呈酸性则用肥皂水等弱碱性液体。$$, ARRAY[$$虫咬急救$$,$$生活医学$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_055$$, $$日常生活与安全$$, $$single$$, $$高铁上不允许吸烟的主要原因是？$$, $$["影响他人健康", "车厢空间小", "会触发高灵敏度的烟雾报警器导致紧急降速停车", "车规规定"]$$, $$[2]$$, $$medium$$, $$高铁全封闭且装有高灵敏烟雾探测报警系统，吸烟会导致自动降速逼停列车引发事故。$$, ARRAY[$$高铁知识$$,$$安全法$$]::text[], $${"工学": 1.0, "军事学": 0.4, "管理学": 0.2, "医学": 0.8, "日子人": 1.0}$$, 'batch'),
  ($$saf_056$$, $$日常生活与安全$$, $$multiple$$, $$网购快递如果显示包裹破损或包装被调换过，你应该？$$, $$["直接签收再联系卖家", "当面验货并拍照留存证据", "拒收", "找人代收"]$$, $$[1, 2]$$, $$easy$$, $$外包装明显破损应验尸甚至直接拒收，并留存证据交由卖家和快递处理。$$, ARRAY[$$消费者权益$$,$$网购$$]::text[], $${"日子人": 1.0, "医学": 0.3, "工学": 0.2}$$, 'batch'),
  ($$saf_057$$, $$日常生活与安全$$, $$single$$, $$发现有人触电，正确的第一行动是？$$, $$["用手去拉开触电者", "大声呼救", "切断电源或用绝缘物体挑开电线", "往触电者身上泼冷水"]$$, $$[2]$$, $$easy$$, $$未切断电源前触电者带电，用手拉会造成连环触电。$$, ARRAY[$$触电急救$$,$$安全用电$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_058$$, $$日常生活与安全$$, $$single$$, $$“过劳死”发病的核心物理原因多数是由于？$$, $$["长期缺乏睡眠", "神经衰弱", "潜在心脑血管系统疾病突然发作", "营养不良"]$$, $$[2]$$, $$medium$$, $$过度劳累是诱因，直接死因多为心肌梗死、脑出血等心脑血管急症。$$, ARRAY[$$职业健康$$,$$医学常识$$]::text[], $${"日子人": 1.0, "医学": 0.3, "工学": 0.2}$$, 'batch'),
  ($$saf_059$$, $$日常生活与安全$$, $$multiple$$, $$游泳时如果不慎发生小腿抽筋，正确的应对方法是？$$, $$["大声呼救并用力挣扎", "保持冷静，深吸气", "在水下将抽筋腿伸直，并把脚趾用力向背侧弯起", "立刻游回岸边"]$$, $$[1, 2]$$, $$medium$$, $$深吸气增加浮力，反向拉伸肌肉能缓解抽筋，挣扎会导致下沉加速溺水。$$, ARRAY[$$游泳安全$$,$$防溺水$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
  ($$saf_060$$, $$日常生活与安全$$, $$single$$, $$如果在野外迷路，以下哪种方法不适合用来辨别方向？$$, $$["利用指南针或GPS", "观察树木年轮，宽的一面是南方", "寻找北极星", "看鸟飞的方向"]$$, $$[3]$$, $$easy$$, $$鸟类飞行受觅食和气候即时影响大，无法作为辨别方向的稳定依据。$$, ARRAY[$$野外生存$$,$$方向辨别$$]::text[], $${"医学": 0.8, "日子人": 1.0, "工学": 0.3}$$, 'batch'),
