  ($$spo_001$$, $$体育常识$$, $$single$$, $$标准的一场足球比赛（非加时）总时长为多少分钟？$$, $$["60分钟", "90分钟", "100分钟", "120分钟"]$$, $$[1]$$, $$easy$$, $$一场标准的成年人11制足球比赛总时长为90分钟，分为上下半场各45分钟。$$, ARRAY[$$足球$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_002$$, $$体育常识$$, $$single$$, $$被称为世界第一大运动的是？$$, $$["篮球", "网球", "排球", "足球"]$$, $$[3]$$, $$easy$$, $$足球由于其全球广泛的参与度和庞大的球迷群体，被公认为世界第一大运动。$$, ARRAY[$$足球$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_003$$, $$体育常识$$, $$single$$, $$乒乓球比赛中，每局比赛的获胜分通常是？（不考虑平局加分情况）$$, $$["11分", "15分", "21分", "25分"]$$, $$[0]$$, $$easy$$, $$自2001年起，国际乒联将每局21分制改为11分制。$$, ARRAY[$$乒乓球$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_004$$, $$体育常识$$, $$single$$, $$在篮球比赛中（如NBA或FIBA），三分线外投篮命中得3分，罚球命中得几分？$$, $$["0.5分", "1分", "2分", "3分"]$$, $$[1]$$, $$easy$$, $$篮球比赛中只有通过在罚球线进行罚球命中才能获得1分。$$, ARRAY[$$篮球$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_005$$, $$体育常识$$, $$single$$, $$被称为“国球”并在奥运历史上为中国贡献金牌最多的运动项目之一是？$$, $$["乒乓球", "羽毛球", "体操", "跳水"]$$, $$[0]$$, $$easy$$, $$乒乓球在我国被称为国球，中国队在国际大赛中长期占据统治地位。$$, ARRAY[$$中国体育$$,$$乒乓球$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_006$$, $$体育常识$$, $$single$$, $$网球计分方法非常特殊，得一分被称为？$$, $$["10", "15", "20", "25"]$$, $$[1]$$, $$medium$$, $$网球的一局计分制度为0, 15, 30, 40。得第一分为15。$$, ARRAY[$$网球计分$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_007$$, $$体育常识$$, $$single$$, $$高尔夫球场上，标准杆数为72杆，如果选手在一个4杆洞用了3杆完成，这被称为？$$, $$["老鹰球", "小鸟球", "柏忌", "双柏忌"]$$, $$[1]$$, $$medium$$, $$低于标准杆一杆称为小鸟球(Birdie)，低于两杆称为老鹰球(Eagle)。$$, ARRAY[$$高尔夫$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_008$$, $$体育常识$$, $$single$$, $$田径比赛中被称为“田”的通常是指？$$, $$["跑道上的径赛项目", "投掷和跳跃项目", "马拉松", "竞走"]$$, $$[1]$$, $$medium$$, $$田径（Track and Field）中，“径”指跑道上的赛跑项目，“田”指在田赛场中进行的跳跃和投掷项目。$$, ARRAY[$$田径$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_009$$, $$体育常识$$, $$single$$, $$马拉松长跑的比赛距离是？$$, $$["42公里", "42.195公里", "42.0975公里", "50公里"]$$, $$[1]$$, $$easy$$, $$马拉松比赛全程距离为42.195公里（26英里385码）。$$, ARRAY[$$长跑$$,$$马拉松$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_010$$, $$体育常识$$, $$single$$, $$女子七项全能不包括下列哪项运动？$$, $$["铅球", "跳高", "100米栏", "撑杆跳高"]$$, $$[3]$$, $$hard$$, $$女子七项全能包括：100米栏、跳高、推铅球、200米、跳远、标枪、800米。撑杆跳高不在其中。$$, ARRAY[$$田径$$,$$全能$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_011$$, $$体育常识$$, $$single$$, $$羽毛球比赛中，以下哪项是可能出现的比分？$$, $$["21:0", "21:20", "25:23", "30:29"]$$, $$[0, 2, 3]$$, $$medium$$, $$羽毛球目前实行的是每局先得21分者胜（如果在20平后，须领先对手2分）30分为上限。$$, ARRAY[$$羽毛球$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_012$$, $$体育常识$$, $$single$$, $$足球比赛中，如果防守方球员在己方禁区内对进攻方犯规，主裁判应判罚？$$, $$["角球", "任意球", "点球", "界外球"]$$, $$[2]$$, $$easy$$, $$防守球员在己方禁区（罚球区）内犯规，判罚点球。$$, ARRAY[$$足球规则$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_013$$, $$体育常识$$, $$single$$, $$被誉为“篮球大帝”，带领芝加哥公牛队六夺NBA总冠军的球员是？$$, $$["巴西", "勒布朗·詹姆斯", "迈克尔·乔丹", "魔术师约翰逊"]$$, $$[2]$$, $$easy$$, $$迈克尔·乔丹被广泛认为是篮球史上最伟大的球员。$$, ARRAY[$$篮球$$,$$NBA$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_014$$, $$体育常识$$, $$single$$, $$斯诺克（Snooker）台球比赛中，台面上共有红球多少个？$$, $$["10个", "15个", "21个", "22个"]$$, $$[1]$$, $$medium$$, $$斯诺克开局时有15颗红球（每颗1分）以及6颗彩球。$$, ARRAY[$$台球$$,$$斯诺克$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_015$$, $$体育常识$$, $$single$$, $$被称为三大“绅士运动”之一的是？$$, $$["高尔夫、网球、斯诺克", "足球、篮球、排球", "拳击、摔跤、柔道", "跳水、游泳、花样游泳"]$$, $$[0]$$, $$medium$$, $$网球、高尔夫和斯诺克因极具观赏性、强调比赛礼仪，传统上被称为绅士运动。$$, ARRAY[$$绅士运动$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_016$$, $$体育常识$$, $$single$$, $$排球比赛中，除了决胜局（第五局）外，每局通常要先达到多少分且领先至少两分？$$, $$["15分", "21分", "25分", "30分"]$$, $$[2]$$, $$easy$$, $$室内排球前四局为25分制，第五局决胜局为15分制。$$, ARRAY[$$排球规则$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_017$$, $$体育常识$$, $$single$$, $$F1是一项顶级赛车运动，它的全称是？$$, $$["一级方程式赛车", "超级跑车拉力赛", "房车锦标赛", "越野拉力赛"]$$, $$[0]$$, $$easy$$, $$F1全称是世界一级方程式锦标赛 (FIA Formula One World Championship)。$$, ARRAY[$$赛车$$,$$F1$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_018$$, $$体育常识$$, $$single$$, $$四大满贯网球赛事中，唯一在红土场地上进行的是？$$, $$["澳大利亚网球公开赛", "法国网球公开赛", "温布尔登网球锦标赛", "美国网球公开赛"]$$, $$[1]$$, $$medium$$, $$法网（罗兰·加洛斯）是著名的红土赛事；温网为草地，澳网美网为硬地。$$, ARRAY[$$网球$$,$$大满贯$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_019$$, $$体育常识$$, $$single$$, $$国际象棋的棋盘是由多少个黑白相间的格子组成的？$$, $$["64个", "81个", "100个", "121个"]$$, $$[0]$$, $$medium$$, $$国际象棋棋盘是一个8×8的方阵，共有64个小黑白格。$$, ARRAY[$$棋类比赛$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_020$$, $$体育常识$$, $$single$$, $$现代柔道运动起源于哪个国家？$$, $$["韩国", "日本", "泰国", "中国"]$$, $$[1]$$, $$easy$$, $$柔道（Judo）起源于日本武术，由嘉纳治五郎在19世纪后期创立。$$, ARRAY[$$武术$$,$$柔道$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_021$$, $$体育常识$$, $$single$$, $$被称为世界三大自行车环赛之一，历史最悠久、影响力最大的是？$$, $$["环意自行车赛", "环法自行车赛", "环西自行车赛", "环青海湖自行车赛"]$$, $$[1]$$, $$medium$$, $$环法国自行车赛 (Tour de France) 是最知名和最重要的多日自行车锦标赛。$$, ARRAY[$$自行车$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_022$$, $$体育常识$$, $$single$$, $$排球运动中的“自由人”不能做下列哪个动作？$$, $$["在后排防守救球", "替换后排球员", "发球", "穿与其他队员不同颜色的球衣"]$$, $$[2]$$, $$hard$$, $$自由防守球员（自由人）不能发球、拦网或试图拦网，也不能将高于球网上沿的球直接处理过网。$$, ARRAY[$$排球规则$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_023$$, $$体育常识$$, $$multiple$$, $$游泳项目在世锦赛和奥运会中的四大标准竞技泳姿包括？$$, $$["自由泳", "蛙泳", "仰泳", "蝶泳"]$$, $$[0, 1, 2, 3]$$, $$easy$$, $$游泳比赛规定的四大游姿即为自由泳（通常采用爬泳）、蛙泳、仰泳和蝶泳。$$, ARRAY[$$游泳$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_024$$, $$体育常识$$, $$multiple$$, $$现代五项属于田径界著名的全能比赛形式，以下哪些项目属于男子现代五项？$$, $$["射击与击剑", "游泳", "马术", "跨栏"]$$, $$[0, 1, 2]$$, $$hard$$, $$现代五项由马术、击剑、射击、越野跑和游泳组成。现在射击和跑合并为了原名激光跑。$$, ARRAY[$$现代五项$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_025$$, $$体育常识$$, $$multiple$$, $$乒乓球双打比赛的特殊规则有？$$, $$["发球时必须从己方的右半区发到对方的右半区", "搭档两人必须交替击球", "可以一人连续打两个球", "发球完全没有任何区域限制"]$$, $$[0, 1]$$, $$medium$$, $$乒乓球双打规定发球必须从右半区发至右半区，且同伴之间必须轮流击球，不得一人连击。$$, ARRAY[$$乒乓球规则$$]::text[], $${"教育学": 0.5, "医学": 0.3, "日子人": 0.4}$$, 'batch'),
  ($$spo_026$$, $$体育常识$$, $$multiple$$, $$在篮球运动中，以下哪些行为属于犯规(Foul)而非违例(Violation)？$$, $$["打手", "阻挡", "恶意拉拽", "走步"]$$, $$[0, 1, 2]$$, $$medium$$, $$走步属于违例动作，对方通常只是获得球权，而打手、阻挡是身体接触造成的犯规，会被记录甚至罚球。$$, ARRAY[$$篮球规则$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_027$$, $$体育常识$$, $$multiple$$, $$足球比赛中红牌的作用包括？$$, $$["被罚球员必须无条件离场", "该队必须少一人继续比赛", "罚下场的球员可以被替补席球员立刻替换", "一般伴有至少停赛一场的追加处罚"]$$, $$[0, 1, 3]$$, $$easy$$, $$被红牌罚下后不可被替换，球队只能以少打多进行剩余比赛。$$, ARRAY[$$足球$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_028$$, $$体育常识$$, $$multiple$$, $$下列运动中哪些属于依靠得分直接决定胜负，而不采用主观评委打分的“客观计分项目”？$$, $$["花样滑冰", "网球", "篮球", "艺术体操"]$$, $$[1, 2]$$, $$easy$$, $$花样滑冰和艺术体操都需要裁判依据艺术表现和动作完成度来打分；网球篮球则是客观的进球/出界得分制。$$, ARRAY[$$体育分类$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
  ($$spo_029$$, $$体育常识$$, $$multiple$$, $$世界顶级的职业体育联赛季后赛中，哪些长期采用“七场四胜制”？$$, $$["NBA 总决赛", "MLB 世界大赛", "NFL 欧洲足联冠军联赛决赛", "欧冠决赛"]$$, $$[0, 1]$$, $$medium$$, $$NBA和MLB的总决赛都是七局四胜制。而欧洲足球冠军联赛的决赛为单场定胜负。$$, ARRAY[$$体育联赛$$]::text[], $${"教育学": 1.0, "日子人": 0.6, "历史学": 0.3, "医学": 0.15}$$, 'batch'),
